animation_update::AttackPayload payload_from_attack_box(const animation_update::FrameAttackBox& box) {
    if (!box.payload.payload_id.empty()) {
        return animation_update::sanitize_attack_payload(box.payload);
    }
    return animation_update::attack_payload_from_box(
        box.damage_amount,
        box.payload_id.empty() ? box.id : box.payload_id,
        box.meta_json);
}

void write_payload_to_attack_box(animation_update::FrameAttackBox& box,
                                 const animation_update::AttackPayload& payload_values) {
    animation_update::AttackPayload payload = animation_update::sanitize_attack_payload(payload_values);
    if (payload.payload_id.empty()) {
        payload.payload_id = box.payload_id.empty() ? box.id : box.payload_id;
    }
    box.payload = payload;
    box.payload_id = payload.payload_id;
    box.damage_amount = payload.damage_amount;
    box.meta_json = animation_update::merge_attack_payload_into_meta_json(box.meta_json, payload);
}

animation_update::AttackPayload resolve_payload_for_box_id(const Animation& animation,
                                                           const animation_update::FrameAttackBox& selected_box) {
    const std::string target_id = selected_box.id;
    if (target_id.empty()) {
        return payload_from_attack_box(selected_box);
    }
    for (const auto& frame : animation.primary_frames()) {
        for (const auto& candidate : frame.attack_boxes.boxes) {
            if (candidate.id == target_id) {
                return payload_from_attack_box(candidate);
            }
        }
    }
    return payload_from_attack_box(selected_box);
}

bool project_runtime_box_point_to_screen(const Asset::RuntimeBoxPoint3& world_point,
                                         const WarpedScreenGrid& cam,
                                         SDL_FPoint& out_screen);

bool projected_volume_contains_screen_point(const Asset::RuntimeBoxVolume& volume,
                                            const WarpedScreenGrid& cam,
                                            SDL_Point screen_point);

std::optional<BoxCornerPickResult> find_box_corner_at_screen_point_for_index(
    const std::vector<Asset::RuntimeBoxVolume>& volumes,
    int box_index,
    const WarpedScreenGrid& cam,
    SDL_Point screen_point,
    int radius_px) {
    if (box_index < 0 || box_index >= static_cast<int>(volumes.size())) {
        return std::nullopt;
    }
    const auto& volume = volumes[static_cast<std::size_t>(box_index)];
    if (!volume.valid) {
        return std::nullopt;
    }
    const float radius_sq = static_cast<float>(radius_px * radius_px);
    float best_dist_sq = radius_sq;
    std::optional<BoxCornerPickResult> best;
    // Only the four 2D box corners are interactive. The far/extruded points are debug-only.
    for (int point_index = 0; point_index < 4; ++point_index) {
        SDL_FPoint projected{};
        if (!project_runtime_box_point_to_screen(volume.world_points[static_cast<std::size_t>(point_index)],
                                                 cam,
                                                 projected)) {
            continue;
        }
        const float dx = projected.x - static_cast<float>(screen_point.x);
        const float dy = projected.y - static_cast<float>(screen_point.y);
        const float dist_sq = dx * dx + dy * dy;
        if (dist_sq <= best_dist_sq) {
            best_dist_sq = dist_sq;
            best = BoxCornerPickResult{
                box_index,
                point_index % 4,
                point_index,
            };
        }
    }
    return best;
}

bool box_body_contains_screen_point_for_index(const std::vector<Asset::RuntimeBoxVolume>& volumes,
                                              int box_index,
                                              const WarpedScreenGrid& cam,
                                              SDL_Point screen_point) {
    if (box_index < 0 || box_index >= static_cast<int>(volumes.size())) {
        return false;
    }
    const auto& volume = volumes[static_cast<std::size_t>(box_index)];
    if (!volume.valid) {
        return false;
    }
    return projected_volume_contains_screen_point(volume, cam, screen_point);
}

float normalize_angle_delta_degrees(float value) {
    float normalized = std::fmod(value, 360.0f);
    if (normalized > 180.0f) {
        normalized -= 360.0f;
    } else if (normalized < -180.0f) {
        normalized += 360.0f;
    }
    return normalized;
}

float screen_angle_degrees(const SDL_FPoint& center, const SDL_Point& point) {
    const float dx = static_cast<float>(point.x) - center.x;
    const float dy = static_cast<float>(point.y) - center.y;
    return static_cast<float>(std::atan2(dy, dx) * (180.0 / kPi));
}

float normalize_oval_angle_degrees(float degrees) {
    return oval_anchor_math::normalize_angle_degrees(degrees);
}

float clamp_oval_radius_offset_degrees(float degrees) {
    if (!std::isfinite(degrees)) {
        return 0.0f;
    }
    return std::clamp(degrees, 0.0f, 360.0f);
}

std::vector<AssetInfo::OvalAnchorPoint> sort_oval_points_by_angle(
    const std::vector<AssetInfo::OvalAnchorPoint>& points) {
    return devmode::oval_point_topology::sort_points_by_angle(points);
}

int nearest_oval_point_index_for_angle(const std::vector<AssetInfo::OvalAnchorPoint>& points, float angle_degrees) {
    if (points.empty() || !std::isfinite(angle_degrees)) {
        return -1;
    }
    const float target = normalize_oval_angle_degrees(angle_degrees);
    int best_index = -1;
    float best_delta = std::numeric_limits<float>::max();
    for (std::size_t i = 0; i < points.size(); ++i) {
        float delta = std::fabs(normalize_oval_angle_degrees(points[i].angle_degrees) - target);
        delta = std::min(delta, 360.0f - delta);
        if (delta < best_delta) {
            best_delta = delta;
            best_index = static_cast<int>(i);
        }
    }
    return best_index;
}

void recompute_oval_point_from_angle(AssetInfo::OvalAnchorPoint& point, float width_radius_x, float height_radius_z) {
    point.angle_degrees = normalize_oval_angle_degrees(point.angle_degrees);
    oval_anchor_math::compute_xz_offsets_from_angle(point.angle_degrees,
                                                    width_radius_x,
                                                    height_radius_z,
                                                    point.texture_x,
                                                    point.texture_y);
    if (!std::isfinite(point.depth_offset)) {
        point.depth_offset = 0.0f;
    }
}

bool is_oval_center_anchor_name(const std::string& anchor_name) {
    constexpr const char* kOvalCenterSuffix = "_oval_center";
    if (anchor_name.size() <= std::strlen(kOvalCenterSuffix)) {
        return false;
    }
    const std::size_t suffix_pos = anchor_name.size() - std::strlen(kOvalCenterSuffix);
    return anchor_name.compare(suffix_pos, std::strlen(kOvalCenterSuffix), kOvalCenterSuffix) == 0;
}

bool compute_rotation_handle_screen_for_volume(const Asset::RuntimeBoxVolume& volume,
                                               const WarpedScreenGrid& cam,
                                               SDL_FPoint& out_handle,
                                               SDL_FPoint* out_top_mid = nullptr,
                                               SDL_FPoint* out_center = nullptr) {
    if (!volume.valid) {
        return false;
    }

    std::array<SDL_FPoint, 4> near_points{};
    for (int i = 0; i < 4; ++i) {
        if (!project_runtime_box_point_to_screen(volume.world_points[static_cast<std::size_t>(i)], cam, near_points[static_cast<std::size_t>(i)])) {
            return false;
        }
    }

    SDL_FPoint center{
        (near_points[0].x + near_points[1].x + near_points[2].x + near_points[3].x) * 0.25f,
        (near_points[0].y + near_points[1].y + near_points[2].y + near_points[3].y) * 0.25f,
    };
    SDL_FPoint top_mid{
        (near_points[0].x + near_points[1].x) * 0.5f,
        (near_points[0].y + near_points[1].y) * 0.5f,
    };

    float dir_x = top_mid.x - center.x;
    float dir_y = top_mid.y - center.y;
    const float dir_len = std::hypot(dir_x, dir_y);
    if (!std::isfinite(dir_len) || dir_len <= 1e-4f) {
        dir_x = 0.0f;
        dir_y = -1.0f;
    } else {
        dir_x /= dir_len;
        dir_y /= dir_len;
    }

    out_handle = SDL_FPoint{
        top_mid.x + (dir_x * kBoxRotationHandleDistancePx),
        top_mid.y + (dir_y * kBoxRotationHandleDistancePx),
    };
    if (out_top_mid) {
        *out_top_mid = top_mid;
    }
    if (out_center) {
        *out_center = center;
    }
    return std::isfinite(out_handle.x) && std::isfinite(out_handle.y);
}

std::optional<BoxRotationHandlePickResult> find_box_rotation_handle_at_screen_point_for_index(
    const std::vector<Asset::RuntimeBoxVolume>& volumes,
    int box_index,
    const WarpedScreenGrid& cam,
    SDL_Point screen_point,
    int radius_px) {
    if (box_index < 0 || box_index >= static_cast<int>(volumes.size())) {
        return std::nullopt;
    }
    const auto& volume = volumes[static_cast<std::size_t>(box_index)];
    SDL_FPoint handle{};
    SDL_FPoint center{};
    if (!compute_rotation_handle_screen_for_volume(volume, cam, handle, nullptr, &center)) {
        return std::nullopt;
    }
    const float dx = handle.x - static_cast<float>(screen_point.x);
    const float dy = handle.y - static_cast<float>(screen_point.y);
    const float dist_sq = dx * dx + dy * dy;
    const float radius_sq = static_cast<float>(radius_px * radius_px);
    if (dist_sq > radius_sq) {
        return std::nullopt;
    }
    return BoxRotationHandlePickResult{
        box_index,
        handle,
        center,
    };
}

bool box_trace_enabled() {
    static const bool enabled = [] {
        const char* raw = SDL_getenv("VIBBLE_BOX_TRACE");
        if (!raw || !*raw) {
            return false;
        }
        const std::string value(raw);
        return value == "1" || value == "true" || value == "TRUE" || value == "on" || value == "ON";
    }();
    return enabled;
}

template <typename TBox>
std::string box_ids_csv(const std::vector<TBox>& boxes) {
    std::ostringstream out;
    for (std::size_t i = 0; i < boxes.size(); ++i) {
        if (i > 0) {
            out << ",";
        }
        out << boxes[i].id;
    }
    return out.str();
}

std::string sanitize_box_id(std::string value) {
    std::string out;
    out.reserve(value.size());
    for (char ch : value) {
        const unsigned char uch = static_cast<unsigned char>(ch);
        if (std::isalnum(uch) != 0 || ch == '_' || ch == '-' || ch == '.') {
            out.push_back(static_cast<char>(std::tolower(uch)));
        } else if (std::isspace(uch) != 0) {
            out.push_back('_');
        }
    }
    return out;
}

std::string ensure_unique_box_id(const std::string& raw_id,
                                 const char* fallback_prefix,
                                 int frame_index,
                                 std::size_t ordinal,
                                 std::unordered_set<std::string>& used_ids) {
    std::string base = sanitize_box_id(raw_id);
    if (base.empty()) {
        base = sanitize_box_id(std::string{fallback_prefix} + "_" +
                               std::to_string(frame_index + 1) + "_" +
                               std::to_string(ordinal + 1));
    }
    std::string candidate = base;
    int suffix = 2;
    while (!used_ids.insert(candidate).second) {
        candidate = base + "_" + std::to_string(suffix++);
    }
    return candidate;
}

const nlohmann::json* locate_room_manifest_animation_map(const nlohmann::json& manifest_payload) {
    if (!manifest_payload.is_object()) {
        return nullptr;
    }
    const auto animations_it = manifest_payload.find("animations");
    if (animations_it == manifest_payload.end() || !animations_it->is_object()) {
        return nullptr;
    }
    const nlohmann::json& animations_node = *animations_it;
    const auto nested_it = animations_node.find("animations");
    if (nested_it != animations_node.end() && nested_it->is_object()) {
        return &(*nested_it);
    }
    return &animations_node;
}

std::optional<nlohmann::json> find_room_manifest_animation_payload(const nlohmann::json& manifest_payload,
                                                                    const std::string& animation_id) {
    const nlohmann::json* animations_map = locate_room_manifest_animation_map(manifest_payload);
    if (!animations_map) {
        return std::nullopt;
    }
    auto it = animations_map->find(animation_id);
    if (it == animations_map->end() || !it->is_object()) {
        return std::nullopt;
    }
    return *it;
}

std::vector<devmode::room_movement_payload::MovementFrame>
movement_frames_from_runtime_animation(const Animation& animation) {
    std::vector<devmode::room_movement_payload::MovementFrame> frames;
    if (!animation.has_frames()) {
        frames.push_back(devmode::room_movement_payload::MovementFrame{});
        return frames;
    }

    frames.resize(std::max<std::size_t>(std::size_t{1}, animation.frame_count()));
    for (std::size_t i = 0; i < animation.frame_count(); ++i) {
        const AnimationFrame* runtime_frame = animation.primary_frame_at(i);
        if (!runtime_frame) {
            continue;
        }
        auto& frame = frames[i];
        frame.dx = static_cast<float>(runtime_frame->dx);
        frame.dy = static_cast<float>(runtime_frame->dy);
        frame.dz = static_cast<float>(runtime_frame->dz);
        frame.rotation_degrees = runtime_frame->rotation_degrees;
        frame.resort_z = runtime_frame->z_resort;
    }
    return frames;
}

struct MovementRelativePath {
    std::vector<SDL_FPoint> xy;
    std::vector<float> z;
};

MovementRelativePath build_movement_relative_path(
    const std::vector<devmode::room_movement_payload::MovementFrame>& frames) {
    MovementRelativePath path{};
    path.xy.assign(frames.size(), SDL_FPoint{0.0f, 0.0f});
    path.z.assign(frames.size(), 0.0f);
    if (frames.empty()) {
        return path;
    }

    for (std::size_t i = 1; i < frames.size(); ++i) {
        const auto& frame = frames[i];
        AnimationFrame runtime_frame{};
        runtime_frame.dx = static_cast<int>(std::lround(frame.dx));
        runtime_frame.dy = static_cast<int>(std::lround(frame.dy));
        runtime_frame.dz = static_cast<int>(std::lround(frame.dz));
        runtime_frame.rotation_degrees = frame.rotation_degrees;
        const axis::WorldPos delta =
            animation_update::movement_rotation::frame_world_delta_absolute_yaw(runtime_frame);
        path.xy[i].x = path.xy[i - 1].x + static_cast<float>(delta.x);
        path.xy[i].y = path.xy[i - 1].y + static_cast<float>(delta.z);
        path.z[i] = path.z[i - 1] + static_cast<float>(delta.y);
    }
    return path;
}

std::vector<std::vector<devmode::room_movement_payload::MovementFrame>>
resolve_room_movement_paths_for_animation(const Asset* target, const std::string& animation_id);

std::vector<devmode::room_movement_payload::MovementFrame>
resolve_room_movement_frames_for_animation(const Asset* target, const std::string& animation_id) {
    auto paths = resolve_room_movement_paths_for_animation(target, animation_id);
    if (!paths.empty()) return paths.front();
    return {devmode::room_movement_payload::MovementFrame{}};
}

std::vector<std::vector<devmode::room_movement_payload::MovementFrame>>
resolve_room_movement_paths_for_animation(const Asset* target, const std::string& animation_id) {
    if (!target || !target->info || animation_id.empty()) {
        return {{devmode::room_movement_payload::MovementFrame{}}};
    }

    nlohmann::json manifest_payload = target->info->manifest_payload();
    nlohmann::json existing_payload =
        find_room_manifest_animation_payload(manifest_payload, animation_id).value_or(nlohmann::json::object());
    const bool has_local_movement =
        existing_payload.is_object() &&
        existing_payload.contains("movement") &&
        existing_payload["movement"].is_array();

    if (has_local_movement || (existing_payload.contains("movement_paths") && existing_payload["movement_paths"].is_array())) {
        std::vector<std::vector<devmode::room_movement_payload::MovementFrame>> paths;
        if (existing_payload.contains("movement_paths") && existing_payload["movement_paths"].is_array()) {
            for (const auto& path_payload : existing_payload["movement_paths"]) {
                nlohmann::json wrapped = nlohmann::json::object();
                wrapped["movement"] = path_payload;
                paths.push_back(devmode::room_movement_payload::parse_frames_from_payload(wrapped));
            }
        }
        if (paths.empty() && has_local_movement) {
            paths.push_back(devmode::room_movement_payload::parse_frames_from_payload(existing_payload));
        }
        if (!paths.empty()) return paths;
    }

    return {{devmode::room_movement_payload::MovementFrame{}}};
}

std::string make_unique_floor_box_id(const std::vector<AssetInfo::FloorBox>& boxes,
                                     const std::string& preferred_id = std::string{}) {
    std::unordered_set<std::string> used_ids;
    used_ids.reserve(boxes.size());
    for (const auto& box : boxes) {
        if (!box.id.empty()) {
            used_ids.insert(box.id);
        }
    }

    std::string base = vibble::strings::trim_copy(preferred_id);
    if (base.empty()) {
        base = "floor_box";
    }
    if (used_ids.find(base) == used_ids.end()) {
        return base;
    }

    int suffix = 1;
    std::string candidate = base + "_" + std::to_string(suffix);
    while (used_ids.find(candidate) != used_ids.end()) {
        ++suffix;
        candidate = base + "_" + std::to_string(suffix);
    }
    return candidate;
}

std::string make_unique_floor_box_name(const std::vector<AssetInfo::FloorBox>& boxes,
                                       const std::string& desired_name,
                                       const std::string& current_name = std::string{}) {
    const std::string trimmed = vibble::strings::trim_copy(desired_name);
    std::string base_name = trimmed.empty() ? std::string("Floor Box") : trimmed;
    if (!current_name.empty() && base_name == current_name) {
        return base_name;
    }

    std::unordered_set<std::string> used_names;
    used_names.reserve(boxes.size());
    for (const auto& box : boxes) {
        if (!box.name.empty() && box.name != current_name) {
            used_names.insert(box.name);
        }
    }

    if (used_names.find(base_name) == used_names.end()) {
        return base_name;
    }

    int suffix = 2;
    std::string candidate = base_name + " " + std::to_string(suffix);
    while (used_names.find(candidate) != used_names.end()) {
        ++suffix;
        candidate = base_name + " " + std::to_string(suffix);
    }
    return candidate;
}

template <typename TItem>
int find_index_by_id_name_index(const std::vector<TItem>& items,
                                const std::string& id,
                                const std::string& name,
                                int index_fallback) {
    if (!id.empty()) {
        const auto id_it = std::find_if(items.begin(), items.end(), [&](const TItem& item) {
            return item.id == id;
        });
        if (id_it != items.end()) {
            return static_cast<int>(std::distance(items.begin(), id_it));
        }
    }
    if (!name.empty()) {
        const auto name_it = std::find_if(items.begin(), items.end(), [&](const TItem& item) {
            return item.name == name;
        });
        if (name_it != items.end()) {
            return static_cast<int>(std::distance(items.begin(), name_it));
        }
    }
    if (index_fallback >= 0 && index_fallback < static_cast<int>(items.size())) {
        return index_fallback;
    }
    return -1;
}

int find_index_by_name_index(const std::vector<AssetInfo::OvalAnchorMapping>& mappings,
                             const std::string& name,
                             int index_fallback) {
    if (!name.empty()) {
        const auto name_it = std::find_if(mappings.begin(), mappings.end(), [&](const AssetInfo::OvalAnchorMapping& mapping) {
            return mapping.name == name;
        });
        if (name_it != mappings.end()) {
            return static_cast<int>(std::distance(mappings.begin(), name_it));
        }
    }
    if (index_fallback >= 0 && index_fallback < static_cast<int>(mappings.size())) {
        return index_fallback;
    }
    return -1;
}

std::string normalize_floor_box_tag(std::string raw_tag) {
    std::string normalized = vibble::strings::to_lower_copy(vibble::strings::trim_copy(raw_tag));
    if (normalized.empty()) {
        return std::string{};
    }
    return normalized;
}

std::vector<std::string> normalize_floor_box_tags(const std::vector<std::string>& tags) {
    std::set<std::string> deduped;
    for (const auto& raw_tag : tags) {
        const std::string normalized = normalize_floor_box_tag(raw_tag);
        if (!normalized.empty()) {
            deduped.insert(normalized);
        }
    }
    return std::vector<std::string>(deduped.begin(), deduped.end());
}

std::array<SDL_FPoint, 4> floor_box_world_corners(const Asset& asset, const AssetInfo::FloorBox& box) {
    const float half_width = std::max(0.0f, box.width) * 0.5f;
    const float half_depth = std::max(0.0f, box.depth) * 0.5f;
    const float center_x = static_cast<float>(asset.world_x()) + box.position_x;
    const float center_z = static_cast<float>(asset.world_z()) + box.position_z;
    return std::array<SDL_FPoint, 4>{
        SDL_FPoint{center_x - half_width, center_z - half_depth}, // TL
        SDL_FPoint{center_x + half_width, center_z - half_depth}, // TR
        SDL_FPoint{center_x - half_width, center_z + half_depth}, // BL
        SDL_FPoint{center_x + half_width, center_z + half_depth}, // BR
    };
}

SDL_FPoint floor_box_world_center(const Asset& asset, const AssetInfo::FloorBox& box) {
    return SDL_FPoint{
        static_cast<float>(asset.world_x()) + box.position_x,
        static_cast<float>(asset.world_z()) + box.position_z,
    };
}

struct ImpassableShapeProjection {
    bool valid = false;
    std::vector<SDL_FPoint> anchor_screen_points;
    std::vector<SDL_FPoint> floor_world_points;
    std::vector<SDL_FPoint> floor_screen_points;
};

long long impassable_orientation(const AssetInfo::ImpassableShapePoint& a,
                                 const AssetInfo::ImpassableShapePoint& b,
                                 const AssetInfo::ImpassableShapePoint& c) {
    return (static_cast<long long>(b.x) - static_cast<long long>(a.x)) *
               (static_cast<long long>(c.y) - static_cast<long long>(a.y)) -
           (static_cast<long long>(b.y) - static_cast<long long>(a.y)) *
               (static_cast<long long>(c.x) - static_cast<long long>(a.x));
}

bool impassable_point_on_segment(const AssetInfo::ImpassableShapePoint& a,
                                 const AssetInfo::ImpassableShapePoint& b,
                                 const AssetInfo::ImpassableShapePoint& p) {
    if (impassable_orientation(a, b, p) != 0) {
        return false;
    }
    return p.x >= std::min(a.x, b.x) && p.x <= std::max(a.x, b.x) &&
           p.y >= std::min(a.y, b.y) && p.y <= std::max(a.y, b.y);
}

bool impassable_segments_intersect(const AssetInfo::ImpassableShapePoint& a1,
                                   const AssetInfo::ImpassableShapePoint& a2,
                                   const AssetInfo::ImpassableShapePoint& b1,
                                   const AssetInfo::ImpassableShapePoint& b2) {
    const long long o1 = impassable_orientation(a1, a2, b1);
    const long long o2 = impassable_orientation(a1, a2, b2);
    const long long o3 = impassable_orientation(b1, b2, a1);
    const long long o4 = impassable_orientation(b1, b2, a2);
    if (((o1 > 0 && o2 < 0) || (o1 < 0 && o2 > 0)) &&
        ((o3 > 0 && o4 < 0) || (o3 < 0 && o4 > 0))) {
        return true;
    }
    if (o1 == 0 && impassable_point_on_segment(a1, a2, b1)) return true;
    if (o2 == 0 && impassable_point_on_segment(a1, a2, b2)) return true;
    if (o3 == 0 && impassable_point_on_segment(b1, b2, a1)) return true;
    if (o4 == 0 && impassable_point_on_segment(b1, b2, a2)) return true;
    return false;
}

bool impassable_shape_self_intersects(const std::vector<AssetInfo::ImpassableShapePoint>& points) {
    if (points.size() < 4) {
        return false;
    }
    const std::size_t n = points.size();
    for (std::size_t i = 0; i < n; ++i) {
        const std::size_t i2 = (i + 1) % n;
        for (std::size_t j = i + 1; j < n; ++j) {
            const std::size_t j2 = (j + 1) % n;
            if (i == j || i == j2 || i2 == j || i2 == j2) {
                continue;
            }
            if (impassable_segments_intersect(points[i], points[i2], points[j], points[j2])) {
                return true;
            }
        }
    }
    return false;
}

void normalize_impassable_shape_winding(std::vector<AssetInfo::ImpassableShapePoint>& points) {
    if (points.size() < 3) {
        return;
    }
    long long area2 = 0;
    for (std::size_t i = 0; i < points.size(); ++i) {
        const auto& a = points[i];
        const auto& b = points[(i + 1) % points.size()];
        area2 += static_cast<long long>(a.x) * static_cast<long long>(b.y) -
                 static_cast<long long>(b.x) * static_cast<long long>(a.y);
    }
    if (area2 < 0) {
        std::reverse(points.begin(), points.end());
    }
}

bool project_floor_world_xz_to_screen(const WarpedScreenGrid& cam,
                                      const SDL_FPoint& floor_world_xz,
                                      SDL_FPoint& out_screen) {
    SDL_FPoint linear_screen{};
    if (!cam.project_world_point(SDL_FPoint{floor_world_xz.x, 0.0f},
                                 floor_world_xz.y,
                                 linear_screen) ||
        !std::isfinite(linear_screen.x) ||
        !std::isfinite(linear_screen.y)) {
        return false;
    }
    linear_screen.y = cam.warp_floor_screen_y(0.0f, linear_screen.y);
    if (!std::isfinite(linear_screen.y)) {
        return false;
    }
    out_screen = linear_screen;
    return true;
}

bool project_impassable_shape(const Asset& target,
                              const AssetInfo::ImpassableShape& shape,
                              const WarpedScreenGrid& cam,
                              ImpassableShapeProjection& out_projection) {
    out_projection = ImpassableShapeProjection{};
    if (!shape.enabled || shape.points.size() < 3) {
        return false;
    }

    out_projection.anchor_screen_points.reserve(shape.points.size());
    out_projection.floor_world_points.reserve(shape.points.size());
    out_projection.floor_screen_points.reserve(shape.points.size());

    for (const auto& point : shape.points) {
        DisplacedAssetAnchorPoint sample_anchor{};
        sample_anchor.name = "__impassable_shape_point";
        sample_anchor.texture_x = std::max(0, point.x);
        sample_anchor.texture_y = std::max(0, point.y);
        sample_anchor.depth_offset = 0;
        const auto sample = anchor_points::resolve_frame_anchor_sample(
            target,
            sample_anchor,
            anchor_points::GridMaterialization::None);
        if (sample.resolved.missing || !sample.has_flat_screen_px) {
            return false;
        }

        const anchor_points::AnchorWorldPoint3 floor_projection_point =
            sample.final_anchor_point.valid ? sample.final_anchor_point : sample.flat_relative_pixel_point;
        if (!floor_projection_point.valid ||
            !std::isfinite(floor_projection_point.x) ||
            !std::isfinite(floor_projection_point.z)) {
            return false;
        }

        out_projection.anchor_screen_points.push_back(sample.flat_screen_px);
        out_projection.floor_world_points.push_back(
            SDL_FPoint{floor_projection_point.x, floor_projection_point.z});
        SDL_FPoint floor_screen{};
        if (!project_floor_world_xz_to_screen(
                cam,
                SDL_FPoint{floor_projection_point.x, floor_projection_point.z},
                floor_screen)) {
            return false;
        }
        out_projection.floor_screen_points.push_back(floor_screen);
    }

    out_projection.valid = out_projection.anchor_screen_points.size() >= 3 &&
                           out_projection.floor_screen_points.size() >= 3;
    return out_projection.valid;
}

nlohmann::json default_floor_box_candidate_entry_json() {
    nlohmann::json entry = nlohmann::json::object();
    entry["candidates"] = nlohmann::json::array({
        nlohmann::json::object({{"name", "null"}, {"chance", 0}})
    });
    entry["grid_resolution"] = kFloorBoxCandidateGridResolutionDefault;
    return entry;
}

nlohmann::json build_empty_box_frame_array(std::size_t frame_count) {
    nlohmann::json frames = nlohmann::json::array();
    for (std::size_t i = 0; i < frame_count; ++i) {
        frames.push_back(nlohmann::json::array());
    }
    return frames;
}

int clamp_box_corner_index(int index) {
    return std::clamp(index, 0, 3);
}

int editor_corner_from_runtime_corner(int runtime_corner_index) {
    switch (clamp_box_corner_index(runtime_corner_index)) {
        case 0:
            return 0;  // TL
        case 1:
            return 1;  // TR
        case 2:
            return 3;  // BR -> editor BR
        default:
            return 2;  // BL -> editor BL
    }
}

int runtime_corner_from_editor_corner(int editor_corner_index) {
    switch (clamp_box_corner_index(editor_corner_index)) {
        case 0:
            return 0;  // TL
        case 1:
            return 1;  // TR
        case 2:
            return 3;  // BL -> runtime index 3
        default:
            return 2;  // BR -> runtime index 2
    }
}

animation_update::FrameBoxCornerId editor_corner_id(int editor_corner_index) {
    switch (clamp_box_corner_index(editor_corner_index)) {
        case 0:
            return animation_update::FrameBoxCornerId::TL;
        case 1:
            return animation_update::FrameBoxCornerId::TR;
        case 2:
            return animation_update::FrameBoxCornerId::BL;
        default:
            return animation_update::FrameBoxCornerId::BR;
    }
}

bool project_runtime_box_point_to_screen(const Asset::RuntimeBoxPoint3& world_point,
                                         const WarpedScreenGrid& cam,
                                         SDL_FPoint& out_screen) {
    SDL_FPoint world_xy{world_point.x, world_point.y};
    if (cam.project_world_point(world_xy, world_point.z, out_screen)) {
        return std::isfinite(out_screen.x) && std::isfinite(out_screen.y);
    }
    // map_to_screen_f expects floor-plane x/z coordinates.
    out_screen = cam.map_to_screen_f(SDL_FPoint{world_point.x, world_point.z});
    return std::isfinite(out_screen.x) && std::isfinite(out_screen.y);
}

bool project_runtime_box_point_to_screen_on_floor(const Asset::RuntimeBoxPoint3& world_point,
                                                  const WarpedScreenGrid& cam,
                                                  SDL_FPoint& out_screen) {
    Asset::RuntimeBoxPoint3 floor_point = world_point;
    floor_point.y = 0.0f;
    if (project_runtime_box_point_to_screen(floor_point, cam, out_screen)) {
        return true;
    }
    out_screen = cam.map_to_screen_f(SDL_FPoint{floor_point.x, floor_point.z});
    return std::isfinite(out_screen.x) && std::isfinite(out_screen.y);
}

BoxExtrusionHandleProjection project_extrusion_floor_handles(const Asset::RuntimeBoxVolume& volume,
                                                             const WarpedScreenGrid& cam) {
    BoxExtrusionHandleProjection projection{};
    if (!volume.valid) {
        return projection;
    }
    if (!project_runtime_box_point_to_screen_on_floor(volume.world_points[3], cam, projection.front_a) ||
        !project_runtime_box_point_to_screen_on_floor(volume.world_points[2], cam, projection.front_b) ||
        !project_runtime_box_point_to_screen_on_floor(volume.world_points[7], cam, projection.back_a) ||
        !project_runtime_box_point_to_screen_on_floor(volume.world_points[6], cam, projection.back_b)) {
        return projection;
    }

    projection.front_mid = SDL_FPoint{
        (projection.front_a.x + projection.front_b.x) * 0.5f,
        (projection.front_a.y + projection.front_b.y) * 0.5f,
    };
    projection.back_mid = SDL_FPoint{
        (projection.back_a.x + projection.back_b.x) * 0.5f,
        (projection.back_a.y + projection.back_b.y) * 0.5f,
    };
    projection.axis_center = SDL_FPoint{
        (projection.front_mid.x + projection.back_mid.x) * 0.5f,
        (projection.front_mid.y + projection.back_mid.y) * 0.5f,
    };
    const float axis_dx = projection.back_mid.x - projection.front_mid.x;
    const float axis_dy = projection.back_mid.y - projection.front_mid.y;
    const float axis_len = std::hypot(axis_dx, axis_dy);
    if (!std::isfinite(axis_len) || axis_len <= 1e-4f) {
        return projection;
    }
    projection.axis_unit = SDL_FPoint{axis_dx / axis_len, axis_dy / axis_len};
    projection.half_separation = axis_len * 0.5f;
    projection.valid = std::isfinite(projection.half_separation) && projection.half_separation > 0.0f;
    return projection;
}

float point_to_segment_distance_sq(const SDL_FPoint& point,
                                   const SDL_FPoint& segment_a,
                                   const SDL_FPoint& segment_b) {
    const float ab_x = segment_b.x - segment_a.x;
    const float ab_y = segment_b.y - segment_a.y;
    const float ab_len_sq = ab_x * ab_x + ab_y * ab_y;
    if (!std::isfinite(ab_len_sq) || ab_len_sq <= 1e-6f) {
        const float dx = point.x - segment_a.x;
        const float dy = point.y - segment_a.y;
        return dx * dx + dy * dy;
    }
    const float ap_x = point.x - segment_a.x;
    const float ap_y = point.y - segment_a.y;
    const float t = std::clamp((ap_x * ab_x + ap_y * ab_y) / ab_len_sq, 0.0f, 1.0f);
    const float closest_x = segment_a.x + ab_x * t;
    const float closest_y = segment_a.y + ab_y * t;
    const float dx = point.x - closest_x;
    const float dy = point.y - closest_y;
    return dx * dx + dy * dy;
}

BoxExtrusionHandleSide find_extrusion_handle_at_screen_point(const std::vector<Asset::RuntimeBoxVolume>& volumes,
                                                             int box_index,
                                                             const WarpedScreenGrid& cam,
                                                             SDL_Point screen_point,
                                                             int radius_px) {
    if (box_index < 0 || box_index >= static_cast<int>(volumes.size())) {
        return BoxExtrusionHandleSide::None;
    }
    const auto projection = project_extrusion_floor_handles(volumes[static_cast<std::size_t>(box_index)], cam);
    if (!projection.valid) {
        return BoxExtrusionHandleSide::None;
    }
    const SDL_FPoint pointer{
        static_cast<float>(screen_point.x),
        static_cast<float>(screen_point.y),
    };
    const float max_dist_sq = static_cast<float>(radius_px * radius_px);
    constexpr float kFloorCrosshairHalfWorld = 8.0f;

    float best_dist_sq = max_dist_sq;
    BoxExtrusionHandleSide best_side = BoxExtrusionHandleSide::None;
    const auto& volume = volumes[static_cast<std::size_t>(box_index)];
    for (int point_index = 0; point_index < 8; ++point_index) {
        const auto& point = volume.world_points[static_cast<std::size_t>(point_index)];
        SDL_FPoint x_a{};
        SDL_FPoint x_b{};
        SDL_FPoint z_a{};
        SDL_FPoint z_b{};
        if (!project_floor_world_xz_to_screen(cam,
                                              SDL_FPoint{point.x - kFloorCrosshairHalfWorld, point.z},
                                              x_a) ||
            !project_floor_world_xz_to_screen(cam,
                                              SDL_FPoint{point.x + kFloorCrosshairHalfWorld, point.z},
                                              x_b) ||
            !project_floor_world_xz_to_screen(cam,
                                              SDL_FPoint{point.x, point.z - kFloorCrosshairHalfWorld},
                                              z_a) ||
            !project_floor_world_xz_to_screen(cam,
                                              SDL_FPoint{point.x, point.z + kFloorCrosshairHalfWorld},
                                              z_b)) {
            continue;
        }

        const float dist_sq = std::min(point_to_segment_distance_sq(pointer, x_a, x_b),
                                       point_to_segment_distance_sq(pointer, z_a, z_b));
        if (dist_sq <= best_dist_sq) {
            best_dist_sq = dist_sq;
            best_side = (point_index < 4) ? BoxExtrusionHandleSide::Front
                                          : BoxExtrusionHandleSide::Back;
        }
    }
    return best_side;
}

bool point_in_screen_polygon(SDL_FPoint point, const std::array<SDL_FPoint, 4>& polygon) {
    bool inside = false;
    for (int i = 0, j = 3; i < 4; j = i++) {
        const SDL_FPoint& pi = polygon[static_cast<std::size_t>(i)];
        const SDL_FPoint& pj = polygon[static_cast<std::size_t>(j)];
        const bool intersects = ((pi.y > point.y) != (pj.y > point.y));
        if (!intersects) {
            continue;
        }
        const float denominator = (pj.y - pi.y);
        if (std::fabs(denominator) <= 1e-6f) {
            continue;
        }
        const float x_intersection = ((pj.x - pi.x) * (point.y - pi.y) / denominator) + pi.x;
        if (point.x < x_intersection) {
            inside = !inside;
        }
    }
    return inside;
}

bool projected_volume_contains_screen_point(const Asset::RuntimeBoxVolume& volume,
                                            const WarpedScreenGrid& cam,
                                            SDL_Point screen_point) {
    if (!volume.valid) {
        return false;
    }

    std::array<SDL_FPoint, 8> projected{};
    for (int point_index = 0; point_index < 8; ++point_index) {
        if (!project_runtime_box_point_to_screen(volume.world_points[static_cast<std::size_t>(point_index)],
                                                 cam,
                                                 projected[static_cast<std::size_t>(point_index)])) {
            return false;
        }
    }

    const SDL_FPoint p{static_cast<float>(screen_point.x), static_cast<float>(screen_point.y)};
    for (const auto& face : kBoxVolumeFaces) {
        std::array<SDL_FPoint, 4> polygon{
            projected[static_cast<std::size_t>(face[0])],
            projected[static_cast<std::size_t>(face[1])],
            projected[static_cast<std::size_t>(face[2])],
            projected[static_cast<std::size_t>(face[3])],
        };
        if (point_in_screen_polygon(p, polygon)) {
            return true;
        }
    }
    return false;
}

std::optional<BoxCornerPickResult> find_box_corner_at_screen_point(const std::vector<Asset::RuntimeBoxVolume>& volumes,
                                                                    const WarpedScreenGrid& cam,
                                                                    SDL_Point screen_point,
                                                                    int radius_px) {
    if (volumes.empty()) {
        return std::nullopt;
    }
    const float radius_sq = static_cast<float>(radius_px * radius_px);
    float best_dist_sq = radius_sq;
    std::optional<BoxCornerPickResult> best;
    for (std::size_t box_index = 0; box_index < volumes.size(); ++box_index) {
        const auto& volume = volumes[box_index];
        if (!volume.valid) {
            continue;
        }
        // Only the four 2D box corners are interactive. The far/extruded points are debug-only.
        for (int point_index = 0; point_index < 4; ++point_index) {
            const Asset::RuntimeBoxPoint3& world_point = volume.world_points[static_cast<std::size_t>(point_index)];
            SDL_FPoint projected{};
            if (!project_runtime_box_point_to_screen(world_point, cam, projected)) {
                continue;
            }
            const float dx = projected.x - static_cast<float>(screen_point.x);
            const float dy = projected.y - static_cast<float>(screen_point.y);
            const float dist_sq = dx * dx + dy * dy;
            if (dist_sq <= best_dist_sq) {
                best_dist_sq = dist_sq;
                best = BoxCornerPickResult{
                    static_cast<int>(box_index),
                    point_index % 4,
                    point_index};
            }
        }
    }
    return best;
}

std::optional<int> find_box_body_at_screen_point(const std::vector<Asset::RuntimeBoxVolume>& volumes,
                                                 const WarpedScreenGrid& cam,
                                                 SDL_Point screen_point) {
    for (int box_index = static_cast<int>(volumes.size()) - 1; box_index >= 0; --box_index) {
        const auto& volume = volumes[static_cast<std::size_t>(box_index)];
        if (!volume.valid) {
            continue;
        }
        if (projected_volume_contains_screen_point(volume, cam, screen_point)) {
            return box_index;
        }
    }
    return std::nullopt;
}

SDL_FPoint sample_quadratic_point(const SDL_FPoint& p0,
                                  const SDL_FPoint& p1,
                                  const SDL_FPoint& p2,
                                  float t) {
    const float clamped_t = std::clamp(t, 0.0f, 1.0f);
    auto lerp = [](const SDL_FPoint& a, const SDL_FPoint& b, float ratio) {
        return SDL_FPoint{a.x + (b.x - a.x) * ratio, a.y + (b.y - a.y) * ratio};
    };
    const SDL_FPoint a = lerp(p0, p1, clamped_t);
    const SDL_FPoint b = lerp(p1, p2, clamped_t);
    return lerp(a, b, clamped_t);
}

float remap_to_quadratic_arclength_t(const SDL_FPoint& p0,
                                     const SDL_FPoint& p1,
                                     const SDL_FPoint& p2,
                                     float ratio) {
    constexpr int kSamples = 32;
    const float target_ratio = std::clamp(ratio, 0.0f, 1.0f);
    if (target_ratio <= 0.0f) {
        return 0.0f;
    }
    if (target_ratio >= 1.0f) {
        return 1.0f;
    }

    std::array<float, kSamples + 1> cumulative{};
    SDL_FPoint prev = sample_quadratic_point(p0, p1, p2, 0.0f);
    cumulative[0] = 0.0f;
    float total_length = 0.0f;
    for (int i = 1; i <= kSamples; ++i) {
        const float t = static_cast<float>(i) / static_cast<float>(kSamples);
        const SDL_FPoint current = sample_quadratic_point(p0, p1, p2, t);
        const float dx = current.x - prev.x;
        const float dy = current.y - prev.y;
        total_length += std::sqrt(dx * dx + dy * dy);
        cumulative[static_cast<std::size_t>(i)] = total_length;
        prev = current;
    }
    if (total_length <= 1e-5f) {
        return target_ratio;
    }

    const float target_length = target_ratio * total_length;
    for (int i = 1; i <= kSamples; ++i) {
        const float segment_end = cumulative[static_cast<std::size_t>(i)];
        if (target_length > segment_end) {
            continue;
        }
        const float segment_start = cumulative[static_cast<std::size_t>(i - 1)];
        const float segment_len = std::max(1e-5f, segment_end - segment_start);
        const float local = (target_length - segment_start) / segment_len;
        const float t0 = static_cast<float>(i - 1) / static_cast<float>(kSamples);
        const float t1 = static_cast<float>(i) / static_cast<float>(kSamples);
        return t0 + (t1 - t0) * local;
    }
    return 1.0f;
}

constexpr std::array<std::array<int, 2>, 12> kBoxVolumeEdges{{
    {{0, 1}}, {{1, 2}}, {{2, 3}}, {{3, 0}},
    {{4, 5}}, {{5, 6}}, {{6, 7}}, {{7, 4}},
    {{0, 4}}, {{1, 5}}, {{2, 6}}, {{3, 7}},
}};
constexpr float kShiftEdgePanMaxSpeedBottomWorldUnitsPerSecond = 1400.0f;
SDL_Point snap_world_point_to_overlay_grid(SDL_Point world, int resolution) {
    const int clamped = vibble::grid::clamp_resolution(resolution);
    return vibble::grid::global_grid().snap_to_vertex(world, clamped);
}

SDL_Point grid_point_for_asset(const Asset* asset) {
    if (!asset) {
        return SDL_Point{0, 0};
    }
    if (asset->grid_point()) {
        return asset->grid_point()->to_sdl_point();
    }
    return asset->world_xz_point();
}

SDL_Point grid_point_for_screen(const WarpedScreenGrid& cam, SDL_Point screen_point) {
    const SDL_FPoint world_f = cam.screen_to_map(screen_point);
    return SDL_Point{
        static_cast<int>(std::lround(world_f.x)),
        static_cast<int>(std::lround(world_f.y))
    };
}

bool solve_texture_point_for_screen_target(
    int initial_texture_x,
    int initial_texture_y,
    const SDL_FPoint& desired_screen_px,
    const std::function<bool(int, int, SDL_FPoint&)>& sample_screen_for_texture,
    int max_texture_x,
    int max_texture_y,
    int& out_texture_x,
    int& out_texture_y) {
    if (!sample_screen_for_texture ||
        !std::isfinite(desired_screen_px.x) ||
        !std::isfinite(desired_screen_px.y)) {
        return false;
    }

    auto clamp_tex_x = [&](int value) {
        const int non_negative = std::max(0, value);
        return (max_texture_x >= 0) ? std::clamp(non_negative, 0, max_texture_x) : non_negative;
    };
    auto clamp_tex_y = [&](int value) {
        const int non_negative = std::max(0, value);
        return (max_texture_y >= 0) ? std::clamp(non_negative, 0, max_texture_y) : non_negative;
    };

    int tex_x = clamp_tex_x(initial_texture_x);
    int tex_y = clamp_tex_y(initial_texture_y);

    auto distance_sq = [&](int x, int y, float& out_dist_sq) {
        SDL_FPoint projected{};
        const int sample_x = clamp_tex_x(x);
        const int sample_y = clamp_tex_y(y);
        if (!sample_screen_for_texture(sample_x, sample_y, projected)) {
            return false;
        }
        const float dx = projected.x - desired_screen_px.x;
        const float dy = projected.y - desired_screen_px.y;
        out_dist_sq = dx * dx + dy * dy;
        return std::isfinite(out_dist_sq);
    };

    auto run_local_jacobian_solve = [&](int start_x, int start_y, int& solved_x, int& solved_y) -> bool {
        solved_x = clamp_tex_x(start_x);
        solved_y = clamp_tex_y(start_y);
        bool sampled_any = false;
        constexpr int kSolveIterations = 14;
        constexpr float kMaxSolveStepPixels = 192.0f;
        for (int iter = 0; iter < kSolveIterations; ++iter) {
            const int sample_x = clamp_tex_x(solved_x);
            const int sample_y = clamp_tex_y(solved_y);
            const int sample_x_plus = clamp_tex_x(sample_x + 1);
            const int sample_y_plus = clamp_tex_y(sample_y + 1);

            SDL_FPoint base{};
            SDL_FPoint plus_x{};
            SDL_FPoint plus_y{};
            if (!sample_screen_for_texture(sample_x, sample_y, base) ||
                !sample_screen_for_texture(sample_x_plus, sample_y, plus_x) ||
                !sample_screen_for_texture(sample_x, sample_y_plus, plus_y)) {
                break;
            }
            sampled_any = true;

            const float j00 = plus_x.x - base.x;
            const float j01 = plus_y.x - base.x;
            const float j10 = plus_x.y - base.y;
            const float j11 = plus_y.y - base.y;
            const float det = j00 * j11 - j01 * j10;
            if (std::fabs(det) < 1e-6f) {
                break;
            }

            const float rx = desired_screen_px.x - base.x;
            const float ry = desired_screen_px.y - base.y;
            float dx = (rx * j11 - ry * j01) / det;
            float dy = (ry * j00 - rx * j10) / det;
            if (!std::isfinite(dx) || !std::isfinite(dy)) {
                break;
            }

            dx = std::clamp(dx, -kMaxSolveStepPixels, kMaxSolveStepPixels);
            dy = std::clamp(dy, -kMaxSolveStepPixels, kMaxSolveStepPixels);

            const int next_x = clamp_tex_x(static_cast<int>(std::lround(static_cast<float>(sample_x) + dx)));
            const int next_y = clamp_tex_y(static_cast<int>(std::lround(static_cast<float>(sample_y) + dy)));
            if (next_x == sample_x && next_y == sample_y) {
                break;
            }
            solved_x = next_x;
            solved_y = next_y;
        }
        return sampled_any;
    };

    int solved_x = tex_x;
    int solved_y = tex_y;
    bool solved_from_local_jacobian = run_local_jacobian_solve(tex_x, tex_y, solved_x, solved_y);
    if (!solved_from_local_jacobian) {
        const int fallback_seed_x = (max_texture_x >= 0) ? (max_texture_x / 2) : clamp_tex_x(initial_texture_x);
        const int fallback_seed_y = (max_texture_y >= 0) ? (max_texture_y / 2) : clamp_tex_y(initial_texture_y);
        solved_from_local_jacobian = run_local_jacobian_solve(fallback_seed_x, fallback_seed_y, solved_x, solved_y);
    }
    tex_x = solved_x;
    tex_y = solved_y;

    int best_x = tex_x;
    int best_y = tex_y;
    float best_dist_sq = std::numeric_limits<float>::max();
    auto consider = [&](int x, int y) {
        float dist_sq = 0.0f;
        if (!distance_sq(x, y, dist_sq)) {
            return;
        }
        if (dist_sq < best_dist_sq) {
            best_dist_sq = dist_sq;
            best_x = clamp_tex_x(x);
            best_y = clamp_tex_y(y);
        }
    };

    consider(tex_x, tex_y);
    for (int radius : {10, 6, 3, 1}) {
        for (int dy = -radius; dy <= radius; ++dy) {
            for (int dx = -radius; dx <= radius; ++dx) {
                consider(tex_x + dx, tex_y + dy);
            }
        }
        tex_x = best_x;
        tex_y = best_y;
    }

    // Aggressive fallback sweep when local Jacobian solve gets stuck.
    if (!std::isfinite(best_dist_sq) || best_dist_sq > 9.0f) {
        for (int radius : {16, 32, 64}) {
            const int step = std::max(1, radius / 6);
            for (int dy = -radius; dy <= radius; dy += step) {
                for (int dx = -radius; dx <= radius; dx += step) {
                    consider(tex_x + dx, tex_y + dy);
                }
            }
            tex_x = best_x;
            tex_y = best_y;
        }
    }

    if ((!std::isfinite(best_dist_sq) || best_dist_sq > 9.0f) &&
        max_texture_x >= 0 &&
        max_texture_y >= 0) {
        const int max_dim = std::max(max_texture_x + 1, max_texture_y + 1);
        int step = std::max(1, max_dim / 24);
        while (step >= 1) {
            for (int y = 0; y <= max_texture_y; y += step) {
                for (int x = 0; x <= max_texture_x; x += step) {
                    consider(x, y);
                }
            }
            if (step == 1) {
                break;
            }
            step = std::max(1, step / 2);
        }
    }

    if (!std::isfinite(best_dist_sq)) {
        return false;
    }

    out_texture_x = best_x;
    out_texture_y = best_y;
    return true;
}

bool solve_texture_point_for_screen_target(
    int initial_texture_x,
    int initial_texture_y,
    const SDL_FPoint& desired_screen_px,
    const std::function<bool(int, int, SDL_FPoint&)>& sample_screen_for_texture,
    int& out_texture_x,
    int& out_texture_y) {
    return solve_texture_point_for_screen_target(
        initial_texture_x,
        initial_texture_y,
        desired_screen_px,
        sample_screen_for_texture,
        -1,
        -1,
        out_texture_x,
        out_texture_y);
}

bool build_render_object_projection(const WarpedScreenGrid& cam,
                                    const RenderObject& obj,
                                    float perspective_scale,
                                    float world_z,
                                    render_projection::ProjectedSpriteFrame& out_projection) {
    return render_projection::build_render_object_projected_frame(
        cam, obj, perspective_scale, world_z, out_projection);
}

void render_grid_point_marker(SDL_Renderer* renderer, const WarpedScreenGrid& cam, SDL_Point world_pt, SDL_Color color, int radius_px = 3) {
    if (!renderer) return;
    SDL_FPoint screen_f = cam.map_to_screen(world_pt);
    if (!std::isfinite(screen_f.x) || !std::isfinite(screen_f.y)) {
        return;
    }
    const int sx = static_cast<int>(std::lround(screen_f.x));
    const int sy = static_cast<int>(std::lround(screen_f.y));

    SDL_SetRenderDrawColor(renderer, color.r, color.g, color.b, color.a);
    SDL_RenderPoint(renderer, sx, sy);
    for (int dx = -radius_px; dx <= radius_px; ++dx) {
        SDL_RenderPoint(renderer, sx + dx, sy);
    }
    for (int dy = -radius_px; dy <= radius_px; ++dy) {
        SDL_RenderPoint(renderer, sx, sy + dy);
    }
}

