void RoomEditor::open_room_config_for_json_entry(nlohmann::json& room_data, bool is_trail_context) {
    ensure_room_configurator();
    if (!room_cfg_ui_) {
        return;
    }
    room_cfg_ui_->set_room_metadata_only_mode(true);
    room_cfg_ui_->set_bounds(room_config_bounds_);
    room_cfg_ui_->open(room_data, is_trail_context, [this, is_trail_context]() {
        if (!assets_) {
            return;
        }
        assets_->mark_map_data_dirty();
        if (mark_map_dirty_callback_) {
            mark_map_dirty_callback_(devmode::core::DevSaveCoordinator::Priority::Debounced);
        }
        if (is_trail_context) {
            show_notice("Trail template saved.");
        } else {
            show_notice("Room template saved.");
        }
    });
    room_config_dock_open_ = true;
    room_config_panel_visible_ = true;
}

void RoomEditor::create_room_from_footer() {
    if (!assets_) return;
    nlohmann::json& map_info = assets_->map_info_json();
    std::string key = map_layers::create_room_entry(map_info);
    if (key.empty()) {
        show_notice("Unable to create room entry.");
        return;
    }
    nlohmann::json& room_entry = map_info["rooms_data"][key];
    room_entry["geometry"] = "Square";
    room_entry["width"] = vibble::weighted_range::to_json(vibble::weighted_range::make_legacy_uniform(1200, 1800));
    room_entry["height"] = vibble::weighted_range::to_json(vibble::weighted_range::make_legacy_uniform(1200, 1800));
    room_entry["is_boss"] = false;
    room_entry["inherits_live_dynamic_assets"] = false;
    room_entry["inherit_map_floor_color"] = true;
    room_entry["tags"] = nlohmann::json::array();
    if (!room_entry.contains("spawn_groups") || !room_entry["spawn_groups"].is_array()) {
        room_entry["spawn_groups"] = nlohmann::json::array();
    }

    open_room_config_for_json_entry(room_entry, false);
    show_notice("Created room template: " + key);
}

void RoomEditor::create_trail_from_footer() {
    if (!assets_) return;
    nlohmann::json& map_info = assets_->map_info_json();
    nlohmann::json& trails = map_info["trails_data"];
    if (!trails.is_object()) {
        trails = nlohmann::json::object();
    }
    const std::string key = map_layers::make_unique_template_key(map_info, "NewTrail", "NewTrail");
    nlohmann::json& trail_entry = trails[key];
    trail_entry = nlohmann::json::object();
    trail_entry["name"] = key;
    trail_entry["geometry"] = "Square";
    trail_entry["width"] = vibble::weighted_range::to_json(vibble::weighted_range::make_legacy_uniform(600, 900));
    trail_entry["tags"] = nlohmann::json::array();
    trail_entry["anti_tags"] = nlohmann::json::array();
    if (!trail_entry.contains("spawn_groups") || !trail_entry["spawn_groups"].is_array()) {
        trail_entry["spawn_groups"] = nlohmann::json::array();
    }

    open_room_config_for_json_entry(trail_entry, true);
    show_notice("Created trail template: " + key);
}

void RoomEditor::regenerate_room() {
    if (room_cfg_ui_ && room_cfg_ui_->is_locked()) {
        SDL_LogWarn(SDL_LOG_CATEGORY_APPLICATION, "[RoomEditor] Room configurator is locked; regeneration skipped.");
        return;
    }
    regenerate_current_room();
}

void RoomEditor::regenerate_room_from_template(const std::string& template_key) {
    if (room_cfg_ui_ && room_cfg_ui_->is_locked()) {
        SDL_LogWarn(SDL_LOG_CATEGORY_APPLICATION, "[RoomEditor] Room configurator is locked; regeneration from template skipped.");
        return;
    }
    if (!assets_ || !current_room_ || !current_room_->room_area) {
        return;
    }
    if (template_key.empty()) {
        show_notice("Room regen failed: empty room template key");
        return;
    }
    const std::string current_type = vibble::strings::to_lower_copy(current_room_->type);
    if (current_type == "trail") {
        show_notice("Room regen failed: trail rooms cannot be replaced by regen");
        return;
    }

    nlohmann::json& map_info = assets_->map_info_json();
    nlohmann::json& rooms_data = map_info["rooms_data"];
    if (!rooms_data.is_object()) {
        show_notice("Room regen failed: map rooms_data is missing");
        return;
    }
    auto template_it = rooms_data.find(template_key);
    if (template_it == rooms_data.end() || !template_it->is_object()) {
        show_notice("Room regen failed: selected room template is missing");
        return;
    }
    const std::string template_type = vibble::strings::to_lower_copy(template_it->value("type", std::string("room")));
    if (template_type == "trail") {
        show_notice("Room regen failed: selected template is a trail");
        return;
    }

    map_graph::RoomRegenSnapshot snapshot = map_graph::capture_room_regen_snapshot(current_room_);
    map_graph::RoomRegenPlan plan = map_graph::build_room_regen_plan(snapshot, template_key);
    if (!snapshot.valid || !plan.valid || !snapshot.old_room) {
        show_notice("Room regen failed: unable to build regen plan");
        return;
    }

    RuntimeWorldContext* world_context = assets_->runtime_world_context();
    if (!world_context) {
        show_notice("Room regen failed: runtime world context unavailable");
        return;
    }

    auto collect_spawn_ids = [](const Room* room) {
        std::vector<std::string> spawn_ids;
        if (!room) {
            return spawn_ids;
        }
        const nlohmann::json& room_data = room->assets_data();
        auto groups_it = room_data.find("spawn_groups");
        if (groups_it == room_data.end() || !groups_it->is_array()) {
            return spawn_ids;
        }
        spawn_ids.reserve(groups_it->size());
        for (const auto& entry : *groups_it) {
            if (!entry.is_object()) {
                continue;
            }
            const std::string spawn_id = entry.value("spawn_id", std::string{});
            if (!spawn_id.empty()) {
                spawn_ids.push_back(spawn_id);
            }
        }
        return spawn_ids;
    };

    std::vector<std::string> spawn_ids_to_delete = collect_spawn_ids(snapshot.old_room);
    for (Room* trail_room : snapshot.connected_trails) {
        std::vector<std::string> trail_spawn_ids = collect_spawn_ids(trail_room);
        spawn_ids_to_delete.insert(spawn_ids_to_delete.end(), trail_spawn_ids.begin(), trail_spawn_ids.end());
    }
    std::sort(spawn_ids_to_delete.begin(), spawn_ids_to_delete.end());
    spawn_ids_to_delete.erase(std::unique(spawn_ids_to_delete.begin(), spawn_ids_to_delete.end()),
                              spawn_ids_to_delete.end());

    clear_selection();
    clear_room_trail_nav_entries();
    assets_->delete_assets_for_spawn_groups(spawn_ids_to_delete);
    for (const std::string& spawn_id : spawn_ids_to_delete) {
        if (!spawn_id.empty()) {
            prune_spawn_group_transient_references(spawn_id);
        }
    }

    for (Room* trail_room : snapshot.connected_trails) {
        if (!trail_room) {
            continue;
        }
        std::vector<Room*> linked = trail_room->connected_rooms;
        for (Room* linked_room : linked) {
            if (linked_room) {
                linked_room->remove_connecting_room(trail_room);
            }
        }
        trail_room->connected_rooms.clear();
    }

    Room* old_room = snapshot.old_room;
    std::vector<Room*> old_links = old_room->connected_rooms;
    for (Room* linked_room : old_links) {
        if (linked_room) {
            linked_room->remove_connecting_room(old_room);
        }
    }
    old_room->connected_rooms.clear();

    for (Room* trail_room : snapshot.connected_trails) {
        world_context->remove_room(trail_room);
    }

    auto estimate_map_radius = [](const std::vector<Room*>& rooms) -> double {
        double max_radius = 10000.0;
        for (Room* room : rooms) {
            if (!room || !room->room_area) {
                continue;
            }
            int min_x = 0;
            int min_y = 0;
            int max_x = 0;
            int max_y = 0;
            std::tie(min_x, min_y, max_x, max_y) = room->room_area->get_bounds();
            max_radius = std::max(max_radius, static_cast<double>(std::max({std::abs(min_x), std::abs(min_y), std::abs(max_x), std::abs(max_y)})));
        }
        return std::max(1.0, max_radius);
    };

    nlohmann::json& template_data_ref = *template_it;
    const double map_radius = estimate_map_radius(assets_->rooms());
    auto replacement_room = std::make_unique<Room>(
        Room::Point{plan.replacement_center.x, plan.replacement_center.y},
        "room",
        template_key,
        snapshot.parent,
        assets_->map_id(),
        &assets_->library(),
        nullptr,
        &template_data_ref,
        old_room->map_grid_settings(),
        map_radius,
        "rooms_data",
        &map_info,
        assets_->manifest_store(),
        assets_->map_id(),
        Room::ManifestWriter{});

    Room* replacement_room_ptr = replacement_room.get();
    replacement_room_ptr->layer = old_room->layer;
    replacement_room_ptr->camera_height_px = old_room->camera_height_px;
    replacement_room_ptr->camera_tilt_deg = old_room->camera_tilt_deg;
    replacement_room_ptr->camera_zoom_percent = old_room->camera_zoom_percent;
    replacement_room_ptr->camera_center_dx = old_room->camera_center_dx;
    replacement_room_ptr->camera_center_dz = old_room->camera_center_dz;
    replacement_room_ptr->children = snapshot.children;
    replacement_room_ptr->set_sibling_left(snapshot.left_sibling);
    replacement_room_ptr->set_sibling_right(snapshot.right_sibling);

    for (Room* child : snapshot.children) {
        if (child && child->parent == old_room) {
            child->parent = replacement_room_ptr;
        }
    }
    if (snapshot.parent) {
        for (Room*& child_ref : snapshot.parent->children) {
            if (child_ref == old_room) {
                child_ref = replacement_room_ptr;
            }
        }
    }
    if (snapshot.left_sibling && snapshot.left_sibling->right_sibling == old_room) {
        snapshot.left_sibling->set_sibling_right(replacement_room_ptr);
    }
    if (snapshot.right_sibling && snapshot.right_sibling->left_sibling == old_room) {
        snapshot.right_sibling->set_sibling_left(replacement_room_ptr);
    }

    if (!world_context->replace_room(old_room, std::move(replacement_room))) {
        show_notice("Room regen failed: runtime room replacement did not commit");
        return;
    }

    std::vector<std::unique_ptr<Asset>> initial_room_assets = std::move(replacement_room_ptr->get_room_assets());
    integrate_spawned_assets(initial_room_assets);

    int requested_trail_pairs = static_cast<int>(plan.planned_trail_pairs.size());
    int generated_trail_pairs = 0;
    std::vector<std::unique_ptr<Room>> successful_new_trails;
    successful_new_trails.reserve(plan.planned_trail_pairs.size());
    nlohmann::json& trails_data = map_info["trails_data"];
    if (!trails_data.is_object()) {
        trails_data = nlohmann::json::object();
    }

    for (const auto& trail_pair : plan.planned_trail_pairs) {
        Room* neighbor = trail_pair.second;
        if (!neighbor || !neighbor->room_area) {
            continue;
        }
        GenerateTrails trail_generator(trails_data);
        std::vector<Room*> room_refs{replacement_room_ptr, neighbor};
        trail_generator.set_all_rooms_reference(room_refs);
        const std::vector<std::pair<Room*, Room*>> single_pair{{replacement_room_ptr, neighbor}};
        auto generated = trail_generator.generate_trails(
            single_pair,
            assets_->map_id(),
            &assets_->library(),
            map_radius,
            &map_info,
            assets_->manifest_store(),
            {});
        if (!generated.trail_rooms.empty()) {
            generated_trail_pairs += static_cast<int>(generated.trail_rooms.size());
            for (auto& trail_room : generated.trail_rooms) {
                if (trail_room) {
                    successful_new_trails.push_back(std::move(trail_room));
                }
            }
        }
    }

    if (!successful_new_trails.empty()) {
        world_context->append_rooms(std::move(successful_new_trails));
    }

    assets_->set_editor_current_room(replacement_room_ptr);
    assets_->notify_rooms_changed();
    assets_->rebuild_from_grid_state();
    assets_->refresh_active_asset_lists();
    set_current_room(replacement_room_ptr, room_locked_for_edit_);
    clear_room_trail_nav_entries();
    rebuild_room_spawn_id_cache();
    refresh_spawn_group_config_ui();
    mark_spatial_index_dirty();

    const int failed_pairs = std::max(0, requested_trail_pairs - generated_trail_pairs);
    if (failed_pairs > 0) {
        show_notice("Room regenerated with trail warnings (" + std::to_string(generated_trail_pairs) + "/" +
                    std::to_string(requested_trail_pairs) + " trails rebuilt)");
    } else {
        show_notice("Room regenerated: " + template_key);
    }
}

void RoomEditor::focus_camera_on_asset(Asset* asset, double height_factor, int duration_steps) {
    if (!asset || !assets_) return;

    if (info_ui_ && info_ui_->is_visible()) {
        return;
    }

    WarpedScreenGrid& cam = assets_->getView();
    cam.set_manual_height_override(true);
    cam.set_focus_override(asset->world_xz_point());
    cam.animate_height_to_scale(height_factor * 1000.0, duration_steps);
    mark_spatial_index_dirty();
}

void RoomEditor::focus_camera_on_room_center(bool reframe_height) {
    if (!enabled_ || !assets_) return;
    if (!current_room_ || !current_room_->room_area) return;

    WarpedScreenGrid& cam = assets_->getView();
    const SDL_Point room_center = current_room_->room_area->get_center();
    const SDL_Point center{
        room_center.x + current_room_->camera_center_dx,
        room_center.y + current_room_->camera_center_dz
    };
    cam.set_manual_height_override(true);
    cam.set_focus_override(center);

    if (reframe_height) {
        cam.animate_height_to_scale(cam.default_camera_height_for_room(current_room_));
    }
    mark_spatial_index_dirty();
}

RoomEditor::DragMode RoomEditor::drag_mode_for_spawn_method(const std::string& method, bool ctrl_modifier) {
    if (method == "Exact" || method == "Exact Position") {
        return DragMode::Exact;
    }
    if (method == "Percent") {
        return DragMode::Percent;
    }
    if (method == "Perimeter") {
        return ctrl_modifier ? DragMode::PerimeterCenter : DragMode::Perimeter;
    }
    if (method == "Edge") {
        return DragMode::Edge;
    }
    return DragMode::Free;
}

RoomEditor::PerimeterHandleHover RoomEditor::perimeter_handle_hover_target(const std::string& spawn_id,
                                                                            SDL_Point screen_point) {
    if (spawn_id.empty() || !assets_) {
        return PerimeterHandleHover::None;
    }
    auto overlay = compute_perimeter_overlay_for_spawn(spawn_id);
    if (!overlay || overlay->radius <= 0.0) {
        return PerimeterHandleHover::None;
    }

    const WarpedScreenGrid& cam = assets_->getView();
    const SDL_FPoint center_screen_f = cam.map_to_screen(overlay->center);
    const SDL_FPoint edge_screen_f = cam.map_to_screen(SDL_Point{
        overlay->center.x + static_cast<int>(std::lround(overlay->radius)),
        overlay->center.y});
    const float dx = edge_screen_f.x - center_screen_f.x;
    const float dy = edge_screen_f.y - center_screen_f.y;
    const float radius_px = std::max(1.0f, std::hypot(dx, dy));

    const float center_dx = static_cast<float>(screen_point.x) - center_screen_f.x;
    const float center_dy = static_cast<float>(screen_point.y) - center_screen_f.y;
    const float center_dist = std::hypot(center_dx, center_dy);
    if (center_dist <= std::max(8.0f, radius_px * 0.08f)) {
        return PerimeterHandleHover::Center;
    }

    const float ring_dist = std::fabs(center_dist - radius_px);
    if (ring_dist <= 8.0f) {
        return PerimeterHandleHover::Radius;
    }
    return PerimeterHandleHover::None;
}

bool RoomEditor::is_asset_active_for_input(const Asset* asset) const {
    if (!asset) {
        return false;
    }
    const std::vector<Asset*>* source_assets = selection_asset_source();
    if (!source_assets) {
        return false;
    }
    return std::find(source_assets->begin(), source_assets->end(), const_cast<Asset*>(asset)) != source_assets->end();
}

bool RoomEditor::is_mouse_press_asset_valid() const {
    if (!mouse_press_state_.valid || !mouse_press_state_.pressed_asset) {
        return false;
    }
    if (mouse_press_state_.pressed_identity != mouse_press_state_.pressed_asset) {
        return false;
    }
    return is_asset_active_for_input(mouse_press_state_.pressed_asset);
}

void RoomEditor::clear_mouse_press_state(bool reset_click_tracking) {
    mouse_press_state_ = MousePressState{};
    if (reset_click_tracking) {
        last_click_spawn_id_.clear();
        last_click_time_ms_ = 0;
    }
}

bool RoomEditor::consume_pressed_asset_release(Uint32 click_time_ms, std::string& out_spawn_id) {
    out_spawn_id.clear();
    if (!is_mouse_press_asset_valid() || mouse_press_state_.was_dragged) {
        return false;
    }
    const bool open_spawn_group_panel =
        should_open_spawn_group_panel_for_click(mouse_press_state_.pressed_spawn_id,
                                                mouse_press_state_.pressed_has_spawn_group,
                                                click_time_ms);
    if (!open_spawn_group_panel || !mouse_press_state_.pressed_has_spawn_group ||
        mouse_press_state_.pressed_spawn_id.empty()) {
        return false;
    }
    out_spawn_id = mouse_press_state_.pressed_spawn_id;
    return true;
}

void RoomEditor::reset_click_state() {
    click_buffer_frames_ = 0;
    rclick_buffer_frames_ = 0;
    suppress_next_left_click_ = false;
    last_click_spawn_id_.clear();
    last_click_time_ms_ = 0;
    suppress_world_left_click_frames_ = 0;
    clear_mouse_press_state(false);
    clear_dynamic_boundary_proxy_selection();
    reset_drag_state();
}

void RoomEditor::clear_selection() {
    if (anchor_mode_active()) {
        exit_anchor_edit_mode(true);
    }
    if (movement_mode_active()) {
        exit_movement_edit_mode(true);
    }
    clear_focus();
    clear_geometry_selection();
    const bool had_selection = !selected_assets_.empty();
    const bool had_highlight = !highlighted_assets_.empty();
    const bool had_hover = hovered_asset_ != nullptr;
    const bool had_anchor_hover = hovered_anchor_asset_ != nullptr;
    selected_assets_.clear();
    highlighted_assets_.clear();
    hovered_asset_ = nullptr;
    hovered_anchor_asset_ = nullptr;
    clear_dynamic_boundary_proxy_selection();
    reset_drag_state();
    clear_mouse_press_state(true);
    sync_spawn_group_panel_with_selection();
    if (had_selection || had_highlight || had_hover || had_anchor_hover) {
        mark_highlight_dirty();
    }
    const std::vector<Asset*>* source_assets = selection_asset_source();
    if (!source_assets) return;
    for (Asset* asset : *source_assets) {
        if (!asset) continue;
        asset->set_selected(false);
        asset->set_highlighted(false);
    }
}

void RoomEditor::clear_highlighted_assets() {
    const bool had_highlight = !highlighted_assets_.empty();
    const size_t prev_selection_size = selected_assets_.size();
    Asset* prev_hover = hovered_asset_;
    Asset* prev_anchor_hover = hovered_anchor_asset_;
    const bool had_boundary_selection = selected_dynamic_boundary_proxy_.has_value() ||
                                        hovered_dynamic_boundary_proxy_.has_value();
    highlighted_assets_.clear();
    if (!active_assets_) {
        selected_assets_.clear();
        hovered_asset_ = nullptr;
        hovered_anchor_asset_ = nullptr;
        clear_dynamic_boundary_proxy_selection();
        if (had_highlight ||
            had_boundary_selection ||
            prev_selection_size != selected_assets_.size() ||
            hovered_asset_ != prev_hover ||
            hovered_anchor_asset_ != prev_anchor_hover) {
            mark_highlight_dirty();
        }
        return;
    }
    auto erase_if_inactive = [this](Asset* asset) {
        if (!asset) return true;
        auto it = std::find(active_assets_->begin(), active_assets_->end(), asset);
        if (it == active_assets_->end()) {
            asset->set_highlighted(false);
            asset->set_selected(false);
            return true;
        }
        return false;
};

    selected_assets_.erase( std::remove_if(selected_assets_.begin(), selected_assets_.end(), erase_if_inactive), selected_assets_.end());

    if (hovered_asset_ && erase_if_inactive(hovered_asset_)) {
        hovered_asset_ = nullptr;
        hover_miss_frames_ = 0;
    }
    if (hovered_anchor_asset_ && erase_if_inactive(hovered_anchor_asset_)) {
        hovered_anchor_asset_ = nullptr;
    }

    for (Asset* asset : *active_assets_) {
        if (!asset) {
            continue;
        }
        asset->set_highlighted(false);
        const bool is_selected = std::find(selected_assets_.begin(), selected_assets_.end(), asset) != selected_assets_.end();
        asset->set_selected(is_selected);
    }
    sync_spawn_group_panel_with_selection();
    if (had_highlight ||
        had_boundary_selection ||
        prev_selection_size != selected_assets_.size() ||
        hovered_asset_ != prev_hover ||
        hovered_anchor_asset_ != prev_anchor_hover) {
        mark_highlight_dirty();
    }
}

void RoomEditor::purge_asset(Asset* asset) {
    if (!asset) return;
    if (anchor_mode_active() && anchor_edit_.target_asset == asset) {
        exit_anchor_edit_mode(true);
    }
    if (oval_mode_active() && oval_edit_.target_asset == asset) {
        exit_oval_anchor_edit_mode(true);
    }
    if (movement_mode_active() && movement_edit_.target_asset == asset) {
        exit_movement_edit_mode(true);
    }
    bool highlight_sources_changed = false;
    if (hovered_asset_ == asset) {
        hovered_asset_ = nullptr;
        hover_miss_frames_ = 0;
        highlight_sources_changed = true;
    }
    if (hovered_anchor_asset_ == asset) {
        hovered_anchor_asset_ = nullptr;
        highlight_sources_changed = true;
    }
    remove_asset_from_spatial_index(asset);
    auto erase_from = [asset, &highlight_sources_changed](std::vector<Asset*>& vec) {
        const auto before = vec.size();
        vec.erase(std::remove(vec.begin(), vec.end(), asset), vec.end());
        if (vec.size() != before) {
            highlight_sources_changed = true;
        }
};
    erase_from(selected_assets_);
    erase_from(highlighted_assets_);
    if (drag_anchor_asset_ == asset) {
        drag_anchor_asset_ = nullptr;
        dragging_ = false;
    }
    drag_states_.erase(std::remove_if(drag_states_.begin(), drag_states_.end(),
                                      [asset](const DraggedAssetState& state) { return state.asset == asset; }),
                       drag_states_.end());
    if (drag_states_.empty()) {
        reset_drag_state();
    }
    sync_spawn_group_panel_with_selection();
    if (highlight_sources_changed) {
        mark_highlight_dirty();
    }
}


void RoomEditor::set_pointer_queries_suspended(bool suspended) {
    if (pointer_queries_suspended_ == suspended) {
        return;
    }
    pointer_queries_suspended_ = suspended;
    if (suspended) {
        hovered_asset_ = nullptr;
        hovered_anchor_asset_ = nullptr;
        hovered_dynamic_boundary_proxy_.reset();
        hover_miss_frames_ = 3;
    }
    mark_highlight_dirty();
}

void RoomEditor::set_external_asset_selection_blocked(bool blocked) {
    if (external_asset_selection_blocked_ == blocked) {
        return;
    }
    external_asset_selection_blocked_ = blocked;
    if (!blocked) {
        return;
    }

    marquee_selection_.reset();
    clear_mouse_press_state(true);
    hovered_anchor_asset_ = nullptr;
    hovered_dynamic_boundary_proxy_.reset();
    if (hovered_asset_) {
        hovered_asset_ = nullptr;
        mark_highlight_dirty();
    }
}

void RoomEditor::refresh_cursor_world_state(const WarpedScreenGrid& cam, SDL_Point screen_pt) {
    const SDL_FPoint world_f = cam.screen_to_map(screen_pt);
    if (!std::isfinite(world_f.x) || !std::isfinite(world_f.y)) {
        has_last_raw_mouse_world_ = false;
        cursor_snap_resolution_ = 0;
        return;
    }

    const SDL_Point world_pt{
        static_cast<int>(std::lround(world_f.x)),
        static_cast<int>(std::lround(world_f.y))};

    last_raw_mouse_world_ = world_pt;
    has_last_raw_mouse_world_ = true;
    if (!snap_to_grid_enabled_) {
        cursor_snap_resolution_ = 0;
        snapped_cursor_world_ = world_pt;
        return;
    }

    cursor_snap_resolution_ = current_grid_resolution();
    snapped_cursor_world_ = snap_world_point_to_overlay_grid(world_pt, cursor_snap_resolution_);
}

bool RoomEditor::asset_selection_blocked_by_open_panels() const {
    if (!enabled_) {
        return true;
    }
    if (external_asset_selection_blocked_ || any_blocking_panel_visible()) {
        return true;
    }
    if (room_cfg_ui_ && room_cfg_ui_->visible()) {
        return true;
    }
    if (spawn_group_panel_ && spawn_group_panel_->is_visible()) {
        return true;
    }
    if (is_asset_library_open() || is_asset_info_editor_open() || has_active_modal() || is_camera_settings_open()) {
        return true;
    }
    return false;
}

bool RoomEditor::asset_selection_allowed_now() const {
    if (editor_mode_ != EditorMode::Normal) {
        return false;
    }
    return !asset_selection_blocked_by_open_panels();
}

void RoomEditor::set_height_scale_factor(double factor) {
    height_scale_factor_ = (factor > 0.0) ? factor : 1.0;
    camera_controls_.set_height_scale_factor(height_scale_factor_);
}

void RoomEditor::apply_asset_scale_live_update(Asset* asset, int scale_percent) {
    if (!asset || !asset->info) {
        return;
    }

    const int clamped_percent = std::clamp(scale_percent, 1, 400);
    asset->info->set_scale_percentage(static_cast<float>(clamped_percent));
    asset->on_scale_factor_changed();
    if (assets_ && asset->info->tillable) {
        if (auto tiling = assets_->compute_tiling_for_asset(asset); tiling && tiling->is_valid()) {
            asset->set_tiling_info(*tiling);
        } else {
            asset->set_tiling_info(std::nullopt);
        }
    }

    if (save_coordinator_ && manifest_store_) {
        nlohmann::json payload = asset->info->manifest_payload();
        save_coordinator_->enqueue_manifest_asset(asset->info->name,
                                                  std::move(payload),
                                                  devmode::core::DevSaveCoordinator::Priority::Debounced,
                                                  "Scale",
                                                  [this]() {
                                                      if (assets_) {
                                                          assets_->mark_active_assets_dirty();
                                                      }
                                                  });
    } else if (manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(asset->info->name, true);
        if (!session) {
            SDL_LogWarn(SDL_LOG_CATEGORY_APPLICATION,
                        "[RoomEditor] Failed to open manifest session for '%s'",
                        asset->info->name.c_str());
            return;
        }
        session.data() = asset->info->manifest_payload();
        if (!session.commit()) {
            SDL_LogWarn(SDL_LOG_CATEGORY_APPLICATION,
                        "[RoomEditor] Failed to commit manifest for '%s'",
                        asset->info->name.c_str());
            return;
        }
        if (assets_) {
            assets_->mark_active_assets_dirty();
        }
    }
}

bool RoomEditor::apply_scroll_size_adjustment(const Input& input) {
    const int scroll_y = input.getScrollY();
    if (scroll_y == 0) {
        return false;
    }

    const std::vector<std::string> selected_ids = selected_spawn_group_ids();
    if (selected_ids.size() > 1) {
        return false;
    }
    if (selected_assets_.size() != 1) {
        return false;
    }

    Asset* primary = selected_assets_.empty() ? nullptr : selected_assets_.front();
    if (!primary || !primary->info) {
        return false;
    }
    const std::string& method = primary->spawn_method;
    const bool exact_method = (method == "Exact" || method == "Exact Position");
    if (!exact_method) {
        return false;
    }

    const int ticks = std::abs(scroll_y);
    if (ticks <= 0) {
        return false;
    }

    const int direction = (scroll_y < 0) ? 1 : -1;
    const int current_percent = std::max(1, static_cast<int>(std::lround(primary->info->scale_factor * 100.0f)));
    const int next_percent = current_percent + (direction * ticks);
    apply_asset_scale_live_update(primary, next_percent);
    return true;
}

bool RoomEditor::select_asset_or_group(Asset* asset) {
    if (!asset || !asset_belongs_to_room(asset)) {
        return false;
    }

    clear_geometry_selection();
    clear_dynamic_boundary_proxy_selection();
    selected_assets_.clear();

    bool select_group = !asset->spawn_id.empty();
    const std::string& method = asset->spawn_method;
    if (method == "Exact" || method == "Exact Position" || method == "Percent") {
        select_group = false;
    }

    if (select_group && active_assets_) {
        for (Asset* candidate : *active_assets_) {
            if (!candidate) continue;
            if (!asset_belongs_to_room(candidate)) continue;
            if (candidate->spawn_id == asset->spawn_id) {
                selected_assets_.push_back(candidate);
            }
        }
    } else {
        selected_assets_.push_back(asset);
    }

    hovered_asset_ = selected_assets_.empty() ? asset : selected_assets_.front();
    sync_spawn_group_panel_with_selection();
    mark_highlight_dirty();
    return !selected_assets_.empty();
}

bool RoomEditor::should_open_spawn_group_panel_for_click(const std::string& spawn_id,
                                                         bool has_spawn_group,
                                                         Uint32 click_time_ms) {
    if (!has_spawn_group || spawn_id.empty()) {
        last_click_spawn_id_.clear();
        last_click_time_ms_ = 0;
        return false;
    }

    constexpr Uint32 kDoubleClickWindowMs = 300;
    const bool is_double_click = !last_click_spawn_id_.empty() &&
                                 last_click_spawn_id_ == spawn_id &&
                                 last_click_time_ms_ != 0 &&
                                 click_time_ms >= last_click_time_ms_ &&
                                 (click_time_ms - last_click_time_ms_) <= kDoubleClickWindowMs;

    last_click_spawn_id_ = spawn_id;
    last_click_time_ms_ = click_time_ms;
    return is_double_click;
}

Asset* RoomEditor::selected_asset_within_interaction_radius(SDL_Point screen_point) const {
    if (selected_assets_.empty() || !assets_) {
        return nullptr;
    }

    const WarpedScreenGrid& cam = assets_->getView();
    ensure_spatial_index(cam);
    constexpr int kInteractionRadiusPx = 24;
    const int kInteractionRadius2 = kInteractionRadiusPx * kInteractionRadiusPx;

    Asset* best = nullptr;
    int best_dist2 = std::numeric_limits<int>::max();
    int best_area = std::numeric_limits<int>::max();
    int best_screen_y = std::numeric_limits<int>::max();
    for (Asset* asset : selected_assets_) {
        if (!asset || asset->dead) continue;
        if (!asset_belongs_to_room(asset)) continue;
        if (asset->info && type_is_fog(*asset->info)) continue;
        SDL_Rect bounds{0, 0, 0, 0};
        int screen_y = 0;
        bool have_bounds = false;

        auto bounds_it = asset_bounds_cache_.find(asset);
        if (bounds_it != asset_bounds_cache_.end()) {
            bounds = bounds_it->second.bounds;
            screen_y = bounds_it->second.screen_y;
            have_bounds = screen_rect_is_reasonable(bounds);
        }
        if (!have_bounds) {
            have_bounds = compute_asset_screen_bounds(cam, asset, bounds, screen_y);
        }

        int dist2 = std::numeric_limits<int>::max();
        int area = std::numeric_limits<int>::max();
        if (have_bounds) {
            const int min_x = bounds.x;
            const int max_x = bounds.x + bounds.w - 1;
            const int min_y = bounds.y;
            const int max_y = bounds.y + bounds.h - 1;
            const int closest_x = std::clamp(screen_point.x, min_x, max_x);
            const int closest_y = std::clamp(screen_point.y, min_y, max_y);
            const int dx = closest_x - screen_point.x;
            const int dy = closest_y - screen_point.y;
            dist2 = dx * dx + dy * dy;
            area = bounds.w * bounds.h;
        } else {
            SDL_Point gp = grid_point_for_asset(asset);
            SDL_FPoint screen_f = cam.map_to_screen(gp);
            if (!std::isfinite(screen_f.x) || !std::isfinite(screen_f.y)) {
                continue;
            }
            const int dx = static_cast<int>(std::lround(screen_f.x)) - screen_point.x;
            const int dy = static_cast<int>(std::lround(screen_f.y)) - screen_point.y;
            dist2 = dx * dx + dy * dy;
            screen_y = static_cast<int>(std::lround(screen_f.y));
        }

        const bool is_better =
            dist2 < best_dist2 ||
            (dist2 == best_dist2 && screen_y < best_screen_y) ||
            (dist2 == best_dist2 && screen_y == best_screen_y && area < best_area);
        if (dist2 <= kInteractionRadius2 && is_better) {
            best = asset;
            best_dist2 = dist2;
            best_screen_y = screen_y;
            best_area = area;
        }
    }

    return best;
}

bool RoomEditor::delete_selected_asset_or_group() {
    const std::vector<std::string> spawn_ids = selected_spawn_group_ids();
    if (spawn_ids.empty()) {
        return false;
    }

    int deleted_count = 0;
    for (const std::string& spawn_id : spawn_ids) {
        if (spawn_id.empty()) {
            continue;
        }
        if (delete_spawn_group_internal(spawn_id)) {
            ++deleted_count;
        }
    }
    if (deleted_count <= 0) {
        return false;
    }
    clear_selection();
    if (deleted_count == 1) {
        show_notice("Deleted spawn group");
    } else {
        show_notice("Deleted " + std::to_string(deleted_count) + " spawn groups");
    }
    return true;
}

bool RoomEditor::handle_camera_settings_mouse_controls(const Input& input) {
    if (!camera_settings_lock_active_) {
        return false;
    }

    const bool shift_down =
        is_shift_key_down() ||
        input.isScancodeDown(SDL_SCANCODE_LSHIFT) ||
        input.isScancodeDown(SDL_SCANCODE_RSHIFT);
    bool consumed = false;
    int height_delta_px = 0;
    int zoom_delta_percent = 0;
    float tilt_delta_deg = 0.0f;
    float pan_delta_percent = 0.0f;

    const int scroll_y = input.getScrollY();
    const bool center_depth_scroll_override = oval_mode_active() && oval_edit_.center_selected;
    if (scroll_y != 0 && !center_depth_scroll_override) {
        const int ticks = std::abs(scroll_y);
        const int direction = (scroll_y > 0) ? 1 : -1;
        if (shift_down) {
            zoom_delta_percent = direction * kCameraZoomScrollStep * ticks;
        } else {
            height_delta_px = direction * kCameraHeightScrollStep * ticks;
        }
        consumed = true;
    }

    if (!camera_settings_drag_.active) {
        if (input.wasPressed(Input::LEFT)) {
            camera_settings_drag_.active = true;
            camera_settings_drag_.button = Input::LEFT;
            camera_settings_drag_.mode = shift_down ? CameraSettingsDragState::Mode::Pan
                                                   : CameraSettingsDragState::Mode::Tilt;
            consumed = true;
        } else if (input.wasPressed(Input::RIGHT)) {
            camera_settings_drag_.active = true;
            camera_settings_drag_.button = Input::RIGHT;
            camera_settings_drag_.mode = CameraSettingsDragState::Mode::Pan;
            consumed = true;
        }
    }

    if (camera_settings_drag_.active) {
        const bool button_down = input.isDown(camera_settings_drag_.button);
        if (!button_down) {
            camera_settings_drag_.active = false;
            camera_settings_drag_.mode = CameraSettingsDragState::Mode::None;
            consumed = true;
        }
    }

    if (camera_settings_drag_.active) {
        const int dy = input.getDY();
        if (dy != 0) {
            const float delta = -static_cast<float>(dy);
            switch (camera_settings_drag_.mode) {
                case CameraSettingsDragState::Mode::Tilt:
                    tilt_delta_deg = delta * kCameraTiltDegreesPerPixel;
                    consumed = true;
                    break;
                case CameraSettingsDragState::Mode::Pan:
                    pan_delta_percent = delta * kCameraPanPercentPerPixel;
                    consumed = true;
                    break;
                case CameraSettingsDragState::Mode::None:
                    break;
            }
        }
    }

    (void)height_delta_px;
    (void)zoom_delta_percent;
    (void)tilt_delta_deg;
    (void)pan_delta_percent;

    if (assets_) {
        if (camera_settings_drag_.active && !camera_settings_drag_active_notified_) {
            assets_->notify_camera_activity(true);
            camera_settings_drag_active_notified_ = true;
        } else if (!camera_settings_drag_.active && camera_settings_drag_active_notified_) {
            assets_->notify_camera_activity(false);
            camera_settings_drag_active_notified_ = false;
        }
    }

    return consumed;
}

bool RoomEditor::is_spawn_group_panel_visible() const {
    return spawn_group_panel_ && spawn_group_panel_->is_visible();
}

void RoomEditor::set_blocking_panel_visible(BlockingPanel panel, bool visible) {
    const size_t index = static_cast<size_t>(panel);
    if (index >= blocking_panel_visible_.size()) {
        return;
    }
    blocking_panel_visible_[index] = visible;
}

bool RoomEditor::any_blocking_panel_visible() const {
    return std::any_of(blocking_panel_visible_.begin(),
                       blocking_panel_visible_.end(),
                       [](bool state) { return state; });
}

void RoomEditor::set_room_trail_nav_visibility(bool visible) {
    if (room_nav_visible_ == visible) {
        return;
    }
    room_nav_visible_ = visible;
    if (!visible) {
        clear_room_trail_nav_entries();
    }
}

float RoomEditor::edge_pan_intensity(int value, int max_value, float threshold_fraction) {
    if (max_value <= 1) {
        return 0.0f;
    }
    const float clamped_fraction = std::clamp(threshold_fraction, 0.0f, 0.5f);
    const float threshold = static_cast<float>(max_value) * clamped_fraction;
    if (threshold <= 1e-3f) {
        return 0.0f;
    }
    const float signed_penetration = (value < 0)
        ? std::min(threshold, static_cast<float>(-value))
        : std::max(0.0f, threshold - static_cast<float>(value));
    if (signed_penetration <= 0.0f) {
        return 0.0f;
    }
    const float linear = std::clamp(signed_penetration / threshold, 0.0f, 1.0f);
    return std::pow(linear, kShiftEdgePanExponent);
}

bool RoomEditor::apply_shift_edge_pan(const Input& input, WarpedScreenGrid& cam) {
    const bool dragging_asset = dragging_;
    if (!dragging_asset || screen_w_ <= 1 || screen_h_ <= 1) {
        return false;
    }

    const SDL_Point screen_pt{input.getX(), input.getY()};
    if (is_ui_blocking_input(screen_pt.x, screen_pt.y)) {
        return false;
    }

    // Project the screen center and cursor onto the warped floor so the threshold
    // respects world-space distances instead of raw screen pixels.
    const SDL_Point screen_center{ screen_w_ / 2, screen_h_ / 2 };
    const SDL_FPoint center_world = cam.screen_to_map(screen_center);
    const SDL_FPoint cursor_world = cam.screen_to_map(screen_pt);
    if (!std::isfinite(center_world.x) || !std::isfinite(center_world.y) ||
        !std::isfinite(cursor_world.x) || !std::isfinite(cursor_world.y)) {
        return false;
    }

    // Use the distance from the screen center to a point near the bottom of the screen
    // to define the outer (max) half-extent of the panning square.
    const int bottom_sample_y = std::clamp(
        static_cast<int>(std::lround(static_cast<double>(screen_h_ - 1) * kShiftEdgePanBottomSampleInset)),
        0,
        std::max(0, screen_h_ - 1));
    const SDL_FPoint bottom_world = cam.screen_to_map(SDL_Point{ screen_w_ / 2, bottom_sample_y });
    const double outer_half_extent = std::hypot(
        static_cast<double>(bottom_world.x) - static_cast<double>(center_world.x),
        static_cast<double>(bottom_world.y) - static_cast<double>(center_world.y));
    if (!std::isfinite(outer_half_extent) || outer_half_extent <= 1e-6) {
        return false;
    }

    const double inner_half_extent = outer_half_extent * 0.98; // 95% sized inner square

    // Chebyshev distance gives us a square region (max(|dx|, |dy|)).
    const double offset_x = static_cast<double>(cursor_world.x) - static_cast<double>(center_world.x);
    const double offset_y = static_cast<double>(cursor_world.y) - static_cast<double>(center_world.y);
    const double cheb_dist = std::max(std::abs(offset_x), std::abs(offset_y));

    const double ramp_den = std::max(outer_half_extent - inner_half_extent, 1e-9);
    double intensity = (cheb_dist - inner_half_extent) / ramp_den;
    intensity = std::clamp(intensity, 0.0, 1.0);
    if (intensity <= 0.0) {
        return false;
    }

    const double dir_len = std::hypot(offset_x, offset_y);
    if (!std::isfinite(dir_len) || dir_len <= 1e-6) {
        return false;
    }

    const double world_dir_x = offset_x / dir_len;
    const double world_dir_y = offset_y / dir_len;

    constexpr float kFallbackDtSeconds = 1.0f / 60.0f;
    const double world_step = static_cast<double>(kShiftEdgePanMaxSpeedBottomWorldUnitsPerSecond) *
                              intensity *
                              static_cast<double>(kFallbackDtSeconds);

    const SDL_Point before_center = cam.get_screen_center();
    SDL_Point target_center = before_center;
    target_center.x = static_cast<int>(std::lround(static_cast<double>(target_center.x) + world_dir_x * world_step));
    target_center.y = static_cast<int>(std::lround(static_cast<double>(target_center.y) + world_dir_y * world_step));

    if (target_center.x == before_center.x && target_center.y == before_center.y) {
        return false;
    }

    cam.set_focus_override(target_center);
    cam.set_screen_center(target_center);
    return true;
}

void RoomEditor::handle_mouse_input(const Input& input) {
    if (!input_) return;

    const bool editor_mode_active =
        hitbox_mode_active() || attack_box_mode_active() || impassable_box_mode_active() || floor_box_mode_active() ||
        movement_mode_active() || oval_mode_active() || anchor_mode_active();
    if (editor_mode_active) {
        if (hitbox_mode_active()) {
            handle_hitbox_mode_mouse_input(input);
        } else if (attack_box_mode_active()) {
            handle_attack_box_mode_mouse_input(input);
        } else if (impassable_box_mode_active()) {
            handle_impassable_box_mode_mouse_input(input);
        } else if (floor_box_mode_active()) {
            handle_floor_box_mode_mouse_input(input);
        } else if (movement_mode_active()) {
            handle_movement_mode_mouse_input(input);
        } else if (oval_mode_active()) {
            handle_oval_mode_mouse_input(input);
        } else if (anchor_mode_active()) {
            handle_anchor_mode_mouse_input(input);
        }

        if (!assets_) {
            return;
        }
        WarpedScreenGrid& cam = assets_->getView();
        const SDL_Point screen_pt{input_->getX(), input_->getY()};
        refresh_cursor_world_state(cam, screen_pt);
        if (handle_camera_settings_mouse_controls(input)) {
            return;
        }

        const float prev_scale = cam.get_scale();
        const SDL_Point prev_center = cam.get_screen_center();
        const EditorInteractionState interaction_state = current_editor_interaction_state();
        bool pointer_blocks_camera_controls = interaction_state.camera_blocked;
        if (shared_footer_bar_ && shared_footer_bar_->visible() &&
            shared_footer_bar_->contains(screen_pt.x, screen_pt.y)) {
            pointer_blocks_camera_controls = true;
        }

        if (anchor_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_anchor_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (oval_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_oval_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (movement_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_movement_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (hitbox_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_hitbox_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (attack_box_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_attack_box_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (impassable_box_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_impassable_box_ui_blocking_point(screen_pt.x, screen_pt.y);
        } else if (floor_box_mode_active()) {
            pointer_blocks_camera_controls =
                pointer_blocks_camera_controls || is_floor_box_ui_blocking_point(screen_pt.x, screen_pt.y);
        }

        if (interaction_state.camera_blocked) {
            camera_controls_.cancel(cam);
        }
        if (!camera_settings_lock_active_) {
            if (!pointer_blocks_camera_controls) {
                camera_controls_.handle_input(cam, input, false);
            }
        }
        if (std::fabs(cam.get_scale() - prev_scale) > 1e-6 ||
            cam.get_screen_center().x != prev_center.x ||
            cam.get_screen_center().y != prev_center.y) {
            mark_spatial_index_dirty();
        }

        const bool now_panning = camera_controls_.is_panning();
        if (now_panning) {
            if (!camera_pan_active_notified_) {
                camera_pan_active_notified_ = true;
                assets_->notify_camera_activity(true);
            }
        } else if (camera_pan_active_notified_) {
            camera_pan_active_notified_ = false;
            camera_pan_just_finished_ = true;
            suppress_left_click_frames_ = 2;
            if (input_) {
                input_->consumeMouseButton(Input::LEFT);
            }
            assets_->notify_camera_activity(false);
        }

        if (camera_pan_just_finished_ && input_) {
            input_->clearClickBuffer();
        }
        refresh_cursor_world_state(cam, screen_pt);
        return;
    }

    const bool shift_down =
        input.isScancodeDown(SDL_SCANCODE_LSHIFT) || input.isScancodeDown(SDL_SCANCODE_RSHIFT);
    const bool space_down = input.isScancodeDown(SDL_SCANCODE_SPACE);
    const bool shift_space_down = shift_down && space_down;
    const bool shift_down_just_pressed = shift_down && !shift_was_down_last_frame_;
    const bool shift_space_just_pressed = shift_space_down && !shift_space_was_down_last_frame_;

    shift_was_down_last_frame_ = shift_down;
    shift_space_was_down_last_frame_ = shift_space_down;

    if (shift_down_just_pressed) {
        reset_selection_filter();
    }
    if (shift_space_just_pressed) {
        cycle_selection_filter();
    }

    if (assets_) {
        const SDL_Point screen_pt{input_->getX(), input_->getY()};
        refresh_cursor_world_state(assets_->getView(), screen_pt);
    }
    if (handle_camera_settings_mouse_controls(input)) {
        return;
    }

    auto commit_marquee_selection = [this](const SDL_Point& screen_pt) {
        if (!marquee_selection_.active) {
            return false;
        }
        marquee_selection_.current_screen = screen_pt;
        const bool should_commit_selection = marquee_selection_.threshold_passed;
        if (marquee_selection_.threshold_passed && assets_) {
            const int left = std::min(marquee_selection_.start_screen.x, marquee_selection_.current_screen.x);
            const int top = std::min(marquee_selection_.start_screen.y, marquee_selection_.current_screen.y);
            const int right = std::max(marquee_selection_.start_screen.x, marquee_selection_.current_screen.x);
            const int bottom = std::max(marquee_selection_.start_screen.y, marquee_selection_.current_screen.y);
            const WarpedScreenGrid& cam = assets_->getView();
            std::vector<Asset*> inside{};
            inside.reserve(64);
            for (Asset* asset : assets_->all) {
                if (!asset || asset->dead || !asset_belongs_to_room(asset)) {
                    continue;
                }
                if (asset->info && type_is_fog(*asset->info)) {
                    continue;
                }
                SDL_Point anchor_screen{0, 0};
                if (!asset_anchor_screen_position(cam, asset, anchor_screen)) {
                    continue;
                }
                if (anchor_screen.x >= left && anchor_screen.x <= right &&
                    anchor_screen.y >= top && anchor_screen.y <= bottom) {
                    inside.push_back(asset);
                }
            }
            marquee_selection_.last_selection = inside;
            select_assets_direct(inside);
        } else {
            if (!mouse_press_state_.valid) {
                clear_selection();
            }
        }
        marquee_selection_.reset();
        clear_mouse_press_state(false);
        if (should_commit_selection) {
            suppress_next_left_click_ = true;
            click_buffer_frames_ = 3;
            last_click_spawn_id_.clear();
            last_click_time_ms_ = 0;
        }
        return true;
    };

    if (shift_down && asset_selection_allowed_now()) {
        const SDL_Point screen_pt{input_->getX(), input_->getY()};
        bool left_down = input_->isDown(Input::LEFT);
        if (suppress_world_left_click_frames_ > 0) {
            left_down = false;
        }

        if (marquee_selection_.active && !left_down && mouse_press_state_.prev_left_down) {
            (void)commit_marquee_selection(screen_pt);
            mouse_press_state_.prev_left_down = left_down;
            return;
        }

        if (left_down && !mouse_press_state_.prev_left_down) {
            const bool had_selection_before_press = !selected_assets_.empty();

            Asset* selection_hit = hit_test_asset_anchor(screen_pt, kShiftAnchorSelectRadiusPx);
            if (!selection_hit) {
                selection_hit = hit_test_asset(screen_pt, nullptr);
            }
            mouse_press_state_.pressed_asset = selection_hit;
            mouse_press_state_.pressed_identity = selection_hit;
            mouse_press_state_.pressed_spawn_id = selection_hit ? selection_hit->spawn_id : std::string{};
            mouse_press_state_.pressed_has_spawn_group = selection_hit && !selection_hit->spawn_id.empty();
            mouse_press_state_.forced_drag_mode = DragMode::None;
            mouse_press_state_.was_dragged = false;
            mouse_press_state_.press_screen = screen_pt;
            mouse_press_state_.valid = selection_hit != nullptr;

            if (!selection_hit) {
                if (had_selection_before_press) {
                    clear_selection();
                }
                marquee_selection_.reset();
                marquee_selection_.active = true;
                marquee_selection_.start_screen = screen_pt;
                marquee_selection_.current_screen = screen_pt;
            } else {
                const bool hit_was_already_selected =
                    had_selection_before_press &&
                    std::find(selected_assets_.begin(), selected_assets_.end(), selection_hit) != selected_assets_.end();
                if (!hit_was_already_selected) {
                    select_asset_or_group(selection_hit);
                }
            }
        } else if (left_down && marquee_selection_.active) {
            marquee_selection_.current_screen = screen_pt;
            const int dx = screen_pt.x - marquee_selection_.start_screen.x;
            const int dy = screen_pt.y - marquee_selection_.start_screen.y;
            const int dist2 = dx * dx + dy * dy;
            if (!marquee_selection_.threshold_passed &&
                dist2 > (kMouseDragThresholdPx * kMouseDragThresholdPx)) {
                marquee_selection_.threshold_passed = true;
            }
            if (marquee_selection_.threshold_passed && assets_) {
                const int left = std::min(marquee_selection_.start_screen.x, marquee_selection_.current_screen.x);
                const int top = std::min(marquee_selection_.start_screen.y, marquee_selection_.current_screen.y);
                const int right = std::max(marquee_selection_.start_screen.x, marquee_selection_.current_screen.x);
                const int bottom = std::max(marquee_selection_.start_screen.y, marquee_selection_.current_screen.y);
                const WarpedScreenGrid& cam = assets_->getView();
                std::vector<Asset*> inside{};
                inside.reserve(64);
                for (Asset* asset : assets_->all) {
                    if (!asset || asset->dead || !asset_belongs_to_room(asset)) {
                        continue;
                    }
                    if (asset->info && type_is_fog(*asset->info)) {
                        continue;
                    }
                    SDL_Point anchor_screen{0, 0};
                    if (!asset_anchor_screen_position(cam, asset, anchor_screen)) {
                        continue;
                    }
                    if (anchor_screen.x >= left && anchor_screen.x <= right &&
                        anchor_screen.y >= top && anchor_screen.y <= bottom) {
                        inside.push_back(asset);
                    }
                }
                marquee_selection_.last_selection = inside;
            }
        }

        mouse_press_state_.prev_left_down = left_down;
        if (marquee_selection_.active) {
            return;
        }
    } else if (marquee_selection_.active) {
        const SDL_Point screen_pt{input_->getX(), input_->getY()};
        bool left_down = input_->isDown(Input::LEFT);
        if (suppress_world_left_click_frames_ > 0) {
            left_down = false;
        }
        if (!asset_selection_allowed_now()) {
            marquee_selection_.reset();
            clear_mouse_press_state(true);
        } else {
            (void)commit_marquee_selection(screen_pt);
        }
        mouse_press_state_.prev_left_down = left_down;
        return;
    }

    if (!assets_) {
        return;
    }

    const bool consumed_scroll_for_scale = apply_scroll_size_adjustment(input);
    if (consumed_scroll_for_scale && input_) {
        input_->consumeScroll();
    }

    const int scroll_y = consumed_scroll_for_scale ? 0 : input.getScrollY();
    const bool camera_scroll_event = (scroll_y != 0);
    if (camera_scroll_event && assets_) {
        assets_->notify_camera_activity(true);
        assets_->notify_camera_activity(false);
    }

    WarpedScreenGrid& cam = assets_->getView();
    const float prev_scale = cam.get_scale();
    const SDL_Point prev_center = cam.get_screen_center();

    const SDL_Point screen_pt{ input_->getX(), input_->getY() };
    bool left_down                = input_->isDown(Input::LEFT);
    bool left_pressed_this_frame  = input_->wasPressed(Input::LEFT);
    bool left_released_this_frame = input_->wasReleased(Input::LEFT);
    if (suppress_world_left_click_frames_ > 0) {
        left_down = false;
        left_pressed_this_frame = false;
        left_released_this_frame = false;
    }
    const bool selection_allowed = asset_selection_allowed_now();
    Asset* anchor_hit =
        (selection_allowed && shift_down) ? hit_test_asset_anchor(screen_pt, kShiftAnchorHoverRadiusPx) : nullptr;
    std::optional<DynamicBoundaryProxyHit> boundary_proxy_hit =
        (selection_allowed && shift_down) ? hit_test_dynamic_boundary_sprite(screen_pt) : std::nullopt;

    Asset* hit_before_pan = nullptr;
    const bool has_selection = selection_allowed && !selected_assets_.empty();
    const bool has_boundary_proxy_selection = selection_allowed && selected_dynamic_boundary_proxy_.has_value();
    if (selection_allowed) {
        hit_before_pan = hit_test_asset(screen_pt, nullptr);
        if (!selected_assets_.empty()) {
            hit_before_pan = selected_asset_within_interaction_radius(screen_pt);
        } else if (shift_down && anchor_hit) {
            hit_before_pan = anchor_hit;
        } else if (shift_down && boundary_proxy_hit) {
            hit_before_pan = nullptr;
        } else if (!shift_down) {
            hit_before_pan = nullptr;
        }
    }
    const bool selection_interaction_active =
        selection_allowed && (shift_down || has_selection || has_boundary_proxy_selection);
    bool perimeter_handle_blocks_pan = false;
    if (has_selection) {
        for (Asset* asset : selected_assets_) {
            if (!asset || asset->spawn_method != "Perimeter" || asset->spawn_id.empty()) {
                continue;
            }
            perimeter_handle_blocks_pan =
                perimeter_handle_hover_target(asset->spawn_id, screen_pt) != PerimeterHandleHover::None;
            break;
        }
    }
    const bool selection_blocks_camera_pan =
        (selection_allowed && has_selection) || any_editor_point_selected();
    const bool pointer_blocks_pan = selection_blocks_camera_pan ||
                                    (!selection_interaction_active && dragging_) ||
                                    (selection_interaction_active && !dragging_ &&
                                     (hit_before_pan || perimeter_handle_blocks_pan) &&
                                     (left_down || left_pressed_this_frame));

    if (selection_blocks_camera_pan && camera_controls_.is_panning()) {
        // Stop any in-progress camera drag as soon as a selection exists so asset dragging has priority.
        camera_controls_.cancel(cam);
    }

    if (!camera_settings_lock_active_) {
        camera_controls_.handle_input(cam, input, pointer_blocks_pan);
        if (dragging_ && !camera_controls_.is_panning()) {
            apply_shift_edge_pan(input, cam);
        }
    }
    if (std::fabs(cam.get_scale() - prev_scale) > 1e-6 ||
        cam.get_screen_center().x != prev_center.x ||
        cam.get_screen_center().y != prev_center.y) {
        mark_spatial_index_dirty();
    }

    if (assets_) {
        const bool now_panning = camera_controls_.is_panning();
        if (now_panning) {
            if (!camera_pan_active_notified_) {
                camera_pan_active_notified_ = true;
                assets_->notify_camera_activity(true);
            }
        } else if (camera_pan_active_notified_) {
            camera_pan_active_notified_ = false;
            camera_pan_just_finished_ = true;
            suppress_left_click_frames_ = 2;
            if (input_) {
                input_->consumeMouseButton(Input::LEFT);
            }
            assets_->notify_camera_activity(false);
        }
    }

    if (camera_pan_just_finished_ && input_) {
        input_->clearClickBuffer();
    }

    refresh_cursor_world_state(cam, screen_pt);

    perimeter_hover_target_ = PerimeterHandleHover::None;
    if (selection_allowed && !selected_assets_.empty()) {
        for (Asset* asset : selected_assets_) {
            if (!asset || asset->spawn_method != "Perimeter" || asset->spawn_id.empty()) {
                continue;
            }
            perimeter_hover_target_ = perimeter_handle_hover_target(asset->spawn_id, screen_pt);
            break;
        }
    }

    if (selected_geometry_room_) {
        clear_geometry_selection();
    }
    hovered_geometry_room_ = nullptr;
    if (!left_down) {
        geometry_drag_pending_dirty_ = false;
        geometry_drag_handle_ = GeometryHandle::None;
    }

    Asset* hit = nullptr;
    if (selection_allowed) {
        hit = hit_test_asset(screen_pt, nullptr);
        if (!selected_assets_.empty()) {
            hit = selected_asset_within_interaction_radius(screen_pt);
        } else if (shift_down && anchor_hit) {
            hit = anchor_hit;
        }
    }

    auto rebuild_highlight = [this]() {
        highlighted_assets_.clear();
        if (!selected_assets_.empty()) {
            highlighted_assets_.insert(highlighted_assets_.end(), selected_assets_.begin(), selected_assets_.end());
        }
        if (hovered_asset_) {
            if (std::find(highlighted_assets_.begin(),
                          highlighted_assets_.end(),
                          hovered_asset_) == highlighted_assets_.end()) {
                highlighted_assets_.push_back(hovered_asset_);
            }
        }
        mark_highlight_dirty();
};

    if (!selection_allowed) {
        marquee_selection_.reset();
        clear_mouse_press_state(true);
        hovered_anchor_asset_ = nullptr;
        hovered_dynamic_boundary_proxy_.reset();
        if (hovered_asset_) {
            hovered_asset_ = nullptr;
            mark_highlight_dirty();
        }
    } else if (!shift_down && selected_assets_.empty() && !left_down && !dragging_ && !selected_dynamic_boundary_proxy_) {
        clear_mouse_press_state(false);
        hovered_anchor_asset_ = nullptr;
        hovered_dynamic_boundary_proxy_.reset();
    }

    if (suppress_next_left_click_) {
        if (click_buffer_frames_ > 0) {
            --click_buffer_frames_;
        } else {
            suppress_next_left_click_ = false;
        }
    }

    if (selection_interaction_active && left_down && !mouse_press_state_.prev_left_down) {
        const bool had_selection_before_press = !selected_assets_.empty();

        Asset* selection_hit = nullptr;
        std::optional<DynamicBoundaryProxyHit> selection_boundary_hit;
        DragMode forced_drag_mode = DragMode::None;
        if (!selected_assets_.empty()) {
            selection_hit = selected_asset_within_interaction_radius(screen_pt);
            if (!selection_hit &&
                perimeter_hover_target_ != PerimeterHandleHover::None &&
                selected_spawn_group_ids().size() <= 1) {
                selection_hit = selected_assets_.front();
                forced_drag_mode =
                    (perimeter_hover_target_ == PerimeterHandleHover::Center) ? DragMode::PerimeterCenter
                                                                              : DragMode::Perimeter;
            }
        } else if (shift_down) {
            selection_hit = hit_test_asset_anchor(screen_pt, kShiftAnchorSelectRadiusPx);
            if (!selection_hit) {
                selection_hit = hit_test_asset(screen_pt, nullptr);
            }
            if (!selection_hit && boundary_proxy_hit) {
                selection_boundary_hit = boundary_proxy_hit;
            }
        }

        if (!selection_hit && !selection_boundary_hit && !selected_assets_.empty()) {
            clear_selection();
        }
        if (!selection_hit && !selection_boundary_hit && selected_dynamic_boundary_proxy_) {
            clear_dynamic_boundary_proxy_selection();
            mark_highlight_dirty();
        }

        mouse_press_state_.pressed_asset = selection_hit;
        mouse_press_state_.pressed_identity = selection_hit;
        mouse_press_state_.pressed_spawn_id = selection_hit ? selection_hit->spawn_id : std::string{};
        mouse_press_state_.pressed_has_spawn_group = selection_hit && !selection_hit->spawn_id.empty();
        mouse_press_state_.forced_drag_mode = forced_drag_mode;
        mouse_press_state_.was_dragged = false;
        mouse_press_state_.press_screen = screen_pt;
        mouse_press_state_.valid = selection_hit != nullptr;
        if (!selection_hit) {
            last_click_spawn_id_.clear();
            last_click_time_ms_ = 0;
        }

        if (selection_hit) {
            const bool hit_was_already_selected =
                had_selection_before_press &&
                std::find(selected_assets_.begin(), selected_assets_.end(), selection_hit) != selected_assets_.end();
            if (!hit_was_already_selected) {
                select_asset_or_group(selection_hit);
            }
            rebuild_highlight();
        } else if (selection_boundary_hit) {
            clear_selection();
            selected_dynamic_boundary_proxy_ = selection_boundary_hit->key;
            hovered_dynamic_boundary_proxy_ = selection_boundary_hit->key;
            sync_spawn_group_panel_with_selection();
            mark_highlight_dirty();
        } else {

            if (!selected_assets_.empty() ||
                !highlighted_assets_.empty() ||
                hovered_asset_ ||
                selected_dynamic_boundary_proxy_ ||
                hovered_dynamic_boundary_proxy_) {
                selected_assets_.clear();
                highlighted_assets_.clear();
                hovered_asset_ = nullptr;
                clear_dynamic_boundary_proxy_selection();
                clear_mouse_press_state(true);
                sync_spawn_group_panel_with_selection();
                mark_highlight_dirty();
            }
        }
    }

    if (left_down && mouse_press_state_.valid) {
        if (!is_mouse_press_asset_valid()) {
            clear_mouse_press_state(true);
            if (dragging_) {
                reset_drag_state();
            }
        } else {
            const int dx = screen_pt.x - mouse_press_state_.press_screen.x;
            const int dy = screen_pt.y - mouse_press_state_.press_screen.y;
            const int dist2 = dx * dx + dy * dy;

            if (!mouse_press_state_.was_dragged && selection_interaction_active &&
                dist2 > kMouseDragThresholdPx * kMouseDragThresholdPx) {
                mouse_press_state_.was_dragged = true;
                dragging_ = true;
                drag_last_world_ = snapped_cursor_world_;
                const bool ctrl_modifier =
                    input.isScancodeDown(SDL_SCANCODE_LCTRL) || input.isScancodeDown(SDL_SCANCODE_RCTRL);
                begin_drag_session(snapped_cursor_world_, ctrl_modifier, mouse_press_state_.forced_drag_mode);
            }

            if (mouse_press_state_.was_dragged && dragging_) {
                update_drag_session(snapped_cursor_world_);

                if (hovered_asset_ != mouse_press_state_.pressed_asset) {
                    hovered_asset_ = mouse_press_state_.pressed_asset;
                    rebuild_highlight();
                }
            }
        }
    }

    if (!left_down && mouse_press_state_.prev_left_down && mouse_press_state_.valid) {
        const bool pressed_asset_valid = is_mouse_press_asset_valid();
        if (mouse_press_state_.was_dragged) {
            if (dragging_) {
                finalize_drag_session();
                dragging_ = false;
            }

            suppress_next_left_click_ = true;
            click_buffer_frames_      = 3;
            last_click_spawn_id_.clear();
            last_click_time_ms_       = 0;

            if (pressed_asset_valid) {
                sync_spawn_group_panel_with_selection();
                rebuild_highlight();
            }
        } else if (pressed_asset_valid) {
            std::string spawn_id_to_open;
            if (consume_pressed_asset_release(SDL_GetTicks(), spawn_id_to_open)) {
                open_spawn_group_editor_by_id(spawn_id_to_open);
            }

            if (hovered_asset_ == mouse_press_state_.pressed_asset) {
                hovered_asset_ = mouse_press_state_.pressed_asset;
                rebuild_highlight();
            }

            suppress_next_left_click_ = true;
            click_buffer_frames_      = 2;
        }

        clear_mouse_press_state(false);
    }

    if (!selection_allowed) {
        hovered_anchor_asset_ = nullptr;
        hovered_dynamic_boundary_proxy_.reset();
        if (hovered_asset_) {
            hovered_asset_ = nullptr;
            mark_highlight_dirty();
        }
    } else if (!dragging_ && selected_assets_.empty() && !selected_dynamic_boundary_proxy_) {
        const auto prev_boundary_hover = hovered_dynamic_boundary_proxy_;
        Asset* hover_candidate = shift_down ? (anchor_hit ? anchor_hit : hit) : hit;
        hovered_anchor_asset_ = shift_down ? anchor_hit : nullptr;
        hovered_dynamic_boundary_proxy_ =
            shift_down && boundary_proxy_hit
                ? std::optional<DynamicBoundaryProxyKey>(boundary_proxy_hit->key)
                : std::nullopt;
        if (hovered_asset_ != hover_candidate) {
            hovered_asset_ = hover_candidate;
            rebuild_highlight();
        }
        if (hovered_dynamic_boundary_proxy_ != prev_boundary_hover) {
            mark_highlight_dirty();
        }
    } else if (!dragging_ && !selected_assets_.empty()) {
        hovered_anchor_asset_ = shift_down ? anchor_hit : nullptr;
        hovered_dynamic_boundary_proxy_.reset();
        Asset* hover_candidate = selected_asset_within_interaction_radius(screen_pt);
        if (!hover_candidate) {
            hover_candidate = selected_assets_.front();
        }
        if (hovered_asset_ != hover_candidate) {
            hovered_asset_ = hover_candidate;
            rebuild_highlight();
        }
    } else if (!dragging_ && selected_dynamic_boundary_proxy_) {
        const auto prev_boundary_hover = hovered_dynamic_boundary_proxy_;
        hovered_anchor_asset_ = nullptr;
        hovered_asset_ = nullptr;
        if (boundary_proxy_hit && boundary_proxy_hit->key == *selected_dynamic_boundary_proxy_) {
            hovered_dynamic_boundary_proxy_ = boundary_proxy_hit->key;
        } else {
            hovered_dynamic_boundary_proxy_.reset();
        }
        if (hovered_dynamic_boundary_proxy_ != prev_boundary_hover) {
            mark_highlight_dirty();
        }
    } else {
        hovered_anchor_asset_ = nullptr;
        hovered_dynamic_boundary_proxy_.reset();
    }

    const bool any_left_activity = left_pressed_this_frame || left_released_this_frame || left_down;
    const bool suppress_click_now = suppress_left_click_frames_ > 0 || camera_pan_just_finished_;
    if (selection_allowed &&
        !dragging_ && !suppress_next_left_click_ && !any_left_activity && !suppress_click_now) {
        handle_click(input);
    }

    if (suppress_left_click_frames_ > 0) {
        --suppress_left_click_frames_;
    }
    if (suppress_world_left_click_frames_ > 0) {
        --suppress_world_left_click_frames_;
    }
    camera_pan_just_finished_ = false;

    mouse_press_state_.prev_left_down = left_down;
}

bool RoomEditor::asset_anchor_screen_position(const WarpedScreenGrid& cam,
                                              const Asset* asset,
                                              SDL_Point& out_screen) const {
    if (!asset) {
        return false;
    }

    if (const auto* projected = cam.grid_point_for_asset(asset)) {
        const SDL_FPoint projected_screen = projected->screen_position();
        if (std::isfinite(projected_screen.x) && std::isfinite(projected_screen.y)) {
            out_screen = SDL_Point{
                static_cast<int>(std::lround(projected_screen.x)),
                static_cast<int>(std::lround(projected_screen.y))
            };
            return true;
        }
    }

    const SDL_Point world_anchor = grid_point_for_asset(asset);
    const SDL_FPoint screen_f = cam.map_to_screen(world_anchor);
    if (!std::isfinite(screen_f.x) || !std::isfinite(screen_f.y)) {
        return false;
    }

    out_screen = SDL_Point{
        static_cast<int>(std::lround(screen_f.x)),
        static_cast<int>(std::lround(screen_f.y))
    };
    return true;
}

const std::vector<Asset*>* RoomEditor::selection_asset_source() const {
    if (active_assets_ && !active_assets_->empty()) {
        return active_assets_;
    }
    if (assets_) {
        return &assets_->all;
    }
    return nullptr;
}

Asset* RoomEditor::hit_test_asset_anchor(SDL_Point screen_point, int pick_radius_px) const {
    if (!assets_ || pick_radius_px <= 0) {
        return nullptr;
    }

    const WarpedScreenGrid& cam = assets_->getView();
    const int radius2 = pick_radius_px * pick_radius_px;

    Asset* best = nullptr;
    int best_dist2 = std::numeric_limits<int>::max();
    int best_screen_y = std::numeric_limits<int>::max();

    auto consider_asset = [&](Asset* asset) {
        if (!asset || asset->dead) {
            return;
        }
        if (!asset_belongs_to_room(asset)) {
            return;
        }
        if (asset->info && type_is_fog(*asset->info)) {
            return;
        }
        if (selected_assets_.empty() && !asset_matches_selection_filter(asset)) {
            return;
        }

        SDL_Point anchor_px{0, 0};
        if (!asset_anchor_screen_position(cam, asset, anchor_px)) {
            return;
        }

        const int dx = anchor_px.x - screen_point.x;
        const int dy = anchor_px.y - screen_point.y;
        const int dist2 = dx * dx + dy * dy;
        if (dist2 > radius2) {
            return;
        }

        const bool is_better =
            !best ||
            dist2 < best_dist2 ||
            (dist2 == best_dist2 && anchor_px.y < best_screen_y);
        if (is_better) {
            best = asset;
            best_dist2 = dist2;
            best_screen_y = anchor_px.y;
        }
    };

    if (!selected_assets_.empty()) {
        for (Asset* asset : selected_assets_) {
            consider_asset(asset);
        }
    } else {
        const std::vector<Asset*>* source_assets = selection_asset_source();
        if (!source_assets || source_assets->empty()) {
            return nullptr;
        }
        for (Asset* asset : *source_assets) {
            consider_asset(asset);
        }
    }

    return best;
}

Asset* RoomEditor::resolve_bound_child_for_owner(
    Asset* owner,
    SDL_Point screen_point,
    const std::unordered_set<std::string>* allowed_anchor_names) const {
    if (!owner || !assets_ || owner->dead) {
        return nullptr;
    }

    const WarpedScreenGrid& cam = assets_->getView();
    ensure_spatial_index(cam);

    const auto bindings = anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().debug_bindings_snapshot();
    Asset* best = nullptr;
    bool best_contains = false;
    int best_score = std::numeric_limits<int>::max();
    int best_screen_y = std::numeric_limits<int>::max();

    for (const auto& binding : bindings) {
        if (binding.owner != owner) {
            continue;
        }
        if (allowed_anchor_names && !allowed_anchor_names->empty() &&
            allowed_anchor_names->find(binding.anchor_name) == allowed_anchor_names->end()) {
            continue;
        }
        Asset* child = binding.child_asset;
        if (!child || child->dead || !child->info || !is_asset_pointer_live(child)) {
            continue;
        }

        bool contains = false;
        int dist2 = std::numeric_limits<int>::max() / 4;
        int screen_y = std::numeric_limits<int>::max();

        auto bounds_it = asset_bounds_cache_.find(child);
        if (bounds_it != asset_bounds_cache_.end()) {
            const SDL_Rect rect = bounds_it->second.bounds;
            contains = SDL_PointInRect(&screen_point, &rect) != 0;
            const int cx = rect.x + (rect.w / 2);
            const int cy = rect.y + (rect.h / 2);
            const int dx = cx - screen_point.x;
            const int dy = cy - screen_point.y;
            dist2 = dx * dx + dy * dy;
            screen_y = bounds_it->second.screen_y;
        } else {
            SDL_Point child_anchor_px{0, 0};
            if (!asset_anchor_screen_position(cam, child, child_anchor_px)) {
                continue;
            }
            const int dx = child_anchor_px.x - screen_point.x;
            const int dy = child_anchor_px.y - screen_point.y;
            dist2 = dx * dx + dy * dy;
            screen_y = child_anchor_px.y;
        }

        const int score = contains ? dist2 : (dist2 + 50000);

        const bool is_better =
            !best ||
            (contains && !best_contains) ||
            (contains == best_contains && score < best_score) ||
            (contains == best_contains && score == best_score && screen_y < best_screen_y);
        if (is_better) {
            best = child;
            best_contains = contains;
            best_score = score;
            best_screen_y = screen_y;
        }
    }

    return best;
}

bool RoomEditor::navigate_to_bound_child_asset_info(Asset* child) {
    if (!child || !child->info || child->dead || !is_asset_pointer_live(child) || !asset_belongs_to_room(child)) {
        return false;
    }

    Asset* parent = nullptr;
    if (anchor_mode_active() && anchor_edit_.target_asset) {
        parent = anchor_edit_.target_asset;
    } else if (oval_mode_active() && oval_edit_.target_asset) {
        parent = oval_edit_.target_asset;
    } else if (info_ui_) {
        parent = info_ui_->get_target_asset();
    }

    AssetEditorSubview return_subview = AssetEditorSubview::AssetInfo;
    if (oval_mode_active()) {
        return_subview = AssetEditorSubview::OvalAnchor;
    } else if (anchor_mode_active()) {
        return_subview = light_mode_active() ? AssetEditorSubview::Light : AssetEditorSubview::Anchor;
    }

    const AssetEditorSubview previous_subview = asset_editor_subview_;
    const bool pushed_parent_history = (parent && parent != child);
    if (pushed_parent_history) {
        asset_info_parent_history_.push_back(AssetInfoParentHistoryEntry{parent, return_subview});
    }

    preserve_asset_info_parent_history_on_next_open_ = true;
    open_asset_info_editor_for_asset(child, false);
    const bool opened_child_info =
        info_ui_ && info_ui_->is_visible() && info_ui_->get_target_asset() == child;
    if (!opened_child_info) {
        SDL_Log("RoomEditor: failed to open bound child asset info; staying on current editor.");
        preserve_asset_info_parent_history_on_next_open_ = false;
        if (pushed_parent_history && !asset_info_parent_history_.empty()) {
            asset_info_parent_history_.pop_back();
        }
        if (previous_subview == AssetEditorSubview::Anchor ||
            previous_subview == AssetEditorSubview::Light ||
            previous_subview == AssetEditorSubview::OvalAnchor) {
            set_asset_editor_subview(previous_subview, false);
        }
        return false;
    }
    suppress_parent_asset_return_frames_ = std::max(suppress_parent_asset_return_frames_, 2);
    return true;
}

bool RoomEditor::try_return_to_parent_asset_info() {
    while (!asset_info_parent_history_.empty()) {
        const AssetInfoParentHistoryEntry entry = asset_info_parent_history_.back();
        asset_info_parent_history_.pop_back();
        Asset* parent = entry.parent;
        if (!parent || parent->dead || !parent->info || !is_asset_pointer_live(parent) || !asset_belongs_to_room(parent)) {
            continue;
        }
        preserve_asset_info_parent_history_on_next_open_ = true;
        open_asset_info_editor_for_asset(parent, false);
        if (entry.return_subview == AssetEditorSubview::Anchor ||
            entry.return_subview == AssetEditorSubview::Light ||
            entry.return_subview == AssetEditorSubview::OvalAnchor) {
            if (can_enter_asset_editor_subview(entry.return_subview)) {
                set_asset_editor_subview(entry.return_subview, false);
            } else if (entry.return_subview == AssetEditorSubview::Light &&
                       can_enter_asset_editor_subview(AssetEditorSubview::Anchor)) {
                set_asset_editor_subview(AssetEditorSubview::Anchor, false);
            }
        }
        return true;
    }
    return false;
}

Asset* RoomEditor::hit_test_asset(SDL_Point screen_point, SDL_Renderer* ) const {
    if (!assets_) return nullptr;
    const std::vector<Asset*>* source_assets = selection_asset_source();
    if (!source_assets || source_assets->empty()) {
        return nullptr;
    }

    const WarpedScreenGrid& cam = assets_->getView();
    const SDL_Point cursor_grid = grid_point_for_screen(cam, screen_point);

    const bool can_use_spatial = (source_assets == active_assets_) && ensure_spatial_index(cam);
    if (!can_use_spatial) {

        return hit_test_asset_fallback(cam, screen_point);
    }

    const std::vector<Asset*> candidates = gather_candidate_assets_for_point(screen_point);
    if (!candidates.empty()) {
        Asset* best = nullptr;
        int best_bottom = std::numeric_limits<int>::max();
        int best_top = std::numeric_limits<int>::max();
        int best_screen_y = std::numeric_limits<int>::max();
        int best_area = std::numeric_limits<int>::max();
        int best_dist2 = std::numeric_limits<int>::max();

        auto consider_candidate = [&](Asset* asset,
                                      const SDL_Rect& rect,
                                      int screen_y) {
            if (!asset) return;
            if (!asset_belongs_to_room(asset)) {
                return;
            }
            if (!asset_matches_selection_filter(asset)) {
                return;
            }
            if (!SDL_PointInRect(&screen_point, &rect)) {
                return;
            }
            const SDL_Point asset_grid = grid_point_for_asset(asset);
            const int dx = asset_grid.x - cursor_grid.x;
            const int dy = asset_grid.y - cursor_grid.y;
            const int dist2 = dx * dx + dy * dy;
            const int bottom = rect.y + rect.h;
            const int top = rect.y;
            const int area = rect.w * rect.h;
            const bool is_better =
                !best ||
                dist2 < best_dist2 ||
                (dist2 == best_dist2 && bottom < best_bottom) ||
                (dist2 == best_dist2 && bottom == best_bottom && top < best_top) ||
                (dist2 == best_dist2 && bottom == best_bottom && top == best_top && screen_y < best_screen_y) ||
                (dist2 == best_dist2 && bottom == best_bottom && top == best_top && screen_y == best_screen_y && area < best_area);
            if (is_better) {
                best = asset;
                best_bottom = bottom;
                best_top = top;
                best_screen_y = screen_y;
                best_dist2 = dist2;
                best_area = area;
            }
        };

        for (Asset* asset : candidates) {
            auto bc = asset_bounds_cache_.find(asset);
            if (bc == asset_bounds_cache_.end()) {
                continue;
            }
            const AssetSpatialEntry& entry = bc->second;
            consider_candidate(asset, entry.bounds, entry.screen_y);
        }

        if (best) {
            return best;
        }
    }

    return hit_test_asset_fallback(cam, screen_point);
}

void RoomEditor::mark_spatial_index_dirty() const {
    spatial_index_dirty_ = true;
    cached_camera_state_valid_ = false;
    asset_bounds_cache_.clear();
    spatial_grid_.clear();
}

bool RoomEditor::camera_state_changed(const WarpedScreenGrid& cam) const {
    if (!cached_camera_state_valid_) {
        return false;
    }
    const float scale = cam.get_scale();
    if (std::fabs(scale - cached_camera_scale_) > kCameraScaleEpsilon) {
        return true;
    }
    SDL_Point center = cam.get_screen_center();
    if (center.x != cached_camera_center_.x || center.y != cached_camera_center_.y) {
        return true;
    }
    const double zoom_percent = cam.get_zoom_percent();
    if (std::fabs(zoom_percent - cached_camera_zoom_percent_) > kCameraProjectionEpsilon) {
        return true;
    }
    const float pitch_deg = cam.current_pitch_degrees();
    if (std::fabs(static_cast<double>(pitch_deg) - static_cast<double>(cached_camera_pitch_deg_)) > kCameraProjectionEpsilon) {
        return true;
    }
    const double anchor_world_z = cam.current_anchor_world_z();
    if (std::fabs(anchor_world_z - cached_camera_anchor_world_z_) > kCameraProjectionEpsilon) {
        return true;
    }

    return false;
}

bool RoomEditor::ensure_spatial_index(const WarpedScreenGrid& cam) const {
    if (!active_assets_) {
        return false;
    }

    if (camera_state_changed(cam)) {
        mark_spatial_index_dirty();
    }

    if (spatial_index_dirty_) {
        rebuild_spatial_index(cam);
    }

    return !spatial_index_dirty_;
}

bool RoomEditor::compute_asset_render_object_bounds(const WarpedScreenGrid& cam,
                                                    Asset* asset,
                                                    SDL_Rect& out_rect) const {
    if (!asset) {
        return false;
    }

    if (const auto& tiling = asset->tiling_info(); tiling && tiling->is_valid()) {
        const float left = static_cast<float>(tiling->coverage.x);
        const float right = static_cast<float>(tiling->coverage.x + tiling->coverage.w);
        const float top = static_cast<float>(tiling->coverage.y);
        const float bottom = static_cast<float>(tiling->coverage.y + tiling->coverage.h);
        SDL_FPoint p0{};
        SDL_FPoint p1{};
        SDL_FPoint p2{};
        SDL_FPoint p3{};
        if (cam.project_world_point(SDL_FPoint{left, 0.0f}, top, p0) &&
            cam.project_world_point(SDL_FPoint{right, 0.0f}, top, p1) &&
            cam.project_world_point(SDL_FPoint{left, 0.0f}, bottom, p2) &&
            cam.project_world_point(SDL_FPoint{right, 0.0f}, bottom, p3) &&
            std::isfinite(p0.x) && std::isfinite(p0.y) &&
            std::isfinite(p1.x) && std::isfinite(p1.y) &&
            std::isfinite(p2.x) && std::isfinite(p2.y) &&
            std::isfinite(p3.x) && std::isfinite(p3.y)) {
            const float min_x = std::min(std::min(p0.x, p1.x), std::min(p2.x, p3.x));
            const float max_x = std::max(std::max(p0.x, p1.x), std::max(p2.x, p3.x));
            const float min_y = std::min(std::min(p0.y, p1.y), std::min(p2.y, p3.y));
            const float max_y = std::max(std::max(p0.y, p1.y), std::max(p2.y, p3.y));
            if (max_x > min_x && max_y > min_y) {
                const int left_px = static_cast<int>(std::floor(min_x));
                const int top_px = static_cast<int>(std::floor(min_y));
                const int right_px = static_cast<int>(std::ceil(max_x));
                const int bottom_px = static_cast<int>(std::ceil(max_y));
                out_rect = SDL_Rect{
                    left_px,
                    top_px,
                    std::max(1, right_px - left_px),
                    std::max(1, bottom_px - top_px)};
                if (screen_rect_is_reasonable(out_rect)) {
                    return true;
                }
            }
        }
    }

    RenderObject obj{};
    if (!render_build::build_direct_asset_render_object(asset, obj)) {
        return false;
    }

    float min_x = std::numeric_limits<float>::infinity();
    float min_y = std::numeric_limits<float>::infinity();
    float max_x = -std::numeric_limits<float>::infinity();
    float max_y = -std::numeric_limits<float>::infinity();
    SDL_FPoint base_screen{};
    bool have_bounds = false;
    const float base_depth = static_cast<float>(asset->world_z());
    const auto* gp = cam.grid_point_for_asset(asset);
    const float perspective_scale =
        (gp && std::isfinite(gp->perspective_scale()) && gp->perspective_scale() > 0.0f)
            ? gp->perspective_scale()
            : 1.0f;

    if (obj.screen_rect.w > 0 && obj.screen_rect.h > 0) {
        const float object_world_z = base_depth + obj.world_z_offset;
        render_projection::ProjectedSpriteFrame projection{};
        if (build_render_object_projection(cam, obj, perspective_scale, object_world_z, projection)) {
            const float obj_min_x = std::min(std::min(projection.screen_tl.x, projection.screen_tr.x),
                                             std::min(projection.screen_bl.x, projection.screen_br.x));
            const float obj_max_x = std::max(std::max(projection.screen_tl.x, projection.screen_tr.x),
                                             std::max(projection.screen_bl.x, projection.screen_br.x));
            const float obj_min_y = std::min(std::min(projection.screen_tl.y, projection.screen_tr.y),
                                             std::min(projection.screen_bl.y, projection.screen_br.y));
            const float obj_max_y = std::max(std::max(projection.screen_tl.y, projection.screen_tr.y),
                                             std::max(projection.screen_bl.y, projection.screen_br.y));
            if (std::isfinite(obj_min_x) && std::isfinite(obj_max_x) &&
                std::isfinite(obj_min_y) && std::isfinite(obj_max_y) &&
                obj_max_x > obj_min_x && obj_max_y > obj_min_y) {
                min_x = std::min(min_x, obj_min_x);
                min_y = std::min(min_y, obj_min_y);
                max_x = std::max(max_x, obj_max_x);
                max_y = std::max(max_y, obj_max_y);
                have_bounds = true;
            }
        }

        if (!have_bounds) {
            SDL_FPoint world_point{
                static_cast<float>(obj.screen_rect.x),
                static_cast<float>(obj.screen_rect.y)
            };
            if (!cam.project_world_point(world_point, object_world_z, base_screen)) {
                return false;
            }
            const float half_width = static_cast<float>(obj.screen_rect.w) * 0.5f;
            const float height = static_cast<float>(obj.screen_rect.h);
            if (!std::isfinite(base_screen.x) || !std::isfinite(base_screen.y) ||
                !std::isfinite(half_width) || !std::isfinite(height)) {
                return false;
            }

            const float left = base_screen.x - half_width;
            const float right = base_screen.x + half_width;
            const float top = base_screen.y - height;
            const float bottom = base_screen.y;
            if (!std::isfinite(left) || !std::isfinite(right) ||
                !std::isfinite(top) || !std::isfinite(bottom)) {
                return false;
            }

            min_x = left;
            min_y = top;
            max_x = right;
            max_y = bottom;
            have_bounds = true;
        }
    }

    if (!have_bounds) {
        return false;
    }

    const int left = static_cast<int>(std::floor(min_x));
    const int top = static_cast<int>(std::floor(min_y));
    const int right = static_cast<int>(std::ceil(max_x));
    const int bottom = static_cast<int>(std::ceil(max_y));

    const int width = std::max(1, right - left);
    const int height = std::max(1, bottom - top);

    out_rect = SDL_Rect{left, top, width, height};
    return screen_rect_is_reasonable(out_rect);
}

bool RoomEditor::compute_asset_screen_bounds(const WarpedScreenGrid& cam,
                                             Asset* asset,
                                             SDL_Rect& out_rect,
                                             int& out_screen_y) const {
    if (!asset) {
        return false;
    }

    auto* gp = cam.grid_point_for_asset(asset);
    if (!gp || !gp->is_on_screen()) {
        return false;
    }

    if (gp->perspective_scale() <= 0.0f || gp->vertical_scale() <= 0.0f) {
        return false;
    }

    if (compute_asset_render_object_bounds(cam, asset, out_rect)) {
        out_screen_y = static_cast<int>(std::lround(gp->screen_position().y));
        return true;
    }

    SDL_Texture* tex = asset->get_current_frame();

    int fw = asset->cached_w;
    int fh = asset->cached_h;
    if ((fw == 0 || fh == 0) && tex) {
        float fwf = 0.0f;
        float fhf = 0.0f;
        if (SDL_GetTextureSize(tex, &fwf, &fhf)) {
            fw = static_cast<int>(std::lround(fwf));
            fh = static_cast<int>(std::lround(fhf));
        }
        if (asset->cached_w == 0) asset->cached_w = fw;
        if (asset->cached_h == 0) asset->cached_h = fh;
    }
    if ((fw == 0 || fh == 0) && asset->info) {
        fw = asset->info->original_canvas_width;
        fh = asset->info->original_canvas_height;
        if (asset->cached_w == 0) asset->cached_w = fw;
        if (asset->cached_h == 0) asset->cached_h = fh;
    }
    if (fw <= 0 || fh <= 0) return false;

    const float runtime_width = asset->runtime_width_px();
    const float runtime_height = asset->runtime_height_px();
    const float fallback_runtime_scale = asset->runtime_resolved_scale();

    float scaled_fw = runtime_width;
    float scaled_fh = runtime_height;
    if (!(scaled_fw > 0.0f) || !(scaled_fh > 0.0f)) {
        scaled_fw = static_cast<float>(fw) * fallback_runtime_scale;
        scaled_fh = static_cast<float>(fh) * fallback_runtime_scale;
    }

    const float perspective_scale = gp->perspective_scale();
    const float vertical_scale = gp->vertical_scale();
    const float screen_width = scaled_fw * perspective_scale;
    const float screen_height = scaled_fh * perspective_scale * vertical_scale;
    if (!std::isfinite(screen_width) || !std::isfinite(screen_height) ||
        screen_width <= 0.0f || screen_height <= 0.0f) {
        return false;
    }

    const int sw = std::max(1, static_cast<int>(std::lround(static_cast<double>(screen_width))));
    const int sh = std::max(1, static_cast<int>(std::lround(static_cast<double>(screen_height))));

    const SDL_FPoint screen_pos = gp->screen_position();
    const float center_x = screen_pos.x;
    const float center_y = screen_pos.y;
    const int   left     = static_cast<int>(std::lround(center_x - static_cast<float>(sw) * 0.5f));
    const int   top      = static_cast<int>(std::lround(center_y)) - sh;
    out_rect             = SDL_Rect{left, top, sw, sh};
    out_screen_y         = static_cast<int>(std::lround(center_y));
    return screen_rect_is_reasonable(out_rect);
}

void RoomEditor::rebuild_spatial_index(const WarpedScreenGrid& cam) const {
    asset_bounds_cache_.clear();
    spatial_grid_.clear();

    if (active_assets_) {
        for (Asset* asset : *active_assets_) {
            if (!asset) continue;
            SDL_Rect rect{0, 0, 0, 0};
            int screen_y = 0;
            if (!compute_asset_screen_bounds(cam, asset, rect, screen_y)) {
                continue;
            }
            insert_asset_entry(asset, rect, screen_y);
        }
    }

    cached_camera_scale_ = cam.get_scale();
    cached_camera_center_ = cam.get_screen_center();
    cached_camera_zoom_percent_ = cam.get_zoom_percent();
    cached_camera_pitch_deg_ = cam.current_pitch_degrees();
    cached_camera_anchor_world_z_ = cam.current_anchor_world_z();

    cached_camera_state_valid_ = true;
    spatial_index_dirty_ = false;
}

void RoomEditor::insert_asset_entry(Asset* asset, const SDL_Rect& rect, int screen_y) const {
    if (!asset || !screen_rect_is_reasonable(rect)) {
        return;
    }

    AssetSpatialEntry entry;
    entry.bounds = rect;
    entry.screen_y = screen_y;

    const std::int64_t right_px = static_cast<std::int64_t>(rect.x) + static_cast<std::int64_t>(rect.w) - 1;
    const std::int64_t bottom_px = static_cast<std::int64_t>(rect.y) + static_cast<std::int64_t>(rect.h) - 1;
    const std::int64_t left = floor_div_i64(rect.x, kSpatialCellSize);
    const std::int64_t right = floor_div_i64(right_px, kSpatialCellSize);
    const std::int64_t top = floor_div_i64(rect.y, kSpatialCellSize);
    const std::int64_t bottom = floor_div_i64(bottom_px, kSpatialCellSize);
    if (right < left || bottom < top) {
        return;
    }

    const std::int64_t cell_count_x = right - left + 1;
    const std::int64_t cell_count_y = bottom - top + 1;
    if (cell_count_x <= 0 || cell_count_y <= 0) {
        return;
    }
    const std::int64_t total_cells = cell_count_x * cell_count_y;
    if (total_cells > kMaxSpatialCellsPerAsset) {
        return;
    }

    for (std::int64_t cx = left; cx <= right; ++cx) {
        if (cx < std::numeric_limits<int>::min() || cx > std::numeric_limits<int>::max()) {
            continue;
        }
        for (std::int64_t cy = top; cy <= bottom; ++cy) {
            if (cy < std::numeric_limits<int>::min() || cy > std::numeric_limits<int>::max()) {
                continue;
            }
            add_asset_to_cell(asset, static_cast<int>(cx), static_cast<int>(cy), entry.cells);
        }
    }
    if (entry.cells.empty()) {
        return;
    }

    asset_bounds_cache_[asset] = std::move(entry);
}

void RoomEditor::add_asset_to_cell(Asset* asset, int cell_x, int cell_y, std::vector<int64_t>& cell_keys) const {
    if (!asset) return;
    const int64_t key = make_cell_key(cell_x, cell_y);
    auto& bucket = spatial_grid_[key];
    bucket.push_back(asset);
    cell_keys.push_back(key);
}

void RoomEditor::remove_asset_from_spatial_index(Asset* asset) const {
    if (!asset) return;
    auto it = asset_bounds_cache_.find(asset);
    if (it == asset_bounds_cache_.end()) {
        return;
    }
    const std::vector<int64_t> cells = it->second.cells;
    for (int64_t key : cells) {
        auto grid_it = spatial_grid_.find(key);
        if (grid_it == spatial_grid_.end()) {
            continue;
        }
        auto& bucket = grid_it->second;
        bucket.erase(std::remove(bucket.begin(), bucket.end(), asset), bucket.end());
        if (bucket.empty()) {
            spatial_grid_.erase(grid_it);
        }
    }
    asset_bounds_cache_.erase(it);
}

void RoomEditor::refresh_asset_spatial_entry(const WarpedScreenGrid& cam, Asset* asset) const {
    if (!asset) return;
    if (spatial_index_dirty_ || !cached_camera_state_valid_) {
        return;
    }

    remove_asset_from_spatial_index(asset);

    SDL_Rect rect{0, 0, 0, 0};
    int screen_y = 0;
    if (!compute_asset_screen_bounds(cam, asset, rect, screen_y)) {
        return;
    }
    insert_asset_entry(asset, rect, screen_y);
}

void RoomEditor::refresh_spatial_entries_for_dragged_assets() {
    if (!assets_) {
        return;
    }
    const WarpedScreenGrid& cam = assets_->getView();
    if (spatial_index_dirty_ || !cached_camera_state_valid_) {
        return;
    }

    for (const auto& state : drag_states_) {
        if (!state.asset) continue;
        refresh_asset_spatial_entry(cam, state.asset);
    }
}

void RoomEditor::sync_dragged_assets_immediately() {
    bool moved_any = false;
    for (auto& state : drag_states_) {
        Asset* asset = state.asset;
        if (!asset) {
            continue;
        }
        SDL_Point current{asset->world_x(), asset->world_z()};
        if (current.x == state.last_synced_pos.x && current.y == state.last_synced_pos.y) {
            continue;
        }
        asset->clear_grid_residency_cache();
        asset->sync_transform_to_position();
        asset->mark_composite_dirty();
        if (assets_) {
            const world::GridPoint old_pos = world::GridPoint::make_virtual(
                state.last_synced_pos.x,
                0,
                state.last_synced_pos.y,
                asset->grid_resolution);
            const world::GridPoint new_pos = world::GridPoint::make_virtual(
                current.x,
                0,
                current.y,
                asset->grid_resolution);
            (void)assets_->world_grid().move_asset(asset, old_pos, new_pos);
            if (asset->info && asset->info->tillable) {
                if (auto tiling = assets_->compute_tiling_for_asset(asset); tiling && tiling->is_valid()) {
                    asset->set_tiling_info(*tiling);
                } else {
                    asset->set_tiling_info(std::nullopt);
                }
            }
        }
        state.last_synced_pos = current;
        moved_any = true;
    }
    if (moved_any && assets_) {
        assets_->mark_active_assets_dirty();
    }
}

std::vector<Asset*> RoomEditor::gather_candidate_assets_for_point(SDL_Point screen_point) const {
    std::vector<Asset*> result;
    if (spatial_grid_.empty()) {
        return result;
    }

    const int cell_x = floor_div(screen_point.x, kSpatialCellSize);
    const int cell_y = floor_div(screen_point.y, kSpatialCellSize);
    std::unordered_set<Asset*> unique;
    unique.reserve(16);

    for (int dx = -1; dx <= 1; ++dx) {
        for (int dy = -1; dy <= 1; ++dy) {
            const int64_t key = make_cell_key(cell_x + dx, cell_y + dy);
            auto it = spatial_grid_.find(key);
            if (it == spatial_grid_.end()) {
                continue;
            }
            for (Asset* asset : it->second) {
                if (!asset) continue;
                if (unique.insert(asset).second) {
                    result.push_back(asset);
                }
            }
        }
    }

    return result;
}

Asset* RoomEditor::hit_test_asset_fallback(const WarpedScreenGrid& cam, SDL_Point screen_point) const {
    const std::vector<Asset*>* source_assets = selection_asset_source();
    if (!source_assets || source_assets->empty()) {
        return nullptr;
    }

    const SDL_Point cursor_grid = grid_point_for_screen(cam, screen_point);
    Asset* best = nullptr;
    int best_bottom = std::numeric_limits<int>::max();
    int best_top = std::numeric_limits<int>::max();
    int best_screen_y = std::numeric_limits<int>::max();
    int best_area = std::numeric_limits<int>::max();
    int best_dist2 = std::numeric_limits<int>::max();

    auto consider_candidate = [&](Asset* asset,
                                  const SDL_Rect& rect,
                                  int screen_y) {
        if (!asset) return;
        if (!asset_belongs_to_room(asset)) {
            return;
        }
        if (!asset_matches_selection_filter(asset)) {
            return;
        }
        if (!SDL_PointInRect(&screen_point, &rect)) {
            return;
        }
        const SDL_Point asset_grid = grid_point_for_asset(asset);
        const int dx = asset_grid.x - cursor_grid.x;
        const int dy = asset_grid.y - cursor_grid.y;
        const int dist2 = dx * dx + dy * dy;
        const int bottom = rect.y + rect.h;
        const int top = rect.y;
        const int area = rect.w * rect.h;
        const bool is_better =
            !best ||
            dist2 < best_dist2 ||
            (dist2 == best_dist2 && bottom < best_bottom) ||
            (dist2 == best_dist2 && bottom == best_bottom && top < best_top) ||
            (dist2 == best_dist2 && bottom == best_bottom && top == best_top && screen_y < best_screen_y) ||
            (dist2 == best_dist2 && bottom == best_bottom && top == best_top && screen_y == best_screen_y && area < best_area);
        if (is_better) {
            best = asset;
            best_bottom = bottom;
            best_top = top;
            best_screen_y = screen_y;
            best_dist2 = dist2;
            best_area = area;
        }
};

    for (Asset* asset : *source_assets) {
        if (!asset) continue;
        if (!asset_belongs_to_room(asset)) {
            continue;
        }
        if (!asset_matches_selection_filter(asset)) {
            continue;
        }

        SDL_Rect rect{0, 0, 0, 0};
        int screen_y = 0;
        if (!compute_asset_screen_bounds(cam, asset, rect, screen_y)) {
            continue;
        }

        consider_candidate(asset, rect, screen_y);
    }

    return best;
}

void RoomEditor::update_hover_state(Asset* hit) {
    if (pointer_queries_suspended_) {
        if (hovered_asset_) {
            hovered_asset_ = nullptr;
            hover_miss_frames_ = 3;
            mark_highlight_dirty();
        }
        return;
    }

    Asset* previous = hovered_asset_;
    if (hit) {
        hovered_asset_ = hit;
        hover_miss_frames_ = 0;
    } else {
        if (++hover_miss_frames_ >= 3) {
            hovered_asset_ = nullptr;
            hover_miss_frames_ = 3;
        }
    }
    if (hovered_asset_ != previous) {
        mark_highlight_dirty();
    }
}

Room* RoomEditor::find_geometry_room_at_point(SDL_Point world_point) const {
    if (!assets_) {
        return nullptr;
    }
    Room* best = nullptr;
    int best_layer = std::numeric_limits<int>::min();
    for (Room* room : assets_->rooms()) {
        if (!room || !room->room_area) continue;
        if (!room->room_area->contains_point(world_point)) continue;
        if (!best || room->layer >= best_layer) {
            best = room;
            best_layer = room->layer;
        }
    }
    return best;
}

bool RoomEditor::geometry_room_is_trail(const Room* room) const {
    if (!room) return false;
    std::string lowered = room->type;
    std::transform(lowered.begin(), lowered.end(), lowered.begin(), [](unsigned char ch) {
        return static_cast<char>(std::tolower(ch));
    });
    return lowered == "trail";
}

RoomEditor::GeometryHandle RoomEditor::hit_test_geometry_handle(Room* room, SDL_Point world_point) const {
    if (!room || !room->room_area) return GeometryHandle::None;
    const auto& root = room->assets_data();
    const bool is_circle = [&]() {
        std::string g = root.value("geometry", std::string{"square"});
        std::transform(g.begin(), g.end(), g.begin(), [](unsigned char ch) { return static_cast<char>(std::tolower(ch)); });
        return g == "circle";
    }();
    const auto default_range = vibble::weighted_range::make_legacy_uniform(1, 1);
    vibble::weighted_range::WeightedIntRange width_range = default_range;
    if (root.contains("width")) {
        width_range = read_weighted_range_field(root, "width", default_range);
    } else if (root.contains("min_width") || root.contains("max_width")) {
        width_range = read_weighted_range_legacy_pair(root, "min_width", "max_width", default_range);
    } else if (root.contains("min_radius") || root.contains("max_radius") || root.contains("radius")) {
        width_range = read_weighted_range_legacy_pair(root, "min_radius", "max_radius", default_range);
    }
    auto [min_w, max_w] = range_bounds(width_range);
    min_w = std::max(1, min_w);
    max_w = std::max(min_w, max_w);
    const SDL_Point c = room->room_area->get_center();
    const double dx = static_cast<double>(world_point.x - c.x);
    const double dy = static_cast<double>(world_point.y - c.y);
    const double dist = std::hypot(dx, dy);
    const double metric = is_circle ? dist : std::max(std::abs(dx), std::abs(dy));
    const double min_edge = static_cast<double>(min_w) * 0.5;
    const double max_edge = static_cast<double>(max_w) * 0.5;
    const double tol = std::max(12.0, static_cast<double>(max_w) * 0.05);

    if (std::abs(metric - max_edge) <= tol) return GeometryHandle::Max;
    if (std::abs(metric - min_edge) <= tol) return GeometryHandle::Min;
    return GeometryHandle::None;
}

bool RoomEditor::is_point_between_geometry_bounds(Room* room, SDL_Point world_point) const {
    if (!room || !room->room_area) return false;
    const auto& root = room->assets_data();
    const bool is_circle = [&]() {
        std::string g = root.value("geometry", std::string{"square"});
        std::transform(g.begin(), g.end(), g.begin(), [](unsigned char ch) { return static_cast<char>(std::tolower(ch)); });
        return g == "circle";
    }();
    const auto default_range = vibble::weighted_range::make_legacy_uniform(1, 1);
    vibble::weighted_range::WeightedIntRange width_range = default_range;
    if (root.contains("width")) {
        width_range = read_weighted_range_field(root, "width", default_range);
    } else if (root.contains("min_width") || root.contains("max_width")) {
        width_range = read_weighted_range_legacy_pair(root, "min_width", "max_width", default_range);
    } else if (root.contains("min_radius") || root.contains("max_radius") || root.contains("radius")) {
        width_range = read_weighted_range_legacy_pair(root, "min_radius", "max_radius", default_range);
    }
    auto [min_w, max_w] = range_bounds(width_range);
    min_w = std::max(1, min_w);
    max_w = std::max(min_w, max_w);
    if (geometry_room_is_trail(room)) {
        if (root.contains("height")) {
            const auto height_range = read_weighted_range_field(root, "height", default_range);
            auto [min_h, max_h] = range_bounds(height_range);
            max_w = std::max(max_w, std::max(min_h, max_h));
        } else {
            max_w = std::max(max_w, root.value("max_height", max_w));
        }
    }

    const SDL_Point c = room->room_area->get_center();
    const double dx = static_cast<double>(world_point.x - c.x);
    const double dy = static_cast<double>(world_point.y - c.y);
    const double metric = is_circle ? std::hypot(dx, dy) : std::max(std::abs(dx), std::abs(dy));
    return metric >= static_cast<double>(min_w) * 0.5 && metric <= static_cast<double>(max_w) * 0.5;
}

void RoomEditor::clear_geometry_selection() {
    if (geometry_drag_pending_dirty_ && selected_geometry_room_) {
        mark_geometry_dirty(selected_geometry_room_);
    }
    geometry_drag_pending_dirty_ = false;
    hovered_geometry_room_ = nullptr;
    selected_geometry_room_ = nullptr;
    geometry_drag_handle_ = GeometryHandle::None;
}

void RoomEditor::mark_geometry_dirty(Room* room) {
    if (!room) return;
    room->mark_dirty();
    mark_spatial_index_dirty();
    if (mark_map_dirty_callback_) {
        mark_map_dirty_callback_(devmode::core::DevSaveCoordinator::Priority::Debounced);
    }
}

bool RoomEditor::regenerate_geometry(Room* room) {
    if (!room || !room->room_area || !assets_) return false;
    auto& root = room->assets_data();
    const auto default_range = vibble::weighted_range::make_legacy_uniform(1, 1);
    vibble::weighted_range::WeightedIntRange width_range = root.contains("width")
        ? read_weighted_range_field(root, "width", default_range)
        : (root.contains("min_width") || root.contains("max_width")
               ? read_weighted_range_legacy_pair(root, "min_width", "max_width", default_range)
               : default_range);
    vibble::weighted_range::WeightedIntRange height_range = root.contains("height")
        ? read_weighted_range_field(root, "height", width_range)
        : (root.contains("min_height") || root.contains("max_height")
               ? read_weighted_range_legacy_pair(root, "min_height", "max_height", width_range)
               : width_range);
    if (root.contains("geometry")) {
        std::string g = root.value("geometry", std::string{"square"});
        std::transform(g.begin(), g.end(), g.begin(), [](unsigned char ch) { return static_cast<char>(std::tolower(ch)); });
        if (g == "circle") {
            height_range = width_range;
        }
    }
    std::mt19937 rng(std::random_device{}());
    const int chosen_w = std::max(1, resolve_weighted_dimension(width_range, rng));
    const int chosen_h = std::max(1, resolve_weighted_dimension(height_range, rng));

    constexpr int kRegeneratedRoomEdgeSmoothness = 0;
    std::string geometry = root.value("geometry", std::string{"Square"});
    if (!geometry.empty()) geometry[0] = static_cast<char>(std::toupper(static_cast<unsigned char>(geometry[0])));
    const SDL_Point center = room->room_area->get_center();
    const int map_w = std::max(1, std::abs(center.x) * 2 + chosen_w * 4);
    const int map_h = std::max(1, std::abs(center.y) * 2 + chosen_h * 4);
    try {
        room->room_area = std::make_unique<Area>(room->room_name,
                                                 center,
                                                 chosen_w,
                                                 chosen_h,
                                                 geometry,
                                                 kRegeneratedRoomEdgeSmoothness,
                                                 map_w,
                                                 map_h,
                                                 room->room_area->resolution());
        room->room_area->set_type(room->type);
    } catch (...) {
        return false;
    }

    std::vector<Asset*> to_delete;
    to_delete.reserve(assets_->all.size());
    for (Asset* asset : assets_->all) {
        if (!asset || asset->dead || asset == assets_->player) continue;
        if (asset->owning_room_name() == room->room_name) {
            to_delete.push_back(asset);
            continue;
        }
        if (room->room_area->contains_point(asset->world_xz_point())) {
            to_delete.push_back(asset);
        }
    }
    if (!to_delete.empty()) {
        auto batch = assets_->begin_world_mutation_batch();
        for (Asset* asset : to_delete) {
            batch.mark_for_deletion(asset);
        }
        (void)batch.commit();
    }

    Room* previous = current_room_;
    current_room_ = room;
    regenerate_current_room();
    current_room_ = previous;

    mark_geometry_dirty(room);
    return true;
}

std::optional<std::string> RoomEditor::find_room_area_at_point(SDL_Point world_point) {
    if (!current_room_) {
        return std::nullopt;
    }

    nlohmann::json& root = current_room_->assets_data();

    struct AreaMetadata {
        int z = 0;
        bool visible = true;
        std::size_t order = 0;
};

    std::unordered_map<std::string, AreaMetadata> metadata;
    std::size_t order_counter = 0;

    if (root.is_object() && root.contains("areas") && root["areas"].is_array()) {
        for (const auto& entry : root["areas"]) {
            if (!entry.is_object()) {
                ++order_counter;
                continue;
            }

            std::string name = entry.value("name", std::string{});
            if (name.empty()) {
                ++order_counter;
                continue;
            }

            AreaMetadata data;
            data.z = entry.value("z", 0);
            data.visible = !(entry.contains("visible") && entry["visible"].is_boolean() && !entry["visible"].get<bool>());
            data.order = order_counter;
            metadata.insert_or_assign(name, data);

            ++order_counter;
        }
    }

    std::size_t fallback_order = order_counter;
    std::optional<std::string> best_name;
    int best_z = std::numeric_limits<int>::min();
    std::size_t best_order = 0;
    bool have_best_order = false;

    auto consider_area = [&](const std::string& name, const Area* area) {
        if (!area) {
            return;
        }

        auto it = metadata.find(name);
        AreaMetadata info;
        if (it != metadata.end()) {
            info = it->second;
        } else {
            info.order = fallback_order++;
        }

        if (!info.visible) {
            return;
        }

        if (!area->contains_point(world_point)) {
            return;
        }

        bool take = false;
        if (!best_name) {
            take = true;
        } else if (info.z > best_z) {
            take = true;
        } else if (info.z == best_z) {
            if (!have_best_order || info.order >= best_order) {
                take = true;
            }
        }

        if (take) {
            best_name = name;
            best_z = info.z;
            best_order = info.order;
            have_best_order = true;
        }
};

    for (const auto& named : current_room_->areas) {
        if (named.name.empty()) {
            continue;
        }
        consider_area(named.name, named.area.get());
    }

    return best_name;
}

void RoomEditor::handle_click(const Input& input) {
    if (!input_) return;

    SDL_Point world_mouse = snapped_cursor_world_;
    SDL_Point screen_mouse{input_->getX(), input_->getY()};

    if (suppress_next_left_click_) {
        if (input_->wasClicked(Input::LEFT)) {
            suppress_next_left_click_ = false;
            click_buffer_frames_ = 0;
            return;
        }
    }

    const bool shift_modifier =
        is_shift_key_down() ||
        input.isScancodeDown(SDL_SCANCODE_LSHIFT) ||
        input.isScancodeDown(SDL_SCANCODE_RSHIFT);
    const bool selection_allowed = asset_selection_allowed_now();

    if (input_->wasClicked(Input::RIGHT)) {
        if (rclick_buffer_frames_ > 0) {
            --rclick_buffer_frames_;
            return;
        }
        rclick_buffer_frames_ = 2;

        auto open_library_at = [&](const SDL_Point& point) {
            begin_library_placement(point);
            open_asset_library();
            if (!is_asset_library_open()) {
                clear_library_placement();
            }
        };

        Asset* target = nullptr;
        if (selection_allowed && shift_modifier) {
            if (hovered_asset_ && asset_belongs_to_room(hovered_asset_)) {
                target = hovered_asset_;
            }
            if (!target) {
                target = hit_test_asset_anchor(screen_mouse, kShiftAnchorSelectRadiusPx);
            }
            if (!target) {
                target = hit_test_asset(screen_mouse, nullptr);
            }
        }
        if (target) {
            if (shift_modifier) {
                select_asset_or_group(target);
            }
            if (spawn_group_panel_) {
                spawn_group_panel_->close();
                spawn_group_panel_->set_visible(false);
            }
            clear_active_spawn_group_target();
            open_asset_info_editor_for_asset(target, false);
            return;
        }

        if (selection_allowed && shift_modifier) {
            if (auto boundary_hit = hit_test_dynamic_boundary_sprite(screen_mouse)) {
                open_asset_info_for_dynamic_boundary(*boundary_hit);
                return;
            }
        }

        bool inside_room = true;
        if (current_room_ && current_room_->room_area) {
            inside_room = current_room_->room_area->contains_point(world_mouse);
        }
        if (inside_room) {
            open_library_at(world_mouse);
        } else {
            clear_library_placement();
            open_asset_library();
        }
        return;
    } else {
        rclick_buffer_frames_ = 0;
    }

    if (!input_->wasClicked(Input::LEFT)) {
        click_buffer_frames_ = 0;
        return;
    }

    click_buffer_frames_ = std::max(0, click_buffer_frames_ - 1);

    const bool asset_info_open =
        is_asset_info_modal_blocking() || (info_ui_ && info_ui_->is_visible());
    const bool floating_modal_open = DockManager::instance().active_panel() != nullptr;

    if (asset_info_open || floating_modal_open) {
        return;
    }
    if (!selection_allowed) {
        return;
    }

    if (!selected_assets_.empty()) {
        if (!selected_asset_within_interaction_radius(screen_mouse)) {
            clear_selection();
        }
        return;
    }

    if (selected_dynamic_boundary_proxy_) {
        if (!hit_test_dynamic_boundary_sprite(screen_mouse)) {
            clear_dynamic_boundary_proxy_selection();
            mark_highlight_dirty();
        }
        return;
    }

    if (!shift_modifier) {
        return;
    }

    Asset* clicked_asset = nullptr;

    clicked_asset = hit_test_asset_anchor(screen_mouse, kShiftAnchorSelectRadiusPx);
    if (!clicked_asset) {
        clicked_asset = hit_test_asset(screen_mouse, nullptr);
    }

    if (clicked_asset) {
        select_asset_or_group(clicked_asset);
    } else {
        if (auto boundary_hit = hit_test_dynamic_boundary_sprite(screen_mouse)) {
            clear_selection();
            selected_dynamic_boundary_proxy_ = boundary_hit->key;
            hovered_dynamic_boundary_proxy_ = boundary_hit->key;
            mark_highlight_dirty();
            return;
        }
    }
}

nlohmann::json* RoomEditor::find_area_entry_json(Room* room, const std::string& area_name) const {
    if (!room) return nullptr;
    nlohmann::json& root = room->assets_data();
    if (root.is_object() && root.contains("areas") && root["areas"].is_array()) {
        for (auto& entry : root["areas"]) {
            if (!entry.is_object()) continue;
            if (entry.value("name", std::string{}) == area_name) {
                return &entry;
            }
        }
    }
    return nullptr;
}

void RoomEditor::ensure_area_anchor_spawn_entry(Room* room, const std::string& area_name) {
    if (!room) return;
    nlohmann::json& root = room->assets_data();
    auto& groups = ensure_spawn_groups_array(root);
    nlohmann::json* existing = nullptr;
    for (auto& entry : groups) {
        if (!entry.is_object()) continue;
        const bool linked = entry.value("link_to_area", false);
        const std::string linked_area = entry.value("linked_area", std::string{});
        const std::string display = entry.value("display_name", std::string{});
        if ((linked && linked_area == area_name) || (!linked && display == area_name)) {
            existing = &entry;
            break;
        }
    }
    const int default_resolution = room->map_grid_settings().grid_resolution;
    int width = 0, height = 0;
    if (room->room_area) {
        auto b = room->room_area->get_bounds();
        width = std::max(1, std::get<2>(b) - std::get<0>(b));
        height = std::max(1, std::get<3>(b) - std::get<1>(b));
    }
    if (!existing) {
        nlohmann::json entry = nlohmann::json::object();
        entry["display_name"] = area_name;
        entry["position"] = "Exact";
        entry["dx"] = 0;
        entry["dz"] = 0;
        if (width > 0) entry["origional_width"] = width;
        if (height > 0) entry["origional_height"] = height;
        entry["link_to_area"] = true;
        entry["linked_area"] = area_name;
        devmode::spawn::ensure_spawn_group_entry_defaults(entry, area_name, default_resolution);
        groups.push_back(std::move(entry));
        save_current_room_assets_json();
    } else {
        devmode::spawn::ensure_spawn_group_entry_defaults(*existing, area_name, default_resolution);
        if (existing->value("position", std::string{"Random"}) != std::string{"Exact"}) {
            (*existing)["position"] = "Exact";
        }
        if (width > 0 && !existing->contains("origional_width")) (*existing)["origional_width"] = width;
        if (height > 0 && !existing->contains("origional_height")) (*existing)["origional_height"] = height;
        if (!existing->value("link_to_area", false)) (*existing)["link_to_area"] = true;
        if (existing->value("linked_area", std::string{}) != area_name) (*existing)["linked_area"] = area_name;
        save_current_room_assets_json();
    }
}

void RoomEditor::begin_area_drag_session(const std::string& area_name, const SDL_Point& world_mouse) {
    area_dragging_ = true;
    area_drag_moved_ = false;
    area_drag_name_ = area_name;
    area_drag_last_world_ = world_mouse;
    area_drag_start_world_ = world_mouse;
    MapGridSettings map_settings = current_room_ ? current_room_->map_grid_settings() : MapGridSettings::defaults();
    map_settings.clamp();
    area_drag_resolution_ = snap_to_grid_enabled_
        ? vibble::grid::clamp_resolution(map_settings.grid_resolution)
        : 0;

    ensure_area_anchor_spawn_entry(current_room_, area_drag_name_);
}

void RoomEditor::update_area_drag_session(const SDL_Point& world_mouse) {
    area_drag_last_world_ = world_mouse;
    area_drag_moved_ = true;
}

void RoomEditor::finalize_area_drag_session() {
    if (!current_room_ || area_drag_name_.empty()) {
        area_dragging_ = false;
        area_drag_moved_ = false;
        return;
    }

    vibble::grid::Grid& grid_service = vibble::grid::global_grid();
    SDL_Point snapped = area_drag_last_world_;
    if (snap_to_grid_enabled_ && area_drag_resolution_ > 0) {
        snapped = grid_service.snap_to_vertex(area_drag_last_world_, area_drag_resolution_);
    }

    SDL_Point center{0, 0};
    if (current_room_->room_area) {
        auto c = current_room_->room_area->get_center();
        center.x = c.x; center.y = c.y;
    }
    const int dx = snapped.x - center.x;
    const int dy = snapped.y - center.y;

    if (nlohmann::json* area_entry = find_area_entry_json(current_room_, area_drag_name_)) {
        (*area_entry)["anchor_relative_to_center"] = true;
        (*area_entry)["anchor"] = nlohmann::json::object({ {"x", dx}, {"y", dy} });

        enqueue_current_room_save(devmode::core::DevSaveCoordinator::Priority::Debounced);
    }

    nlohmann::json& root = current_room_->assets_data();
    if (auto* groups_ptr = devmode::spawn::find_spawn_groups_array(root)) {
        for (auto& entry : const_cast<nlohmann::json&>(*groups_ptr)) {
            if (!entry.is_object()) continue;
            if (entry.value("link_to_area", false) && entry.value("linked_area", std::string{}) == area_drag_name_) {
                entry["position"] = "Exact";
                entry["dx"] = dx;
                entry["dz"] = dy;

                if (current_room_->room_area) {
                    auto b = current_room_->room_area->get_bounds();
                    const int w = std::max(1, std::get<2>(b) - std::get<0>(b));
                    const int h = std::max(1, std::get<3>(b) - std::get<1>(b));
                    if (!entry.contains("origional_width")) entry["origional_width"] = w;
                    if (!entry.contains("origional_height")) entry["origional_height"] = h;
                }
                break;
            }
        }
    }

    save_current_room_assets_json();
    area_dragging_ = false;
    area_drag_moved_ = false;
}

void RoomEditor::update_highlighted_assets() {
    if (!highlight_dirty_) {
        return;
    }
    highlight_dirty_ = false;
    const std::vector<Asset*>* source_assets = selection_asset_source();
    if (!source_assets) return;

    highlighted_assets_.clear();

    if (!selected_assets_.empty()) {
        // When something is selected, lock highlights to the selection.
        highlighted_assets_ = selected_assets_;
    } else if (hovered_asset_ && asset_belongs_to_room(hovered_asset_)) {
        // No selection: allow hover highlighting (plus its spawn group).
        highlighted_assets_.push_back(hovered_asset_);
        if (!hovered_asset_->spawn_id.empty()) {
            for (Asset* asset : *source_assets) {
                if (!asset_belongs_to_room(asset)) continue;
                if (asset->spawn_id != hovered_asset_->spawn_id) continue;
                if (std::find(highlighted_assets_.begin(), highlighted_assets_.end(), asset) == highlighted_assets_.end()) {
                    highlighted_assets_.push_back(asset);
                }
            }
        }

    }
    for (Asset* asset : *source_assets) {
        if (!asset) continue;
        asset->set_highlighted(false);
        asset->set_selected(false);
    }

    for (Asset* asset : highlighted_assets_) {
        if (!asset) continue;
        if (std::find(selected_assets_.begin(), selected_assets_.end(), asset) != selected_assets_.end()) {
            asset->set_selected(true);
            asset->set_highlighted(false);
        } else {
            asset->set_highlighted(true);
            asset->set_selected(false);
        }
    }
}

bool RoomEditor::anchor_mode_active() const {
    return editor_mode_ == EditorMode::AnchorEdit || editor_mode_ == EditorMode::LightEdit;
}

bool RoomEditor::light_mode_active() const {
    return editor_mode_ == EditorMode::LightEdit;
}

bool RoomEditor::oval_mode_active() const {
    return editor_mode_ == EditorMode::OvalAnchorEdit;
}

bool RoomEditor::movement_mode_active() const {
    return editor_mode_ == EditorMode::MovementEdit;
}

bool RoomEditor::hitbox_mode_active() const {
    return editor_mode_ == EditorMode::HitBoxEdit;
}

bool RoomEditor::attack_box_mode_active() const {
    return editor_mode_ == EditorMode::AttackBoxEdit;
}

bool RoomEditor::impassable_box_mode_active() const {
    return editor_mode_ == EditorMode::ImpassableBoxEdit;
}

bool RoomEditor::floor_box_mode_active() const {
    return editor_mode_ == EditorMode::FloorBoxEdit;
}

std::size_t RoomEditor::editor_mode_index(EditorMode mode) {
    return static_cast<std::size_t>(mode);
}

std::string RoomEditor::delete_mode_label(EditorMode mode) const {
    switch (mode) {
        case EditorMode::AnchorEdit: return "Anchor";
        case EditorMode::LightEdit: return "Light";
        case EditorMode::OvalAnchorEdit: return "Oval";
        case EditorMode::MovementEdit: return "Movement";
        case EditorMode::HitBoxEdit: return "Hit Box";
        case EditorMode::AttackBoxEdit: return "Attack Box";
        case EditorMode::ImpassableBoxEdit: return "Impassable";
        case EditorMode::FloorBoxEdit: return "Floor Box";
        case EditorMode::Normal:
        default:
            return "Editor";
    }
}

bool RoomEditor::mode_delete_confirmation_disabled(EditorMode mode) const {
    const std::size_t idx = editor_mode_index(mode);
    if (idx >= suppress_delete_confirmation_by_mode_.size()) {
        return false;
    }
    return suppress_delete_confirmation_by_mode_[idx];
}

void RoomEditor::set_mode_delete_confirmation_disabled(EditorMode mode, bool disabled) {
    const std::size_t idx = editor_mode_index(mode);
    if (idx >= suppress_delete_confirmation_by_mode_.size()) {
        return;
    }
    suppress_delete_confirmation_by_mode_[idx] = disabled;
}

RoomEditor::DeleteConfirmResult RoomEditor::prompt_delete_confirmation(const DeleteIntentSummary& summary) {
    if (delete_confirm_callback_) {
        return delete_confirm_callback_(summary);
    }

    std::ostringstream body;
    body << "Mode: " << delete_mode_label(summary.mode) << "\n";
    body << "Domain: " << (summary.domain_label ? summary.domain_label : "unknown") << "\n";
    body << "Type: " << (summary.entity_type ? summary.entity_type : "unknown") << "\n";
    body << "Scope: " << (summary.scope_label ? summary.scope_label : "current selection") << "\n";
    body << "Affected: " << summary.affected_count << "\n\n";
    body << "Confirm delete?";

    const std::string title = delete_mode_label(summary.mode) + " Delete Confirmation";
    const auto pressed = devmode::dialogs::show_choice(
        parent_window_,
        title,
        body.str(),
        {
            devmode::dialogs::DialogButton{0, "Cancel", false, true, false},
            devmode::dialogs::DialogButton{1, "Delete", false, false, true},
            devmode::dialogs::DialogButton{2, "Delete + Don't Ask Again", true, false, true},
        },
        devmode::dialogs::MessageIcon::Warning);
    if (!pressed) {
        return DeleteConfirmResult::Cancel;
    }
    if (*pressed == 2) {
        return DeleteConfirmResult::ConfirmDontAskAgain;
    }
    if (*pressed == 1) {
        return DeleteConfirmResult::Confirm;
    }
    return DeleteConfirmResult::Cancel;
}

bool RoomEditor::execute_delete_with_confirmation(const DeleteIntentSummary& summary,
                                                  const std::function<bool()>& validate_selection,
                                                  const std::function<bool()>& perform_delete) {
    if (!validate_selection || !perform_delete) {
        return false;
    }
    if (summary.affected_count <= 0) {
        return false;
    }

    // Runtime delete must be deterministic and immediate. When no test hook is
    // installed, execute the scoped delete directly instead of relying on a
    // confirmation dialog path that can drift while UI focus changes.
    if (!delete_confirm_callback_) {
        return perform_delete();
    }

    if (!validate_selection()) {
        SDL_Log("[RoomEditor][DeleteGuard] stale-or-invalid selection before confirmation mode=%d domain=%s",
                static_cast<int>(summary.mode),
                summary.domain_label ? summary.domain_label : "unknown");
        return false;
    }

    if (!mode_delete_confirmation_disabled(summary.mode)) {
        const DeleteConfirmResult decision = prompt_delete_confirmation(summary);
        if (decision == DeleteConfirmResult::Cancel) {
            return false;
        }
        if (decision == DeleteConfirmResult::ConfirmDontAskAgain) {
            set_mode_delete_confirmation_disabled(summary.mode, true);
        }
    }

    if (!validate_selection()) {
        SDL_Log("[RoomEditor][DeleteGuard] stale-or-invalid selection at confirmation mode=%d domain=%s",
                static_cast<int>(summary.mode),
                summary.domain_label ? summary.domain_label : "unknown");
        return false;
    }
    return perform_delete();
}

bool RoomEditor::is_anchor_edit_mode_active() const {
    return anchor_mode_active();
}

bool RoomEditor::is_light_edit_mode_active() const {
    return light_mode_active();
}

bool RoomEditor::is_asset_stack_editor_active() const {
    return anchor_mode_active() || light_mode_active() || oval_mode_active() ||
           movement_mode_active() || hitbox_mode_active() || attack_box_mode_active() ||
           impassable_box_mode_active() ||
           floor_box_mode_active();
}

bool RoomEditor::mode_owns_domain(EditorMode mode, OwnershipDomain domain) const {
    switch (mode) {
        case EditorMode::AnchorEdit:
            return domain == OwnershipDomain::AnchorNonLight ||
                   domain == OwnershipDomain::AnchorPointChildCandidates;
        case EditorMode::LightEdit:
            return domain == OwnershipDomain::AnchorLight ||
                   domain == OwnershipDomain::AnchorPointChildCandidates;
        case EditorMode::OvalAnchorEdit:
            return domain == OwnershipDomain::OvalMappingAndPoints ||
                   domain == OwnershipDomain::AnchorPointChildCandidates;
        case EditorMode::MovementEdit:
            return domain == OwnershipDomain::Movement;
        case EditorMode::HitBoxEdit:
            return domain == OwnershipDomain::HitBoxes;
        case EditorMode::AttackBoxEdit:
            return domain == OwnershipDomain::AttackBoxes;
        case EditorMode::ImpassableBoxEdit:
            return domain == OwnershipDomain::ImpassableGeometry;
        case EditorMode::FloorBoxEdit:
            return domain == OwnershipDomain::FloorBoxCandidates;
        case EditorMode::Normal:
        default:
            return false;
    }
}

bool RoomEditor::active_mode_owns_domain(OwnershipDomain domain) const {
    return mode_owns_domain(editor_mode_, domain);
}

bool RoomEditor::log_rejected_domain_mutation(const char* operation, OwnershipDomain domain) const {
    const char* op = operation ? operation : "unknown";
    const char* domain_name = "unknown";
    switch (domain) {
        case OwnershipDomain::AnchorNonLight: domain_name = "anchor_non_light"; break;
        case OwnershipDomain::AnchorLight: domain_name = "anchor_light"; break;
        case OwnershipDomain::OvalMappingAndPoints: domain_name = "oval_mapping_and_points"; break;
        case OwnershipDomain::AnchorPointChildCandidates: domain_name = "anchor_point_child_candidates"; break;
        case OwnershipDomain::Movement: domain_name = "movement"; break;
        case OwnershipDomain::HitBoxes: domain_name = "hit_boxes"; break;
        case OwnershipDomain::AttackBoxes: domain_name = "attack_boxes"; break;
        case OwnershipDomain::ImpassableGeometry: domain_name = "impassable_geometry"; break;
        case OwnershipDomain::FloorBoxCandidates: domain_name = "floor_box_candidates"; break;
    }
    SDL_Log("[RoomEditor][OwnershipGuard] rejected operation=%s mode=%d domain=%s",
            op,
            static_cast<int>(editor_mode_),
            domain_name);
    SDL_assert(false && "RoomEditor ownership guard rejected out-of-scope mutation");
    return false;
}

void RoomEditor::reconcile_mode_ownership_state(EditorMode previous_mode) {
    (void)previous_mode;
    if (!active_mode_owns_domain(OwnershipDomain::AnchorNonLight) &&
        !active_mode_owns_domain(OwnershipDomain::AnchorLight)) {
        clear_anchor_selection();
        if (anchor_candidate_editor_.open) {
            close_anchor_candidate_editor();
        }
    } else {
        ensure_anchor_selection_valid();
    }
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        oval_edit_.selected_point_index = -1;
        oval_edit_.hovered_point_index = -1;
        oval_edit_.center_selected = false;
        oval_edit_.center_hovered = false;
        oval_edit_.center_dragging = false;
    }
    if (!active_mode_owns_domain(OwnershipDomain::HitBoxes)) {
        hitbox_edit_.selected_box_index = -1;
        hitbox_edit_.hovered_box_index = -1;
        hitbox_edit_.dragging_box = false;
        hitbox_edit_.dragging_corner = false;
    }
    if (!active_mode_owns_domain(OwnershipDomain::AttackBoxes)) {
        attack_box_edit_.selected_box_index = -1;
        attack_box_edit_.hovered_box_index = -1;
        attack_box_edit_.dragging_box = false;
        attack_box_edit_.dragging_corner = false;
    }
    if (!active_mode_owns_domain(OwnershipDomain::ImpassableGeometry)) {
        impassable_box_edit_.selected_box_index = -1;
        impassable_box_edit_.hovered_box_index = -1;
        impassable_box_edit_.dragging_box = false;
        impassable_box_edit_.dragging_corner = false;
    }
    if (!active_mode_owns_domain(OwnershipDomain::FloorBoxCandidates)) {
        floor_box_edit_.selected_box_index = -1;
        floor_box_edit_.hovered_box_index = -1;
        floor_box_edit_.dragging_box = false;
        floor_box_edit_.dragging_corner = false;
        if (floor_box_candidate_editor_.open) {
            close_floor_box_candidate_editor();
        }
    }
}

bool RoomEditor::is_asset_editor_tab_scope_active() const {
    return asset_editor_tab_scope_active();
}

bool RoomEditor::is_asset_pointer_live(const Asset* asset) const {
    if (!asset || !assets_) {
        return false;
    }
    return std::find(assets_->all.begin(), assets_->all.end(), asset) != assets_->all.end();
}

Asset* RoomEditor::selected_anchor_mode_asset() const {
    if (info_ui_ && info_ui_->is_visible()) {
        Asset* target = info_ui_->get_target_asset();
        if (is_asset_pointer_live(target)) {
            return target;
        }
    }

    if (selected_assets_.size() == 1) {
        Asset* candidate = selected_assets_.front();
        if (is_asset_pointer_live(candidate) && asset_belongs_to_room(candidate)) {
            return candidate;
        }
    }

    if (selected_assets_.size() == 1) {
        Asset* candidate = selected_assets_.front();
        if (is_asset_pointer_live(candidate)) {
            return candidate;
        }
    }

    return nullptr;
}

devmode::FileSourcedAnimationSelection RoomEditor::resolve_file_sourced_animation_selection_for_target(const Asset* target,
                                                                                                       const std::string& animation_id) const {
    if (!target || !target->info) {
        return {};
    }
    return devmode::resolve_file_sourced_animation_selection(target->info.get(), animation_id);
}

void RoomEditor::ensure_anchor_editor_widgets() {
    if (!anchor_navigation_panel_) {
        anchor_navigation_panel_ = std::make_unique<BottomNavigationPanel>();
    }
    if (!anchor_tools_panel_) {
        anchor_tools_panel_ = std::make_unique<RoomAnchorToolsPanel>();
        anchor_tools_panel_->set_on_select([this](const std::string& name) {
            anchor_edit_.selected_anchor_name = name;
            anchor_edit_.point_selected = !name.empty();
            sync_anchor_tools_panel();
        });
        anchor_tools_panel_->set_on_add([this]() {
            add_anchor_in_current_frame();
        });
        anchor_tools_panel_->set_on_rename([this](const std::string& name) {
            rename_selected_anchor_in_current_frame(name);
        });
        anchor_tools_panel_->set_on_delete([this]() {
            delete_selected_anchor_in_current_frame();
        });
        anchor_tools_panel_->set_on_apply_details([this](const RoomAnchorToolsPanel::DetailValues& values) {
            apply_anchor_panel_detail_update(values);
        });
        anchor_tools_panel_->set_on_apply_light_details([this](const RoomAnchorToolsPanel::LightValues& values) {
            apply_anchor_panel_light_update(values);
        });
        anchor_tools_panel_->set_on_propagate([this](RoomAnchorToolsPanel::PropagationScope scope) {
            switch (scope) {
                case RoomAnchorToolsPanel::PropagationScope::NextFrame:
                    apply_anchor_current_frame_to_scope(EditorFramePropagationScope::NextFrame);
                    break;
                case RoomAnchorToolsPanel::PropagationScope::Animation:
                    apply_anchor_current_frame_to_scope(EditorFramePropagationScope::Animation);
                    break;
                case RoomAnchorToolsPanel::PropagationScope::Asset:
                    apply_anchor_current_frame_to_scope(EditorFramePropagationScope::Asset);
                    break;
            }
        });
        anchor_tools_panel_->set_on_open_candidates([this](const std::string& anchor_name,
                                                            SDL_Point click_point,
                                                            SDL_Rect row_rect,
                                                            devmode::CandidateSourceContext source_context) {
            open_anchor_candidate_editor(anchor_name, click_point, row_rect, source_context);
        });
    }

    if (anchor_tools_panel_) {
        anchor_tools_panel_->set_screen_dimensions(screen_w_, screen_h_);
        anchor_tools_panel_->set_visible(anchor_mode_active() || light_mode_active());
        anchor_tools_panel_->set_light_editor_mode(light_mode_active());
    }
}

