std::string build_stack_animation_preview_signature(const AssetInfo& info) {
    std::ostringstream ss;
    ss << info.asset_dir_path() << "|" << info.start_animation << "|" << info.animations.size();
    for (const auto& [id, animation] : info.animations) {
        ss << "|" << id
           << "|k=" << animation.source.kind
           << "|p=" << animation.source.path
           << "|n=" << animation.source.name
           << "|f=" << animation.number_of_frames
           << "|ix=" << (animation.invert_frames_horizontal ? 1 : 0)
           << "|iy=" << (animation.invert_frames_vertical ? 1 : 0)
           << "|rev=" << (animation.reverse_source ? 1 : 0)
           << "|inh=" << (animation.inherit_data ? 1 : 0);
    }
    return ss.str();
}

std::uint64_t build_stack_animation_preview_signature_hash_legacy(const AssetInfo& info) {
    return static_cast<std::uint64_t>(std::hash<std::string>{}(build_stack_animation_preview_signature(info)));
}

void RoomEditor::ensure_stack_animation_list_panel() {
    if (stack_animation_list_panel_) {
        return;
    }
    stack_animation_list_panel_ = std::make_unique<animation_editor::AnimationListPanel>();
    stack_animation_list_panel_->set_show_delete_button(false);
    stack_animation_list_panel_->set_on_selection_changed([this](const std::optional<std::string>& animation_id) {
        if (!animation_id.has_value() || animation_id->empty()) {
            return;
        }
        if (this->apply_stack_animation_selection(*animation_id)) {
            this->force_stack_animation_sync_ = true;
            this->sync_stack_animation_list_panel();
            this->update_asset_editor_layout();
        }
    });
}

bool RoomEditor::is_stack_animation_list_subview_active() const {
    if (!enabled_ || !asset_editor_tab_scope_active()) {
        return false;
    }
    switch (asset_editor_subview_) {
        case AssetEditorSubview::AssetInfo:
        case AssetEditorSubview::Anchor:
        case AssetEditorSubview::Light:
        case AssetEditorSubview::OvalAnchor:
        case AssetEditorSubview::Movement:
        case AssetEditorSubview::Hitbox:
        case AssetEditorSubview::AttackBox:
        case AssetEditorSubview::ImpassableBox:
            return true;
        case AssetEditorSubview::AnimationEditor:
        case AssetEditorSubview::FloorBoxes:
            return false;
    }
    return false;
}

Asset* RoomEditor::stack_animation_list_target_asset() const {
    switch (asset_editor_subview_) {
        case AssetEditorSubview::Anchor:
        case AssetEditorSubview::Light:
            return is_asset_pointer_live(anchor_edit_.target_asset) ? anchor_edit_.target_asset : nullptr;
        case AssetEditorSubview::OvalAnchor:
            return is_asset_pointer_live(oval_edit_.target_asset) ? oval_edit_.target_asset : nullptr;
        case AssetEditorSubview::Movement:
            return is_asset_pointer_live(movement_edit_.target_asset) ? movement_edit_.target_asset : nullptr;
        case AssetEditorSubview::Hitbox:
            return is_asset_pointer_live(hitbox_edit_.target_asset) ? hitbox_edit_.target_asset : nullptr;
        case AssetEditorSubview::AttackBox:
            return is_asset_pointer_live(attack_box_edit_.target_asset) ? attack_box_edit_.target_asset : nullptr;
        case AssetEditorSubview::ImpassableBox:
            return is_asset_pointer_live(impassable_box_edit_.target_asset) ? impassable_box_edit_.target_asset : nullptr;
        case AssetEditorSubview::AssetInfo: {
            Asset* target = info_ui_ ? info_ui_->get_target_asset() : nullptr;
            if ((!target || !is_asset_pointer_live(target)) && selected_assets_.size() == 1) {
                target = selected_assets_.front();
            }
            return is_asset_pointer_live(target) ? target : nullptr;
        }
        case AssetEditorSubview::AnimationEditor:
        case AssetEditorSubview::FloorBoxes:
            return nullptr;
    }
    return nullptr;
}

std::optional<std::string> RoomEditor::stack_animation_list_selected_animation_id() const {
    switch (asset_editor_subview_) {
        case AssetEditorSubview::Anchor:
        case AssetEditorSubview::Light:
            return anchor_edit_.animation_id.empty() ? std::nullopt : std::make_optional(anchor_edit_.animation_id);
        case AssetEditorSubview::OvalAnchor:
            return oval_edit_.animation_id.empty() ? std::nullopt : std::make_optional(oval_edit_.animation_id);
        case AssetEditorSubview::Movement:
            return movement_edit_.animation_id.empty() ? std::nullopt : std::make_optional(movement_edit_.animation_id);
        case AssetEditorSubview::Hitbox:
            return hitbox_edit_.animation_id.empty() ? std::nullopt : std::make_optional(hitbox_edit_.animation_id);
        case AssetEditorSubview::AttackBox:
            return attack_box_edit_.animation_id.empty() ? std::nullopt : std::make_optional(attack_box_edit_.animation_id);
        case AssetEditorSubview::ImpassableBox:
            return impassable_box_edit_.animation_id.empty() ? std::nullopt : std::make_optional(impassable_box_edit_.animation_id);
        case AssetEditorSubview::AssetInfo: {
            Asset* target = stack_animation_list_target_asset();
            if (!target || target->current_animation.empty()) {
                return std::nullopt;
            }
            return target->current_animation;
        }
        case AssetEditorSubview::AnimationEditor:
        case AssetEditorSubview::FloorBoxes:
            return std::nullopt;
    }
    return std::nullopt;
}

bool RoomEditor::is_stack_animation_editable_id(const std::string& animation_id) const {
    if (animation_id.empty()) {
        return false;
    }
    return stack_animation_list_selectable_ids_.find(animation_id) != stack_animation_list_selectable_ids_.end();
}

bool RoomEditor::is_point_inside_stack_animation_list(int x, int y) const {
    if (!enabled_ || !stack_animation_list_visible_) {
        return false;
    }
    SDL_Point p{x, y};
    return SDL_PointInRect(&p, &stack_animation_list_bounds_) != 0;
}

void RoomEditor::sync_stack_animation_list_preview_provider(const AssetInfo* info) {
    if (!stack_animation_list_panel_) {
        return;
    }
    if (!info) {
        stack_animation_preview_document_.reset();
        stack_animation_preview_provider_.reset();
        stack_animation_preview_revision_ = 0;
        stack_animation_list_panel_->set_preview_provider({});
        return;
    }

    std::uint64_t metadata_revision = info->animation_metadata_revision();
    if (metadata_revision == 0) {
        metadata_revision = build_stack_animation_preview_signature_hash_legacy(*info);
    }
    const bool needs_reload = !stack_animation_preview_document_ ||
                              !stack_animation_preview_provider_ ||
                              metadata_revision != stack_animation_preview_revision_;
    if (needs_reload) {
        if (!stack_animation_preview_document_) {
            stack_animation_preview_document_ = std::make_shared<animation_editor::AnimationDocument>();
        }
        if (!stack_animation_preview_provider_) {
            stack_animation_preview_provider_ = std::make_shared<animation_editor::PreviewProvider>();
        }

        std::filesystem::path asset_root;
        try {
            asset_root = info->asset_dir_path();
        } catch (...) {
            asset_root.clear();
        }
        stack_animation_preview_document_->load_from_manifest(info->manifest_payload(), asset_root, {});
        stack_animation_preview_provider_->set_document(stack_animation_preview_document_);
        stack_animation_preview_revision_ = metadata_revision;
    }

    stack_animation_list_panel_->set_preview_provider(stack_animation_preview_provider_);
}

void RoomEditor::sync_stack_animation_list_panel() {
    static const std::vector<animation_editor::AnimationListPanel::ExternalRow> kEmptyExternalRows;
    ensure_stack_animation_list_panel();
    if (!stack_animation_list_panel_) {
        return;
    }

    stack_animation_list_selectable_ids_.clear();
    const bool list_visible = is_stack_animation_list_subview_active();
    stack_animation_list_visible_ = list_visible;
    if (!list_visible) {
        sync_stack_animation_list_preview_provider(nullptr);
        stack_animation_list_panel_->set_external_rows(kEmptyExternalRows);
        stack_animation_list_panel_->set_selected_animation_id(std::nullopt);
        return;
    }

    Asset* target = stack_animation_list_target_asset();
    if (!target || !target->info) {
        sync_stack_animation_list_preview_provider(nullptr);
        stack_animation_list_panel_->set_external_rows(kEmptyExternalRows);
        stack_animation_list_panel_->set_selected_animation_id(std::nullopt);
        return;
    }

    const std::optional<std::string> requested = stack_animation_list_selected_animation_id();
    const auto model = devmode::resolve_stack_animation_list_model(target->info.get(), requested.value_or(std::string{}));
    sync_stack_animation_list_preview_provider(target->info.get());

    std::vector<animation_editor::AnimationListPanel::ExternalRow> rows;
    rows.reserve(model.rows.size());
    for (const auto& row : model.rows) {
        animation_editor::AnimationListPanel::ExternalRow panel_row;
        panel_row.id = row.animation_id;
        panel_row.level = row.level;
        panel_row.missing_source = row.missing_source;
        panel_row.selectable = row.editable_in_stack_mode;
        if (row.editable_in_stack_mode) {
            stack_animation_list_selectable_ids_.insert(row.animation_id);
        }
        rows.push_back(std::move(panel_row));
    }
    stack_animation_list_panel_->set_external_rows(std::move(rows));
    if (requested.has_value() && !requested->empty()) {
        stack_animation_list_panel_->set_selected_animation_id(requested);
    } else if (model.has_selection()) {
        stack_animation_list_panel_->set_selected_animation_id(model.resolved_animation_id);
    } else {
        stack_animation_list_panel_->set_selected_animation_id(std::nullopt);
    }
}

bool RoomEditor::apply_stack_animation_selection(const std::string& animation_id) {
    if (animation_id.empty()) {
        return false;
    }
    if (!is_stack_animation_editable_id(animation_id)) {
        return false;
    }

    switch (asset_editor_subview_) {
        case AssetEditorSubview::AssetInfo: {
            Asset* target = stack_animation_list_target_asset();
            if (!target || !target->info) {
                return false;
            }
            int next_frame_index = 0;
            auto current_anim_it = target->info->animations.find(target->current_animation);
            if (current_anim_it != target->info->animations.end() && current_anim_it->second.has_frames()) {
                for (std::size_t i = 0; i < current_anim_it->second.frame_count(); ++i) {
                    if (current_anim_it->second.primary_frame_at(i) == target->current_frame) {
                        next_frame_index = static_cast<int>(i);
                        break;
                    }
                }
            }
            return apply_asset_preview_animation_and_frame(target, animation_id, next_frame_index);
        }
        case AssetEditorSubview::Anchor:
        case AssetEditorSubview::Light: {
            const int frame = resolve_anchor_mode_frame_index();
            if (apply_anchor_animation_and_frame(animation_id, frame)) {
                refresh_anchor_mode_handles();
                sync_anchor_tools_panel();
                return true;
            }
            return false;
        }
        case AssetEditorSubview::OvalAnchor: {
            const int frame = resolve_oval_mode_frame_index();
            return apply_oval_animation_and_frame(animation_id, frame);
        }
        case AssetEditorSubview::Movement: {
            if (!movement_mode_active() || !movement_edit_.target_asset || !movement_edit_.target_asset->info) {
                return false;
            }
            if (movement_edit_.dirty_since_last_flush) {
                persist_movement_current_animation(devmode::core::DevSaveCoordinator::Priority::Debounced);
            }
            end_movement_vertical_wheel_edit(false);
            int next_frame_index = movement_edit_.frame_index;
            auto next_anim_it = movement_edit_.target_asset->info->animations.find(animation_id);
            if (next_anim_it != movement_edit_.target_asset->info->animations.end() && next_anim_it->second.has_frames()) {
                next_frame_index = devmode::room_anchor_mode::wrap_index(
                    next_frame_index,
                    static_cast<int>(next_anim_it->second.frame_count()));
            } else {
                next_frame_index = 0;
            }
            reload_movement_paths_for_animation(animation_id, next_frame_index, true);
            if (apply_movement_animation_and_frame(animation_id, next_frame_index)) {
                refresh_movement_editor_selection(false);
                sync_movement_panel_frame_values();
                return true;
            }
            return false;
        }
        case AssetEditorSubview::Hitbox: {
            const int frame = resolve_hitbox_mode_frame_index();
            if (apply_hitbox_animation_and_frame(animation_id, frame)) {
                sync_hitbox_tools_panel();
                return true;
            }
            return false;
        }
        case AssetEditorSubview::AttackBox: {
            const int frame = resolve_attack_box_mode_frame_index();
            if (apply_attack_box_animation_and_frame(animation_id, frame)) {
                sync_attack_box_tools_panel();
                sync_attack_payload_editor();
                return true;
            }
            return false;
        }
        case AssetEditorSubview::ImpassableBox: {
            const int frame = resolve_impassable_box_mode_frame_index();
            if (apply_impassable_box_animation_and_frame(animation_id, frame)) {
                sync_impassable_box_tools_panel();
                return true;
            }
            return false;
        }
        case AssetEditorSubview::AnimationEditor:
        case AssetEditorSubview::FloorBoxes:
            return false;
    }
    return false;
}

void RoomEditor::sync_floor_box_tools_panel() {
    if (!floor_box_tools_panel_) {
        return;
    }

    const bool floor_enabled = floor_box_edit_.target_asset &&
                               floor_box_edit_.target_asset->info &&
                               floor_box_edit_.target_asset->info->is_floor_boxes_enabled();
    floor_box_tools_panel_->set_system_enabled(floor_enabled);
    floor_box_tools_panel_->set_recommendation_pool(floor_box_recommendation_pool());

    std::vector<std::string> names;
    const auto* target_info = floor_box_edit_.target_asset ? floor_box_edit_.target_asset->info.get() : nullptr;
    if (floor_enabled && target_info) {
        names.reserve(target_info->floor_boxes.size());
        for (std::size_t i = 0; i < target_info->floor_boxes.size(); ++i) {
            const auto& box = target_info->floor_boxes[i];
            if (!box.name.empty()) {
                names.push_back(box.name);
            } else {
                names.push_back("Floor Box " + std::to_string(static_cast<int>(i + 1)));
            }
        }
    }

    floor_box_tools_panel_->set_floor_box_names(names);
    int selected_box = floor_box_edit_.selected_box_index;
    if (selected_box >= static_cast<int>(names.size())) {
        selected_box = -1;
    }
    floor_box_edit_.selected_box_index = selected_box;
    floor_box_tools_panel_->set_selection(selected_box);

    if (target_info && selected_box >= 0 && selected_box < static_cast<int>(target_info->floor_boxes.size())) {
        const auto& source = target_info->floor_boxes[static_cast<std::size_t>(selected_box)];
        RoomFloorBoxToolsPanel::DetailValues values;
        values.name = source.name;
        values.enabled = source.enabled;
        values.position_x = source.position_x;
        values.position_z = source.position_z;
        values.width = source.width;
        values.depth = source.depth;
        values.tags = source.tags;
        floor_box_tools_panel_->set_detail_values(values);
    } else {
        floor_box_tools_panel_->set_detail_values(RoomFloorBoxToolsPanel::DetailValues{});
    }

    if (!target_info || selected_box < 0 || selected_box >= static_cast<int>(target_info->floor_boxes.size())) {
        floor_box_edit_.selected_corner_index = -1;
        floor_box_edit_.hovered_box_index = -1;
        floor_box_edit_.hovered_corner_index = -1;
        floor_box_edit_.dragging_corner = false;
        floor_box_edit_.dragging_box = false;
    }

    sync_floor_box_candidate_editor();
}

std::vector<std::string> RoomEditor::floor_box_recommendation_pool() const {
    std::set<std::string> pool;
    if (assets_) {
        for (const auto& pair : assets_->library().all()) {
            const std::shared_ptr<AssetInfo>& info = pair.second;
            if (!info || !info->is_floor_boxes_enabled()) {
                continue;
            }
            for (const auto& box : info->floor_boxes_payload()) {
                for (const auto& tag : box.tags) {
                    const std::string normalized = normalize_floor_box_tag(tag);
                    if (!normalized.empty()) {
                        pool.insert(normalized);
                    }
                }
            }
        }
    }
    return std::vector<std::string>(pool.begin(), pool.end());
}

void RoomEditor::sync_hitbox_tools_panel() {
    if (!hitbox_tools_panel_) {
        return;
    }
    const bool hitbox_enabled = hitbox_edit_.target_asset &&
                                hitbox_edit_.target_asset->info &&
                                hitbox_edit_.target_asset->info->is_hitbox_enabled();
    std::vector<std::string> names;
    AnimationFrame* frame = hitbox_edit_.target_asset ? hitbox_edit_.target_asset->current_frame : nullptr;
    if (hitbox_enabled && frame) {
        const auto& boxes = frame->hit_boxes.boxes;
        names.reserve(boxes.size());
        for (std::size_t i = 0; i < boxes.size(); ++i) {
            const auto& box = boxes[i];
            if (!box.name.empty()) {
                names.push_back(box.name);
            } else {
                names.push_back("Hit Box " + std::to_string(static_cast<int>(i + 1)));
            }
        }
    }

    hitbox_tools_panel_->set_box_names(names);
    int selected_box = hitbox_edit_.selected_box_index;
    if (selected_box >= static_cast<int>(names.size())) {
        selected_box = static_cast<int>(names.size()) - 1;
    }
    if (selected_box < 0) {
        selected_box = -1;
        hitbox_edit_.selected_corner_index = -1;
        hitbox_edit_.selected_point_index = -1;
        hitbox_edit_.point_selected = false;
        hitbox_edit_.dragging_corner = false;
        hitbox_edit_.dragging_box = false;
        hitbox_edit_.dragging_rotation = false;
        hitbox_edit_.hovered_rotation_handle = false;
        clear_box_extrusion_drag_state(hitbox_edit_);
        clear_box_extrusion_hover_state(hitbox_edit_);
    } else {
        hitbox_edit_.selected_corner_index = clamp_box_corner_index(hitbox_edit_.selected_corner_index);
        const int selected_side = (hitbox_edit_.selected_point_index >= 4) ? 4 : 0;
        const int selected_runtime_corner = runtime_corner_from_editor_corner(hitbox_edit_.selected_corner_index);
        hitbox_edit_.selected_point_index = selected_side + selected_runtime_corner;
    }
    hitbox_edit_.selected_box_index = selected_box;
    hitbox_tools_panel_->set_selection(selected_box, hitbox_edit_.selected_corner_index);

    RoomBoxToolsPanel::DetailValues values;
    if (frame && selected_box >= 0 && selected_box < static_cast<int>(frame->hit_boxes.boxes.size())) {
        const auto& box = frame->hit_boxes.boxes[static_cast<std::size_t>(selected_box)];
        values.name = box.name;
        values.extrusion_forward = box.extrusion_forward;
        values.extrusion_backward = box.extrusion_backward;
    }
    hitbox_tools_panel_->set_detail_values(values);
}

void RoomEditor::sync_attack_box_tools_panel() {
    if (!attack_box_tools_panel_) {
        return;
    }
    const bool attack_enabled = attack_box_edit_.target_asset &&
                                attack_box_edit_.target_asset->info &&
                                attack_box_edit_.target_asset->info->is_attack_box_enabled();
    std::vector<std::string> names;
    AnimationFrame* frame = attack_box_edit_.target_asset ? attack_box_edit_.target_asset->current_frame : nullptr;
    if (attack_enabled && frame) {
        const auto& boxes = frame->attack_boxes.boxes;
        names.reserve(boxes.size());
        for (std::size_t i = 0; i < boxes.size(); ++i) {
            const auto& box = boxes[i];
            if (!box.name.empty()) {
                names.push_back(box.name);
            } else {
                names.push_back("Attack Box " + std::to_string(static_cast<int>(i + 1)));
            }
        }
    }

    attack_box_tools_panel_->set_box_names(names);
    int selected_box = attack_box_edit_.selected_box_index;
    if (selected_box >= static_cast<int>(names.size())) {
        selected_box = static_cast<int>(names.size()) - 1;
    }
    if (selected_box < 0) {
        selected_box = -1;
        attack_box_edit_.selected_corner_index = -1;
        attack_box_edit_.selected_point_index = -1;
        attack_box_edit_.point_selected = false;
        attack_box_edit_.dragging_corner = false;
        attack_box_edit_.dragging_box = false;
        attack_box_edit_.dragging_rotation = false;
        attack_box_edit_.hovered_rotation_handle = false;
        clear_box_extrusion_drag_state(attack_box_edit_);
        clear_box_extrusion_hover_state(attack_box_edit_);
    } else {
        attack_box_edit_.selected_corner_index = clamp_box_corner_index(attack_box_edit_.selected_corner_index);
        const int selected_side = (attack_box_edit_.selected_point_index >= 4) ? 4 : 0;
        const int selected_runtime_corner = runtime_corner_from_editor_corner(attack_box_edit_.selected_corner_index);
        attack_box_edit_.selected_point_index = selected_side + selected_runtime_corner;
    }
    attack_box_edit_.selected_box_index = selected_box;
    attack_box_tools_panel_->set_selection(selected_box, attack_box_edit_.selected_corner_index);

    RoomBoxToolsPanel::DetailValues values;
    if (frame && selected_box >= 0 && selected_box < static_cast<int>(frame->attack_boxes.boxes.size())) {
        const auto& box = frame->attack_boxes.boxes[static_cast<std::size_t>(selected_box)];
        values.name = box.name;
        values.extrusion_forward = box.extrusion_forward;
        values.extrusion_backward = box.extrusion_backward;
        values.damage = box.damage_amount;
    }
    attack_box_tools_panel_->set_detail_values(values);
    sync_attack_payload_editor();
}

void RoomEditor::sync_attack_payload_editor() {
    if (!attack_payload_editor_) {
        return;
    }
    AnimationFrame* frame = attack_box_edit_.target_asset ? attack_box_edit_.target_asset->current_frame : nullptr;
    const int selected_box = attack_box_edit_.selected_box_index;
    if (!frame || selected_box < 0 || selected_box >= static_cast<int>(frame->attack_boxes.boxes.size())) {
        attack_payload_editor_->clear_payload();
        return;
    }
    const auto& box = frame->attack_boxes.boxes[static_cast<std::size_t>(selected_box)];
    animation_update::AttackPayload payload = payload_from_attack_box(box);
    if (attack_box_edit_.target_asset && attack_box_edit_.target_asset->info) {
        auto anim_it = attack_box_edit_.target_asset->info->animations.find(attack_box_edit_.animation_id);
        if (anim_it != attack_box_edit_.target_asset->info->animations.end()) {
            payload = resolve_payload_for_box_id(anim_it->second, box);
        }
    }
    attack_payload_editor_->set_payload(payload);
}

bool RoomEditor::persist_floor_boxes(devmode::core::DevSaveCoordinator::Priority priority,
                                     bool flush_now,
                                     const char* reason,
                                     const char* flush_tag) {
    if (!floor_box_mode_active() || !floor_box_edit_.target_asset || !floor_box_edit_.target_asset->info) {
        return false;
    }

    std::shared_ptr<AssetInfo> target_info = floor_box_edit_.target_asset->info;
    if (!persist_asset_manifest_from_info(target_info,
                                          priority,
                                          reason ? reason : "Floor Box Edit",
                                          flush_tag ? flush_tag : "room-floor-box-edit",
                                          flush_now)) {
        return false;
    }
    floor_box_edit_.dirty_since_last_flush = !flush_now;
    return true;
}

bool RoomEditor::add_floor_box() {
    if (!floor_box_mode_active() || !floor_box_edit_.target_asset || !floor_box_edit_.target_asset->info) {
        return false;
    }

    Asset* target = floor_box_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    if (!target_info || !target_info->is_floor_boxes_enabled()) {
        return false;
    }

    AssetInfo::FloorBox box{};
    box.id = make_unique_floor_box_id(target_info->floor_boxes);
    box.name = make_unique_floor_box_name(target_info->floor_boxes, "Floor Box");
    box.position_x = 0.0f;
    box.position_z = 0.0f;
    box.width = 128.0f;
    box.depth = 128.0f;
    box.enabled = true;
    box.tags = {};
    target_info->floor_boxes.push_back(box);

    floor_box_edit_.selected_box_index = static_cast<int>(target_info->floor_boxes.size()) - 1;
    floor_box_edit_.selected_corner_index = -1;
    floor_box_edit_.hovered_box_index = -1;
    floor_box_edit_.hovered_corner_index = -1;
    floor_box_edit_.dragging_corner = false;
    floor_box_edit_.dragging_box = false;
    target->refresh_runtime_floor_boxes_cache();
    sync_floor_box_tools_panel();
    return persist_floor_boxes(devmode::core::DevSaveCoordinator::Priority::Debounced,
                               false,
                               "Floor Box Add",
                               "room-floor-box-add");
}

bool RoomEditor::delete_selected_floor_box() {
    if (!active_mode_owns_domain(OwnershipDomain::FloorBoxCandidates)) {
        return log_rejected_domain_mutation("delete_selected_floor_box", OwnershipDomain::FloorBoxCandidates);
    }
    if (!floor_box_mode_active() || !floor_box_edit_.target_asset || !floor_box_edit_.target_asset->info) {
        return false;
    }

    Asset* target = floor_box_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    if (!target_info || !target_info->is_floor_boxes_enabled()) {
        return false;
    }

    const int selected = floor_box_edit_.selected_box_index;
    if (selected < 0 || selected >= static_cast<int>(target_info->floor_boxes.size())) {
        return false;
    }
    const AssetInfo::FloorBox& selected_box = target_info->floor_boxes[static_cast<std::size_t>(selected)];
    const std::string selected_box_id_snapshot = selected_box.id;
    const std::string selected_box_name_snapshot = selected_box.name;
    DeleteIntentSummary summary{};
    summary.mode = editor_mode_;
    summary.domain_label = "floor_box_candidates";
    summary.entity_type = "Floor box";
    summary.scope_label = "current asset";
    summary.affected_count = 1;
    const int selected_snapshot = selected;

    return execute_delete_with_confirmation(
        summary,
        [this, target, selected_snapshot, selected_box_id_snapshot, selected_box_name_snapshot]() {
            if (!(active_mode_owns_domain(OwnershipDomain::FloorBoxCandidates) &&
                  floor_box_mode_active() &&
                  floor_box_edit_.target_asset == target &&
                  target &&
                  target->info)) {
                return false;
            }
            const auto& boxes = target->info->floor_boxes;
            const int resolved_index = find_index_by_id_name_index(
                boxes,
                selected_box_id_snapshot,
                selected_box_name_snapshot,
                selected_snapshot);
            return resolved_index >= 0;
        },
        [this, target, target_info, selected_snapshot, selected_box_id_snapshot, selected_box_name_snapshot]() {
            const int delete_index = find_index_by_id_name_index(
                target_info->floor_boxes,
                selected_box_id_snapshot,
                selected_box_name_snapshot,
                selected_snapshot);
            if (delete_index < 0) {
                return false;
            }
            target_info->floor_boxes.erase(target_info->floor_boxes.begin() + static_cast<std::size_t>(delete_index));
            if (floor_box_candidate_editor_.open && floor_box_candidate_editor_.target_asset == target) {
                close_floor_box_candidate_editor();
            }
            floor_box_edit_.selected_box_index = -1;
            floor_box_edit_.selected_corner_index = -1;
            floor_box_edit_.hovered_box_index = -1;
            floor_box_edit_.hovered_corner_index = -1;
            floor_box_edit_.dragging_corner = false;
            floor_box_edit_.dragging_box = false;

            target->refresh_runtime_floor_boxes_cache();
            sync_floor_box_tools_panel();
            return persist_floor_boxes(kDeletePersistPriority,
                                       kDeletePersistFlushNow,
                                       "Floor Box Delete",
                                       "room-floor-box-delete");
        });
}

bool RoomEditor::apply_floor_box_panel_detail_update(const RoomFloorBoxToolsPanel::DetailValues& values) {
    if (!floor_box_mode_active() || !floor_box_edit_.target_asset || !floor_box_edit_.target_asset->info) {
        return false;
    }

    Asset* target = floor_box_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    if (!target_info || !target_info->is_floor_boxes_enabled()) {
        return false;
    }

    const int selected = floor_box_edit_.selected_box_index;
    if (selected < 0 || selected >= static_cast<int>(target_info->floor_boxes.size())) {
        return false;
    }

    auto& boxes = target_info->floor_boxes;
    auto& box = boxes[static_cast<std::size_t>(selected)];
    bool changed = false;

    const std::string normalized_name = make_unique_floor_box_name(boxes, values.name, box.name);
    if (normalized_name != box.name) {
        box.name = normalized_name;
        changed = true;
    }

    const float width = std::max(0.0f, values.width);
    const float depth = std::max(0.0f, values.depth);
    if (box.position_x != values.position_x) {
        box.position_x = values.position_x;
        changed = true;
    }
    if (box.position_z != values.position_z) {
        box.position_z = values.position_z;
        changed = true;
    }
    if (box.width != width) {
        box.width = width;
        changed = true;
    }
    if (box.depth != depth) {
        box.depth = depth;
        changed = true;
    }
    if (box.enabled != values.enabled) {
        box.enabled = values.enabled;
        changed = true;
    }
    const std::vector<std::string> normalized_tags = normalize_floor_box_tags(values.tags);
    if (box.tags != normalized_tags) {
        box.tags = normalized_tags;
        changed = true;
    }

    if (!changed) {
        return false;
    }

    target->refresh_runtime_floor_boxes_cache();
    sync_floor_box_tools_panel();
    return persist_floor_boxes(devmode::core::DevSaveCoordinator::Priority::Debounced,
                               false,
                               "Floor Box Properties",
                               "room-floor-box-properties");
}

bool RoomEditor::add_hitbox_in_current_frame() {
    const AnimationFrame* frame = hitbox_edit_.target_asset ? hitbox_edit_.target_asset->current_frame : nullptr;
    const SDL_Point dims = resolve_anchor_editor_frame_dimensions(hitbox_edit_.target_asset, frame);
    const bool changed = mutate_hitbox_current_frame(
        [this, dims](std::vector<animation_update::FrameHitBox>& boxes) {
            std::vector<std::string> names;
            names.reserve(boxes.size());
            for (const auto& box : boxes) {
                names.push_back(box.name);
            }
            boxes.push_back(devmode::room_box_payload::make_default_hit_box(names, dims.x, dims.y));
            hitbox_edit_.selected_box_index = static_cast<int>(boxes.size()) - 1;
            hitbox_edit_.selected_corner_index = 0;
            hitbox_edit_.selected_point_index = 0;
            hitbox_edit_.dragging_box = false;
            hitbox_edit_.dragging_corner = false;
            hitbox_edit_.dragging_rotation = false;
            hitbox_edit_.hovered_rotation_handle = false;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);
    if (changed && box_trace_enabled() && hitbox_edit_.target_asset && hitbox_edit_.target_asset->current_frame) {
        const auto& boxes = hitbox_edit_.target_asset->current_frame->hit_boxes.boxes;
        SDL_Log("[BoxFlow][create] kind=hitbox asset=%s anim=%s frame=%d count=%zu ids=%s",
                hitbox_edit_.target_asset->info ? hitbox_edit_.target_asset->info->name.c_str() : "<unknown>",
                hitbox_edit_.animation_id.c_str(),
                hitbox_edit_.target_asset->current_frame->frame_index,
                boxes.size(),
                box_ids_csv(boxes).c_str());
    }
    return changed;
}

bool RoomEditor::delete_selected_hitbox_in_current_frame() {
    if (!active_mode_owns_domain(OwnershipDomain::HitBoxes)) {
        return log_rejected_domain_mutation("delete_selected_hitbox_in_current_frame", OwnershipDomain::HitBoxes);
    }
    if (!hitbox_mode_active() || !hitbox_edit_.target_asset || !hitbox_edit_.target_asset->info) {
        return false;
    }
    Asset* target = hitbox_edit_.target_asset;
    const std::string animation_id_snapshot = hitbox_edit_.animation_id;
    auto anim_it = target->info->animations.find(animation_id_snapshot);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }
    const int frame_index_snapshot = devmode::room_anchor_mode::wrap_index(
        hitbox_edit_.frame_index,
        static_cast<int>(anim_it->second.frame_count()));
    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index_snapshot));
    if (!frame) {
        return false;
    }
    const int selected = hitbox_edit_.selected_box_index;
    if (selected < 0 || selected >= static_cast<int>(frame->hit_boxes.boxes.size())) {
        return false;
    }
    const auto& selected_box = frame->hit_boxes.boxes[static_cast<std::size_t>(selected)];
    const std::string selected_box_id_snapshot = selected_box.id;
    const std::string selected_box_name_snapshot = selected_box.name;
    DeleteIntentSummary summary{};
    summary.mode = editor_mode_;
    summary.domain_label = "hit_boxes";
    summary.entity_type = "Hit box";
    summary.scope_label = "current frame";
    summary.affected_count = 1;
    const int selected_snapshot = selected;
    return execute_delete_with_confirmation(
        summary,
        [this,
         target,
         animation_id_snapshot,
         frame_index_snapshot,
         selected_snapshot,
         selected_box_id_snapshot,
         selected_box_name_snapshot]() {
            if (!(active_mode_owns_domain(OwnershipDomain::HitBoxes) &&
                  hitbox_mode_active() &&
                  target &&
                  target->info)) {
                return false;
            }
            auto validate_anim_it = target->info->animations.find(animation_id_snapshot);
            if (validate_anim_it == target->info->animations.end() || !validate_anim_it->second.has_frames()) {
                return false;
            }
            if (frame_index_snapshot < 0 ||
                frame_index_snapshot >= static_cast<int>(validate_anim_it->second.frame_count())) {
                return false;
            }
            AnimationFrame* validate_frame =
                validate_anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index_snapshot));
            if (!validate_frame) {
                return false;
            }
            const int resolved_index = find_index_by_id_name_index(
                validate_frame->hit_boxes.boxes,
                selected_box_id_snapshot,
                selected_box_name_snapshot,
                selected_snapshot);
            return resolved_index >= 0;
        },
        [this,
         target,
         animation_id_snapshot,
         frame_index_snapshot,
         selected_snapshot,
         selected_box_id_snapshot,
         selected_box_name_snapshot]() {
            hitbox_edit_.target_asset = target;
            hitbox_edit_.animation_id = animation_id_snapshot;
            hitbox_edit_.frame_index = frame_index_snapshot;
            return mutate_hitbox_current_frame(
                [this, selected_snapshot, selected_box_id_snapshot, selected_box_name_snapshot](
                    std::vector<animation_update::FrameHitBox>& boxes) {
                    const int delete_index = find_index_by_id_name_index(
                        boxes,
                        selected_box_id_snapshot,
                        selected_box_name_snapshot,
                        selected_snapshot);
                    if (delete_index < 0) {
                        return false;
                    }
                    boxes.erase(boxes.begin() + static_cast<std::size_t>(delete_index));
                    hitbox_edit_.selected_box_index = -1;
                    hitbox_edit_.selected_corner_index = -1;
                    hitbox_edit_.selected_point_index = -1;
                    hitbox_edit_.point_selected = false;
                    hitbox_edit_.dragging_box = false;
                    hitbox_edit_.dragging_corner = false;
                    hitbox_edit_.dragging_rotation = false;
                    hitbox_edit_.drag_reference_point_index = -1;
                    hitbox_edit_.drag_reference_corner_index = -1;
                    hitbox_edit_.hovered_box_index = -1;
                    hitbox_edit_.hovered_corner_index = -1;
                    hitbox_edit_.hovered_point_index = -1;
                    hitbox_edit_.hovered_rotation_handle = false;
                    clear_box_extrusion_drag_state(hitbox_edit_);
                    clear_box_extrusion_hover_state(hitbox_edit_);
                    return true;
                },
                kDeletePersistPriority,
                kDeletePersistFlushNow);
        });
}

