bool RoomEditor::anchor_visible_in_current_mode(const DisplacedAssetAnchorPoint& anchor) const {
    return devmode::room_anchor_mode::anchor_visible_in_mode(
        anchor,
        devmode::room_anchor_mode::owner_from_light_mode(light_mode_active()),
        [this](const std::string& anchor_name) {
            return is_valid_oval_center_anchor_name(anchor_name);
        });
}

bool RoomEditor::anchor_mutable_in_current_mode(const DisplacedAssetAnchorPoint& anchor) const {
    return devmode::room_anchor_mode::anchor_mutable_in_mode(
        anchor,
        devmode::room_anchor_mode::owner_from_light_mode(light_mode_active()),
        [this](const std::string& anchor_name) {
            return is_valid_oval_center_anchor_name(anchor_name);
        });
}

bool RoomEditor::anchor_name_exists_across_eligible_animations(const std::shared_ptr<AssetInfo>& target_info,
                                                               const std::string& name) const {
    if (!target_info || name.empty()) {
        return false;
    }
    for (const std::string& animation_id : eligible_anchor_animation_names(*target_info)) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        const std::size_t frame_count = anim_it->second.frame_count();
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            const AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            const auto it = std::find_if(frame->anchor_points.begin(),
                                         frame->anchor_points.end(),
                                         [&](const DisplacedAssetAnchorPoint& anchor) {
                                             return anchor.is_valid() && anchor.name == name;
                                         });
            if (it != frame->anchor_points.end()) {
                return true;
            }
        }
    }
    return false;
}

void RoomEditor::ensure_anchor_selection_valid() {
    if (!anchor_mode_active()) {
        return;
    }
    if (anchor_edit_.handles.empty()) {
        anchor_edit_.selected_anchor_name.clear();
        anchor_edit_.hovered_anchor_name.clear();
        anchor_edit_.dragging_anchor_name.clear();
        anchor_edit_.point_selected = false;
        anchor_edit_.dragging = false;
        anchor_edit_.dragging_depth = false;
        return;
    }

    auto has_anchor = [this](const std::string& name) {
        return std::find_if(anchor_edit_.handles.begin(), anchor_edit_.handles.end(),
                            [&](const AnchorHandleSample& sample) {
                                return sample.name == name;
                            }) != anchor_edit_.handles.end();
    };

    if (anchor_edit_.selected_anchor_name.empty() || !has_anchor(anchor_edit_.selected_anchor_name)) {
        anchor_edit_.selected_anchor_name.clear();
        anchor_edit_.point_selected = false;
    } else {
        anchor_edit_.point_selected = true;
    }
    if (!anchor_edit_.hovered_anchor_name.empty() && !has_anchor(anchor_edit_.hovered_anchor_name)) {
        anchor_edit_.hovered_anchor_name.clear();
    }
    if (anchor_edit_.dragging && !has_anchor(anchor_edit_.dragging_anchor_name)) {
        anchor_edit_.dragging = false;
        anchor_edit_.dragging_anchor_name.clear();
    }
    if (anchor_edit_.dragging_depth && !has_anchor(anchor_edit_.dragging_anchor_name)) {
        anchor_edit_.dragging_depth = false;
        anchor_edit_.dragging_anchor_name.clear();
    }
}

bool RoomEditor::ensure_selected_anchor_light_attachment() {
    if (!light_mode_active() || anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }

    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const bool changed = mutate_anchor_current_frame(
        [&](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* selected_anchor = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                anchor_edit_.selected_anchor_name,
                owner,
                [this](const std::string& anchor_name) {
                    return is_valid_oval_center_anchor_name(anchor_name);
                });
            if (!selected_anchor) {
                return false;
            }

            bool changed = false;
            const bool needs_attachment = !selected_anchor->has_light_data;
            if (needs_attachment) {
                selected_anchor->has_light_data = true;
                changed = true;
            }
            selected_anchor->light.sanitize();
            if (needs_attachment && !selected_anchor->light.enabled) {
                selected_anchor->light.enabled = true;
                changed = true;
            }
            return changed;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);
    if (changed && anchor_edit_.target_asset) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
            anchor_edit_.target_asset,
            anchor_edit_.selected_anchor_name);
    }
    return changed;
}

void RoomEditor::sync_anchor_tools_panel() {
    ensure_anchor_editor_widgets();
    if (!anchor_tools_panel_) {
        return;
    }

    if (!anchor_mode_active()) {
        anchor_tools_panel_->set_visible(false);
        anchor_tools_panel_->set_light_editor_mode(false);
        anchor_tools_panel_->set_anchor_names({});
        anchor_tools_panel_->set_selected_anchor({});
        anchor_tools_panel_->set_detail_values(RoomAnchorToolsPanel::DetailValues{});
        anchor_tools_panel_->set_light_values(RoomAnchorToolsPanel::LightValues{});
        if (!oval_mode_active()) {
            close_anchor_candidate_editor();
        }
        return;
    }

    std::vector<std::string> names;
    if (anchor_edit_.target_asset && anchor_edit_.target_asset->info) {
        auto anim_it = anchor_edit_.target_asset->info->animations.find(anchor_edit_.animation_id);
        if (anim_it != anchor_edit_.target_asset->info->animations.end() && anim_it->second.has_frames()) {
            const int frame_index =
                devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index, static_cast<int>(anim_it->second.frame_count()));
            AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
            if (frame) {
                names.reserve(frame->anchor_points.size());
                for (const auto& anchor : frame->anchor_points) {
                    if (anchor_visible_in_current_mode(anchor)) {
                        names.push_back(anchor.name);
                    }
                }
            }
        }
    }

    anchor_tools_panel_->set_visible(true);
    anchor_tools_panel_->set_light_editor_mode(light_mode_active());
    anchor_tools_panel_->set_anchor_names(names);
    ensure_anchor_selection_valid();
    if (light_mode_active()) {
        ensure_selected_anchor_light_attachment();
    }
    anchor_tools_panel_->set_selected_anchor(anchor_edit_.selected_anchor_name);
    auto selected_it = std::find_if(anchor_edit_.handles.begin(),
                                    anchor_edit_.handles.end(),
                                    [&](const AnchorHandleSample& handle) {
                                        return handle.name == anchor_edit_.selected_anchor_name;
                                    });
    if (selected_it != anchor_edit_.handles.end()) {
        RoomAnchorToolsPanel::DetailValues detail{};
        detail.depth_offset = selected_it->depth_offset;
        detail.flip_horizontal = selected_it->flip_horizontal;
        detail.flip_vertical = selected_it->flip_vertical;
        detail.rotation_degrees = selected_it->rotation_degrees;
        detail.hidden = selected_it->hidden;
        detail.orphan_on_end = anchor_edit_.target_asset->info->anchor_point_child_candidate_orphan_on_end(
            anchor_edit_.selected_anchor_name);
        detail.resolve_x = selected_it->resolve_x;
        detail.scaling_method = selected_it->scaling_method;
        anchor_tools_panel_->set_detail_values(detail);

        RoomAnchorToolsPanel::LightValues light_values{};
        light_values.has_light_data = light_mode_active() || selected_it->has_light_data;
        light_values.enabled = selected_it->light.enabled;
        light_values.color_r = static_cast<int>(selected_it->light.color_r);
        light_values.color_g = static_cast<int>(selected_it->light.color_g);
        light_values.color_b = static_cast<int>(selected_it->light.color_b);
        light_values.opacity = selected_it->light.opacity;
        light_values.intensity = selected_it->light.intensity;
        light_values.radius = selected_it->light.radius;
        light_values.falloff = selected_it->light.falloff;
        light_values.shadow_strength = selected_it->light.shadow_strength;
        light_values.cast_shadows = selected_it->light.cast_shadows;
        anchor_tools_panel_->set_light_values(light_values);
    } else {
        anchor_tools_panel_->set_detail_values(RoomAnchorToolsPanel::DetailValues{});
        anchor_tools_panel_->set_light_values(RoomAnchorToolsPanel::LightValues{});
    }
    sync_anchor_candidate_editor();
}

void RoomEditor::refresh_oval_mode_handles() {
    oval_edit_.handles.clear();
    oval_edit_.guide_screen_samples.clear();
    oval_edit_.center_screen_px = SDL_FPoint{0.0f, 0.0f};
    oval_edit_.has_center_screen_px = false;
    oval_edit_.center_world_x = 0.0f;
    oval_edit_.center_world_y = 0.0f;
    oval_edit_.center_world_z = 0.0f;
    oval_edit_.has_center_world = false;

    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info || !assets_) {
        return;
    }
    Asset* target = oval_edit_.target_asset;
    const auto& mappings = target->info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return;
    }
    const auto& mapping = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    if (mapping.points.empty()) {
        return;
    }

    const std::string center_anchor_name = AssetInfo::oval_center_anchor_name_for_mapping(mapping.name);
    const auto center_anchor_state = target->anchor_state(center_anchor_name,
                                                          anchor_points::GridMaterialization::None,
                                                          Asset::AnchorResolveMode::ForceRecompute);

    const SDL_Point origin_world = target->world_xy_point();
    const float fallback_world_z = static_cast<float>(target->world_z()) + target->world_z_offset();
    const int fallback_layer = target->grid_point() ? target->grid_point()->resolution_layer() : target->grid_resolution;
    const auto perspective_sample = target->runtime_perspective_sample();
    const bool fallback_has_flat_perspective =
        std::isfinite(perspective_sample.scale) && perspective_sample.scale > 0.0f;
    const float fallback_flat_perspective =
        fallback_has_flat_perspective ? std::max(0.0001f, perspective_sample.scale) : 1.0f;

    const bool center_exists = center_anchor_state.has_value() && center_anchor_state->exists;
    const float center_x = center_exists ? center_anchor_state->world_exact_pos_2d.x : static_cast<float>(origin_world.x);
    const float center_y = center_exists ? center_anchor_state->world_exact_pos_2d.y : static_cast<float>(origin_world.y);
    const float center_z = center_exists ? center_anchor_state->world_exact_z : fallback_world_z;
    const int center_layer = center_exists ? center_anchor_state->resolution_layer : fallback_layer;
    const float center_flat_perspective = center_exists ? center_anchor_state->flat_perspective_scale : fallback_flat_perspective;
    const bool center_has_flat_perspective = center_exists ? center_anchor_state->has_flat_perspective_scale : fallback_has_flat_perspective;

    SDL_FPoint center_screen{};
    if (assets_->getView().project_world_point(SDL_FPoint{center_x, center_y}, center_z, center_screen)) {
        oval_edit_.center_screen_px = center_screen;
        oval_edit_.has_center_screen_px = std::isfinite(center_screen.x) && std::isfinite(center_screen.y);
    }
    oval_edit_.center_world_x = center_x;
    oval_edit_.center_world_y = center_y;
    oval_edit_.center_world_z = center_z;
    oval_edit_.has_center_world =
        std::isfinite(center_x) &&
        std::isfinite(center_y) &&
        std::isfinite(center_z);

    constexpr int kGuideSampleCount = 72;
    oval_edit_.guide_screen_samples.reserve(kGuideSampleCount);
    for (int sample_index = 0; sample_index < kGuideSampleCount; ++sample_index) {
        const float sample_angle =
            (360.0f * static_cast<float>(sample_index)) / static_cast<float>(kGuideSampleCount);
        int offset_x = 0;
        int offset_z = 0;
        oval_anchor_math::compute_xz_offsets_from_angle(sample_angle,
                                                        mapping.width_radius_x,
                                                        mapping.height_radius_z,
                                                        offset_x,
                                                        offset_z);
        const oval_anchor_math::WorldPoint3 sample_world =
            oval_anchor_math::make_flat_xz_point(center_x, center_y, center_z, offset_x, offset_z);
        if (!sample_world.valid) {
            continue;
        }
        SDL_FPoint sample_screen{};
        if (!assets_->getView().project_world_point(SDL_FPoint{sample_world.x, sample_world.y},
                                                    sample_world.z,
                                                    sample_screen)) {
            continue;
        }
        if (!std::isfinite(sample_screen.x) || !std::isfinite(sample_screen.y)) {
            continue;
        }
        oval_edit_.guide_screen_samples.push_back(sample_screen);
    }

    oval_edit_.handles.reserve(mapping.points.size());
    for (std::size_t point_index = 0; point_index < mapping.points.size(); ++point_index) {
        const auto& point = mapping.points[point_index];
        const oval_anchor_math::WorldPoint3 flat_point =
            oval_anchor_math::make_flat_xz_point(center_x,
                                                 center_y,
                                                 center_z,
                                                 point.texture_x,
                                                 point.texture_y);
        oval_anchor_math::WorldPoint3 final_point =
            oval_anchor_math::apply_vertical_offset(flat_point, point.depth_offset);
        if (!final_point.valid) {
            final_point = flat_point;
        }

        SDL_FPoint flat_screen{};
        bool has_flat_screen =
            assets_->getView().project_world_point(SDL_FPoint{flat_point.x, flat_point.y}, flat_point.z, flat_screen) &&
            std::isfinite(flat_screen.x) &&
            std::isfinite(flat_screen.y);

        SDL_FPoint final_screen{};
        bool has_final_screen =
            assets_->getView().project_world_point(SDL_FPoint{final_point.x, final_point.y}, final_point.z, final_screen) &&
            std::isfinite(final_screen.x) &&
            std::isfinite(final_screen.y);

        OvalPointHandleSample handle{};
        handle.point_index = static_cast<int>(point_index);
        handle.angle_degrees = point.angle_degrees;
        handle.flat_screen_px = flat_screen;
        handle.has_flat_screen_px = has_flat_screen;
        handle.final_screen_px = has_final_screen ? final_screen : flat_screen;
        handle.has_final_screen_px = has_final_screen || has_flat_screen;
        const oval_anchor_math::WorldPoint3 floor_projection_point = final_point.valid ? final_point : flat_point;
        if (floor_projection_point.valid &&
            std::isfinite(floor_projection_point.x) &&
            std::isfinite(floor_projection_point.z)) {
            handle.floor_world_xz = SDL_FPoint{floor_projection_point.x, floor_projection_point.z};
            handle.has_floor_world_xz = true;
        }
        oval_edit_.handles.push_back(handle);
    }

    (void)center_layer;
    (void)center_flat_perspective;
    (void)center_has_flat_perspective;
}

bool RoomEditor::selected_oval_mapping_binding_valid() const {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }

    const Asset* target = oval_edit_.target_asset;
    const auto& mappings = target->info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }

    const AssetInfo::OvalAnchorMapping& selected_mapping =
        mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    const std::string anchor_name = vibble::strings::trim_copy(selected_mapping.name);
    if (anchor_name.empty()) {
        return false;
    }

    const auto explicit_it = std::find_if(
        target->info->anchor_point_child_candidates.begin(),
        target->info->anchor_point_child_candidates.end(),
        [&](const AssetInfo::AnchorChildPointCandidate& entry) {
            return vibble::strings::trim_copy(entry.anchor_point_name) == anchor_name;
        });
    if (explicit_it != target->info->anchor_point_child_candidates.end()) {
        const nlohmann::json normalized_entry =
            target->info->anchor_point_child_candidate_candidates(anchor_name);
        const auto candidates_it = normalized_entry.find("candidates");
        if (candidates_it == normalized_entry.end() || !candidates_it->is_array()) {
            return false;
        }
        const vibble::spawn::RuntimeCandidates runtime_candidates =
            vibble::spawn::RuntimeCandidates::from_json(*candidates_it);
        if (runtime_candidates.empty()) {
            return false;
        }
        if (assets_) {
            const vibble::spawn::RuntimeCandidates::AssetCatalogView catalog{
                &assets_->library().all(),
                false
            };
            const auto resolved =
                runtime_candidates.pick_hashed(0, catalog, vibble::spawn::ZeroWeightPolicy::NoSelection);
            if (!resolved || resolved->is_null || resolved->resolved_asset_name.empty()) {
                return false;
            }
        }
        return true;
    }

    const std::string fallback_asset = vibble::strings::trim_copy(selected_mapping.asset_name);
    if (fallback_asset.empty()) {
        return false;
    }
    if (fallback_asset == target->info->name) {
        return false;
    }
    if (assets_ && !assets_->library().get(fallback_asset)) {
        return false;
    }
    return true;
}

bool RoomEditor::resolve_selected_oval_lock_target(float& out_world_x,
                                                   float& out_world_z,
                                                   float& out_heading_radians) const {
    out_world_x = 0.0f;
    out_world_z = 0.0f;
    out_heading_radians = 0.0f;

    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info || !oval_edit_.has_center_world) {
        return false;
    }

    const auto& mappings = oval_edit_.target_asset->info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }
    const AssetInfo::OvalAnchorMapping& mapping = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];

    float world_x = 0.0f;
    float world_z = 0.0f;
    bool has_target = false;
    if (oval_edit_.selected_point_index >= 0 &&
        oval_edit_.selected_point_index < static_cast<int>(mapping.points.size())) {
        const AssetInfo::OvalAnchorPoint& point =
            mapping.points[static_cast<std::size_t>(oval_edit_.selected_point_index)];
        const float compensated_angle = normalize_oval_angle_degrees(
            point.angle_degrees - clamp_oval_radius_offset_degrees(mapping.radius_offset_degrees));
        int offset_x = 0;
        int offset_z = 0;
        oval_anchor_math::compute_xz_offsets_from_angle(compensated_angle,
                                                        mapping.width_radius_x,
                                                        mapping.height_radius_z,
                                                        offset_x,
                                                        offset_z);
        world_x = oval_edit_.center_world_x + static_cast<float>(offset_x);
        world_z = oval_edit_.center_world_z + static_cast<float>(offset_z);
        has_target = std::isfinite(world_x) && std::isfinite(world_z);
    } else {
        SDL_Point target_screen{};
        if (oval_edit_.center_selected) {
            target_screen.x = std::max(0, screen_w_ / 2);
            target_screen.y = std::max(0, screen_h_ - 1);
        } else if (input_) {
            target_screen.x = input_->getX();
            target_screen.y = input_->getY();
        } else {
            return false;
        }

        std::optional<SDL_Point> target_world;
        if (input_) {
            target_world = input_->screen_to_world(target_screen);
        }
        if (!target_world && assets_) {
            target_world = grid_point_for_screen(assets_->getView(), target_screen);
        }
        if (!target_world) {
            return false;
        }

        world_x = static_cast<float>(target_world->x);
        world_z = static_cast<float>(target_world->y);
        has_target = std::isfinite(world_x) && std::isfinite(world_z);
    }

    if (!has_target) {
        return false;
    }

    const float heading_dx = world_x - oval_edit_.center_world_x;
    const float heading_dz = world_z - oval_edit_.center_world_z;
    constexpr float kMinHeadingLengthSq = 1e-4f;
    float heading_radians = 0.0f;
    if (heading_dx * heading_dx + heading_dz * heading_dz > kMinHeadingLengthSq) {
        heading_radians = static_cast<float>(std::atan2(heading_dz, heading_dx));
    } else if (oval_edit_.target_asset && oval_edit_.target_asset->has_directional_heading_radians()) {
        heading_radians = oval_edit_.target_asset->directional_heading_radians();
    }
    if (!std::isfinite(heading_radians)) {
        return false;
    }

    out_world_x = world_x;
    out_world_z = world_z;
    out_heading_radians = heading_radians;
    return true;
}

void RoomEditor::sync_oval_attachment_lock() {
    if (!oval_mode_active()) {
        release_oval_attachment_lock();
        return;
    }

    Asset* owner = oval_edit_.target_asset;
    if (!owner || owner->dead) {
        release_oval_attachment_lock();
        return;
    }
    refresh_oval_mode_handles();

    float target_world_x = 0.0f;
    float target_world_z = 0.0f;
    float heading_radians = 0.0f;
    if (!resolve_selected_oval_lock_target(target_world_x, target_world_z, heading_radians)) {
        release_oval_attachment_lock();
        return;
    }

    if (!oval_edit_.attachment_lock_active) {
        const Asset::AnchorBasisSignature signature = owner->compute_anchor_basis_signature();
        oval_edit_.attachment_lock_active = true;
        oval_edit_.attachment_lock_had_heading = signature.directional_heading_valid;
        oval_edit_.attachment_lock_heading_radians = signature.directional_heading_radians;
        oval_edit_.attachment_lock_had_target = signature.directional_target_valid;
        oval_edit_.attachment_lock_target_world_x = signature.directional_target_world_x;
        oval_edit_.attachment_lock_target_world_z = signature.directional_target_world_z;
    }

    bool changed = false;
    changed = owner->set_directional_target_world_xz(target_world_x, target_world_z) || changed;
    changed = owner->set_directional_heading_radians(heading_radians) || changed;
    if (changed) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(owner, std::string{});
    }
}

void RoomEditor::release_oval_attachment_lock() {
    if (!oval_edit_.attachment_lock_active) {
        return;
    }

    Asset* owner = oval_edit_.target_asset;
    bool changed = false;
    if (owner && !owner->dead) {
        if (oval_edit_.attachment_lock_had_target) {
            changed = owner->set_directional_target_world_xz(oval_edit_.attachment_lock_target_world_x,
                                                             oval_edit_.attachment_lock_target_world_z) || changed;
        } else if (owner->has_directional_target_world_xz()) {
            owner->clear_directional_target_world_xz();
            changed = true;
        }

        if (oval_edit_.attachment_lock_had_heading) {
            changed = owner->set_directional_heading_radians(oval_edit_.attachment_lock_heading_radians) || changed;
        } else if (owner->has_directional_heading_radians()) {
            owner->clear_directional_heading_radians();
            changed = true;
        }

        if (changed) {
            anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(owner, std::string{});
        }
    }

    oval_edit_.attachment_lock_active = false;
    oval_edit_.attachment_lock_had_heading = false;
    oval_edit_.attachment_lock_heading_radians = 0.0f;
    oval_edit_.attachment_lock_had_target = false;
    oval_edit_.attachment_lock_target_world_x = 0.0f;
    oval_edit_.attachment_lock_target_world_z = 0.0f;
}

void RoomEditor::sync_oval_tools_panel() {
    ensure_oval_editor_widgets();
    if (!oval_tools_panel_) {
        return;
    }

    if (!oval_mode_active()) {
        oval_tools_panel_->set_visible(false);
        oval_tools_panel_->set_oval_names({});
        oval_tools_panel_->set_selected_oval_index(-1);
        oval_tools_panel_->set_point_count(0);
        oval_tools_panel_->set_selected_point_index(-1);
        oval_tools_panel_->set_asset_binding_status(RoomOvalToolsPanel::AssetBindingStatus{});
        oval_tools_panel_->set_center_anchor_status({}, false);
        oval_tools_panel_->set_center_selected(false);
        if (oval_point_child_editor_panel_) {
            oval_point_child_editor_panel_->set_visible(false);
            oval_point_child_editor_panel_->set_point_selected(false);
            oval_point_child_editor_panel_->set_resolved_asset_name({});
            oval_point_child_editor_panel_->set_recommendation_pool({});
        }
        return;
    }

    oval_tools_panel_->set_visible(true);
    if (oval_point_child_editor_panel_) {
        oval_point_child_editor_panel_->set_visible(false);
    }
    std::vector<std::string> oval_names;
    if (!oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        oval_tools_panel_->set_oval_names({});
        oval_tools_panel_->set_selected_oval_index(-1);
        oval_tools_panel_->set_point_count(0);
        oval_tools_panel_->set_selected_point_index(-1);
        oval_tools_panel_->set_asset_binding_status(RoomOvalToolsPanel::AssetBindingStatus{});
        oval_tools_panel_->set_center_selected(false);
        if (oval_point_child_editor_panel_) {
            oval_point_child_editor_panel_->set_visible(false);
            oval_point_child_editor_panel_->set_point_selected(false);
            oval_point_child_editor_panel_->set_resolved_asset_name({});
            oval_point_child_editor_panel_->set_recommendation_pool({});
        }
        return;
    }

    auto& mappings = oval_edit_.target_asset->info->oval_anchor_mappings;
    auto resolve_binding_status = [&](const AssetInfo::OvalAnchorMapping& selected_mapping) {
        RoomOvalToolsPanel::AssetBindingStatus status{};
        const Asset* target = oval_edit_.target_asset;
        if (!target || !target->info) {
            return status;
        }

        const std::string anchor_name = vibble::strings::trim_copy(selected_mapping.name);
        if (anchor_name.empty()) {
            status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Invalid;
            status.detail = "invalid oval name";
            return status;
        }

        const auto explicit_it = std::find_if(
            target->info->anchor_point_child_candidates.begin(),
            target->info->anchor_point_child_candidates.end(),
            [&](const AssetInfo::AnchorChildPointCandidate& entry) {
                return vibble::strings::trim_copy(entry.anchor_point_name) == anchor_name;
            });
        if (explicit_it != target->info->anchor_point_child_candidates.end()) {
            const nlohmann::json normalized_entry =
                target->info->anchor_point_child_candidate_candidates(anchor_name);
            const auto candidates_it = normalized_entry.find("candidates");
            if (candidates_it == normalized_entry.end() || !candidates_it->is_array()) {
                status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Invalid;
                status.detail = "explicit payload invalid";
                return status;
            }
            const vibble::spawn::RuntimeCandidates runtime_candidates =
                vibble::spawn::RuntimeCandidates::from_json(*candidates_it);
            if (runtime_candidates.empty()) {
                status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Invalid;
                status.detail = "explicit candidates empty";
                return status;
            }
            status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::ExplicitCandidates;
            if (assets_) {
                const vibble::spawn::RuntimeCandidates::AssetCatalogView catalog{
                    &assets_->library().all(),
                    false
                };
                const auto resolved =
                    runtime_candidates.pick_hashed(0, catalog, vibble::spawn::ZeroWeightPolicy::NoSelection);
                if (!resolved || resolved->is_null || resolved->resolved_asset_name.empty()) {
                    status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Missing;
                    status.detail = "explicit assets missing";
                } else {
                    status.detail = resolved->resolved_asset_name;
                }
            }
            return status;
        }

        const std::string fallback_asset = vibble::strings::trim_copy(selected_mapping.asset_name);
        if (fallback_asset.empty()) {
            status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Invalid;
            status.detail = "fallback not set";
            return status;
        }
        if (fallback_asset == target->info->name) {
            status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Invalid;
            status.detail = "fallback equals owner";
            return status;
        }
        if (assets_ && !assets_->library().get(fallback_asset)) {
            status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::Missing;
            status.detail = fallback_asset;
            return status;
        }

        status.kind = RoomOvalToolsPanel::AssetBindingStatusKind::OvalFallback;
        status.detail = fallback_asset;
        return status;
    };
    auto resolve_binding_asset_name = [&](const AssetInfo::OvalAnchorMapping& selected_mapping) -> std::string {
        const Asset* target = oval_edit_.target_asset;
        if (!target || !target->info) {
            return {};
        }
        const std::string anchor_name = vibble::strings::trim_copy(selected_mapping.name);
        if (anchor_name.empty()) {
            return {};
        }

        const auto explicit_it = std::find_if(
            target->info->anchor_point_child_candidates.begin(),
            target->info->anchor_point_child_candidates.end(),
            [&](const AssetInfo::AnchorChildPointCandidate& entry) {
                return vibble::strings::trim_copy(entry.anchor_point_name) == anchor_name;
            });
        if (explicit_it != target->info->anchor_point_child_candidates.end()) {
            const nlohmann::json normalized_entry =
                target->info->anchor_point_child_candidate_candidates(anchor_name);
            const auto candidates_it = normalized_entry.find("candidates");
            if (candidates_it == normalized_entry.end() || !candidates_it->is_array()) {
                return {};
            }
            const vibble::spawn::RuntimeCandidates runtime_candidates =
                vibble::spawn::RuntimeCandidates::from_json(*candidates_it);
            if (runtime_candidates.empty()) {
                return {};
            }
            if (assets_) {
                const vibble::spawn::RuntimeCandidates::AssetCatalogView catalog{
                    &assets_->library().all(),
                    false
                };
                const auto resolved =
                    runtime_candidates.pick_hashed(0, catalog, vibble::spawn::ZeroWeightPolicy::NoSelection);
                if (resolved && !resolved->is_null && !resolved->resolved_asset_name.empty()) {
                    return resolved->resolved_asset_name;
                }
            }
            return {};
        }

        const std::string fallback_asset = vibble::strings::trim_copy(selected_mapping.asset_name);
        if (fallback_asset.empty()) {
            return {};
        }
        if (target->info && fallback_asset == target->info->name) {
            return {};
        }
        if (assets_ && !assets_->library().get(fallback_asset)) {
            return {};
        }
        return fallback_asset;
    };
    auto build_recommendation_pool_for_asset = [&](const std::string& asset_name) {
        std::set<std::string> deduped;
        if (asset_name.empty() || !assets_) {
            return std::vector<std::string>{};
        }
        const std::shared_ptr<AssetInfo> child_info = assets_->library().get(asset_name);
        if (!child_info) {
            return std::vector<std::string>{};
        }
        for (const auto& [anim_name, animation] : child_info->animations) {
            (void)anim_name;
            for (const auto& raw_tag : animation.tags) {
                const std::string normalized = vibble::strings::to_lower_copy(vibble::strings::trim_copy(raw_tag));
                if (!normalized.empty()) {
                    deduped.insert(normalized);
                }
            }
        }
        return std::vector<std::string>(deduped.begin(), deduped.end());
    };
    oval_names.reserve(mappings.size());
    for (const auto& mapping : mappings) {
        oval_names.push_back(mapping.name);
    }
    oval_tools_panel_->set_oval_names(oval_names);

    if (oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        oval_edit_.selected_oval_index = -1;
    }
    if (oval_edit_.selected_oval_index < 0) {
        oval_edit_.selected_point_index = -1;
        oval_edit_.center_selected = false;
        oval_edit_.center_hovered = false;
        oval_edit_.center_dragging = false;
    }
    oval_tools_panel_->set_selected_oval_index(oval_edit_.selected_oval_index);

    if (oval_edit_.selected_oval_index >= 0 &&
        oval_edit_.selected_oval_index < static_cast<int>(mappings.size())) {
        const auto& mapping = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
        const std::string resolved_child_asset_name = resolve_binding_asset_name(mapping);
        RoomOvalToolsPanel::OvalProperties properties{};
        properties.name = mapping.name;
        properties.width_radius_x = mapping.width_radius_x;
        properties.height_radius_z = mapping.height_radius_z;
        properties.radius_offset_degrees = mapping.radius_offset_degrees;
        oval_tools_panel_->set_oval_properties(properties);
        oval_tools_panel_->set_asset_binding_status(resolve_binding_status(mapping));

        const std::string center_anchor_name = AssetInfo::oval_center_anchor_name_for_mapping(mapping.name);
        const bool center_present =
            oval_edit_.target_asset->current_frame && oval_edit_.target_asset->current_frame->find_anchor(center_anchor_name);
        oval_tools_panel_->set_center_anchor_status(center_anchor_name, center_present);
        if (!center_present) {
            oval_edit_.center_selected = false;
            oval_edit_.center_hovered = false;
            oval_edit_.center_dragging = false;
        }
        oval_tools_panel_->set_center_selected(center_present && oval_edit_.center_selected);
        if (center_present && oval_edit_.target_asset->current_frame) {
            if (const DisplacedAssetAnchorPoint* center_anchor =
                    oval_edit_.target_asset->current_frame->find_anchor(center_anchor_name)) {
                RoomOvalToolsPanel::CenterDetailValues center_values{};
                center_values.depth_offset = center_anchor->depth_offset;
                center_values.rotation_degrees = center_anchor->rotation_degrees;
                center_values.hidden = center_anchor->hidden;
                center_values.resolve_x = center_anchor->resolve_x;
                center_values.flip_horizontal = center_anchor->flip_horizontal;
                center_values.flip_vertical = center_anchor->flip_vertical;
                center_values.scaling_method = center_anchor->scaling_method;
                oval_tools_panel_->set_center_detail_values(center_values);
            } else {
                oval_tools_panel_->set_center_selected(false);
            }
        }

        oval_tools_panel_->set_point_count(static_cast<int>(mapping.points.size()));

        if (oval_edit_.selected_point_index < -1) {
            oval_edit_.selected_point_index = -1;
        }
        if (oval_edit_.selected_point_index >= static_cast<int>(mapping.points.size())) {
            oval_edit_.selected_point_index = mapping.points.empty() ? -1 : static_cast<int>(mapping.points.size()) - 1;
        }
        oval_tools_panel_->set_selected_point_index(oval_edit_.selected_point_index);

        if (oval_edit_.selected_point_index >= 0 &&
            oval_edit_.selected_point_index < static_cast<int>(mapping.points.size())) {
            const auto& point = mapping.points[static_cast<std::size_t>(oval_edit_.selected_point_index)];
            RoomOvalToolsPanel::PointDetailValues values{};
            values.rotation_degrees = point.rotation_degrees;
            values.hidden = point.hidden;
            values.resolve_x = point.resolve_x;
            values.scaling_method = point.scaling_method;
            oval_tools_panel_->set_point_detail_values(values);
            if (oval_point_child_editor_panel_) {
                oval_point_child_editor_panel_->set_visible(true);
                RoomOvalPointChildEditorPanel::PointDetailValues point_values{};
                point_values.rotation_degrees = point.rotation_degrees;
                point_values.hidden = point.hidden;
                point_values.resolve_x = point.resolve_x;
                point_values.scaling_method = point.scaling_method;
                point_values.tags = point.tags;
                point_values.anti_tags = point.anti_tags;
                oval_point_child_editor_panel_->set_point_selected(true);
                oval_point_child_editor_panel_->set_resolved_asset_name(resolved_child_asset_name);
                oval_point_child_editor_panel_->set_recommendation_pool(
                    build_recommendation_pool_for_asset(resolved_child_asset_name));
                oval_point_child_editor_panel_->set_point_detail_values(point_values);
            }
        } else if (oval_point_child_editor_panel_) {
            oval_point_child_editor_panel_->set_visible(false);
            oval_point_child_editor_panel_->set_point_selected(false);
            oval_point_child_editor_panel_->set_resolved_asset_name(resolved_child_asset_name);
            oval_point_child_editor_panel_->set_recommendation_pool(
                build_recommendation_pool_for_asset(resolved_child_asset_name));
        }
    } else {
        oval_edit_.selected_point_index = -1;
        oval_edit_.center_selected = false;
        oval_edit_.center_hovered = false;
        oval_edit_.center_dragging = false;
        oval_tools_panel_->set_asset_binding_status(RoomOvalToolsPanel::AssetBindingStatus{});
        oval_tools_panel_->set_center_anchor_status({}, false);
        oval_tools_panel_->set_center_selected(false);
        oval_tools_panel_->set_point_count(0);
        oval_tools_panel_->set_selected_point_index(-1);
        if (oval_point_child_editor_panel_) {
            oval_point_child_editor_panel_->set_visible(false);
            oval_point_child_editor_panel_->set_point_selected(false);
            oval_point_child_editor_panel_->set_resolved_asset_name({});
            oval_point_child_editor_panel_->set_recommendation_pool({});
        }
    }
    sync_anchor_candidate_editor();
    sync_oval_attachment_lock();
}

std::vector<std::string> RoomEditor::canonical_anchor_names_for_eligible_animations(const AssetInfo& info) const {
    std::set<std::string> canonical_names;
    for (const auto& mapping : info.oval_anchor_mappings) {
        const std::string mapping_name = vibble::strings::trim_copy(mapping.name);
        if (!mapping_name.empty()) {
            canonical_names.insert(mapping_name);
        }
        for (const auto& legacy_name : mapping.legacy_names) {
            const std::string trimmed_legacy = vibble::strings::trim_copy(legacy_name);
            if (!trimmed_legacy.empty()) {
                canonical_names.insert(trimmed_legacy);
            }
        }
    }
    for (const std::string& animation_id : eligible_anchor_animation_names(info)) {
        auto anim_it = info.animations.find(animation_id);
        if (anim_it == info.animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        const std::size_t frame_count = anim_it->second.frame_count();
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            const AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            for (const auto& anchor : frame->anchor_points) {
                if (anchor.is_valid()) {
                    canonical_names.insert(anchor.name);
                }
            }
        }
    }

    return std::vector<std::string>(canonical_names.begin(), canonical_names.end());
}

bool RoomEditor::reconcile_anchor_child_candidates_with_eligible_names(const std::shared_ptr<AssetInfo>& target_info,
                                                                       bool& changed) {
    changed = false;
    if (!target_info) {
        return false;
    }
    const std::vector<std::string> canonical_names =
        canonical_anchor_names_for_eligible_animations(*target_info);
    changed = target_info->reconcile_anchor_point_child_candidates(canonical_names);
    return true;
}

void RoomEditor::close_anchor_candidate_editor() {
    if (anchor_candidate_editor_.pie_widget) {
        anchor_candidate_editor_.pie_widget->hide_search();
    }
    if (anchor_candidate_editor_.panel) {
        anchor_candidate_editor_.panel->close();
    }
    anchor_candidate_editor_.open = false;
    anchor_candidate_editor_.anchor_name.clear();
    anchor_candidate_editor_.target_asset = nullptr;
    anchor_candidate_editor_.source_context = devmode::CandidateSourceContext::AnchorNonLight;
    anchor_candidate_editor_.open_point = SDL_Point{0, 0};
    anchor_candidate_editor_.anchor_row_rect = SDL_Rect{0, 0, 0, 0};
}

Asset* RoomEditor::active_anchor_candidate_target_asset() const {
    if (anchor_mode_active() && anchor_edit_.target_asset && anchor_edit_.target_asset->info) {
        return anchor_edit_.target_asset;
    }
    if (oval_mode_active() && oval_edit_.target_asset && oval_edit_.target_asset->info) {
        return oval_edit_.target_asset;
    }
    return nullptr;
}

bool RoomEditor::anchor_candidate_editor_mode_active() const {
    return anchor_mode_active() || oval_mode_active();
}

bool RoomEditor::validate_anchor_candidate_source_context(devmode::CandidateSourceContext source_context,
                                                          const char* operation) const {
    const char* op = operation ? operation : "unknown";
    const bool anchor_context =
        source_context == devmode::CandidateSourceContext::AnchorNonLight ||
        source_context == devmode::CandidateSourceContext::AnchorLight;
    const bool oval_context =
        source_context == devmode::CandidateSourceContext::OvalPoint ||
        source_context == devmode::CandidateSourceContext::OvalCenter;

    bool valid = false;
    if (anchor_mode_active()) {
        valid = anchor_context;
    } else if (oval_mode_active()) {
        valid = oval_context;
    }

    if (!valid) {
        SDL_Log("[RoomEditor][CandidateSourceGuard] rejected operation=%s mode=%d source=%s",
                op,
                static_cast<int>(editor_mode_),
                devmode::candidate_source_context_name(source_context));
#if !defined(FRAME_EDITOR_TEST_PUBLIC_ACCESS)
        SDL_assert(false && "RoomEditor candidate source guard rejected out-of-scope mutation");
#endif
    }
    return valid;
}

bool RoomEditor::anchor_candidate_anchor_exists_for_target(const Asset* target, const std::string& anchor_name) const {
    if (!target || !target->info || anchor_name.empty()) {
        return false;
    }
    if (anchor_mode_active()) {
        return std::any_of(anchor_edit_.handles.begin(),
                           anchor_edit_.handles.end(),
                           [&](const AnchorHandleSample& handle) {
                               return handle.name == anchor_name;
                           });
    }
    return target->info->find_oval_anchor_mapping(anchor_name, true) != nullptr;
}

void RoomEditor::layout_anchor_candidate_editor_popup() {
    if (!anchor_candidate_editor_.open || !anchor_candidate_editor_.pie_widget || !anchor_candidate_editor_.panel) {
        return;
    }

    constexpr int kPopupMargin = devmode::room_devtools_panel_style::kDefaultPanelPopupMargin;
    constexpr int kPanelPadding = 12;
    constexpr int kPanelHeaderReserve = 162;
    const int min_panel_width = 500;
    const int max_panel_width = 620;
    int panel_width = 560;
    if (screen_w_ > 0) {
        panel_width = std::clamp(panel_width, min_panel_width, std::max(min_panel_width, screen_w_ - (kPopupMargin * 2)));
        panel_width = std::min(panel_width, max_panel_width);
    }

    const int pie_width = std::max(320, panel_width - (kPanelPadding * 2));
    int panel_height = anchor_candidate_editor_.pie_widget->height_for_width(pie_width) + kPanelHeaderReserve;
    if (panel_height <= 0) {
        panel_height = 500;
    }
    if (screen_h_ > 0) {
        panel_height = std::clamp(panel_height, 360, std::max(360, screen_h_ - (kPopupMargin * 2)));
    }

    int panel_x = kPopupMargin;
    int panel_y = kPopupMargin;
    if (screen_w_ > 0) {
        panel_x = (screen_w_ - panel_width) / 2;
    }
    panel_x = std::max(kPopupMargin, panel_x);
    if (screen_w_ > 0) {
        panel_x = std::min(panel_x, std::max(kPopupMargin, screen_w_ - kPopupMargin - panel_width));
    }

    if (screen_h_ > 0) {
        panel_y = (screen_h_ - panel_height) / 2;
    }
    panel_y = std::max(kPopupMargin, panel_y);
    if (screen_h_ > 0) {
        panel_y = std::min(panel_y, std::max(kPopupMargin, screen_h_ - kPopupMargin - panel_height));
    }

    anchor_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    anchor_candidate_editor_.panel->set_visible_height(panel_height);
    anchor_candidate_editor_.panel->set_rect(SDL_Rect{panel_x, panel_y, panel_width, panel_height});
}

void RoomEditor::refresh_anchor_candidate_editor_widget() {
    if (!anchor_candidate_editor_.open || !anchor_candidate_editor_.pie_widget || !anchor_candidate_editor_.panel) {
        return;
    }
    if (!anchor_candidate_editor_mode_active() ||
        !anchor_candidate_editor_.target_asset ||
        !anchor_candidate_editor_.target_asset->info) {
        close_anchor_candidate_editor();
        return;
    }
    nlohmann::json candidate_entry =
        anchor_candidate_editor_.target_asset->info->anchor_point_child_candidate_candidates(anchor_candidate_editor_.anchor_name);
    if (!candidate_entry.is_object()) {
        candidate_entry = nlohmann::json::object();
    }
    sanitize_anchor_candidate_entry_for_source(candidate_entry, anchor_candidate_editor_.source_context);
    anchor_candidate_editor_.panel->set_title(anchor_candidate_editor_.anchor_name + " Candidates");
    anchor_candidate_editor_.pie_widget->set_candidates_from_json(candidate_entry);
    layout_anchor_candidate_editor_popup();
}

void RoomEditor::sync_anchor_candidate_editor() {
    if (!anchor_candidate_editor_.open) {
        return;
    }
    if (!anchor_candidate_editor_mode_active()) {
        close_anchor_candidate_editor();
        return;
    }
    Asset* active_target = active_anchor_candidate_target_asset();
    if (!active_target || !active_target->info) {
        close_anchor_candidate_editor();
        return;
    }
    if (anchor_candidate_editor_.target_asset && anchor_candidate_editor_.target_asset != active_target) {
        close_anchor_candidate_editor();
        return;
    }
    if (!validate_anchor_candidate_source_context(anchor_candidate_editor_.source_context,
                                                  "sync_anchor_candidate_editor")) {
        close_anchor_candidate_editor();
        return;
    }
    anchor_candidate_editor_.target_asset = active_target;
    if (anchor_candidate_editor_.anchor_name.empty()) {
        close_anchor_candidate_editor();
        return;
    }

    const bool anchor_exists =
        anchor_candidate_anchor_exists_for_target(active_target, anchor_candidate_editor_.anchor_name);
    if (!anchor_exists) {
        close_anchor_candidate_editor();
        return;
    }

    if (anchor_mode_active() && anchor_edit_.selected_anchor_name != anchor_candidate_editor_.anchor_name) {
        anchor_edit_.selected_anchor_name = anchor_candidate_editor_.anchor_name;
        anchor_edit_.point_selected = true;
        if (anchor_tools_panel_) {
            anchor_tools_panel_->set_selected_anchor(anchor_edit_.selected_anchor_name);
            anchor_tools_panel_->set_rename_text(anchor_edit_.selected_anchor_name);
        }
    }
    refresh_anchor_candidate_editor_widget();
}

void RoomEditor::open_anchor_candidate_editor(const std::string& anchor_name,
                                              SDL_Point click_point,
                                              const SDL_Rect& row_rect,
                                              devmode::CandidateSourceContext source_context) {
    Asset* target_asset = active_anchor_candidate_target_asset();
    if (anchor_name.empty() || !anchor_candidate_editor_mode_active() || !target_asset || !target_asset->info) {
        close_anchor_candidate_editor();
        return;
    }
    if (!validate_anchor_candidate_source_context(source_context, "open_anchor_candidate_editor")) {
        close_anchor_candidate_editor();
        return;
    }
    if (anchor_mode_active() && is_valid_oval_center_anchor_name(anchor_name)) {
        close_anchor_candidate_editor();
        return;
    }

    std::shared_ptr<AssetInfo> target_info = target_asset->info;
    bool reconciled = false;
    if (!reconcile_anchor_child_candidates_with_eligible_names(target_info, reconciled)) {
        return;
    }
    const nlohmann::json existing_candidate_entry =
        target_info->anchor_point_child_candidate_candidates(anchor_name);
    nlohmann::json normalized_candidate_entry = existing_candidate_entry;
    if (!normalized_candidate_entry.is_object()) {
        normalized_candidate_entry = nlohmann::json::object();
    }
    const bool normalized_changed = sanitize_anchor_candidate_entry_for_source(normalized_candidate_entry, source_context);
    const bool upserted = target_info->upsert_anchor_point_child_candidate(anchor_name,
                                                                            normalized_changed
                                                                                ? normalized_candidate_entry
                                                                                : existing_candidate_entry);
    if (reconciled || upserted) {
        (void)commit_anchor_bulk_edit(target_asset,
                                      target_info,
                                      devmode::core::DevSaveCoordinator::Priority::Debounced,
                                      false,
                                      "Anchor Candidate Reconcile",
                                      "room-anchor-candidate-reconcile");
    }

    if (!anchor_candidate_editor_.panel) {
        anchor_candidate_editor_.panel = std::make_unique<DockableCollapsible>("Anchor Candidates", true);
        anchor_candidate_editor_.panel->set_scroll_enabled(true);
        anchor_candidate_editor_.panel->set_floating_content_width(
            devmode::room_devtools_panel_style::kDefaultPanelFloatingContentWidth);
        anchor_candidate_editor_.panel->set_cell_width(devmode::room_devtools_panel_style::kDefaultPanelCellWidth);
        anchor_candidate_editor_.panel->set_row_gap(devmode::room_devtools_panel_style::kDefaultPanelRowGap);
        anchor_candidate_editor_.panel->set_col_gap(devmode::room_devtools_panel_style::kDefaultPanelColGap);
        anchor_candidate_editor_.panel->set_padding(devmode::room_devtools_panel_style::kDefaultPanelPadding);
        anchor_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    }

    if (!anchor_candidate_editor_.pie_widget) {
        anchor_candidate_editor_.pie_widget = std::make_unique<CandidateEditorPieGraphWidget>();
        anchor_candidate_editor_.pie_widget->set_on_request_layout([this]() { layout_anchor_candidate_editor_popup(); });
        // Match boundary candidate panel interaction feel.
        anchor_candidate_editor_.pie_widget->set_defer_adjust_until_release(true);
        anchor_candidate_editor_.pie_widget->set_on_regenerate({});
        anchor_candidate_editor_.pie_widget->set_on_adjust([this](int index, double delta) {
            mutate_anchor_candidate_entry(
                [index, delta](nlohmann::json& candidate_entry) -> bool {
                    if (index < 0 || std::abs(delta) < 1e-9) {
                        return false;
                    }
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    auto& candidates = candidate_entry["candidates"];
                    if (!candidates.is_array() || index >= static_cast<int>(candidates.size())) {
                        return false;
                    }
                    auto& candidate = candidates[static_cast<std::size_t>(index)];
                    if (!candidate.is_object()) {
                        candidate = nlohmann::json::object();
                    }
                    const double current_weight = std::max(0.0, vibble::spawn_group_codec::read_candidate_chance(candidate, 0.0));
                    const double next_weight = std::max(0.0, current_weight + delta);
                    if (std::fabs(current_weight - next_weight) < 1e-9) {
                        return false;
                    }
                    if (is_integral_weight(next_weight)) {
                        candidate["chance"] = static_cast<int>(std::llround(next_weight));
                    } else {
                        candidate["chance"] = next_weight;
                    }
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced,
                false,
                "Anchor Candidate Adjust",
                "room-anchor-candidate-adjust");
        });
        anchor_candidate_editor_.pie_widget->set_on_delete([this](int index) {
            DeleteIntentSummary summary{};
            summary.mode = editor_mode_;
            summary.domain_label = "anchor_point_child_candidates";
            summary.entity_type = "Anchor candidate entry";
            summary.scope_label = "selected anchor candidate list";
            summary.affected_count = (index >= 0) ? 1 : 0;
            const int index_snapshot = index;
            execute_delete_with_confirmation(
                summary,
                [this, index_snapshot]() {
                    if (index_snapshot < 0 ||
                        !anchor_candidate_editor_mode_active() ||
                        !anchor_candidate_editor_.open ||
                        !anchor_candidate_editor_.target_asset ||
                        !anchor_candidate_editor_.target_asset->info ||
                        anchor_candidate_editor_.anchor_name.empty() ||
                        !validate_anchor_candidate_source_context(anchor_candidate_editor_.source_context,
                                                                  "anchor_candidate_delete_validate")) {
                        return false;
                    }
                    nlohmann::json candidate_entry =
                        anchor_candidate_editor_.target_asset->info->anchor_point_child_candidate_candidates(
                            anchor_candidate_editor_.anchor_name);
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    const auto& candidates = candidate_entry["candidates"];
                    return candidates.is_array() &&
                           index_snapshot < static_cast<int>(candidates.size()) &&
                           !vibble::spawn_group_codec::is_null_candidate_entry(
                               candidates[static_cast<std::size_t>(index_snapshot)]);
                },
                [this, index_snapshot]() {
                    return mutate_anchor_candidate_entry(
                        [index_snapshot](nlohmann::json& candidate_entry) -> bool {
                            if (index_snapshot < 0) {
                                return false;
                            }
                            vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                            auto& candidates = candidate_entry["candidates"];
                            if (!candidates.is_array() || index_snapshot >= static_cast<int>(candidates.size())) {
                                return false;
                            }
                            if (vibble::spawn_group_codec::is_null_candidate_entry(
                                    candidates[static_cast<std::size_t>(index_snapshot)])) {
                                return false;
                            }
                            auto erase_it = candidates.begin() + static_cast<nlohmann::json::difference_type>(index_snapshot);
                            candidates.erase(erase_it);
                            return true;
                        },
                        devmode::core::DevSaveCoordinator::Priority::Debounced,
                        false,
                        "Anchor Candidate Delete",
                        "room-anchor-candidate-delete");
                });
        });
        anchor_candidate_editor_.pie_widget->set_on_add_candidate([this](const std::string& value) {
            mutate_anchor_candidate_entry(
                [value](nlohmann::json& candidate_entry) -> bool {
                    if (value.empty()) {
                        return false;
                    }
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    auto& candidates = candidate_entry["candidates"];
                    if (!candidates.is_array()) {
                        candidates = nlohmann::json::array();
                    }

                    double max_weight = 0.0;
                    for (const auto& candidate : candidates) {
                        max_weight = std::max(max_weight,
                                              std::max(0.0, vibble::spawn_group_codec::read_candidate_chance(candidate, 0.0)));
                    }
                    double new_weight = max_weight > 0.0 ? max_weight * 0.05 : 5.0;
                    if (new_weight <= 0.0 || !std::isfinite(new_weight)) {
                        new_weight = 5.0;
                    }

                    nlohmann::json new_candidate = nlohmann::json::object();
                    new_candidate["name"] = value;
                    if (is_integral_weight(new_weight)) {
                        new_candidate["chance"] = static_cast<int>(std::llround(new_weight));
                    } else {
                        new_candidate["chance"] = new_weight;
                    }
                    candidates.push_back(std::move(new_candidate));
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced,
                false,
                "Anchor Candidate Add",
                "room-anchor-candidate-add");
        });
    }

    DockableCollapsible::Rows panel_rows;
    panel_rows.push_back({anchor_candidate_editor_.pie_widget.get()});
    anchor_candidate_editor_.panel->set_rows(panel_rows);
    anchor_candidate_editor_.panel->set_title(anchor_name + " Candidates");
    anchor_candidate_editor_.panel->open();
    anchor_candidate_editor_.panel->set_visible(true);
    anchor_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});

    anchor_candidate_editor_.pie_widget->set_screen_dimensions(screen_w_, screen_h_);
    anchor_candidate_editor_.pie_widget->set_manifest_store(manifest_store_);
    anchor_candidate_editor_.pie_widget->set_assets(assets_);
    anchor_candidate_editor_.anchor_name = anchor_name;
    anchor_candidate_editor_.target_asset = target_asset;
    anchor_candidate_editor_.open_point = click_point;
    anchor_candidate_editor_.anchor_row_rect = row_rect;
    anchor_candidate_editor_.source_context = source_context;
    anchor_candidate_editor_.open = true;

    if (anchor_mode_active()) {
        anchor_edit_.selected_anchor_name = anchor_name;
        anchor_edit_.point_selected = true;
        if (anchor_tools_panel_) {
            anchor_tools_panel_->set_selected_anchor(anchor_name);
            anchor_tools_panel_->set_rename_text(anchor_name);
        }
    }

    refresh_anchor_candidate_editor_widget();
}

bool RoomEditor::mutate_anchor_candidate_entry(const std::function<bool(nlohmann::json&)>& mutator,
                                               devmode::core::DevSaveCoordinator::Priority priority,
                                               bool flush_now,
                                               const char* reason,
                                               const char* flush_tag) {
    if (!active_mode_owns_domain(OwnershipDomain::AnchorPointChildCandidates)) {
        return log_rejected_domain_mutation("mutate_anchor_candidate_entry", OwnershipDomain::AnchorPointChildCandidates);
    }
    if (!anchor_candidate_editor_mode_active() ||
        !anchor_candidate_editor_.open ||
        !anchor_candidate_editor_.target_asset ||
        !anchor_candidate_editor_.target_asset->info ||
        anchor_candidate_editor_.anchor_name.empty()) {
        return false;
    }
    if (!validate_anchor_candidate_source_context(anchor_candidate_editor_.source_context,
                                                  "mutate_anchor_candidate_entry")) {
        return false;
    }

    std::shared_ptr<AssetInfo> target_info = anchor_candidate_editor_.target_asset->info;
    const nlohmann::json original_entry =
        target_info->anchor_point_child_candidate_candidates(anchor_candidate_editor_.anchor_name);
    nlohmann::json candidate_entry = original_entry;
    if (!candidate_entry.is_object()) {
        candidate_entry = nlohmann::json::object();
    }
    if (!mutator(candidate_entry)) {
        return false;
    }
    sanitize_anchor_candidate_entry_for_source(candidate_entry, anchor_candidate_editor_.source_context);
    if (!target_info->upsert_anchor_point_child_candidate(anchor_candidate_editor_.anchor_name, candidate_entry)) {
        return false;
    }
    if (!commit_anchor_bulk_edit(anchor_candidate_editor_.target_asset,
                                 target_info,
                                 priority,
                                 flush_now,
                                 reason,
                                 flush_tag)) {
        target_info->upsert_anchor_point_child_candidate(anchor_candidate_editor_.anchor_name, original_entry);
        return false;
    }
    if (oval_mode_active()) {
        sync_oval_tools_panel();
    }
    refresh_anchor_candidate_editor_widget();
    return true;
}

bool RoomEditor::handle_anchor_candidate_editor_event(const SDL_Event& event) {
    if (!anchor_candidate_editor_mode_active() ||
        !anchor_candidate_editor_.open ||
        !anchor_candidate_editor_.pie_widget ||
        !anchor_candidate_editor_.panel) {
        return false;
    }

    CandidateEditorPieGraphWidget* widget = anchor_candidate_editor_.pie_widget.get();
    DockableCollapsible* panel = anchor_candidate_editor_.panel.get();
    if (!widget || !panel) {
        return false;
    }

    if (event.type == SDL_EVENT_KEY_DOWN &&
        event.key.key == SDLK_ESCAPE &&
        event.key.repeat == 0) {
        close_anchor_candidate_editor();
        return true;
    }

    if (widget->is_search_visible() &&
        (is_pointer_or_wheel_event(event) || is_text_or_key_event(event)) &&
        widget->handle_event(event)) {
        return true;
    }

    if (panel->handle_event(event)) {
        if (!panel->is_visible()) {
            close_anchor_candidate_editor();
        }
        return true;
    }

    if (!panel->is_visible()) {
        close_anchor_candidate_editor();
        return true;
    }

    if (is_pointer_or_wheel_event(event)) {
        int pointer_x = 0;
        int pointer_y = 0;
        if (event.type == SDL_EVENT_MOUSE_MOTION) {
            pointer_x = event.motion.x;
            pointer_y = event.motion.y;
        } else if (event.type == SDL_EVENT_MOUSE_BUTTON_DOWN || event.type == SDL_EVENT_MOUSE_BUTTON_UP) {
            pointer_x = event.button.x;
            pointer_y = event.button.y;
        } else if (event.type == SDL_EVENT_MOUSE_WHEEL) {
            sdl_mouse_util::GetMouseState(&pointer_x, &pointer_y);
        }

        if (panel->is_point_inside(pointer_x, pointer_y) || widget->is_search_point_inside(pointer_x, pointer_y)) {
            return true;
        }
    }

    return false;
}

void RoomEditor::update_anchor_candidate_editor_search(const Input& input) {
    if (!anchor_candidate_editor_.open || !anchor_candidate_editor_.pie_widget || !anchor_candidate_editor_.panel) {
        return;
    }
    if (!anchor_candidate_editor_mode_active()) {
        close_anchor_candidate_editor();
        return;
    }
    anchor_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    const int min_visible_height = 320;
    const int height_margin = 200;
    int visible_height = min_visible_height;
    if (screen_h_ > 0) {
        visible_height = std::max(min_visible_height, screen_h_ - height_margin);
    }
    anchor_candidate_editor_.panel->set_visible_height(visible_height);
    anchor_candidate_editor_.panel->update(input, screen_w_, screen_h_);
    if (!anchor_candidate_editor_.panel->is_visible()) {
        close_anchor_candidate_editor();
        return;
    }
    anchor_candidate_editor_.pie_widget->set_screen_dimensions(screen_w_, screen_h_);
    anchor_candidate_editor_.pie_widget->update_search(input);
    layout_anchor_candidate_editor_popup();
}

void RoomEditor::render_anchor_candidate_editor(SDL_Renderer* renderer) const {
    if (!renderer || !anchor_candidate_editor_mode_active() || !anchor_candidate_editor_.open || !anchor_candidate_editor_.panel) {
        return;
    }
    anchor_candidate_editor_.panel->render(renderer);
}

int RoomEditor::sanitize_floor_box_candidate_grid_resolution(int value) {
    const int clamped = vibble::grid::clamp_resolution(value);
    return std::clamp(clamped, kFloorBoxCandidateGridResolutionMin, kFloorBoxCandidateGridResolutionMax);
}

nlohmann::json RoomEditor::floor_box_candidate_entry_json_for_index(int box_index) const {
    nlohmann::json candidate_entry = default_floor_box_candidate_entry_json();
    if (!floor_box_mode_active() || !floor_box_edit_.target_asset || !floor_box_edit_.target_asset->info) {
        vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
        candidate_entry["grid_resolution"] =
            sanitize_floor_box_candidate_grid_resolution(candidate_entry.value("grid_resolution",
                                                                               kFloorBoxCandidateGridResolutionDefault));
        return candidate_entry;
    }

    const auto& boxes = floor_box_edit_.target_asset->info->floor_boxes;
    if (box_index < 0 || box_index >= static_cast<int>(boxes.size())) {
        vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
        candidate_entry["grid_resolution"] =
            sanitize_floor_box_candidate_grid_resolution(candidate_entry.value("grid_resolution",
                                                                               kFloorBoxCandidateGridResolutionDefault));
        return candidate_entry;
    }

    const auto& box = boxes[static_cast<std::size_t>(box_index)];
    if (box.candidate.has_value()) {
        candidate_entry = nlohmann::json::object();
        candidate_entry["candidates"] = box.candidate->candidates;
        candidate_entry["grid_resolution"] = box.candidate->grid_resolution;
    }

    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
    candidate_entry["grid_resolution"] =
        sanitize_floor_box_candidate_grid_resolution(candidate_entry.value("grid_resolution",
                                                                           kFloorBoxCandidateGridResolutionDefault));
    return candidate_entry;
}

void RoomEditor::close_floor_box_candidate_editor() {
    if (floor_box_candidate_editor_.pie_widget) {
        floor_box_candidate_editor_.pie_widget->hide_search();
    }
    if (floor_box_candidate_editor_.panel) {
        floor_box_candidate_editor_.panel->close();
    }
    floor_box_candidate_editor_.open = false;
    floor_box_candidate_editor_.target_asset = nullptr;
    floor_box_candidate_editor_.box_index = -1;
    floor_box_candidate_editor_.source_context = devmode::CandidateSourceContext::FloorBox;
    floor_box_candidate_editor_.open_point = SDL_Point{0, 0};
}

bool RoomEditor::floor_box_candidate_editor_mode_active() const {
    return floor_box_mode_active();
}

bool RoomEditor::floor_box_candidate_target_exists() const {
    if (!floor_box_candidate_editor_mode_active() ||
        !floor_box_candidate_editor_.target_asset ||
        !floor_box_candidate_editor_.target_asset->info) {
        return false;
    }
    if (floor_box_edit_.target_asset != floor_box_candidate_editor_.target_asset) {
        return false;
    }
    if (floor_box_candidate_editor_.box_index < 0 ||
        floor_box_candidate_editor_.box_index >=
            static_cast<int>(floor_box_candidate_editor_.target_asset->info->floor_boxes.size())) {
        return false;
    }
    if (floor_box_edit_.selected_box_index != floor_box_candidate_editor_.box_index) {
        return false;
    }
    if (!validate_floor_candidate_source_context(floor_box_candidate_editor_.source_context,
                                                 "floor_box_candidate_target_exists")) {
        return false;
    }
    return true;
}

bool RoomEditor::validate_floor_candidate_source_context(devmode::CandidateSourceContext source_context,
                                                         const char* operation) const {
    const bool valid = floor_box_mode_active() && source_context == devmode::CandidateSourceContext::FloorBox;
    if (!valid) {
        const char* op = operation ? operation : "unknown";
        SDL_Log("[RoomEditor][CandidateSourceGuard] rejected operation=%s mode=%d source=%s",
                op,
                static_cast<int>(editor_mode_),
                devmode::candidate_source_context_name(source_context));
#if !defined(FRAME_EDITOR_TEST_PUBLIC_ACCESS)
        SDL_assert(false && "RoomEditor candidate source guard rejected out-of-scope mutation");
#endif
    }
    return valid;
}

void RoomEditor::layout_floor_box_candidate_editor_popup() {
    if (!floor_box_candidate_editor_.open || !floor_box_candidate_editor_.pie_widget || !floor_box_candidate_editor_.panel) {
        return;
    }

    constexpr int kPopupMargin = devmode::room_devtools_panel_style::kDefaultPanelPopupMargin;
    constexpr int kPanelPadding = 12;
    constexpr int kPanelHeaderReserve = 162;
    const int min_panel_width = 500;
    const int max_panel_width = 620;
    int panel_width = 560;
    if (screen_w_ > 0) {
        panel_width = std::clamp(panel_width, min_panel_width, std::max(min_panel_width, screen_w_ - (kPopupMargin * 2)));
        panel_width = std::min(panel_width, max_panel_width);
    }

    const int pie_width = std::max(320, panel_width - (kPanelPadding * 2));
    int panel_height = floor_box_candidate_editor_.pie_widget->height_for_width(pie_width) + kPanelHeaderReserve;
    if (panel_height <= 0) {
        panel_height = 500;
    }
    if (screen_h_ > 0) {
        panel_height = std::clamp(panel_height, 360, std::max(360, screen_h_ - (kPopupMargin * 2)));
    }

    int panel_x = kPopupMargin;
    int panel_y = kPopupMargin;
    if (screen_w_ > 0) {
        panel_x = (screen_w_ - panel_width) / 2;
    }
    panel_x = std::max(kPopupMargin, panel_x);
    if (screen_w_ > 0) {
        panel_x = std::min(panel_x, std::max(kPopupMargin, screen_w_ - kPopupMargin - panel_width));
    }

    if (screen_h_ > 0) {
        panel_y = (screen_h_ - panel_height) / 2;
    }
    panel_y = std::max(kPopupMargin, panel_y);
    if (screen_h_ > 0) {
        panel_y = std::min(panel_y, std::max(kPopupMargin, screen_h_ - kPopupMargin - panel_height));
    }

    floor_box_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    floor_box_candidate_editor_.panel->set_visible_height(panel_height);
    floor_box_candidate_editor_.panel->set_rect(SDL_Rect{panel_x, panel_y, panel_width, panel_height});
}

void RoomEditor::refresh_floor_box_candidate_editor_widget() {
    if (!floor_box_candidate_editor_.open ||
        !floor_box_candidate_editor_.pie_widget ||
        !floor_box_candidate_editor_.panel) {
        return;
    }
    if (!floor_box_candidate_target_exists()) {
        close_floor_box_candidate_editor();
        return;
    }

    const int box_index = floor_box_candidate_editor_.box_index;
    nlohmann::json candidate_entry = floor_box_candidate_entry_json_for_index(box_index);
    if (!candidate_entry.is_object()) {
        candidate_entry = default_floor_box_candidate_entry_json();
    }
    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
    const int grid_resolution = sanitize_floor_box_candidate_grid_resolution(
        candidate_entry.value("grid_resolution", kFloorBoxCandidateGridResolutionDefault));
    candidate_entry["grid_resolution"] = grid_resolution;

    const auto& box = floor_box_candidate_editor_.target_asset->info->floor_boxes[static_cast<std::size_t>(box_index)];
    floor_box_candidate_editor_.panel->set_title(box.name + " Candidates");
    floor_box_candidate_editor_.pie_widget->set_candidates_from_json(candidate_entry);
    if (floor_box_candidate_editor_.resolution_slider) {
        floor_box_candidate_editor_.resolution_slider->set_value(grid_resolution);
    }
    layout_floor_box_candidate_editor_popup();
}

void RoomEditor::sync_floor_box_candidate_editor() {
    if (!floor_box_candidate_editor_.open) {
        return;
    }
    if (!floor_box_candidate_target_exists()) {
        close_floor_box_candidate_editor();
        return;
    }
    refresh_floor_box_candidate_editor_widget();
}

void RoomEditor::open_floor_box_candidate_editor(int box_index,
                                                 SDL_Point click_point,
                                                 devmode::CandidateSourceContext source_context) {
    if (!floor_box_candidate_editor_mode_active() ||
        !floor_box_edit_.target_asset ||
        !floor_box_edit_.target_asset->info) {
        close_floor_box_candidate_editor();
        return;
    }
    if (!validate_floor_candidate_source_context(source_context, "open_floor_box_candidate_editor")) {
        close_floor_box_candidate_editor();
        return;
    }
    if (box_index < 0 || box_index >= static_cast<int>(floor_box_edit_.target_asset->info->floor_boxes.size())) {
        close_floor_box_candidate_editor();
        return;
    }

    if (!floor_box_candidate_editor_.panel) {
        floor_box_candidate_editor_.panel = std::make_unique<DockableCollapsible>("Floor Box Candidates", true);
        floor_box_candidate_editor_.panel->set_scroll_enabled(true);
        floor_box_candidate_editor_.panel->set_floating_content_width(
            devmode::room_devtools_panel_style::kDefaultPanelFloatingContentWidth);
        floor_box_candidate_editor_.panel->set_cell_width(devmode::room_devtools_panel_style::kDefaultPanelCellWidth);
        floor_box_candidate_editor_.panel->set_row_gap(devmode::room_devtools_panel_style::kDefaultPanelRowGap);
        floor_box_candidate_editor_.panel->set_col_gap(devmode::room_devtools_panel_style::kDefaultPanelColGap);
        floor_box_candidate_editor_.panel->set_padding(devmode::room_devtools_panel_style::kDefaultPanelPadding);
        floor_box_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    }

    if (!floor_box_candidate_editor_.pie_widget) {
        floor_box_candidate_editor_.pie_widget = std::make_unique<CandidateEditorPieGraphWidget>();
        floor_box_candidate_editor_.pie_widget->set_on_request_layout([this]() { layout_floor_box_candidate_editor_popup(); });
        floor_box_candidate_editor_.pie_widget->set_defer_adjust_until_release(true);
        floor_box_candidate_editor_.pie_widget->set_on_regenerate({});
        floor_box_candidate_editor_.pie_widget->set_on_adjust([this](int index, double delta) {
            mutate_floor_box_candidate_entry(
                [index, delta](nlohmann::json& candidate_entry) -> bool {
                    if (index < 0 || std::abs(delta) < 1e-9) {
                        return false;
                    }
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    auto& candidates = candidate_entry["candidates"];
                    if (!candidates.is_array() || index >= static_cast<int>(candidates.size())) {
                        return false;
                    }
                    auto& candidate = candidates[static_cast<std::size_t>(index)];
                    if (!candidate.is_object()) {
                        candidate = nlohmann::json::object();
                    }
                    const double current_weight = std::max(0.0, vibble::spawn_group_codec::read_candidate_chance(candidate, 0.0));
                    const double next_weight = std::max(0.0, current_weight + delta);
                    if (std::fabs(current_weight - next_weight) < 1e-9) {
                        return false;
                    }
                    if (is_integral_weight(next_weight)) {
                        candidate["chance"] = static_cast<int>(std::llround(next_weight));
                    } else {
                        candidate["chance"] = next_weight;
                    }
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced,
                false,
                "Floor Box Candidate Adjust",
                "room-floor-box-candidate-adjust");
        });
        floor_box_candidate_editor_.pie_widget->set_on_delete([this](int index) {
            DeleteIntentSummary summary{};
            summary.mode = editor_mode_;
            summary.domain_label = "floor_box_candidates";
            summary.entity_type = "Floor candidate entry";
            summary.scope_label = "selected floor box candidate list";
            summary.affected_count = (index >= 0) ? 1 : 0;
            const int index_snapshot = index;
            execute_delete_with_confirmation(
                summary,
                [this, index_snapshot]() {
                    if (index_snapshot < 0 ||
                        !floor_box_candidate_target_exists() ||
                        !validate_floor_candidate_source_context(floor_box_candidate_editor_.source_context,
                                                                 "floor_candidate_delete_validate")) {
                        return false;
                    }
                    nlohmann::json candidate_entry = floor_box_candidate_entry_json_for_index(floor_box_candidate_editor_.box_index);
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    const auto& candidates = candidate_entry["candidates"];
                    return candidates.is_array() &&
                           index_snapshot < static_cast<int>(candidates.size()) &&
                           !vibble::spawn_group_codec::is_null_candidate_entry(
                               candidates[static_cast<std::size_t>(index_snapshot)]);
                },
                [this, index_snapshot]() {
                    return mutate_floor_box_candidate_entry(
                        [index_snapshot](nlohmann::json& candidate_entry) -> bool {
                            if (index_snapshot < 0) {
                                return false;
                            }
                            vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                            auto& candidates = candidate_entry["candidates"];
                            if (!candidates.is_array() || index_snapshot >= static_cast<int>(candidates.size())) {
                                return false;
                            }
                            if (vibble::spawn_group_codec::is_null_candidate_entry(
                                    candidates[static_cast<std::size_t>(index_snapshot)])) {
                                return false;
                            }
                            auto erase_it = candidates.begin() + static_cast<nlohmann::json::difference_type>(index_snapshot);
                            candidates.erase(erase_it);
                            return true;
                        },
                        devmode::core::DevSaveCoordinator::Priority::Debounced,
                        false,
                        "Floor Box Candidate Delete",
                        "room-floor-box-candidate-delete");
                });
        });
        floor_box_candidate_editor_.pie_widget->set_on_add_candidate([this](const std::string& value) {
            mutate_floor_box_candidate_entry(
                [value](nlohmann::json& candidate_entry) -> bool {
                    if (value.empty()) {
                        return false;
                    }
                    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
                    auto& candidates = candidate_entry["candidates"];
                    if (!candidates.is_array()) {
                        candidates = nlohmann::json::array();
                    }

                    double max_weight = 0.0;
                    for (const auto& candidate : candidates) {
                        max_weight = std::max(max_weight,
                                              std::max(0.0, vibble::spawn_group_codec::read_candidate_chance(candidate, 0.0)));
                    }
                    double new_weight = max_weight > 0.0 ? max_weight * 0.05 : 5.0;
                    if (new_weight <= 0.0 || !std::isfinite(new_weight)) {
                        new_weight = 5.0;
                    }

                    nlohmann::json new_candidate = nlohmann::json::object();
                    new_candidate["name"] = value;
                    if (is_integral_weight(new_weight)) {
                        new_candidate["chance"] = static_cast<int>(std::llround(new_weight));
                    } else {
                        new_candidate["chance"] = new_weight;
                    }
                    candidates.push_back(std::move(new_candidate));
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced,
                false,
                "Floor Box Candidate Add",
                "room-floor-box-candidate-add");
        });
    }

    if (!floor_box_candidate_editor_.resolution_slider) {
        floor_box_candidate_editor_.resolution_slider = std::make_unique<DMSlider>(
            "Grid Resolution",
            kFloorBoxCandidateGridResolutionMin,
            kFloorBoxCandidateGridResolutionMax,
            kFloorBoxCandidateGridResolutionDefault);
        floor_box_candidate_editor_.resolution_slider->set_on_value_changed([this](int value) {
            mutate_floor_box_candidate_entry(
                [value](nlohmann::json& candidate_entry) -> bool {
                    const int next_resolution = sanitize_floor_box_candidate_grid_resolution(value);
                    const int current_resolution = sanitize_floor_box_candidate_grid_resolution(
                        candidate_entry.value("grid_resolution", kFloorBoxCandidateGridResolutionDefault));
                    if (next_resolution == current_resolution) {
                        return false;
                    }
                    candidate_entry["grid_resolution"] = next_resolution;
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced,
                false,
                "Floor Box Candidate Resolution",
                "room-floor-box-candidate-resolution");
        });
    }
    if (!floor_box_candidate_editor_.resolution_widget) {
        floor_box_candidate_editor_.resolution_widget =
            std::make_unique<SliderWidget>(floor_box_candidate_editor_.resolution_slider.get());
    }

    floor_box_edit_.selected_box_index = box_index;
    floor_box_edit_.selected_corner_index = -1;
    sync_floor_box_tools_panel();

    DockableCollapsible::Rows panel_rows;
    panel_rows.push_back({floor_box_candidate_editor_.resolution_widget.get()});
    panel_rows.push_back({floor_box_candidate_editor_.pie_widget.get()});
    floor_box_candidate_editor_.panel->set_rows(panel_rows);
    floor_box_candidate_editor_.panel->open();
    floor_box_candidate_editor_.panel->set_visible(true);
    floor_box_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});

    floor_box_candidate_editor_.pie_widget->set_screen_dimensions(screen_w_, screen_h_);
    floor_box_candidate_editor_.pie_widget->set_manifest_store(manifest_store_);
    floor_box_candidate_editor_.pie_widget->set_assets(assets_);
    floor_box_candidate_editor_.target_asset = floor_box_edit_.target_asset;
    floor_box_candidate_editor_.box_index = box_index;
    floor_box_candidate_editor_.source_context = source_context;
    floor_box_candidate_editor_.open_point = click_point;
    floor_box_candidate_editor_.open = true;

    refresh_floor_box_candidate_editor_widget();
}

bool RoomEditor::mutate_floor_box_candidate_entry(const std::function<bool(nlohmann::json&)>& mutator,
                                                  devmode::core::DevSaveCoordinator::Priority priority,
                                                  bool flush_now,
                                                  const char* reason,
                                                  const char* flush_tag) {
    if (!active_mode_owns_domain(OwnershipDomain::FloorBoxCandidates)) {
        return log_rejected_domain_mutation("mutate_floor_box_candidate_entry", OwnershipDomain::FloorBoxCandidates);
    }
    if (!floor_box_candidate_editor_mode_active() ||
        !floor_box_candidate_editor_.open ||
        !floor_box_candidate_editor_.target_asset ||
        !floor_box_candidate_editor_.target_asset->info ||
        floor_box_candidate_editor_.box_index < 0) {
        return false;
    }
    if (!validate_floor_candidate_source_context(floor_box_candidate_editor_.source_context,
                                                 "mutate_floor_box_candidate_entry")) {
        return false;
    }

    Asset* target = floor_box_candidate_editor_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    if (!target_info) {
        return false;
    }
    auto& boxes = target_info->floor_boxes;
    const int box_index = floor_box_candidate_editor_.box_index;
    if (box_index < 0 || box_index >= static_cast<int>(boxes.size())) {
        return false;
    }

    const auto original_candidate = boxes[static_cast<std::size_t>(box_index)].candidate;
    nlohmann::json candidate_entry = floor_box_candidate_entry_json_for_index(box_index);
    if (!candidate_entry.is_object()) {
        candidate_entry = default_floor_box_candidate_entry_json();
    }
    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
    candidate_entry["grid_resolution"] = sanitize_floor_box_candidate_grid_resolution(
        candidate_entry.value("grid_resolution", kFloorBoxCandidateGridResolutionDefault));

    if (!mutator(candidate_entry)) {
        return false;
    }

    vibble::spawn_group_codec::sanitize_spawn_group_candidates(candidate_entry);
    const int grid_resolution = sanitize_floor_box_candidate_grid_resolution(
        candidate_entry.value("grid_resolution", kFloorBoxCandidateGridResolutionDefault));
    candidate_entry["grid_resolution"] = grid_resolution;

    AssetInfo::FloorBox::CandidatePayload payload{};
    payload.candidates = candidate_entry["candidates"];
    payload.grid_resolution = grid_resolution;
    boxes[static_cast<std::size_t>(box_index)].candidate = std::move(payload);
    if (!persist_floor_boxes(priority, flush_now, reason, flush_tag)) {
        boxes[static_cast<std::size_t>(box_index)].candidate = original_candidate;
        target->refresh_runtime_floor_boxes_cache();
        sync_floor_box_tools_panel();
        refresh_floor_box_candidate_editor_widget();
        return false;
    }

    target->refresh_runtime_floor_boxes_cache();
    sync_floor_box_tools_panel();
    refresh_floor_box_candidate_editor_widget();
    return true;
}

bool RoomEditor::handle_floor_box_candidate_editor_event(const SDL_Event& event) {
    if (!floor_box_candidate_editor_mode_active() ||
        !floor_box_candidate_editor_.open ||
        !floor_box_candidate_editor_.pie_widget ||
        !floor_box_candidate_editor_.panel) {
        return false;
    }

    CandidateEditorPieGraphWidget* widget = floor_box_candidate_editor_.pie_widget.get();
    DockableCollapsible* panel = floor_box_candidate_editor_.panel.get();
    if (!widget || !panel) {
        return false;
    }

    if (event.type == SDL_EVENT_KEY_DOWN &&
        event.key.key == SDLK_ESCAPE &&
        event.key.repeat == 0) {
        close_floor_box_candidate_editor();
        return true;
    }

    if (widget->is_search_visible() &&
        (is_pointer_or_wheel_event(event) || is_text_or_key_event(event)) &&
        widget->handle_event(event)) {
        return true;
    }

    if (panel->handle_event(event)) {
        if (!panel->is_visible()) {
            close_floor_box_candidate_editor();
        }
        return true;
    }

    if (!panel->is_visible()) {
        close_floor_box_candidate_editor();
        return true;
    }

    if (is_pointer_or_wheel_event(event)) {
        int pointer_x = 0;
        int pointer_y = 0;
        if (event.type == SDL_EVENT_MOUSE_MOTION) {
            pointer_x = event.motion.x;
            pointer_y = event.motion.y;
        } else if (event.type == SDL_EVENT_MOUSE_BUTTON_DOWN || event.type == SDL_EVENT_MOUSE_BUTTON_UP) {
            pointer_x = event.button.x;
            pointer_y = event.button.y;
        } else if (event.type == SDL_EVENT_MOUSE_WHEEL) {
            sdl_mouse_util::GetMouseState(&pointer_x, &pointer_y);
        }

        if (panel->is_point_inside(pointer_x, pointer_y) || widget->is_search_point_inside(pointer_x, pointer_y)) {
            return true;
        }
    }

    return false;
}

void RoomEditor::update_floor_box_candidate_editor_search(const Input& input) {
    if (!floor_box_candidate_editor_.open ||
        !floor_box_candidate_editor_.pie_widget ||
        !floor_box_candidate_editor_.panel) {
        return;
    }
    if (!floor_box_candidate_target_exists()) {
        close_floor_box_candidate_editor();
        return;
    }

    floor_box_candidate_editor_.panel->set_work_area(SDL_Rect{0, 0, screen_w_, screen_h_});
    const int min_visible_height = 360;
    const int height_margin = 180;
    int visible_height = min_visible_height;
    if (screen_h_ > 0) {
        visible_height = std::max(min_visible_height, screen_h_ - height_margin);
    }
    floor_box_candidate_editor_.panel->set_visible_height(visible_height);
    floor_box_candidate_editor_.panel->update(input, screen_w_, screen_h_);
    if (!floor_box_candidate_editor_.panel->is_visible()) {
        close_floor_box_candidate_editor();
        return;
    }

    floor_box_candidate_editor_.pie_widget->set_screen_dimensions(screen_w_, screen_h_);
    floor_box_candidate_editor_.pie_widget->update_search(input);
    layout_floor_box_candidate_editor_popup();
}

void RoomEditor::render_floor_box_candidate_editor(SDL_Renderer* renderer) const {
    if (!renderer ||
        !floor_box_candidate_editor_mode_active() ||
        !floor_box_candidate_editor_.open ||
        !floor_box_candidate_editor_.panel) {
        return;
    }
    floor_box_candidate_editor_.panel->render(renderer);
}

void RoomEditor::refresh_anchor_mode_handles() {
    anchor_edit_.handles.clear();
    if (!anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        sync_anchor_tools_panel();
        return;
    }

    auto anim_it = anchor_edit_.target_asset->info->animations.find(anchor_edit_.animation_id);
    if (anim_it == anchor_edit_.target_asset->info->animations.end() || !anim_it->second.has_frames()) {
        sync_anchor_tools_panel();
        return;
    }

    const int frame_index =
        devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index, static_cast<int>(anim_it->second.frame_count()));
    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
    if (!frame) {
        sync_anchor_tools_panel();
        return;
    }

    anchor_edit_.handles.reserve(frame->anchor_points.size());
    for (const auto& anchor : frame->anchor_points) {
        if (!anchor_visible_in_current_mode(anchor)) {
            continue;
        }
        const anchor_points::FrameAnchorSample sample =
            anchor_points::resolve_frame_anchor_sample(*anchor_edit_.target_asset,
                                                       anchor,
                                                       anchor_points::GridMaterialization::None);
        AnchorHandleSample handle{};
        handle.name = anchor.name;
        handle.texture_x = anchor.texture_x;
        handle.texture_y = anchor.texture_y;
        handle.depth_offset = anchor.depth_offset;
        handle.flip_horizontal = anchor.flip_horizontal;
        handle.flip_vertical = anchor.flip_vertical;
        handle.rotation_degrees = anchor.rotation_degrees;
        handle.hidden = anchor.hidden;
        handle.resolve_x = anchor.resolve_x;
        handle.scaling_method = anchor.scaling_method;
        handle.has_light_data = anchor.has_light_data;
        handle.light = anchor.light;
        handle.flat_screen_px = sample.flat_screen_px;
        handle.has_flat_screen_px = sample.has_flat_screen_px;
        handle.final_screen_px = sample.has_final_screen_px ? sample.final_screen_px : sample.screen_px;
        handle.has_final_screen_px = sample.has_final_screen_px ||
                                     (std::isfinite(sample.screen_px.x) && std::isfinite(sample.screen_px.y));
        if (sample.final_anchor_point.valid &&
            std::isfinite(sample.final_anchor_point.x) &&
            std::isfinite(sample.final_anchor_point.z)) {
            handle.floor_world_xz = SDL_FPoint{sample.final_anchor_point.x, sample.final_anchor_point.z};
            handle.has_floor_world_xz = true;
        } else if (!sample.resolved.missing &&
                   std::isfinite(sample.resolved.world_exact_pos_2d.x) &&
                   std::isfinite(sample.resolved.world_exact_z)) {
            handle.floor_world_xz = SDL_FPoint{sample.resolved.world_exact_pos_2d.x, sample.resolved.world_exact_z};
            handle.has_floor_world_xz = true;
        }
        anchor_edit_.handles.push_back(handle);
    }

    ensure_anchor_selection_valid();
    sync_anchor_tools_panel();
}

int RoomEditor::find_anchor_handle_at_point(SDL_Point screen_point,
                                            int radius_px,
                                            const std::string& preferred_anchor) const {
    if (!anchor_mode_active()) {
        return -1;
    }
    const float radius_sq = static_cast<float>(radius_px * radius_px);

    if (!preferred_anchor.empty()) {
        for (std::size_t i = 0; i < anchor_edit_.handles.size(); ++i) {
            const AnchorHandleSample& handle = anchor_edit_.handles[i];
            if (handle.name != preferred_anchor || !handle.has_final_screen_px) {
                continue;
            }
            const float dx = handle.final_screen_px.x - static_cast<float>(screen_point.x);
            const float dy = handle.final_screen_px.y - static_cast<float>(screen_point.y);
            const float dist_sq = dx * dx + dy * dy;
            if (dist_sq <= radius_sq) {
                return static_cast<int>(i);
            }
            break;
        }
    }

    float best_dist_sq = radius_sq;
    int best_index = -1;
    for (std::size_t i = 0; i < anchor_edit_.handles.size(); ++i) {
        const AnchorHandleSample& handle = anchor_edit_.handles[i];
        if (!handle.has_final_screen_px) {
            continue;
        }
        const float dx = handle.final_screen_px.x - static_cast<float>(screen_point.x);
        const float dy = handle.final_screen_px.y - static_cast<float>(screen_point.y);
        const float dist_sq = dx * dx + dy * dy;
        if (dist_sq <= best_dist_sq) {
            best_dist_sq = dist_sq;
            best_index = static_cast<int>(i);
        }
    }
    return best_index;
}

int RoomEditor::find_anchor_floor_crosshair_at_point(SDL_Point screen_point,
                                                     int radius_px,
                                                     int center_exclusion_px,
                                                     const std::string& preferred_anchor) const {
    if (!anchor_mode_active() || !assets_) {
        return -1;
    }
    const WarpedScreenGrid& cam = assets_->getView();
    const SDL_FPoint pointer{
        static_cast<float>(screen_point.x),
        static_cast<float>(screen_point.y),
    };
    const float max_dist_sq = static_cast<float>(radius_px * radius_px);
    const float center_exclusion_sq = static_cast<float>(center_exclusion_px * center_exclusion_px);
    constexpr float kFloorCrosshairHalfWorld = 8.0f;

    auto hit_handle = [&](const AnchorHandleSample& handle, float& out_dist_sq) -> bool {
        out_dist_sq = max_dist_sq;
        if (!handle.has_floor_world_xz) {
            return false;
        }

        SDL_FPoint center{};
        if (!project_floor_world_xz_to_screen(cam, handle.floor_world_xz, center)) {
            return false;
        }
        const float center_dx = pointer.x - center.x;
        const float center_dy = pointer.y - center.y;
        const float center_dist_sq = center_dx * center_dx + center_dy * center_dy;
        if (center_dist_sq <= center_exclusion_sq) {
            return false;
        }

        SDL_FPoint x_a{};
        SDL_FPoint x_b{};
        SDL_FPoint z_a{};
        SDL_FPoint z_b{};
        if (!project_floor_world_xz_to_screen(
                cam,
                SDL_FPoint{handle.floor_world_xz.x - kFloorCrosshairHalfWorld, handle.floor_world_xz.y},
                x_a) ||
            !project_floor_world_xz_to_screen(
                cam,
                SDL_FPoint{handle.floor_world_xz.x + kFloorCrosshairHalfWorld, handle.floor_world_xz.y},
                x_b) ||
            !project_floor_world_xz_to_screen(
                cam,
                SDL_FPoint{handle.floor_world_xz.x, handle.floor_world_xz.y - kFloorCrosshairHalfWorld},
                z_a) ||
            !project_floor_world_xz_to_screen(
                cam,
                SDL_FPoint{handle.floor_world_xz.x, handle.floor_world_xz.y + kFloorCrosshairHalfWorld},
                z_b)) {
            return false;
        }

        const float x_dist_sq = point_to_segment_distance_sq(pointer, x_a, x_b);
        const float z_dist_sq = point_to_segment_distance_sq(pointer, z_a, z_b);
        out_dist_sq = std::min(x_dist_sq, z_dist_sq);
        return out_dist_sq <= max_dist_sq;
    };

    if (!preferred_anchor.empty()) {
        for (std::size_t i = 0; i < anchor_edit_.handles.size(); ++i) {
            const AnchorHandleSample& handle = anchor_edit_.handles[i];
            if (handle.name != preferred_anchor) {
                continue;
            }
            float dist_sq = max_dist_sq;
            if (hit_handle(handle, dist_sq)) {
                return static_cast<int>(i);
            }
            break;
        }
    }

    float best_dist_sq = max_dist_sq;
    int best_index = -1;
    for (std::size_t i = 0; i < anchor_edit_.handles.size(); ++i) {
        const AnchorHandleSample& handle = anchor_edit_.handles[i];
        float dist_sq = max_dist_sq;
        if (hit_handle(handle, dist_sq) && dist_sq <= best_dist_sq) {
            best_dist_sq = dist_sq;
            best_index = static_cast<int>(i);
        }
    }
    return best_index;
}

void RoomEditor::clear_anchor_selection() {
    anchor_edit_.selected_anchor_name.clear();
    anchor_edit_.hovered_anchor_name.clear();
    anchor_edit_.dragging_anchor_name.clear();
    anchor_edit_.point_selected = false;
    anchor_edit_.dragging = false;
    anchor_edit_.dragging_depth = false;
}

bool RoomEditor::persist_anchor_current_frame(devmode::core::DevSaveCoordinator::Priority priority, bool flush_now) {
    if (!anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    auto anim_it = target->info->animations.find(anchor_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }

    const std::size_t frame_count = anim_it->second.frame_count();
    const std::size_t frame_index = static_cast<std::size_t>(
        devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index, static_cast<int>(frame_count)));
    AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
    if (!frame) {
        return false;
    }

    nlohmann::json payload = target->info->animation_payload(anchor_edit_.animation_id);
    if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                  frame_count,
                                                                  frame_index,
                                                                  frame->anchor_points)) {
        return false;
    }
    if (!target->info->upsert_animation(anchor_edit_.animation_id, payload)) {
        return false;
    }
    target->info->mark_dirty();

    nlohmann::json manifest_payload = target->info->manifest_payload();
    if (save_coordinator_ && manifest_store_) {
        save_coordinator_->enqueue_manifest_asset(
            target->info->name,
            std::move(manifest_payload),
            priority,
            "Anchor Edit",
            [this]() {
                if (assets_) {
                    assets_->mark_active_assets_dirty();
                }
            });
        if (flush_now) {
            save_coordinator_->flush_now("room-anchor-edit-exit");
            anchor_edit_.dirty_since_last_flush = false;
        }
        return true;
    }

    if (manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target->info->name, true);
        if (!session) {
            return false;
        }
        session.data() = std::move(manifest_payload);
        if (!session.commit()) {
            return false;
        }
        if (assets_) {
            assets_->mark_active_assets_dirty();
        }
        anchor_edit_.dirty_since_last_flush = false;
        return true;
    }

    return false;
}

bool RoomEditor::mutate_anchor_current_frame(
    const std::function<bool(std::vector<DisplacedAssetAnchorPoint>&)>& mutator,
    devmode::core::DevSaveCoordinator::Priority priority) {
    const OwnershipDomain domain = light_mode_active()
                                       ? OwnershipDomain::AnchorLight
                                       : OwnershipDomain::AnchorNonLight;
    if (!active_mode_owns_domain(domain)) {
        return log_rejected_domain_mutation("mutate_anchor_current_frame", domain);
    }
    if (!anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }
    auto anim_it = anchor_edit_.target_asset->info->animations.find(anchor_edit_.animation_id);
    if (anim_it == anchor_edit_.target_asset->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }
    const int frame_index =
        devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index, static_cast<int>(anim_it->second.frame_count()));

    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
    if (!frame) {
        return false;
    }

    std::vector<DisplacedAssetAnchorPoint> updated = frame->anchor_points;
    if (!mutator(updated)) {
        return false;
    }

    frame->set_anchor_points(updated);

    anchor_edit_.target_asset->refresh_frame_texture_bindings();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    anchor_edit_.dirty_since_last_flush = true;
    refresh_anchor_mode_handles();
    persist_anchor_current_frame(priority, false);
    return true;
}

bool RoomEditor::persist_hitbox_current_frame(devmode::core::DevSaveCoordinator::Priority priority, bool flush_now) {
    if (!hitbox_mode_active() || !hitbox_edit_.target_asset || !hitbox_edit_.target_asset->info) {
        return false;
    }
    if (!hitbox_edit_.target_asset->info->is_hitbox_enabled()) {
        return false;
    }

    Asset* target = hitbox_edit_.target_asset;
    auto anim_it = target->info->animations.find(hitbox_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }

    const std::size_t frame_count = anim_it->second.frame_count();
    const std::size_t frame_index = static_cast<std::size_t>(
        devmode::room_anchor_mode::wrap_index(hitbox_edit_.frame_index, static_cast<int>(frame_count)));
    AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
    if (!frame) {
        return false;
    }

    nlohmann::json payload = target->info->animation_payload(hitbox_edit_.animation_id);
    if (!devmode::room_box_payload::write_hit_box_frame_to_payload(payload,
                                                                  frame_count,
                                                                  frame_index,
                                                                  frame->hit_boxes.boxes)) {
        return false;
    }
    if (box_trace_enabled()) {
        SDL_Log("[BoxFlow][persist] kind=hitbox asset=%s anim=%s frame=%zu count=%zu ids=%s",
                target->info->name.c_str(),
                hitbox_edit_.animation_id.c_str(),
                frame_index,
                frame->hit_boxes.boxes.size(),
                box_ids_csv(frame->hit_boxes.boxes).c_str());
    }
    if (!target->info->upsert_animation(hitbox_edit_.animation_id, payload)) {
        return false;
    }
    target->info->mark_dirty();

    nlohmann::json manifest_payload = target->info->manifest_payload();
    if (save_coordinator_ && manifest_store_) {
        save_coordinator_->enqueue_manifest_asset(
            target->info->name,
            std::move(manifest_payload),
            priority,
            "Hitbox Edit",
            [this]() {
                if (assets_) {
                    assets_->mark_active_assets_dirty();
                }
            });
        if (flush_now) {
            save_coordinator_->flush_now("room-hitbox-edit-exit");
            hitbox_edit_.dirty_since_last_flush = false;
        }
        return true;
    }

    if (manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target->info->name, true);
        if (!session) {
            return false;
        }
        session.data() = std::move(manifest_payload);
        if (!session.commit()) {
            return false;
        }
        if (assets_) {
            assets_->mark_active_assets_dirty();
        }
        hitbox_edit_.dirty_since_last_flush = false;
        return true;
    }

    return false;
}

bool RoomEditor::mutate_hitbox_current_frame(
    const std::function<bool(std::vector<animation_update::FrameHitBox>&)>& mutator,
    devmode::core::DevSaveCoordinator::Priority priority,
    bool flush_now) {
    if (!active_mode_owns_domain(OwnershipDomain::HitBoxes)) {
        return log_rejected_domain_mutation("mutate_hitbox_current_frame", OwnershipDomain::HitBoxes);
    }
    if (!hitbox_mode_active() || !hitbox_edit_.target_asset || !hitbox_edit_.target_asset->info) {
        return false;
    }
    if (!hitbox_edit_.target_asset->info->is_hitbox_enabled()) {
        return false;
    }
    Asset* target = hitbox_edit_.target_asset;
    auto anim_it = target->info->animations.find(hitbox_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }
    const int frame_index = devmode::room_anchor_mode::wrap_index(
        hitbox_edit_.frame_index,
        static_cast<int>(anim_it->second.frame_count()));

    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
    if (!frame) {
        return false;
    }

    if (target->current_animation != hitbox_edit_.animation_id || target->current_frame != frame) {
        target->set_current_animation(hitbox_edit_.animation_id);
        target->current_frame = frame;
        target->set_frame_progress(0.0f);
        target->static_frame = true;
        target->refresh_frame_texture_bindings();
    }
    SDL_assert(target->current_frame == frame);

    std::vector<animation_update::FrameHitBox> updated = frame->hit_boxes.boxes;
    if (!mutator(updated)) {
        return false;
    }

    std::unordered_set<std::string> used_ids;
    for (std::size_t i = 0; i < updated.size(); ++i) {
        auto& box = updated[i];
        box.id = ensure_unique_box_id(box.id, "hitbox", frame_index, i, used_ids);
        box.type = "hitbox";
        if (box.frame_start < 0) {
            box.frame_start = frame_index;
        }
        if (box.frame_end < box.frame_start) {
            box.frame_end = box.frame_start;
        }
    }
    assert_unique_box_ids(updated, "hitbox");

    frame->set_hit_boxes(std::move(updated));

    target->refresh_runtime_box_cache_from_frame();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    if (box_trace_enabled()) {
        SDL_Log("[BoxFlow][mutate] kind=hitbox asset=%s anim=%s frame=%d count=%zu ids=%s",
                target->info ? target->info->name.c_str() : "<unknown>",
                hitbox_edit_.animation_id.c_str(),
                frame_index,
                frame->hit_boxes.boxes.size(),
                box_ids_csv(frame->hit_boxes.boxes).c_str());
    }

    hitbox_edit_.dirty_since_last_flush = true;
    sync_hitbox_tools_panel();
    persist_hitbox_current_frame(priority, flush_now);
    return true;
}

bool RoomEditor::persist_impassable_boxes(devmode::core::DevSaveCoordinator::Priority priority, bool flush_now) {
    if (!impassable_box_mode_active() || !impassable_box_edit_.target_asset || !impassable_box_edit_.target_asset->info) {
        return false;
    }
    std::shared_ptr<AssetInfo> target_info = impassable_box_edit_.target_asset->info;
    if (!target_info || !target_info->is_impassable_box_enabled()) {
        return false;
    }

    if (!persist_asset_manifest_from_info(target_info,
                                          priority,
                                          "Impassable Shape Edit",
                                          "room-impassable-shape-edit",
                                          flush_now)) {
        return false;
    }
    if (flush_now) {
        impassable_box_edit_.dirty_since_last_flush = false;
    }
    return true;
}

bool RoomEditor::mutate_impassable_shapes(
    const std::function<bool(std::vector<AssetInfo::ImpassableShape>&)>& mutator,
    devmode::core::DevSaveCoordinator::Priority priority,
    bool flush_now) {
    if (!active_mode_owns_domain(OwnershipDomain::ImpassableGeometry)) {
        return log_rejected_domain_mutation("mutate_impassable_shapes", OwnershipDomain::ImpassableGeometry);
    }
    if (!impassable_box_mode_active() || !impassable_box_edit_.target_asset || !impassable_box_edit_.target_asset->info) {
        return false;
    }
    if (!impassable_box_edit_.target_asset->info->is_impassable_box_enabled()) {
        return false;
    }

    Asset* target = impassable_box_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    std::vector<AssetInfo::ImpassableShape> updated = target_info->impassable_shapes_payload();
    if (!mutator(updated)) {
        return false;
    }

    std::unordered_set<std::string> used_ids;
    std::unordered_set<std::string> used_names;
    const int frame_index = std::max(0, impassable_box_edit_.frame_index);
    for (std::size_t i = 0; i < updated.size(); ++i) {
        auto& shape = updated[i];
        shape.id = ensure_unique_box_id(shape.id, "impassable_shape", frame_index, i, used_ids);
        std::string base_name = vibble::strings::trim_copy(shape.name);
        if (base_name.empty()) {
            base_name = "Impassable Shape";
        }
        std::string unique_name = base_name;
        int suffix = 2;
        while (!used_names.insert(unique_name).second) {
            unique_name = base_name + " " + std::to_string(suffix++);
        }
        shape.name = std::move(unique_name);
        if (shape.points.size() < 3) {
            continue;
        }
        normalize_impassable_shape_winding(shape.points);
    }

    target_info->impassable_shapes = std::move(updated);
    target_info->impassable_enabled = true;
    target_info->mark_dirty();
    target->refresh_runtime_box_cache_from_frame();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    impassable_box_edit_.dirty_since_last_flush = true;
    sync_impassable_box_tools_panel();
    persist_impassable_boxes(priority, flush_now);
    return true;
}

