bool RoomEditor::persist_specific_attack_box_frame(int frame_index,
                                                   devmode::core::DevSaveCoordinator::Priority priority) {
    if (!attack_box_mode_active() || !attack_box_edit_.target_asset || !attack_box_edit_.target_asset->info) {
        return false;
    }

    Asset* target = attack_box_edit_.target_asset;
    auto anim_it = target->info->animations.find(attack_box_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }

    const int wrapped_frame_index = devmode::room_anchor_mode::wrap_index(
        frame_index,
        static_cast<int>(anim_it->second.frame_count()));
    const int previous_frame_index = attack_box_edit_.frame_index;
    attack_box_edit_.frame_index = wrapped_frame_index;
    const bool persisted = persist_attack_box_current_frame(priority, false);
    attack_box_edit_.frame_index = previous_frame_index;
    return persisted;
}

bool RoomEditor::mutate_attack_box_current_frame(
    const std::function<bool(std::vector<animation_update::FrameAttackBox>&)>& mutator,
    devmode::core::DevSaveCoordinator::Priority priority,
    bool flush_now) {
    if (!active_mode_owns_domain(OwnershipDomain::AttackBoxes)) {
        return log_rejected_domain_mutation("mutate_attack_box_current_frame", OwnershipDomain::AttackBoxes);
    }
    if (!attack_box_mode_active() || !attack_box_edit_.target_asset || !attack_box_edit_.target_asset->info) {
        return false;
    }
    if (!attack_box_edit_.target_asset->info->is_attack_box_enabled()) {
        return false;
    }
    Asset* target = attack_box_edit_.target_asset;
    auto anim_it = target->info->animations.find(attack_box_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }
    const int frame_index = devmode::room_anchor_mode::wrap_index(
        attack_box_edit_.frame_index,
        static_cast<int>(anim_it->second.frame_count()));

    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
    if (!frame) {
        return false;
    }

    if (target->current_animation != attack_box_edit_.animation_id || target->current_frame != frame) {
        target->set_current_animation(attack_box_edit_.animation_id);
        target->current_frame = frame;
        target->set_frame_progress(0.0f);
        target->static_frame = true;
        target->refresh_frame_texture_bindings();
    }
    SDL_assert(target->current_frame == frame);

    std::vector<animation_update::FrameAttackBox> updated = frame->attack_boxes.boxes;
    if (!mutator(updated)) {
        return false;
    }

    std::unordered_set<std::string> used_ids;
    for (std::size_t i = 0; i < updated.size(); ++i) {
        auto& box = updated[i];
        box.id = ensure_unique_box_id(box.id, "attack_box", frame_index, i, used_ids);
        box.type = "attack_box";
        if (box.frame_start < 0) {
            box.frame_start = frame_index;
        }
        if (box.frame_end < box.frame_start) {
            box.frame_end = box.frame_start;
        }
        if (box.payload_id.empty()) {
            box.payload_id = box.id;
        }
        if (box.meta_json.empty()) {
            box.meta_json = "{}";
        }
        animation_update::AttackPayload payload = payload_from_attack_box(box);
        if (payload.payload_id.empty()) {
            payload.payload_id = box.payload_id;
        }
        write_payload_to_attack_box(box, payload);
    }
    assert_unique_box_ids(updated, "attack_box");

    frame->set_attack_boxes(std::move(updated));

    target->refresh_runtime_box_cache_from_frame();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    if (box_trace_enabled()) {
        SDL_Log("[BoxFlow][mutate] kind=attack_box asset=%s anim=%s frame=%d count=%zu ids=%s",
                target->info ? target->info->name.c_str() : "<unknown>",
                attack_box_edit_.animation_id.c_str(),
                frame_index,
                frame->attack_boxes.boxes.size(),
                box_ids_csv(frame->attack_boxes.boxes).c_str());
    }

    attack_box_edit_.dirty_since_last_flush = true;
    sync_attack_box_tools_panel();
    persist_attack_box_current_frame(priority, flush_now);
    return true;
}

bool RoomEditor::apply_anchor_panel_detail_update(const RoomAnchorToolsPanel::DetailValues& values) {
    if (!anchor_mode_active() || anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }
    if (!anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    float requested_depth = values.depth_offset;
    const bool requested_flip_horizontal = values.flip_horizontal;
    const bool requested_flip_vertical = values.flip_vertical;
    float requested_rotation = values.rotation_degrees;
    const bool requested_hidden = values.hidden;
    const bool requested_orphan_on_end = values.orphan_on_end;
    const bool requested_resolve_x = values.resolve_x;
    const AnchorScalingMethod requested_scaling_method = values.scaling_method;
    if (!std::isfinite(requested_depth)) {
        requested_depth = 0.0f;
    }
    if (!std::isfinite(requested_rotation)) {
        requested_rotation = 0.0f;
    }

    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };

    AnchorScalingMethod selected_scaling_method = AnchorScalingMethod::Parent;
    bool selected_scaling_method_known = false;
    auto selected_handle_it = std::find_if(
        anchor_edit_.handles.begin(),
        anchor_edit_.handles.end(),
        [&](const AnchorHandleSample& handle) {
            return handle.name == anchor_edit_.selected_anchor_name;
        });
    if (selected_handle_it != anchor_edit_.handles.end()) {
        selected_scaling_method = selected_handle_it->scaling_method;
        selected_scaling_method_known = true;
    } else {
        auto anim_it = target_info->animations.find(anchor_edit_.animation_id);
        if (anim_it != target_info->animations.end() && anim_it->second.has_frames()) {
            const int frame_index = devmode::room_anchor_mode::wrap_index(
                anchor_edit_.frame_index,
                static_cast<int>(anim_it->second.frame_count()));
            if (AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index))) {
                if (const DisplacedAssetAnchorPoint* selected_anchor = devmode::room_anchor_mode::find_anchor_in_mode(
                        frame->anchor_points,
                        anchor_edit_.selected_anchor_name,
                        owner,
                        is_reserved_anchor_name)) {
                    selected_scaling_method = selected_anchor->scaling_method;
                    selected_scaling_method_known = true;
                }
            }
        }
    }

    bool changed = false;
    std::unordered_set<std::string> anchors_to_notify;
    const bool orphan_on_end_changed =
        target_info->set_anchor_point_child_candidate_orphan_on_end(anchor_edit_.selected_anchor_name,
                                                                     requested_orphan_on_end);
    if (orphan_on_end_changed) {
        changed = true;
    }

    const bool local_changed = mutate_anchor_current_frame(
        [&](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* it = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                anchor_edit_.selected_anchor_name,
                owner,
                is_reserved_anchor_name);
            if (!it) {
                return false;
            }

            if (std::fabs(it->depth_offset - requested_depth) < 1e-4f &&
                it->flip_horizontal == requested_flip_horizontal &&
                it->flip_vertical == requested_flip_vertical &&
                std::fabs(it->rotation_degrees - requested_rotation) < 1e-4f &&
                it->hidden == requested_hidden &&
                it->resolve_x == requested_resolve_x) {
                return false;
            }

            it->depth_offset = requested_depth;
            it->flip_horizontal = requested_flip_horizontal;
            it->flip_vertical = requested_flip_vertical;
            it->rotation_degrees = requested_rotation;
            it->hidden = requested_hidden;
            it->resolve_x = requested_resolve_x;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);
    if (local_changed) {
        changed = true;
        anchors_to_notify.insert(anchor_edit_.selected_anchor_name);
    }

    const bool scaling_method_mismatch =
        !selected_scaling_method_known || selected_scaling_method != requested_scaling_method;
    if (scaling_method_mismatch) {
        bool scaling_updated_any = false;
        const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*target_info);
        for (const std::string& animation_id : eligible_ids) {
            auto anim_it = target_info->animations.find(animation_id);
            if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
                continue;
            }

            nlohmann::json payload = target_info->animation_payload(animation_id);
            const std::size_t frame_count = anim_it->second.frame_count();
            bool payload_changed = false;
            for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
                AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
                if (!frame) {
                    continue;
                }

                DisplacedAssetAnchorPoint* selected_anchor = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                    frame->anchor_points,
                    anchor_edit_.selected_anchor_name,
                    owner,
                    is_reserved_anchor_name);
                if (!selected_anchor || selected_anchor->scaling_method == requested_scaling_method) {
                    continue;
                }
                selected_anchor->scaling_method = requested_scaling_method;
                anchors_to_notify.insert(anchor_edit_.selected_anchor_name);
                frame->rebuild_anchor_lookup();
                if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                              frame_count,
                                                                              frame_index,
                                                                              frame->anchor_points)) {
                    return changed;
                }
                payload_changed = true;
                scaling_updated_any = true;
            }

            if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
                return changed;
            }
        }

        if (scaling_updated_any) {
            if (!commit_anchor_bulk_edit(target,
                                         target_info,
                                         devmode::core::DevSaveCoordinator::Priority::Debounced,
                                         false,
                                         "Anchor Scaling Method",
                                         "room-anchor-scaling-method")) {
                return changed;
            }
            changed = true;
        }
    }

    if (orphan_on_end_changed &&
        !commit_anchor_bulk_edit(target,
                                 target_info,
                                 devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Anchor Orphan On End",
                                 "room-anchor-orphan-on-end")) {
        return changed;
    }

    if (changed) {
        for (const std::string& anchor_name : anchors_to_notify) {
            if (anchor_name.empty()) {
                continue;
            }
            anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
                target,
                anchor_name);
        }
    }
    return changed;
}

bool RoomEditor::apply_anchor_panel_light_update(const RoomAnchorToolsPanel::LightValues& values) {
    if (!light_mode_active() || anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }
    if (!anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;

    AnchorLightData next_light{};
    next_light.enabled = values.enabled;
    next_light.color_r = static_cast<std::uint8_t>(std::clamp(values.color_r, 0, 255));
    next_light.color_g = static_cast<std::uint8_t>(std::clamp(values.color_g, 0, 255));
    next_light.color_b = static_cast<std::uint8_t>(std::clamp(values.color_b, 0, 255));
    next_light.opacity = values.opacity;
    next_light.intensity = values.intensity;
    next_light.radius = values.radius;
    next_light.falloff = values.falloff;
    next_light.shadow_strength = values.shadow_strength;
    next_light.cast_shadows = values.cast_shadows;
    next_light.sanitize();

    bool changed = false;
    const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*target_info);
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }

        nlohmann::json payload = target_info->animation_payload(animation_id);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            DisplacedAssetAnchorPoint* selected_anchor = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                frame->anchor_points,
                anchor_edit_.selected_anchor_name,
                owner,
                is_reserved_anchor_name);
            if (!selected_anchor) {
                continue;
            }
            const bool light_payload_changed =
                !selected_anchor->has_light_data ||
                selected_anchor->light.enabled != next_light.enabled ||
                selected_anchor->light.color_r != next_light.color_r ||
                selected_anchor->light.color_g != next_light.color_g ||
                selected_anchor->light.color_b != next_light.color_b ||
                std::fabs(selected_anchor->light.opacity - next_light.opacity) > 1e-4f ||
                std::fabs(selected_anchor->light.intensity - next_light.intensity) > 1e-4f ||
                std::fabs(selected_anchor->light.radius - next_light.radius) > 1e-4f ||
                std::fabs(selected_anchor->light.falloff - next_light.falloff) > 1e-4f ||
                std::fabs(selected_anchor->light.shadow_strength - next_light.shadow_strength) > 1e-4f ||
                selected_anchor->light.cast_shadows != next_light.cast_shadows;
            if (!light_payload_changed) {
                continue;
            }
            selected_anchor->has_light_data = true;
            selected_anchor->light = next_light;
            selected_anchor->light.sanitize();
            frame->rebuild_anchor_lookup();
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            changed = true;
        }
        if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
            return false;
        }
    }

    if (changed &&
        !commit_anchor_bulk_edit(target,
                                 target_info,
                                 devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Anchor Light Update",
                                 "room-anchor-light-update")) {
        return false;
    }

    if (changed && target) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
            target,
            anchor_edit_.selected_anchor_name);
    }
    return changed;
}

bool RoomEditor::update_anchor_depth(const std::string& anchor_name, float delta_world) {
    if (anchor_name.empty() || !std::isfinite(delta_world) || std::fabs(delta_world) < 1e-6f) {
        return false;
    }
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& name) {
        return is_valid_oval_center_anchor_name(name);
    };
    const bool changed = mutate_anchor_current_frame(
        [&](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* it = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                anchor_name,
                owner,
                is_reserved_anchor_name);
            if (!it) {
                return false;
            }
            it->depth_offset += delta_world;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);

    if (changed && anchor_edit_.target_asset) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
            anchor_edit_.target_asset,
            anchor_name);
    }
    return changed;
}

bool RoomEditor::begin_anchor_depth_drag(const std::string& anchor_name, SDL_Point screen_point) {
    if (anchor_name.empty() || !anchor_mode_active() || !assets_) {
        return false;
    }
    const auto selected_handle_it = std::find_if(
        anchor_edit_.handles.begin(),
        anchor_edit_.handles.end(),
        [&](const AnchorHandleSample& handle) {
            return handle.name == anchor_name;
        });
    if (selected_handle_it == anchor_edit_.handles.end() || !selected_handle_it->has_floor_world_xz) {
        return false;
    }

    const SDL_Point pointer_floor = grid_point_for_screen(assets_->getView(), screen_point);
    anchor_edit_.dragging_depth = true;
    anchor_edit_.dragging = false;
    anchor_edit_.dragging_anchor_name = anchor_name;
    anchor_edit_.depth_drag_start_depth_offset = selected_handle_it->depth_offset;
    anchor_edit_.depth_drag_start_floor_z = selected_handle_it->floor_world_xz.y;
    anchor_edit_.depth_drag_start_pointer_floor_z = static_cast<float>(pointer_floor.y);
    return true;
}

bool RoomEditor::drag_anchor_depth_to_screen(const std::string& anchor_name, SDL_Point screen_point) {
    if (anchor_name.empty() || !anchor_edit_.dragging_depth || !anchor_mode_active() ||
        !anchor_edit_.target_asset || !anchor_edit_.target_asset->info || !assets_) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    const SDL_Point pointer_floor = grid_point_for_screen(assets_->getView(), screen_point);
    const float target_floor_z =
        anchor_edit_.depth_drag_start_floor_z +
        (static_cast<float>(pointer_floor.y) - anchor_edit_.depth_drag_start_pointer_floor_z);

    const bool changed = mutate_anchor_current_frame(
        [&](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* it = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                anchor_name,
                devmode::room_anchor_mode::owner_from_light_mode(light_mode_active()),
                [this](const std::string& name) {
                    return is_valid_oval_center_anchor_name(name);
                });
            if (!it) {
                return false;
            }

            const auto sample = anchor_points::resolve_frame_anchor_sample(
                *target,
                *it,
                anchor_points::GridMaterialization::None);
            if (sample.resolved.missing || !sample.flat_relative_pixel_point.valid) {
                return false;
            }

            anchor_points::AnchorWorldPoint3 direction{};
            if (!anchor_points::compute_camera_to_point_ray(*target,
                                                            sample.flat_relative_pixel_point,
                                                            direction) ||
                !direction.valid ||
                !std::isfinite(direction.z) ||
                std::fabs(direction.z) <= 1e-6f) {
                return false;
            }

            const float next_depth = (target_floor_z - sample.flat_relative_pixel_point.z) / direction.z;
            if (!std::isfinite(next_depth) || std::fabs(next_depth - it->depth_offset) < 1e-4f) {
                return false;
            }
            it->depth_offset = next_depth;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);

    if (changed && target) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, anchor_name);
    }
    return changed;
}

bool RoomEditor::drag_anchor_to_screen(const std::string& anchor_name, SDL_Point screen_point) {
    if (anchor_name.empty() || !anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    auto anim_it = target->info->animations.find(anchor_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }
    const SDL_FPoint desired_screen{
        static_cast<float>(screen_point.x),
        static_cast<float>(screen_point.y)};

    const bool changed = mutate_anchor_current_frame(
        [&, desired_screen](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* it = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                anchor_name,
                devmode::room_anchor_mode::owner_from_light_mode(light_mode_active()),
                [this](const std::string& name) {
                    return is_valid_oval_center_anchor_name(name);
                });
            if (!it) {
                return false;
            }

            auto sample_screen = [&](int texture_x, int texture_y, SDL_FPoint& out_screen) {
                DisplacedAssetAnchorPoint sample_anchor = *it;
                sample_anchor.texture_x = std::max(0, texture_x);
                sample_anchor.texture_y = std::max(0, texture_y);
                const auto sample = anchor_points::resolve_frame_anchor_sample(
                    *target,
                    sample_anchor,
                    anchor_points::GridMaterialization::None);
                if (sample.resolved.missing) {
                    return false;
                }
                const SDL_FPoint projected = sample.has_final_screen_px ? sample.final_screen_px : sample.screen_px;
                if (!std::isfinite(projected.x) || !std::isfinite(projected.y)) {
                    return false;
                }
                out_screen = projected;
                return true;
            };

            const int base_x = it->texture_x;
            const int base_y = it->texture_y;
            int best_x = base_x;
            int best_y = base_y;
            if (!solve_texture_point_for_screen_target(
                    base_x,
                    base_y,
                    desired_screen,
                    sample_screen,
                    best_x,
                    best_y)) {
                return false;
            }
            if (snap_to_grid_enabled_) {
                float best_snap_dist_sq = kAnchorPointSnapRadiusPx * kAnchorPointSnapRadiusPx;
                int snap_x = best_x;
                int snap_y = best_y;
                for (const auto& candidate : anchors) {
                    if (candidate.name == anchor_name) {
                        continue;
                    }
                    const auto sample = anchor_points::resolve_frame_anchor_sample(
                        *target,
                        candidate,
                        anchor_points::GridMaterialization::None);
                    if (sample.resolved.missing) {
                        continue;
                    }
                    const SDL_FPoint candidate_screen =
                        sample.has_final_screen_px ? sample.final_screen_px : sample.screen_px;
                    if (!std::isfinite(candidate_screen.x) || !std::isfinite(candidate_screen.y)) {
                        continue;
                    }
                    const float dx = candidate_screen.x - desired_screen.x;
                    const float dy = candidate_screen.y - desired_screen.y;
                    const float dist_sq = dx * dx + dy * dy;
                    if (dist_sq <= best_snap_dist_sq) {
                        best_snap_dist_sq = dist_sq;
                        snap_x = candidate.texture_x;
                        snap_y = candidate.texture_y;
                    }
                }
                best_x = snap_x;
                best_y = snap_y;
            }

            if (it->texture_x == best_x && it->texture_y == best_y) {
                return false;
            }
            it->texture_x = best_x;
            it->texture_y = best_y;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);

    if (changed && target) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, anchor_name);
    }
    return changed;
}

std::vector<std::string> RoomEditor::eligible_anchor_animation_names(const AssetInfo& info) const {
    std::vector<std::string> names;
    names.reserve(info.animations.size());
    for (const auto& [animation_id, animation] : info.animations) {
        if (anchor_animation_is_eligible_for_edit(animation)) {
            names.push_back(animation_id);
        }
    }
    std::sort(names.begin(), names.end());
    return names;
}

bool RoomEditor::normalize_anchor_invariants_for_eligible_animations(Asset* target,
                                                                      const std::shared_ptr<AssetInfo>& target_info,
                                                                      bool& updated_any) {
    updated_any = false;
    if (!target || !target_info) {
        return false;
    }

    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*target_info);
    if (eligible_ids.empty()) {
        return true;
    }

    std::set<std::string> canonical_names;
    std::unordered_map<std::string, bool> canonical_has_light_data;
    std::unordered_map<std::string, AnchorLightData> canonical_light_data;
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        nlohmann::json payload = target_info->animation_payload(animation_id);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            std::unordered_set<std::string> seen_names;
            std::vector<DisplacedAssetAnchorPoint> deduped;
            deduped.reserve(frame->anchor_points.size());
            bool frame_changed = false;
            for (const auto& anchor : frame->anchor_points) {
                if (!devmode::room_anchor_mode::anchor_mutable_in_mode(anchor, owner, is_reserved_anchor_name)) {
                    // Preserve anchors owned by other modes (for example oval center or non-light anchors while in light mode).
                    deduped.push_back(anchor);
                    continue;
                }
                if (!seen_names.insert(anchor.name).second) {
                    frame_changed = true;
                    continue;
                }
                canonical_names.insert(anchor.name);
                auto has_light_it = canonical_has_light_data.find(anchor.name);
                if (frame_index == 0) {
                    if (has_light_it == canonical_has_light_data.end()) {
                        canonical_has_light_data.emplace(anchor.name, anchor.has_light_data);
                    }
                    if (anchor.has_light_data) {
                        AnchorLightData canonical_light = anchor.light;
                        canonical_light.sanitize();
                        canonical_light_data[anchor.name] = canonical_light;
                    }
                } else if (has_light_it == canonical_has_light_data.end()) {
                    canonical_has_light_data.emplace(anchor.name, false);
                }
                deduped.push_back(anchor);
            }
            if (!frame_changed) {
                continue;
            }
            frame->set_anchor_points(std::move(deduped));
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            updated_any = true;
        }
        if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
            return false;
        }
    }

    if (canonical_names.empty()) {
        return true;
    }

    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        nlohmann::json payload = target_info->animation_payload(animation_id);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            std::unordered_set<std::string> present_names;
            for (const auto& anchor : frame->anchor_points) {
                if (devmode::room_anchor_mode::anchor_mutable_in_mode(anchor, owner, is_reserved_anchor_name)) {
                    present_names.insert(anchor.name);
                }
            }
            std::vector<DisplacedAssetAnchorPoint> updated = frame->anchor_points;
            bool frame_changed = false;
            for (auto& anchor : updated) {
                if (!devmode::room_anchor_mode::anchor_mutable_in_mode(anchor, owner, is_reserved_anchor_name)) {
                    continue;
                }
                const auto owner_it = canonical_has_light_data.find(anchor.name);
                const bool has_canonical_light = owner_it != canonical_has_light_data.end() && owner_it->second;
                if (!has_canonical_light) {
                    if (anchor.has_light_data) {
                        anchor.has_light_data = false;
                        anchor.light.enabled = false;
                        frame_changed = true;
                    }
                    continue;
                }
                auto light_it = canonical_light_data.find(anchor.name);
                if (light_it == canonical_light_data.end()) {
                    if (anchor.has_light_data) {
                        anchor.has_light_data = false;
                        anchor.light.enabled = false;
                        frame_changed = true;
                    }
                    continue;
                }
                const AnchorLightData& desired_light = light_it->second;
                const bool light_changed =
                    !anchor.has_light_data ||
                    anchor.light.enabled != desired_light.enabled ||
                    anchor.light.color_r != desired_light.color_r ||
                    anchor.light.color_g != desired_light.color_g ||
                    anchor.light.color_b != desired_light.color_b ||
                    std::fabs(anchor.light.opacity - desired_light.opacity) > 1e-4f ||
                    std::fabs(anchor.light.intensity - desired_light.intensity) > 1e-4f ||
                    std::fabs(anchor.light.radius - desired_light.radius) > 1e-4f ||
                    std::fabs(anchor.light.falloff - desired_light.falloff) > 1e-4f ||
                    std::fabs(anchor.light.shadow_strength - desired_light.shadow_strength) > 1e-4f ||
                    anchor.light.cast_shadows != desired_light.cast_shadows;
                if (!light_changed) {
                    continue;
                }
                anchor.has_light_data = true;
                anchor.light = desired_light;
                anchor.light.sanitize();
                frame_changed = true;
            }
            for (const std::string& name : canonical_names) {
                if (present_names.find(name) != present_names.end()) {
                    continue;
                }
                const SDL_Point dims = resolve_anchor_editor_frame_dimensions(target, frame);
                DisplacedAssetAnchorPoint new_anchor =
                    devmode::room_anchor_mode::make_default_anchor_for_frame(name, dims.x, dims.y);
                const auto owner_it = canonical_has_light_data.find(name);
                if (owner_it != canonical_has_light_data.end() && owner_it->second) {
                    new_anchor.has_light_data = true;
                    auto light_it = canonical_light_data.find(name);
                    if (light_it != canonical_light_data.end()) {
                        new_anchor.light = light_it->second;
                    }
                    new_anchor.light.sanitize();
                }
                updated.push_back(std::move(new_anchor));
                frame_changed = true;
                present_names.insert(name);
            }
            if (!frame_changed) {
                continue;
            }
            frame->set_anchor_points(std::move(updated));
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            updated_any = true;
        }
        if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
            return false;
        }
    }

    return true;
}

bool RoomEditor::commit_anchor_bulk_edit(Asset* target,
                                         const std::shared_ptr<AssetInfo>& target_info,
                                         devmode::core::DevSaveCoordinator::Priority priority,
                                         bool flush_now,
                                         const char* reason,
                                         const char* flush_tag) {
    if (!target || !target_info) {
        return false;
    }

    target->refresh_frame_texture_bindings();
    refresh_anchor_mode_handles();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    target_info->mark_dirty();
    nlohmann::json manifest_payload = target_info->manifest_payload();
    if (flush_now && manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target_info->name, true);
        if (!session) {
            return false;
        }
        session.data() = manifest_payload;
        if (!session.commit()) {
            return false;
        }
        devmode::refresh_loaded_animation_instances(assets_, target_info);
        anchor_edit_.dirty_since_last_flush = false;
        return true;
    }

    if (save_coordinator_ && manifest_store_) {
        save_coordinator_->enqueue_manifest_asset(
            target_info->name,
            std::move(manifest_payload),
            priority,
            reason ? reason : "Anchor Edit",
            [assets = assets_, target_info]() {
                devmode::refresh_loaded_animation_instances(assets, target_info);
            });
        if (flush_now) {
            save_coordinator_->flush_now(flush_tag ? flush_tag : "room-anchor-bulk");
            anchor_edit_.dirty_since_last_flush = false;
        } else {
            anchor_edit_.dirty_since_last_flush = true;
        }
        return true;
    }

    if (manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target_info->name, true);
        if (!session) {
            return false;
        }
        session.data() = std::move(manifest_payload);
        if (!session.commit()) {
            return false;
        }
        devmode::refresh_loaded_animation_instances(assets_, target_info);
        anchor_edit_.dirty_since_last_flush = false;
        return true;
    }

    return false;
}

bool RoomEditor::add_anchor_in_current_frame() {
    if (!anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    bool normalized_any = false;
    if (!normalize_anchor_invariants_for_eligible_animations(target, target_info, normalized_any)) {
        return false;
    }

    const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*target_info);
    if (eligible_ids.empty()) {
        return false;
    }

    AnchorScalingMethod global_scaling_method = AnchorScalingMethod::Parent;
    bool global_scaling_method_found = false;
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        const std::size_t frame_count = anim_it->second.frame_count();
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            const AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            for (const auto& anchor : frame->anchor_points) {
                if (!devmode::room_anchor_mode::anchor_mutable_in_mode(anchor, owner, is_reserved_anchor_name)) {
                    continue;
                }
                global_scaling_method = anchor.scaling_method;
                global_scaling_method_found = true;
                break;
            }
            if (global_scaling_method_found) {
                break;
            }
        }
        if (global_scaling_method_found) {
            break;
        }
    }

    std::vector<std::string> existing_names;
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        const std::size_t frame_count = anim_it->second.frame_count();
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            const AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            for (const auto& anchor : frame->anchor_points) {
                if (anchor.is_valid()) {
                    existing_names.push_back(anchor.name);
                }
            }
        }
    }
    const std::string new_anchor_name = devmode::room_anchor_mode::next_default_anchor_name(existing_names, owner);
    if (new_anchor_name.empty()) {
        return false;
    }

    bool updated_any = normalized_any;
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        nlohmann::json payload = target_info->animation_payload(animation_id);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame || find_named_anchor(frame, new_anchor_name)) {
                continue;
            }
            std::vector<DisplacedAssetAnchorPoint> updated = frame->anchor_points;
            const SDL_Point dims = resolve_anchor_editor_frame_dimensions(target, frame);
            DisplacedAssetAnchorPoint new_anchor =
                devmode::room_anchor_mode::make_default_anchor_for_frame(new_anchor_name, dims.x, dims.y);
            new_anchor.scaling_method = global_scaling_method;
            if (owner == devmode::room_anchor_mode::AnchorPointOwner::Light) {
                new_anchor.has_light_data = true;
                new_anchor.light.sanitize();
                new_anchor.light.enabled = true;
            }
            updated.push_back(new_anchor);
            frame->set_anchor_points(std::move(updated));
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            updated_any = true;
        }
        if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
            return false;
        }
    }
    if (target_info->upsert_anchor_point_child_candidate(new_anchor_name, nlohmann::json::object())) {
        updated_any = true;
    }

    if (!updated_any) {
        return false;
    }

    anchor_edit_.selected_anchor_name = new_anchor_name;
    anchor_edit_.point_selected = true;
    if (anchor_tools_panel_) {
        anchor_tools_panel_->set_rename_text(anchor_edit_.selected_anchor_name);
    }
    if (!commit_anchor_bulk_edit(target,
                                 target_info,
                                 devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Anchor Global Add",
                                 "room-anchor-global-add")) {
        return false;
    }
    anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, new_anchor_name);
    return true;
}

bool RoomEditor::duplicate_selected_anchor_in_current_frame() {
    if (!anchor_mode_active() || anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }
    if (!anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }
    if (selected_anchor_is_oval_center()) {
        return false;
    }

    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    const std::string source_anchor_name = anchor_edit_.selected_anchor_name;
    std::string duplicated_anchor_name;
    const bool changed = mutate_anchor_current_frame(
        [&](std::vector<DisplacedAssetAnchorPoint>& anchors) {
            DisplacedAssetAnchorPoint* source_ptr = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                anchors,
                source_anchor_name,
                owner,
                is_reserved_anchor_name);
            if (!source_ptr) {
                return false;
            }
            const std::size_t source_index = static_cast<std::size_t>(std::distance(&anchors.front(), source_ptr));

            std::vector<std::string> existing_names;
            existing_names.reserve(anchors.size());
            for (const auto& anchor : anchors) {
                if (anchor.is_valid()) {
                    existing_names.push_back(anchor.name);
                }
            }

            const std::string desired_name = source_anchor_name + "_copy";
            duplicated_anchor_name = devmode::room_anchor_mode::make_unique_anchor_name(desired_name, existing_names);
            if (duplicated_anchor_name.empty()) {
                return false;
            }

            DisplacedAssetAnchorPoint duplicate = *source_ptr;
            duplicate.name = duplicated_anchor_name;
            if (owner == devmode::room_anchor_mode::AnchorPointOwner::Light) {
                duplicate.has_light_data = true;
                duplicate.light.sanitize();
            }
            anchors.insert(anchors.begin() + static_cast<std::ptrdiff_t>(source_index) + 1, duplicate);
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);

    if (!changed || duplicated_anchor_name.empty()) {
        return false;
    }

    std::shared_ptr<AssetInfo> target_info = anchor_edit_.target_asset ? anchor_edit_.target_asset->info : nullptr;
    if (target_info) {
        const nlohmann::json source_candidates =
            target_info->anchor_point_child_candidate_candidates(source_anchor_name);
        const bool source_orphan_on_end =
            target_info->anchor_point_child_candidate_orphan_on_end(source_anchor_name);
        target_info->upsert_anchor_point_child_candidate(duplicated_anchor_name, source_candidates);
        target_info->set_anchor_point_child_candidate_orphan_on_end(duplicated_anchor_name, source_orphan_on_end);
    }

    anchor_edit_.selected_anchor_name = duplicated_anchor_name;
    anchor_edit_.point_selected = true;
    if (anchor_tools_panel_) {
        anchor_tools_panel_->set_selected_anchor(duplicated_anchor_name);
        anchor_tools_panel_->set_rename_text(duplicated_anchor_name);
    }

    if (anchor_edit_.target_asset) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
            anchor_edit_.target_asset,
            source_anchor_name);
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
            anchor_edit_.target_asset,
            duplicated_anchor_name);
    }
    show_notice(std::string("Duplicated ") +
                (owner == devmode::room_anchor_mode::AnchorPointOwner::Light ? "light anchor: " : "anchor: ") +
                duplicated_anchor_name);
    return true;
}

std::unordered_set<std::string> RoomEditor::valid_oval_center_anchor_names(const AssetInfo& info) const {
    std::unordered_set<std::string> valid_names;
    const auto& mappings = info.oval_anchor_mappings;
    valid_names.reserve(mappings.size() * 2);
    for (const auto& mapping : mappings) {
        if (!mapping.valid()) {
            continue;
        }
        valid_names.insert(AssetInfo::oval_center_anchor_name_for_mapping(mapping.name));
        for (const auto& legacy_name : mapping.legacy_names) {
            valid_names.insert(AssetInfo::oval_center_anchor_name_for_mapping(legacy_name));
        }
    }
    return valid_names;
}

bool RoomEditor::selected_anchor_is_oval_center() const {
    if (!anchor_mode_active() || anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }
    return is_valid_oval_center_anchor_name(anchor_edit_.selected_anchor_name);
}

bool RoomEditor::is_valid_oval_center_anchor_name(const std::string& anchor_name) const {
    if (anchor_name.empty() ||
        !anchor_edit_.target_asset ||
        !anchor_edit_.target_asset->info ||
        !is_oval_center_anchor_name(anchor_name)) {
        return false;
    }

    const std::unordered_set<std::string> valid_names = valid_oval_center_anchor_names(*anchor_edit_.target_asset->info);
    return valid_names.find(anchor_name) != valid_names.end();
}

bool RoomEditor::rename_selected_anchor_in_current_frame(const std::string& desired_name) {
    if (!anchor_mode_active() || anchor_edit_.selected_anchor_name.empty() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    const std::string old_name = anchor_edit_.selected_anchor_name;
    if (selected_anchor_is_oval_center()) {
        show_notice("Oval center anchors are managed by Oval Anchor mode. Rename the oval object instead.");
        if (anchor_tools_panel_) {
            anchor_tools_panel_->set_rename_text(old_name);
        }
        return false;
    }
    const bool selected_anchor_visible = std::any_of(anchor_edit_.handles.begin(),
                                                     anchor_edit_.handles.end(),
                                                     [&](const AnchorHandleSample& handle) {
                                                         return handle.name == old_name;
                                                     });
    if (!selected_anchor_visible) {
        return false;
    }
    bool normalized_any = false;
    if (!normalize_anchor_invariants_for_eligible_animations(target, target_info, normalized_any)) {
        return false;
    }

    const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*target_info);
    if (eligible_ids.empty()) {
        return false;
    }

    std::vector<std::string> existing_names;
    for (const std::string& animation_id : eligible_ids) {
        auto anim_it = target_info->animations.find(animation_id);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }
        const std::size_t frame_count = anim_it->second.frame_count();
        for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
            const AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            for (const auto& anchor : frame->anchor_points) {
                if (anchor.is_valid()) {
                    existing_names.push_back(anchor.name);
                }
            }
        }
    }

    const std::string normalized_name = devmode::room_anchor_mode::make_unique_anchor_name(
        desired_name,
        existing_names,
        old_name);

    bool updated_any = normalized_any;
    if (normalized_name != old_name) {
        for (const std::string& animation_id : eligible_ids) {
            auto anim_it = target_info->animations.find(animation_id);
            if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
                continue;
            }
            nlohmann::json payload = target_info->animation_payload(animation_id);
            const std::size_t frame_count = anim_it->second.frame_count();
            bool payload_changed = false;
            for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
                AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
                if (!frame) {
                    continue;
                }
                if (!devmode::room_anchor_mode::rename_anchor_in_mode(frame->anchor_points,
                                                                      old_name,
                                                                      normalized_name,
                                                                      owner,
                                                                      is_reserved_anchor_name)) {
                    continue;
                }
                frame->rebuild_anchor_lookup();
                if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                              frame_count,
                                                                              frame_index,
                                                                              frame->anchor_points)) {
                    return false;
                }
                payload_changed = true;
                updated_any = true;
            }
            if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
                return false;
            }
        }
        const bool old_name_still_exists = anchor_name_exists_across_eligible_animations(target_info, old_name);
        if (!old_name_still_exists &&
            target_info->rename_anchor_point_child_candidate(old_name, normalized_name)) {
            updated_any = true;
        } else if (old_name_still_exists) {
            nlohmann::json existing_candidate_entry =
                target_info->anchor_point_child_candidate_candidates(old_name);
            if (!existing_candidate_entry.is_object()) {
                existing_candidate_entry = nlohmann::json::object();
            }
            if (target_info->upsert_anchor_point_child_candidate(normalized_name, existing_candidate_entry)) {
                updated_any = true;
            }
        }
        if (!anchor_name_exists_across_eligible_animations(target_info, old_name) &&
            target_info->remove_anchor_point_child_candidate(old_name)) {
            updated_any = true;
        }
    }

    if (!updated_any) {
        return false;
    }

    anchor_edit_.selected_anchor_name = normalized_name;
    anchor_edit_.point_selected = !anchor_edit_.selected_anchor_name.empty();
    if (anchor_tools_panel_) {
        anchor_tools_panel_->set_rename_text(anchor_edit_.selected_anchor_name);
    }
    if (anchor_candidate_editor_.open && anchor_candidate_editor_.anchor_name == old_name) {
        anchor_candidate_editor_.anchor_name = normalized_name;
    }
    if (!commit_anchor_bulk_edit(target,
                                 target_info,
                                 devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Anchor Global Rename",
                                  "room-anchor-global-rename")) {
        return false;
    }
    if (anchor_candidate_editor_.open) {
        sync_anchor_candidate_editor();
    }
    if (normalized_name != old_name) {
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, old_name);
        anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, normalized_name);
    }
    return true;
}

bool RoomEditor::delete_selected_anchor_in_current_frame() {
    if (!active_mode_owns_domain(OwnershipDomain::AnchorNonLight) &&
        !active_mode_owns_domain(OwnershipDomain::AnchorLight)) {
        return log_rejected_domain_mutation("delete_selected_anchor_in_current_frame",
                                            light_mode_active()
                                                ? OwnershipDomain::AnchorLight
                                                : OwnershipDomain::AnchorNonLight);
    }
    if ((!anchor_mode_active() && !light_mode_active()) ||
        anchor_edit_.selected_anchor_name.empty() ||
        !anchor_edit_.target_asset ||
        !anchor_edit_.target_asset->info) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    const std::string deleted_name = anchor_edit_.selected_anchor_name;
    if (is_valid_oval_center_anchor_name(deleted_name)) {
        show_notice("Oval center anchors are managed by Oval Anchor mode. Delete the oval object instead.");
        return false;
    }
    const auto count_affected_anchors = [&](const std::shared_ptr<AssetInfo>& info) {
        if (!info) {
            return 0;
        }
        const std::vector<std::string> eligible_ids = eligible_anchor_animation_names(*info);
        if (eligible_ids.empty()) {
            return 0;
        }
        int affected_count = 0;
        for (const std::string& animation_id : eligible_ids) {
            auto anim_it = info->animations.find(animation_id);
            if (anim_it == info->animations.end() || !anim_it->second.has_frames()) {
                continue;
            }
            const std::size_t frame_count = anim_it->second.frame_count();
            for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
                AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
                if (!frame) {
                    continue;
                }
                if (devmode::room_anchor_mode::find_anchor_in_mode(frame->anchor_points,
                                                                    deleted_name,
                                                                    owner,
                                                                    is_reserved_anchor_name) != nullptr) {
                    ++affected_count;
                }
            }
        }
        return affected_count;
    };
    const int affected_count = count_affected_anchors(target_info);
    if (affected_count <= 0) {
        return false;
    }

    DeleteIntentSummary summary{};
    summary.mode = editor_mode_;
    summary.domain_label = light_mode_active() ? "anchor_light" : "anchor_non_light";
    summary.entity_type = "Anchor";
    summary.scope_label = light_mode_active() ? "eligible light frames" : "eligible non-light frames";
    summary.affected_count = affected_count;
    const std::string deleted_name_snapshot = deleted_name;

    return execute_delete_with_confirmation(
        summary,
        [this, target, target_info, deleted_name_snapshot, count_affected_anchors]() {
            if ((!anchor_mode_active() && !light_mode_active()) ||
                (!active_mode_owns_domain(OwnershipDomain::AnchorNonLight) &&
                 !active_mode_owns_domain(OwnershipDomain::AnchorLight)) ||
                anchor_edit_.target_asset != target ||
                !target ||
                !target->info ||
                deleted_name_snapshot.empty()) {
                return false;
            }
            if (target_info != target->info) {
                return false;
            }
            return count_affected_anchors(target_info) > 0;
        },
        [this, target, target_info, owner, is_reserved_anchor_name, deleted_name_snapshot]() {
            const bool closing_open_candidate_editor =
                anchor_candidate_editor_.open && anchor_candidate_editor_.anchor_name == deleted_name_snapshot;
            bool normalized_any = false;
            if (!light_mode_active()) {
                if (!normalize_anchor_invariants_for_eligible_animations(target, target_info, normalized_any)) {
                    return false;
                }
            }
            const std::vector<std::string> perform_eligible_ids = eligible_anchor_animation_names(*target_info);
            if (perform_eligible_ids.empty()) {
                return false;
            }
            bool updated_any = normalized_any;
            for (const std::string& animation_id : perform_eligible_ids) {
                auto anim_it = target_info->animations.find(animation_id);
                if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
                    continue;
                }
                nlohmann::json payload = target_info->animation_payload(animation_id);
                const std::size_t frame_count = anim_it->second.frame_count();
                bool payload_changed = false;
                for (std::size_t frame_index = 0; frame_index < frame_count; ++frame_index) {
                    AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
                    if (!frame) {
                        continue;
                    }
                    if (!devmode::room_anchor_mode::delete_anchor_in_mode(frame->anchor_points,
                                                                          deleted_name_snapshot,
                                                                          owner,
                                                                          is_reserved_anchor_name)) {
                        continue;
                    }
                    frame->rebuild_anchor_lookup();
                    if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                                  frame_count,
                                                                                  frame_index,
                                                                                  frame->anchor_points)) {
                        return false;
                    }
                    payload_changed = true;
                    updated_any = true;
                }
                if (payload_changed && !target_info->upsert_animation(animation_id, payload)) {
                    return false;
                }
            }
            if (!anchor_name_exists_across_eligible_animations(target_info, deleted_name_snapshot) &&
                target_info->remove_anchor_point_child_candidate(deleted_name_snapshot)) {
                updated_any = true;
            }
            if (!updated_any) {
                return false;
            }
            if (closing_open_candidate_editor) {
                close_anchor_candidate_editor();
            }
            anchor_edit_.selected_anchor_name.clear();
            anchor_edit_.point_selected = false;
            if (anchor_tools_panel_) {
                anchor_tools_panel_->set_rename_text(anchor_edit_.selected_anchor_name);
            }
            if (!commit_anchor_bulk_edit(target,
                                         target_info,
                                         kDeletePersistPriority,
                                         kDeletePersistFlushNow,
                                         "Anchor Global Delete",
                                         "room-anchor-global-delete")) {
                return false;
            }
            anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, deleted_name_snapshot);
            return true;
        });
}

bool RoomEditor::persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority priority,
                                       bool flush_now,
                                       const char* reason,
                                       const char* flush_tag) {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }

    Asset* target = oval_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    target->refresh_frame_texture_bindings();
    target->mark_anchors_dirty();
    if (assets_) {
        assets_->mark_active_assets_dirty();
    }

    target_info->mark_dirty();
    nlohmann::json manifest_payload = target_info->manifest_payload();
    if (flush_now && manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target_info->name, true);
        if (!session) {
            return false;
        }
        session.data() = manifest_payload;
        if (!session.commit()) {
            return false;
        }
        devmode::refresh_loaded_animation_instances(assets_, target_info);
        oval_edit_.dirty_since_last_flush = false;
        return true;
    }

    if (save_coordinator_ && manifest_store_) {
        save_coordinator_->enqueue_manifest_asset(
            target_info->name,
            std::move(manifest_payload),
            priority,
            reason ? reason : "Oval Anchor Edit",
            [assets = assets_, target_info]() {
                devmode::refresh_loaded_animation_instances(assets, target_info);
            });
        if (flush_now) {
            save_coordinator_->flush_now(flush_tag ? flush_tag : "room-oval-anchor");
            oval_edit_.dirty_since_last_flush = false;
        } else {
            oval_edit_.dirty_since_last_flush = true;
        }
        return true;
    }

    if (manifest_store_) {
        auto session = manifest_store_->begin_asset_edit(target_info->name, true);
        if (!session) {
            return false;
        }
        session.data() = std::move(manifest_payload);
        if (!session.commit()) {
            return false;
        }
        devmode::refresh_loaded_animation_instances(assets_, target_info);
        oval_edit_.dirty_since_last_flush = false;
        return true;
    }
    return false;
}

bool RoomEditor::add_oval_mapping() {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("add_oval_mapping", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    Asset* target = oval_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;

    std::unordered_set<std::string> existing_names;
    for (const auto& mapping : target_info->oval_anchor_mappings) {
        if (mapping.valid()) {
            existing_names.insert(mapping.name);
        }
    }
    std::string name = "oval_anchorpoint_1";
    int suffix = 1;
    while (existing_names.find(name) != existing_names.end()) {
        name = "oval_anchorpoint_" + std::to_string(++suffix);
    }

    AssetInfo::OvalAnchorMapping mapping{};
    mapping.name = name;
    mapping.asset_name = target_info->name;
    mapping.width_radius_x = 48.0f;
    mapping.height_radius_z = 24.0f;
    mapping.points.reserve(4);
    for (int i = 0; i < 4; ++i) {
        AssetInfo::OvalAnchorPoint point{};
        point.angle_degrees = static_cast<float>(i) * 90.0f;
        point.rotation_degrees = 0.0f;
        point.hidden = false;
        point.resolve_x = true;
        point.scaling_method = AnchorScalingMethod::Parent;
        recompute_oval_point_from_angle(point, mapping.width_radius_x, mapping.height_radius_z);
        mapping.points.push_back(point);
    }

    if (!target_info->upsert_oval_anchor_mapping(mapping)) {
        return false;
    }
    target->invalidate_anchor_registry();

    int new_index = -1;
    for (std::size_t i = 0; i < target_info->oval_anchor_mappings.size(); ++i) {
        if (target_info->oval_anchor_mappings[i].name == mapping.name) {
            new_index = static_cast<int>(i);
            break;
        }
    }
    oval_edit_.selected_oval_index = new_index;
    oval_edit_.selected_point_index = -1;
    oval_edit_.center_selected = true;
    oval_edit_.center_hovered = false;
    oval_edit_.center_dragging = false;
    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Oval Mapping Add",
                                 "room-oval-mapping-add");
}

bool RoomEditor::delete_selected_oval_mapping() {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("delete_selected_oval_mapping", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    Asset* target = oval_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }
    const int selected_snapshot = oval_edit_.selected_oval_index;
    const std::string selected_mapping_name_snapshot =
        mappings[static_cast<std::size_t>(selected_snapshot)].name;
    DeleteIntentSummary summary{};
    summary.mode = editor_mode_;
    summary.domain_label = "oval_mapping_and_points";
    summary.entity_type = "Oval mapping";
    summary.scope_label = "current asset";
    summary.affected_count = 1;
    return execute_delete_with_confirmation(
        summary,
        [this, target, selected_snapshot, selected_mapping_name_snapshot]() {
            if (!(active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints) &&
                  oval_mode_active() &&
                  oval_edit_.target_asset == target &&
                  target &&
                  target->info)) {
                return false;
            }
            const int resolved_index = find_index_by_name_index(
                target->info->oval_anchor_mappings,
                selected_mapping_name_snapshot,
                selected_snapshot);
            return resolved_index >= 0;
        },
        [this, target, target_info, selected_snapshot, selected_mapping_name_snapshot]() {
            auto& current_mappings = target_info->oval_anchor_mappings;
            const int delete_index = find_index_by_name_index(
                current_mappings,
                selected_mapping_name_snapshot,
                selected_snapshot);
            if (delete_index < 0) {
                return false;
            }
            const std::string mapping_name = current_mappings[static_cast<std::size_t>(delete_index)].name;
            if (!target_info->remove_oval_anchor_mapping(mapping_name)) {
                return false;
            }
            target->invalidate_anchor_registry();

            oval_edit_.selected_oval_index = -1;
            oval_edit_.selected_point_index = -1;
            oval_edit_.center_selected = false;
            oval_edit_.center_hovered = false;
            oval_edit_.center_dragging = false;
            refresh_oval_mode_handles();
            sync_oval_tools_panel();
            return persist_oval_mappings(kDeletePersistPriority,
                                         kDeletePersistFlushNow,
                                         "Oval Mapping Delete",
                                         "room-oval-mapping-delete");
        });
}

bool RoomEditor::apply_selected_oval_properties(const RoomOvalToolsPanel::OvalProperties& properties) {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("apply_selected_oval_properties", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    Asset* target = oval_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }

    const AssetInfo::OvalAnchorMapping current_mapping = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    const std::string old_name = current_mapping.name;
    std::string new_name = vibble::strings::trim_copy(properties.name);
    if (new_name.empty()) {
        new_name = old_name;
    }
    const bool rename_requested = (new_name != old_name);

    bool changed = false;
    if (new_name != old_name) {
        // Live text edits rename frequently; skip legacy alias churn for each keystroke.
        changed = target_info->rename_oval_anchor_mapping(old_name, new_name, false) || changed;
    }

    const AssetInfo::OvalAnchorMapping* mapped = target_info->find_oval_anchor_mapping(new_name, false);
    if (!mapped) {
        mapped = target_info->find_oval_anchor_mapping(old_name, false);
    }
    if (!mapped) {
        return changed;
    }

    AssetInfo::OvalAnchorMapping updated = *mapped;
    const float width = std::max(1.0f, std::fabs(properties.width_radius_x));
    const float height = std::max(1.0f, std::fabs(properties.height_radius_z));
    updated.width_radius_x = width;
    updated.height_radius_z = height;
    updated.radius_offset_degrees = clamp_oval_radius_offset_degrees(properties.radius_offset_degrees);
    for (auto& point : updated.points) {
        recompute_oval_point_from_angle(point, updated.width_radius_x, updated.height_radius_z);
    }

    changed = target_info->upsert_oval_anchor_mapping(updated) || changed;
    if (!changed) {
        return false;
    }
    if (rename_requested) {
        target->invalidate_anchor_registry();
    }

    int selected_index = -1;
    for (std::size_t i = 0; i < target_info->oval_anchor_mappings.size(); ++i) {
        if (target_info->oval_anchor_mappings[i].name == updated.name) {
            selected_index = static_cast<int>(i);
            break;
        }
    }
    oval_edit_.selected_oval_index = selected_index;
    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Oval Mapping Properties",
                                 "room-oval-mapping-properties");
}

std::string RoomEditor::selected_oval_center_anchor_name() const {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return {};
    }
    const auto& mappings = oval_edit_.target_asset->info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return {};
    }
    return AssetInfo::oval_center_anchor_name_for_mapping(
        mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)].name);
}

bool RoomEditor::increment_selected_oval_point_count() {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    std::shared_ptr<AssetInfo> target_info = oval_edit_.target_asset->info;
    auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }

    AssetInfo::OvalAnchorMapping updated = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    if (updated.points.size() < 2) {
        return false;
    }

    float selected_angle = std::numeric_limits<float>::quiet_NaN();
    if (oval_edit_.selected_point_index >= 0 &&
        oval_edit_.selected_point_index < static_cast<int>(updated.points.size())) {
        selected_angle =
            normalize_oval_angle_degrees(updated.points[static_cast<std::size_t>(oval_edit_.selected_point_index)].angle_degrees);
    }

    const std::size_t previous_count = updated.points.size();
    updated.points = devmode::oval_point_topology::double_point_count(updated.points);
    if (updated.points.size() <= previous_count) {
        return false;
    }
    for (std::size_t i = previous_count; i < updated.points.size(); ++i) {
        recompute_oval_point_from_angle(updated.points[i], updated.width_radius_x, updated.height_radius_z);
    }

    if (!target_info->upsert_oval_anchor_mapping(updated)) {
        return false;
    }

    if (std::isfinite(selected_angle)) {
        oval_edit_.selected_point_index =
            nearest_oval_point_index_for_angle(updated.points, selected_angle);
    } else if (oval_edit_.selected_point_index >= 0 && !updated.points.empty()) {
        oval_edit_.selected_point_index =
            std::clamp(oval_edit_.selected_point_index, 0, static_cast<int>(updated.points.size()) - 1);
    } else {
        oval_edit_.selected_point_index = -1;
    }

    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Oval Point Count Increment",
                                 "room-oval-point-count-inc");
}

bool RoomEditor::decrement_selected_oval_point_count() {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    std::shared_ptr<AssetInfo> target_info = oval_edit_.target_asset->info;
    auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }

    AssetInfo::OvalAnchorMapping updated = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    if (updated.points.size() <= 4) {
        return false;
    }

    float selected_angle = std::numeric_limits<float>::quiet_NaN();
    if (oval_edit_.selected_point_index >= 0 &&
        oval_edit_.selected_point_index < static_cast<int>(updated.points.size())) {
        selected_angle =
            normalize_oval_angle_degrees(updated.points[static_cast<std::size_t>(oval_edit_.selected_point_index)].angle_degrees);
    }

    const std::size_t current_count = updated.points.size();
    const std::vector<AssetInfo::OvalAnchorPoint> next_points =
        devmode::oval_point_topology::halve_point_count(updated.points);
    if (next_points.size() >= current_count) {
        return false;
    }

    updated.points = next_points;
    if (!target_info->upsert_oval_anchor_mapping(updated)) {
        return false;
    }

    if (std::isfinite(selected_angle)) {
        oval_edit_.selected_point_index =
            nearest_oval_point_index_for_angle(updated.points, selected_angle);
    } else if (oval_edit_.selected_point_index >= 0 && !updated.points.empty()) {
        oval_edit_.selected_point_index =
            std::clamp(oval_edit_.selected_point_index, 0, static_cast<int>(updated.points.size()) - 1);
    } else {
        oval_edit_.selected_point_index = -1;
    }

    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Oval Point Count Decrement",
                                 "room-oval-point-count-dec");
}

bool RoomEditor::apply_selected_oval_point_details(const RoomOvalToolsPanel::PointDetailValues& values) {
    return apply_selected_oval_point_details_with_tags(values, {}, {}, false);
}

bool RoomEditor::apply_selected_oval_point_details_with_tags(const RoomOvalToolsPanel::PointDetailValues& values,
                                                             const std::vector<std::string>& tags,
                                                             const std::vector<std::string>& anti_tags,
                                                             bool apply_tag_override) {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("apply_selected_oval_point_details", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    std::shared_ptr<AssetInfo> target_info = oval_edit_.target_asset->info;
    auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }

    AssetInfo::OvalAnchorMapping updated = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)];
    if (oval_edit_.selected_point_index < 0 ||
        oval_edit_.selected_point_index >= static_cast<int>(updated.points.size())) {
        return false;
    }

    auto& point = updated.points[static_cast<std::size_t>(oval_edit_.selected_point_index)];
    const bool changed =
        point.rotation_degrees != values.rotation_degrees ||
        point.hidden != values.hidden ||
        point.resolve_x != values.resolve_x ||
        point.scaling_method != values.scaling_method ||
        (apply_tag_override && (point.tags != tags || point.anti_tags != anti_tags));
    if (!changed) {
        return false;
    }

    point.rotation_degrees = values.rotation_degrees;
    point.hidden = values.hidden;
    point.resolve_x = values.resolve_x;
    point.scaling_method = values.scaling_method;
    if (apply_tag_override) {
        point.tags = tags;
        point.anti_tags = anti_tags;
    }
    if (!target_info->upsert_oval_anchor_mapping(updated)) {
        return false;
    }
    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Debounced,
                                 false,
                                 "Oval Point Update",
                                 "room-oval-point-update");
}

bool RoomEditor::mutate_selected_oval_center_anchor(
    const std::function<bool(DisplacedAssetAnchorPoint&)>& mutator,
    devmode::core::DevSaveCoordinator::Priority priority) {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("mutate_selected_oval_center_anchor", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    const std::string center_anchor_name = selected_oval_center_anchor_name();
    if (center_anchor_name.empty()) {
        return false;
    }

    Asset* target = oval_edit_.target_asset;
    auto anim_it = target->info->animations.find(oval_edit_.animation_id);
    if (anim_it == target->info->animations.end() || !anim_it->second.has_frames()) {
        return false;
    }

    const int frame_index =
        devmode::room_anchor_mode::wrap_index(oval_edit_.frame_index, static_cast<int>(anim_it->second.frame_count()));
    AnimationFrame* frame = anim_it->second.primary_frame_at(static_cast<std::size_t>(frame_index));
    if (!frame) {
        return false;
    }

    std::vector<DisplacedAssetAnchorPoint> updated = frame->anchor_points;
    auto anchor_it = std::find_if(updated.begin(),
                                  updated.end(),
                                  [&](const DisplacedAssetAnchorPoint& anchor) {
                                      return anchor.name == center_anchor_name;
                                  });
    if (anchor_it == updated.end()) {
        return false;
    }
    if (!mutator(*anchor_it)) {
        return false;
    }

    frame->set_anchor_points(updated);
    nlohmann::json payload = target->info->animation_payload(oval_edit_.animation_id);
    if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                  anim_it->second.frame_count(),
                                                                  static_cast<std::size_t>(frame_index),
                                                                  frame->anchor_points)) {
        return false;
    }
    if (!target->info->upsert_animation(oval_edit_.animation_id, payload)) {
        return false;
    }

    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, center_anchor_name);
    return persist_oval_mappings(priority,
                                 false,
                                 "Oval Center Update",
                                 "room-oval-center-update");
}

bool RoomEditor::apply_selected_oval_center_details(const RoomOvalToolsPanel::CenterDetailValues& values) {
    if (!oval_mode_active() || !oval_edit_.center_selected) {
        return false;
    }
    return mutate_selected_oval_center_anchor(
        [&](DisplacedAssetAnchorPoint& center_anchor) {
            float requested_depth = std::isfinite(values.depth_offset) ? values.depth_offset : 0.0f;
            float requested_rotation = std::isfinite(values.rotation_degrees) ? values.rotation_degrees : 0.0f;

            if (std::fabs(center_anchor.depth_offset - requested_depth) < 1e-4f &&
                std::fabs(center_anchor.rotation_degrees - requested_rotation) < 1e-4f &&
                center_anchor.hidden == values.hidden &&
                center_anchor.resolve_x == values.resolve_x &&
                center_anchor.flip_horizontal == values.flip_horizontal &&
                center_anchor.flip_vertical == values.flip_vertical &&
                center_anchor.scaling_method == values.scaling_method) {
                return false;
            }

            center_anchor.depth_offset = requested_depth;
            center_anchor.rotation_degrees = requested_rotation;
            center_anchor.hidden = values.hidden;
            center_anchor.resolve_x = values.resolve_x;
            center_anchor.flip_horizontal = values.flip_horizontal;
            center_anchor.flip_vertical = values.flip_vertical;
            center_anchor.scaling_method = values.scaling_method;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);
}

bool RoomEditor::drag_oval_center_to_screen(SDL_Point screen_point) {
    if (!active_mode_owns_domain(OwnershipDomain::OvalMappingAndPoints)) {
        return log_rejected_domain_mutation("drag_oval_center_to_screen", OwnershipDomain::OvalMappingAndPoints);
    }
    if (!oval_mode_active() || !oval_edit_.center_selected || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return false;
    }
    const std::string center_anchor_name = selected_oval_center_anchor_name();
    if (center_anchor_name.empty()) {
        return false;
    }

    const SDL_FPoint desired_screen{
        static_cast<float>(screen_point.x),
        static_cast<float>(screen_point.y),
    };
    return mutate_selected_oval_center_anchor(
        [&](DisplacedAssetAnchorPoint& center_anchor) {
            Asset* target = oval_edit_.target_asset;
            if (!target) {
                return false;
            }
            auto sample_screen = [&](int texture_x, int texture_y, SDL_FPoint& out_screen) {
                DisplacedAssetAnchorPoint sample_anchor = center_anchor;
                sample_anchor.texture_x = std::max(0, texture_x);
                sample_anchor.texture_y = std::max(0, texture_y);
                const auto sample = anchor_points::resolve_frame_anchor_sample(
                    *target,
                    sample_anchor,
                    anchor_points::GridMaterialization::None);
                if (sample.resolved.missing) {
                    return false;
                }
                const SDL_FPoint projected = sample.has_final_screen_px ? sample.final_screen_px : sample.screen_px;
                if (!std::isfinite(projected.x) || !std::isfinite(projected.y)) {
                    return false;
                }
                out_screen = projected;
                return true;
            };

            const int base_x = center_anchor.texture_x;
            const int base_y = center_anchor.texture_y;
            int best_x = base_x;
            int best_y = base_y;
            if (!solve_texture_point_for_screen_target(
                    base_x,
                    base_y,
                    desired_screen,
                    sample_screen,
                    best_x,
                    best_y)) {
                return false;
            }

            if (center_anchor.texture_x == best_x && center_anchor.texture_y == best_y) {
                return false;
            }
            center_anchor.texture_x = best_x;
            center_anchor.texture_y = best_y;
            return true;
        },
        devmode::core::DevSaveCoordinator::Priority::Debounced);
}

bool RoomEditor::apply_oval_center_current_frame_to_scope(EditorFramePropagationScope scope) {
    if (!oval_mode_active() || !oval_edit_.target_asset || !oval_edit_.target_asset->info || !oval_edit_.center_selected) {
        return false;
    }

    Asset* target = oval_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto& mappings = target_info->oval_anchor_mappings;
    if (oval_edit_.selected_oval_index < 0 ||
        oval_edit_.selected_oval_index >= static_cast<int>(mappings.size())) {
        return false;
    }
    const std::string mapping_name = mappings[static_cast<std::size_t>(oval_edit_.selected_oval_index)].name;
    const std::string center_anchor_name = selected_oval_center_anchor_name();
    if (center_anchor_name.empty()) {
        return false;
    }

    const bool ensured_centers = target_info->ensure_oval_center_anchors_for_mapping(mapping_name, true);
    if (ensured_centers) {
        target->invalidate_anchor_registry();
    }

    auto current_anim_it = target_info->animations.find(oval_edit_.animation_id);
    if (current_anim_it == target_info->animations.end() || !current_anim_it->second.has_frames()) {
        return false;
    }

    const std::size_t source_frame_count = current_anim_it->second.frame_count();
    const std::size_t source_frame_index = static_cast<std::size_t>(
        devmode::room_anchor_mode::wrap_index(oval_edit_.frame_index, static_cast<int>(source_frame_count)));
    AnimationFrame* source_frame = current_anim_it->second.primary_frame_at(source_frame_index);
    if (!source_frame) {
        return false;
    }
    const DisplacedAssetAnchorPoint* source_anchor = find_named_anchor(source_frame, center_anchor_name);
    if (!source_anchor) {
        return false;
    }

    std::unordered_map<std::string, std::vector<std::size_t>> apply_indices;
    if (scope == EditorFramePropagationScope::Asset) {
        for (const std::string& animation_id : eligible_anchor_animation_names(*target_info)) {
            auto anim_it = target_info->animations.find(animation_id);
            if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
                continue;
            }
            std::vector<std::size_t>& indices = apply_indices[animation_id];
            indices.reserve(anim_it->second.frame_count());
            for (std::size_t i = 0; i < anim_it->second.frame_count(); ++i) {
                indices.push_back(i);
            }
        }
    } else if (scope == EditorFramePropagationScope::Animation) {
        std::vector<std::size_t>& indices = apply_indices[oval_edit_.animation_id];
        indices.reserve(source_frame_count);
        for (std::size_t i = 0; i < source_frame_count; ++i) {
            indices.push_back(i);
        }
    } else {
        std::vector<std::size_t>& indices = apply_indices[oval_edit_.animation_id];
        const std::size_t next_frame = static_cast<std::size_t>(
            devmode::room_anchor_mode::wrap_index(static_cast<int>(source_frame_index) + 1,
                                                  static_cast<int>(source_frame_count)));
        indices.push_back(next_frame);
    }

    bool updated_any = ensured_centers;
    for (auto& pair : apply_indices) {
        auto anim_it = target_info->animations.find(pair.first);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }

        std::vector<std::size_t>& indices = pair.second;
        std::sort(indices.begin(), indices.end());
        indices.erase(std::unique(indices.begin(), indices.end()), indices.end());

        nlohmann::json payload = target_info->animation_payload(pair.first);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index : indices) {
            if (frame_index >= frame_count) {
                continue;
            }
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            DisplacedAssetAnchorPoint* target_anchor = find_named_anchor_mutable(frame, center_anchor_name);
            if (!target_anchor) {
                continue;
            }
            if (!copy_anchor_authoring_fields(*target_anchor, *source_anchor)) {
                continue;
            }
            frame->rebuild_anchor_lookup();
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            updated_any = true;
        }
        if (payload_changed && !target_info->upsert_animation(pair.first, payload)) {
            return false;
        }
    }

    if (!updated_any) {
        return false;
    }

    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(target, center_anchor_name);
    return persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Immediate,
                                 true,
                                 "Oval Center Bulk Apply",
                                 "room-oval-center-bulk-apply");
}

int RoomEditor::find_oval_point_handle_at_point(SDL_Point screen_point,
                                                int radius_px,
                                                int preferred_point_index) const {
    const float radius_sq = static_cast<float>(radius_px * radius_px);
    if (preferred_point_index >= 0) {
        for (const auto& handle : oval_edit_.handles) {
            if (handle.point_index != preferred_point_index || !handle.has_final_screen_px) {
                continue;
            }
            const float dx = handle.final_screen_px.x - static_cast<float>(screen_point.x);
            const float dy = handle.final_screen_px.y - static_cast<float>(screen_point.y);
            const float dist_sq = dx * dx + dy * dy;
            if (dist_sq <= radius_sq) {
                return handle.point_index;
            }
            break;
        }
    }

    float best_dist_sq = radius_sq;
    int best_index = -1;
    for (const auto& handle : oval_edit_.handles) {
        if (!handle.has_final_screen_px) {
            continue;
        }
        const float dx = handle.final_screen_px.x - static_cast<float>(screen_point.x);
        const float dy = handle.final_screen_px.y - static_cast<float>(screen_point.y);
        const float dist_sq = dx * dx + dy * dy;
        if (dist_sq <= best_dist_sq) {
            best_dist_sq = dist_sq;
            best_index = handle.point_index;
        }
    }
    return best_index;
}

bool RoomEditor::handle_oval_mode_mouse_input(const Input& input) {
    if (!oval_mode_active()) {
        return false;
    }
    refresh_oval_mode_handles();

    const SDL_Point screen_pt{input.getX(), input.getY()};
    const bool left_down = input.isDown(Input::LEFT);
    const bool left_pressed = input.wasPressed(Input::LEFT);
    const bool left_released = input.wasReleased(Input::LEFT);
    const bool right_pressed = input.wasPressed(Input::RIGHT);
    const bool pointer_blocked = is_oval_ui_blocking_point(screen_pt.x, screen_pt.y);
    bool body_hit = false;
    const auto guide_is_hit = [&](SDL_Point point) {
        if (oval_edit_.guide_screen_samples.size() < 2) {
            return false;
        }
        const float threshold_sq = static_cast<float>(kOvalGuidePickRadiusPx * kOvalGuidePickRadiusPx);
        const float px = static_cast<float>(point.x);
        const float py = static_cast<float>(point.y);
        for (std::size_t i = 0; i < oval_edit_.guide_screen_samples.size(); ++i) {
            const SDL_FPoint a = oval_edit_.guide_screen_samples[i];
            const SDL_FPoint b = oval_edit_.guide_screen_samples[(i + 1) % oval_edit_.guide_screen_samples.size()];
            if (!std::isfinite(a.x) || !std::isfinite(a.y) || !std::isfinite(b.x) || !std::isfinite(b.y)) {
                continue;
            }
            const float abx = b.x - a.x;
            const float aby = b.y - a.y;
            const float apx = px - a.x;
            const float apy = py - a.y;
            const float ab_len_sq = abx * abx + aby * aby;
            float t = 0.0f;
            if (ab_len_sq > 1e-4f) {
                t = std::clamp((apx * abx + apy * aby) / ab_len_sq, 0.0f, 1.0f);
            }
            const float nearest_x = a.x + (abx * t);
            const float nearest_y = a.y + (aby * t);
            const float dx = nearest_x - px;
            const float dy = nearest_y - py;
            const float dist_sq = dx * dx + dy * dy;
            if (dist_sq <= threshold_sq) {
                return true;
            }
        }
        return false;
    };

    if (!pointer_blocked) {
        oval_edit_.hovered_point_index =
            find_oval_point_handle_at_point(screen_pt, kOvalPointPickRadiusPx, oval_edit_.selected_point_index);
        body_hit = oval_edit_.hovered_point_index < 0 && guide_is_hit(screen_pt);
        oval_edit_.center_hovered = body_hit;
        oval_edit_.body_hovered = body_hit;

        if (left_pressed && oval_edit_.hovered_point_index >= 0) {
            const bool selection_changed =
                oval_edit_.selected_point_index != oval_edit_.hovered_point_index || oval_edit_.center_selected;
            oval_edit_.selected_point_index = oval_edit_.hovered_point_index;
            oval_edit_.center_selected = false;
            oval_edit_.center_hovered = false;
            oval_edit_.body_hovered = false;
            oval_edit_.center_dragging = false;
            if (selection_changed) {
                sync_oval_tools_panel();
            }
        } else if (left_pressed && body_hit) {
            const bool selection_changed = !oval_edit_.center_selected || oval_edit_.selected_point_index >= 0;
            oval_edit_.center_selected = true;
            oval_edit_.selected_point_index = -1;
            oval_edit_.center_dragging = true;
            if (drag_oval_center_to_screen(screen_pt)) {
                refresh_oval_mode_handles();
            }
            if (selection_changed) {
                sync_oval_tools_panel();
            }
        } else if (left_pressed &&
                   !body_hit &&
                   oval_edit_.hovered_point_index < 0 &&
                   (oval_edit_.selected_point_index >= 0 || oval_edit_.center_selected)) {
            oval_edit_.selected_point_index = -1;
            oval_edit_.center_selected = false;
            oval_edit_.center_hovered = false;
            oval_edit_.body_hovered = false;
            oval_edit_.center_dragging = false;
            sync_oval_tools_panel();
        }
    } else {
        oval_edit_.hovered_point_index = -1;
        oval_edit_.center_hovered = false;
        oval_edit_.body_hovered = false;
    }

    if (right_pressed &&
        !pointer_blocked &&
        body_hit &&
        oval_edit_.target_asset &&
        oval_edit_.target_asset->info) {
        const int mapping_index = oval_edit_.selected_oval_index;

        const auto& mappings = oval_edit_.target_asset->info->oval_anchor_mappings;
        if (mapping_index >= 0 && mapping_index < static_cast<int>(mappings.size())) {
            const AssetInfo::OvalAnchorMapping& mapping = mappings[static_cast<std::size_t>(mapping_index)];
            std::unordered_set<std::string> allowed_anchor_names;
            const std::string primary_anchor = AssetInfo::oval_center_anchor_name_for_mapping(mapping.name);
            if (!primary_anchor.empty()) {
                allowed_anchor_names.insert(primary_anchor);
            }
            for (const auto& legacy_name : mapping.legacy_names) {
                const std::string legacy_anchor = AssetInfo::oval_center_anchor_name_for_mapping(legacy_name);
                if (!legacy_anchor.empty()) {
                    allowed_anchor_names.insert(legacy_anchor);
                }
            }
            Asset* child = nullptr;
            if (!allowed_anchor_names.empty()) {
                child = resolve_bound_child_for_owner(oval_edit_.target_asset, screen_pt, &allowed_anchor_names);
            }
            if (!child) {
                child = resolve_bound_child_for_owner(oval_edit_.target_asset, screen_pt, nullptr);
            }
            if (child && navigate_to_bound_child_asset_info(child)) {
                rclick_buffer_frames_ = 2;
                if (input_) {
                    input_->consumeMouseButton(Input::RIGHT);
                }
                return true;
            }
        }
    }

    if (oval_edit_.center_dragging && left_down && !pointer_blocked) {
        if (drag_oval_center_to_screen(screen_pt)) {
            refresh_oval_mode_handles();
        }
    }
    if (left_released) {
        oval_edit_.center_dragging = false;
    }

    const int scroll_y = input.getScrollY();
    if (scroll_y != 0 && oval_edit_.center_selected && !pointer_blocked) {
        if (mutate_selected_oval_center_anchor(
                [scroll_y](DisplacedAssetAnchorPoint& center_anchor) {
                    const float next_depth =
                        center_anchor.depth_offset + static_cast<float>(scroll_y) * kAnchorDepthScrollStepWorldPx;
                    if (!std::isfinite(next_depth) ||
                        std::fabs(next_depth - center_anchor.depth_offset) < 1e-4f) {
                        return false;
                    }
                    center_anchor.depth_offset = next_depth;
                    return true;
                },
                devmode::core::DevSaveCoordinator::Priority::Debounced) &&
            input_) {
            input_->consumeScroll();
        }
    }

    return true;
}

bool RoomEditor::apply_anchor_current_frame_to_scope(EditorFramePropagationScope scope) {
    if (!anchor_mode_active() || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info ||
        anchor_edit_.selected_anchor_name.empty()) {
        return false;
    }

    Asset* target = anchor_edit_.target_asset;
    std::shared_ptr<AssetInfo> target_info = target->info;
    const auto owner = devmode::room_anchor_mode::owner_from_light_mode(light_mode_active());
    const auto is_reserved_anchor_name = [this](const std::string& anchor_name) {
        return is_valid_oval_center_anchor_name(anchor_name);
    };
    auto current_anim_it = target_info->animations.find(anchor_edit_.animation_id);
    if (current_anim_it == target_info->animations.end() || !current_anim_it->second.has_frames()) {
        return false;
    }

    bool normalized_any = false;
    if (!normalize_anchor_invariants_for_eligible_animations(target, target_info, normalized_any)) {
        return false;
    }

    const std::size_t source_frame_count = current_anim_it->second.frame_count();
    const std::size_t source_frame_index = static_cast<std::size_t>(
        devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index, static_cast<int>(source_frame_count)));
    AnimationFrame* source_frame = current_anim_it->second.primary_frame_at(source_frame_index);
    if (!source_frame) {
        return false;
    }
    const DisplacedAssetAnchorPoint* source_anchor = devmode::room_anchor_mode::find_anchor_in_mode(
        source_frame->anchor_points,
        anchor_edit_.selected_anchor_name,
        owner,
        is_reserved_anchor_name);
    if (!source_anchor) {
        return normalized_any &&
               commit_anchor_bulk_edit(target,
                                       target_info,
                                       devmode::core::DevSaveCoordinator::Priority::Immediate,
                                       true,
                                       "Anchor Bulk Apply",
                                       "room-anchor-bulk-apply");
    }

    std::unordered_map<std::string, std::vector<std::size_t>> apply_indices;
    if (scope == EditorFramePropagationScope::Asset) {
        for (const std::string& animation_id : eligible_anchor_animation_names(*target_info)) {
            auto anim_it = target_info->animations.find(animation_id);
            if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
                continue;
            }
            std::vector<std::size_t>& indices = apply_indices[animation_id];
            indices.reserve(anim_it->second.frame_count());
            for (std::size_t i = 0; i < anim_it->second.frame_count(); ++i) {
                indices.push_back(i);
            }
        }
    } else if (scope == EditorFramePropagationScope::Animation) {
        std::vector<std::size_t>& indices = apply_indices[anchor_edit_.animation_id];
        indices.reserve(source_frame_count);
        for (std::size_t i = 0; i < source_frame_count; ++i) {
            indices.push_back(i);
        }
    } else {
        std::vector<std::size_t>& indices = apply_indices[anchor_edit_.animation_id];
        const std::size_t next_frame = static_cast<std::size_t>(
            devmode::room_anchor_mode::wrap_index(static_cast<int>(source_frame_index) + 1,
                                                  static_cast<int>(source_frame_count)));
        indices.push_back(next_frame);
    }

    bool updated_any = normalized_any;
    for (auto& pair : apply_indices) {
        auto anim_it = target_info->animations.find(pair.first);
        if (anim_it == target_info->animations.end() || !anim_it->second.has_frames()) {
            continue;
        }

        std::vector<std::size_t>& indices = pair.second;
        std::sort(indices.begin(), indices.end());
        indices.erase(std::unique(indices.begin(), indices.end()), indices.end());

        nlohmann::json payload = target_info->animation_payload(pair.first);
        const std::size_t frame_count = anim_it->second.frame_count();
        bool payload_changed = false;
        for (std::size_t frame_index : indices) {
            if (frame_index >= frame_count) {
                continue;
            }
            AnimationFrame* frame = anim_it->second.primary_frame_at(frame_index);
            if (!frame) {
                continue;
            }
            DisplacedAssetAnchorPoint* target_anchor = devmode::room_anchor_mode::find_anchor_in_mode_mutable(
                frame->anchor_points,
                anchor_edit_.selected_anchor_name,
                owner,
                is_reserved_anchor_name);
            if (!target_anchor) {
                continue;
            }
            if (!copy_anchor_authoring_fields(*target_anchor, *source_anchor)) {
                continue;
            }
            frame->rebuild_anchor_lookup();
            if (!devmode::room_anchor_mode::write_anchor_frame_to_payload(payload,
                                                                          frame_count,
                                                                          frame_index,
                                                                          frame->anchor_points)) {
                return false;
            }
            payload_changed = true;
            updated_any = true;
        }
        if (payload_changed) {
            if (!target_info->upsert_animation(pair.first, payload)) {
                return false;
            }
        }
    }

    if (!updated_any) {
        return false;
    }
    if (!commit_anchor_bulk_edit(target,
                                 target_info,
                                 devmode::core::DevSaveCoordinator::Priority::Immediate,
                                 true,
                                 "Anchor Bulk Apply",
                                 "room-anchor-bulk-apply")) {
        return false;
    }
    anchor_bound_asset_helper::AnchorBoundAssetHelper::instance().notify_anchor_changed(
        target,
        anchor_edit_.selected_anchor_name);
    return true;
}

bool RoomEditor::handle_anchor_mode_mouse_input(const Input& input) {
    if (!anchor_mode_active()) {
        return false;
    }
    refresh_anchor_mode_handles();

    const SDL_Point screen_pt{input_->getX(), input_->getY()};
    const bool left_down = input_->isDown(Input::LEFT);
    const bool left_pressed = input_->wasPressed(Input::LEFT);
    const bool left_released = input_->wasReleased(Input::LEFT);
    const bool right_pressed = input_->wasPressed(Input::RIGHT);
    const bool pointer_blocked = is_anchor_ui_blocking_point(screen_pt.x, screen_pt.y);
    const bool selection_locked =
        anchor_edit_.point_selected && !anchor_edit_.selected_anchor_name.empty();

    if (right_pressed && !pointer_blocked && anchor_edit_.target_asset) {
        const std::string preferred_anchor = selection_locked ? anchor_edit_.selected_anchor_name : std::string{};
        int hit = find_anchor_handle_at_point(screen_pt, kAnchorHandlePickRadiusPx, preferred_anchor);
        if (hit < 0) {
            hit = find_anchor_handle_at_point(screen_pt, kAnchorHandlePickRadiusPx, std::string{});
        }
        if (hit >= 0 && static_cast<std::size_t>(hit) < anchor_edit_.handles.size()) {
            std::unordered_set<std::string> allowed_anchor_names;
            allowed_anchor_names.insert(anchor_edit_.handles[static_cast<std::size_t>(hit)].name);
            Asset* child =
                resolve_bound_child_for_owner(anchor_edit_.target_asset, screen_pt, &allowed_anchor_names);
            if (!child) {
                child = resolve_bound_child_for_owner(anchor_edit_.target_asset, screen_pt, nullptr);
            }
            if (child && navigate_to_bound_child_asset_info(child)) {
                rclick_buffer_frames_ = 2;
                if (input_) {
                    input_->consumeMouseButton(Input::RIGHT);
                }
                return true;
            }
        }
    }

    if (left_pressed && !pointer_blocked) {
        bool started_depth_drag = false;
        int depth_hit = -1;
        if (selection_locked) {
            depth_hit = find_anchor_floor_crosshair_at_point(
                screen_pt,
                kAnchorHandlePickRadiusPx,
                5,
                anchor_edit_.selected_anchor_name);
        }
        if (depth_hit < 0) {
            depth_hit = find_anchor_floor_crosshair_at_point(
                screen_pt,
                kAnchorHandlePickRadiusPx,
                selection_locked ? 5 : 0,
                std::string{});
        }
        if (depth_hit >= 0 &&
            static_cast<std::size_t>(depth_hit) < anchor_edit_.handles.size()) {
            const std::string depth_anchor_name = anchor_edit_.handles[static_cast<std::size_t>(depth_hit)].name;
            anchor_edit_.selected_anchor_name = depth_anchor_name;
            anchor_edit_.point_selected = true;
            if (begin_anchor_depth_drag(depth_anchor_name, screen_pt)) {
                started_depth_drag = true;
                sync_anchor_tools_panel();
            }
        }

        const std::string preferred_anchor = selection_locked ? anchor_edit_.selected_anchor_name : std::string{};
        int hit = started_depth_drag ? -1 : find_anchor_handle_at_point(screen_pt, kAnchorHandlePickRadiusPx, preferred_anchor);
        if (!started_depth_drag && selection_locked &&
            hit >= 0 &&
            static_cast<std::size_t>(hit) < anchor_edit_.handles.size() &&
            anchor_edit_.handles[static_cast<std::size_t>(hit)].name != anchor_edit_.selected_anchor_name) {
            hit = -1;
        }
        if (!started_depth_drag && hit >= 0 && static_cast<std::size_t>(hit) < anchor_edit_.handles.size()) {
            anchor_edit_.selected_anchor_name = anchor_edit_.handles[static_cast<std::size_t>(hit)].name;
            anchor_edit_.dragging_anchor_name = anchor_edit_.selected_anchor_name;
            anchor_edit_.point_selected = true;
            anchor_edit_.dragging = true;
            anchor_edit_.dragging_depth = false;
            drag_anchor_to_screen(anchor_edit_.dragging_anchor_name, screen_pt);
            sync_anchor_tools_panel();
        } else if (!started_depth_drag) {
            int floor_hit = find_anchor_floor_crosshair_at_point(screen_pt, kAnchorHandlePickRadiusPx, 0, std::string{});
            if (floor_hit >= 0 && static_cast<std::size_t>(floor_hit) < anchor_edit_.handles.size()) {
                anchor_edit_.selected_anchor_name = anchor_edit_.handles[static_cast<std::size_t>(floor_hit)].name;
                anchor_edit_.dragging_anchor_name.clear();
                anchor_edit_.point_selected = true;
                anchor_edit_.dragging = false;
                anchor_edit_.dragging_depth = false;
                sync_anchor_tools_panel();
            } else {
                clear_anchor_selection();
                sync_anchor_tools_panel();
            }
        }
    }

    if (anchor_edit_.dragging && left_down) {
        drag_anchor_to_screen(anchor_edit_.dragging_anchor_name, screen_pt);
    }
    if (anchor_edit_.dragging_depth && left_down) {
        drag_anchor_depth_to_screen(anchor_edit_.dragging_anchor_name, screen_pt);
    }

    if (left_released) {
        anchor_edit_.dragging = false;
        anchor_edit_.dragging_depth = false;
        anchor_edit_.dragging_anchor_name.clear();
    }

    if (!anchor_edit_.dragging && !anchor_edit_.dragging_depth && !pointer_blocked) {
        const bool selection_locked_now =
            anchor_edit_.point_selected && !anchor_edit_.selected_anchor_name.empty();
        const std::string preferred_anchor = selection_locked_now ? anchor_edit_.selected_anchor_name : std::string{};
        int hover = find_anchor_handle_at_point(screen_pt, kAnchorHandlePickRadiusPx, preferred_anchor);
        if (selection_locked_now &&
            hover >= 0 &&
            static_cast<std::size_t>(hover) < anchor_edit_.handles.size() &&
            anchor_edit_.handles[static_cast<std::size_t>(hover)].name != anchor_edit_.selected_anchor_name) {
            hover = -1;
        }
        if (hover >= 0 && static_cast<std::size_t>(hover) < anchor_edit_.handles.size()) {
            const std::string& hovered_name = anchor_edit_.handles[static_cast<std::size_t>(hover)].name;
            anchor_edit_.hovered_anchor_name = hovered_name;
        } else {
            anchor_edit_.hovered_anchor_name.clear();
        }
    } else if (pointer_blocked) {
        anchor_edit_.hovered_anchor_name.clear();
    }

    const int scroll_y = input.getScrollY();
    if (scroll_y != 0 && !pointer_blocked && !anchor_edit_.dragging_depth) {
        ensure_anchor_selection_valid();
        if (!anchor_edit_.selected_anchor_name.empty() &&
            update_anchor_depth(anchor_edit_.selected_anchor_name,
                                static_cast<float>(scroll_y) * kAnchorDepthScrollStepWorldPx) &&
            input_) {
            input_->consumeScroll();
        }
    }

    return true;
}

void RoomEditor::navigate_anchor_animation(int delta) {
    if (!anchor_mode_active() || delta == 0) {
        return;
    }
    std::vector<std::string> names = anchor_mode_animation_names();
    if (names.empty()) {
        return;
    }
    int index = 0;
    auto found = std::find(names.begin(), names.end(), anchor_edit_.animation_id);
    if (found != names.end()) {
        index = static_cast<int>(std::distance(names.begin(), found));
    }
    const int next_index = devmode::room_anchor_mode::wrap_index(index + delta, static_cast<int>(names.size()));
    const std::string& next_animation = names[static_cast<std::size_t>(next_index)];

    int next_frame_index = anchor_edit_.frame_index;
    if (anchor_edit_.target_asset && anchor_edit_.target_asset->info) {
        auto anim_it = anchor_edit_.target_asset->info->animations.find(next_animation);
        if (anim_it != anchor_edit_.target_asset->info->animations.end() && anim_it->second.has_frames()) {
            next_frame_index =
                devmode::room_anchor_mode::wrap_index(next_frame_index, static_cast<int>(anim_it->second.frame_count()));
        } else {
            next_frame_index = 0;
        }
    }

    if (apply_anchor_animation_and_frame(next_animation, next_frame_index)) {
        refresh_anchor_mode_handles();
    }
}

void RoomEditor::navigate_anchor_frame(int delta) {
    if (!anchor_mode_active() || delta == 0 || !anchor_edit_.target_asset || !anchor_edit_.target_asset->info) {
        return;
    }
    auto anim_it = anchor_edit_.target_asset->info->animations.find(anchor_edit_.animation_id);
    if (anim_it == anchor_edit_.target_asset->info->animations.end() || !anim_it->second.has_frames()) {
        return;
    }
    const int next_frame =
        devmode::room_anchor_mode::wrap_index(anchor_edit_.frame_index + delta, static_cast<int>(anim_it->second.frame_count()));
    if (apply_anchor_animation_and_frame(anchor_edit_.animation_id, next_frame)) {
        refresh_anchor_mode_handles();
    }
}

bool RoomEditor::enter_anchor_edit_mode(bool light_editor_mode) {
    if (anchor_mode_active()) {
        const EditorMode target_mode =
            light_editor_mode ? EditorMode::LightEdit : EditorMode::AnchorEdit;
        if (editor_mode_ != target_mode) {
            const EditorMode previous_mode = editor_mode_;
            editor_mode_ = target_mode;
            reconcile_mode_ownership_state(previous_mode);
            anchor_edit_.light_editor_mode = light_editor_mode;
            refresh_anchor_mode_handles();
            update_asset_editor_layout();
        }
        return true;
    }
    close_anchor_candidate_editor();

    Asset* target = selected_anchor_mode_asset();
    if (!target || !target->info) {
        return false;
    }

    const auto selection = resolve_file_sourced_animation_selection_for_target(target, target->current_animation);
    if (selection.navigable_animation_ids.empty()) {
        return false;
    }

    anchor_edit_ = AnchorEditState{};
    anchor_edit_.target_asset = target;
    anchor_edit_.had_static_frame_before = true;
    anchor_edit_.static_frame_before = target->static_frame;

    const EditorMode previous_mode = editor_mode_;
    editor_mode_ = light_editor_mode ? EditorMode::LightEdit : EditorMode::AnchorEdit;
    reconcile_mode_ownership_state(previous_mode);
    anchor_edit_.light_editor_mode = light_editor_mode;
    anchor_edit_.animation_id = selection.resolved_animation_id;
    anchor_edit_.frame_index = 0;

    if (!apply_anchor_animation_and_frame(anchor_edit_.animation_id, resolve_anchor_mode_frame_index())) {
        const EditorMode failed_mode = editor_mode_;
        editor_mode_ = EditorMode::Normal;
        reconcile_mode_ownership_state(failed_mode);
        anchor_edit_ = AnchorEditState{};
        return false;
    }

    refresh_anchor_mode_handles();
    ensure_anchor_selection_valid();
    sync_anchor_tools_panel();
    update_asset_editor_layout();
    return true;
}

void RoomEditor::exit_anchor_edit_mode(bool flush_immediately) {
    if (!anchor_mode_active()) {
        return;
    }
    close_anchor_candidate_editor();

    const bool target_live = is_asset_pointer_live(anchor_edit_.target_asset);

    if (flush_immediately && target_live) {
        persist_anchor_current_frame(devmode::core::DevSaveCoordinator::Priority::Immediate, true);
    }

    if (target_live && anchor_edit_.target_asset && anchor_edit_.had_static_frame_before) {
        anchor_edit_.target_asset->static_frame = anchor_edit_.static_frame_before;
    }

    const EditorMode previous_mode = editor_mode_;
    editor_mode_ = EditorMode::Normal;
    reconcile_mode_ownership_state(previous_mode);
    anchor_edit_ = AnchorEditState{};
    sync_anchor_tools_panel();
    update_asset_editor_layout();
}

bool RoomEditor::enter_oval_anchor_edit_mode() {
    if (oval_mode_active()) {
        return true;
    }

    Asset* target = selected_anchor_mode_asset();
    if (!target || !target->info) {
        return false;
    }

    const auto selection = resolve_file_sourced_animation_selection_for_target(target, target->current_animation);
    if (!selection.has_selection()) {
        return false;
    }

    release_oval_attachment_lock();
    oval_edit_ = OvalAnchorEditState{};
    oval_edit_.target_asset = target;
    oval_edit_.had_static_frame_before = true;
    oval_edit_.static_frame_before = target->static_frame;
    oval_edit_.selected_oval_index = target->info->oval_anchor_mappings.empty() ? -1 : 0;
    oval_edit_.selected_point_index = -1;

    const EditorMode previous_mode = editor_mode_;
    editor_mode_ = EditorMode::OvalAnchorEdit;
    reconcile_mode_ownership_state(previous_mode);
    oval_edit_.animation_id = selection.resolved_animation_id;
    oval_edit_.frame_index = 0;

    if (!apply_oval_animation_and_frame(oval_edit_.animation_id, resolve_oval_mode_frame_index())) {
        const EditorMode failed_mode = editor_mode_;
        editor_mode_ = EditorMode::Normal;
        reconcile_mode_ownership_state(failed_mode);
        oval_edit_ = OvalAnchorEditState{};
        return false;
    }

    refresh_oval_mode_handles();
    sync_oval_tools_panel();
    update_asset_editor_layout();
    return true;
}

void RoomEditor::exit_oval_anchor_edit_mode(bool flush_immediately) {
    if (!oval_mode_active()) {
        return;
    }

    const bool target_live = is_asset_pointer_live(oval_edit_.target_asset);

    if (flush_immediately && target_live && oval_edit_.dirty_since_last_flush) {
        (void)persist_oval_mappings(devmode::core::DevSaveCoordinator::Priority::Immediate,
                                    true,
                                    "Oval Anchor Edit",
                                    "room-oval-anchor-edit");
    }

    release_oval_attachment_lock();

    if (target_live && oval_edit_.target_asset && oval_edit_.had_static_frame_before) {
        oval_edit_.target_asset->static_frame = oval_edit_.static_frame_before;
    }

    const EditorMode previous_mode = editor_mode_;
    editor_mode_ = EditorMode::Normal;
    reconcile_mode_ownership_state(previous_mode);
    oval_edit_ = OvalAnchorEditState{};
    sync_oval_tools_panel();
    update_asset_editor_layout();
}

void RoomEditor::navigate_oval_animation(int delta) {
    if (!oval_mode_active() || delta == 0) {
        return;
    }
    std::vector<std::string> names = oval_mode_animation_names();
    if (names.empty()) {
        return;
    }
    int index = 0;
    auto found = std::find(names.begin(), names.end(), oval_edit_.animation_id);
    if (found != names.end()) {
        index = static_cast<int>(std::distance(names.begin(), found));
    }
    const int next_index = devmode::room_anchor_mode::wrap_index(index + delta, static_cast<int>(names.size()));
    const std::string& next_animation = names[static_cast<std::size_t>(next_index)];

    int next_frame_index = oval_edit_.frame_index;
    if (oval_edit_.target_asset && oval_edit_.target_asset->info) {
        auto anim_it = oval_edit_.target_asset->info->animations.find(next_animation);
        if (anim_it != oval_edit_.target_asset->info->animations.end() && anim_it->second.has_frames()) {
            next_frame_index =
                devmode::room_anchor_mode::wrap_index(next_frame_index, static_cast<int>(anim_it->second.frame_count()));
        } else {
            next_frame_index = 0;
        }
    }

    (void)apply_oval_animation_and_frame(next_animation, next_frame_index);
}

void RoomEditor::navigate_oval_frame(int delta) {
    if (!oval_mode_active() || delta == 0 || !oval_edit_.target_asset || !oval_edit_.target_asset->info) {
        return;
    }
    auto anim_it = oval_edit_.target_asset->info->animations.find(oval_edit_.animation_id);
    if (anim_it == oval_edit_.target_asset->info->animations.end() || !anim_it->second.has_frames()) {
        return;
    }
    const int next_frame =
        devmode::room_anchor_mode::wrap_index(oval_edit_.frame_index + delta, static_cast<int>(anim_it->second.frame_count()));
    (void)apply_oval_animation_and_frame(oval_edit_.animation_id, next_frame);
}

